            className="flex items-center gap-1.5 text-sm font-medium text-slate-500 hover:text-emerald-500 transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"/></svg>
            <span>{post.shares}</span>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-6 border-t animate-in slide-in-from-top-2 duration-300 ${isDarkMode ? 'bg-slate-900/50 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
          <div className="space-y-4 mb-6">
            {post.comments.length === 0 ? (
              <p className="text-xs text-center text-slate-500 italic">No comments yet. Be the first to share your thoughts!</p>
            ) : (
              post.comments.map(c => (
                <div key={c.id} className="flex gap-3 animate-in fade-in slide-in-from-bottom-1">
                  <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 font-bold text-xs uppercase">
                    {c.username[0]}
                  </div>
                  <div className={`p-3 rounded-2xl flex-1 text-sm ${isDarkMode ? 'bg-slate-800' : 'bg-white shadow-sm'}`}>
                    <div className="flex justify-between mb-1">
                      <span className="font-bold">@{c.username}</span>
                      <span className="text-[10px] text-slate-500">{new Date(c.createdAt).toLocaleTimeString()}</span>
                    </div>
                    <p className={isDarkMode ? 'text-slate-300' : 'text-slate-600'}>{c.content}</p>
                  </div>
                </div>
              ))
            )}
          </div>

          <form onSubmit={handleAddComment} className="flex gap-2">
            <input
              type="text"
              placeholder="Write a comment..."
              value={commentText}
              onChange={(e) => setCommentText(e.target.value)}
              className={`flex-1 px-4 py-2 rounded-full text-sm outline-none transition-all ${
                isDarkMode 
                  ? 'bg-slate-800 border-slate-700 focus:border-indigo-500 text-white' 
                  : 'bg-white border-slate-200 focus:border-blue-500 border text-slate-900'
              }`}
            />
            <button 
              type="submit"
              disabled={!commentText.trim()}
              className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-full text-sm font-bold transition-colors"
            >
              Post
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Post, User } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { PostCard } from './components/PostCard';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<'home' | 'create' | 'login' | 'register' | 'my-stories'>('home');
  const [searchQuery, setSearchQuery] = useState('');

  // Post form state
  const [newTitle, setNewTitle] = useState('');
  const [newContent, setNewContent] = useState('');

  // Auth form states
  const [loginMethod, setLoginMethod] = useState<'username' | 'email'>('username');
  const [authUsername, setAuthUsername] = useState('');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authConfirmPassword, setAuthConfirmPassword] = useState('');
  const [authError, setAuthError] = useState('');

  useEffect(() => {
    setCurrentUser(db.getCurrentUser());
    setPosts(db.getPosts());

    // Particles background
    const particlesCount = 20;
    const existingParticles = document.querySelectorAll('.particle');
    if (existingParticles.length === 0) {
      const body = document.body;
      for(let i=0; i<particlesCount; i++) {
          const p = document.createElement('div');
          p.className = 'particle';
          p.style.left = Math.random() * 100 + 'vw';
          p.style.top = Math.random() * 100 + 'vh';
          p.style.animationDelay = Math.random() * 5 + 's';
          p.style.opacity = (Math.random() * 0.3 + 0.1).toString();
          body.appendChild(p);
      }
    }
  }, []);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');
    const identifier = loginMethod === 'username' ? authUsername : authEmail;
    const result = db.login(identifier, authPassword, loginMethod);
    if (result.success && result.user) {
      setCurrentUser(result.user);
      setCurrentPage('home');
      setAuthUsername('');
      setAuthEmail('');
      setAuthPassword('');
    } else {
      setAuthError(result.error || 'Login failed');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');

    if (authPassword !== authConfirmPassword) {
      setAuthError('Passwords do not match');
      return;
    }

    const result = db.register(authUsername, authEmail, authPassword);
    if (result.success && result.user) {
      setCurrentUser(result.user);
      setCurrentPage('home');
      setAuthUsername('');
      setAuthEmail('');
      setAuthPassword('');
      setAuthConfirmPassword('');
    } else {
      setAuthError(result.error || 'Registration failed');
    }
  };

  const handleCreatePost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    const newPost: Post = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      title: newTitle,
      content: newContent,
      likes: 0,
      likedBy: [],
      shares: 0,
      comments: [],
      createdAt: new Date().toISOString(),
      userAvatar: currentUser.avatar
    };

    db.savePost(newPost);
    setPosts(db.getPosts());
    setNewTitle('');
    setNewContent('');
    setCurrentPage('home');
  };

  const handlePostUpdate = (updatedPost: Post) => {
    setPosts(prev => prev.map(p => p.id === updatedPost.id ? updatedPost : p));
    // Re-sync current user in case their badge/likes changed
    setCurrentUser(db.getCurrentUser());
  };

  const switchAuthPage = (page: 'login' | 'register') => {
    setAuthError('');
    setAuthUsername('');
    setAuthEmail('');
    setAuthPassword('');
    setAuthConfirmPassword('');
    setCurrentPage(page);
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={(page) => {
          setAuthError('');
          setCurrentPage(page as any);
        }}
      />

      <main className="max-w-4xl mx-auto px-4 py-12">
        {(currentPage === 'home' || currentPage === 'my-stories') && (
          <section className="space-y-8 animate-in fade-in duration-500">
            <div className="text-center mb-12">
              <h1 className="font-serif text-4xl md:text-5xl font-bold mb-4">
                {currentPage === 'my-stories' ? 'Your Stories' : 'Latest Stories & Novels'}
              </h1>
              <p className="text-slate-500 max-w-lg mx-auto">
                {currentPage === 'my-stories' 
                  ? 'Review and manage the stories you have brought to life.'
                  : 'Explore the worlds created by our talented community of writers.'}
              </p>
            </div>

            {filteredPosts.length === 0 ? (
              <div className={`p-16 border-2 border-dashed rounded-3xl text-center ${isDarkMode ? 'border-slate-800' : 'border-slate-200 bg-white shadow-xl'}`}>
                <h2 className="text-3xl font-serif font-bold mb-2">No Stories Found</h2>
                <p className="text-slate-500 mb-8">Ready to make your mark? Share your creative masterpiece with the world!</p>
                <button 
                  onClick={() => currentUser ? setCurrentPage('create') : setCurrentPage('login')}
                  className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-bold shadow-lg shadow-indigo-500/30 transition-all hover:-translate-y-1"
                >
                  Create Your First Story
                </button>
              </div>
            ) : (
              <div className="grid gap-8">
                {filteredPosts.map(post => (
                  <PostCard 
                    key={post.id} 
                    post={post} 
                    currentUser={currentUser} 
                    isDarkMode={isDarkMode} 
                    onPostUpdate={handlePostUpdate}
                  />
                ))}
              </div>
            )}
          </section>
        )}

        {currentPage === 'create' && (
          <section className="animate-in fade-in slide-in-from-bottom-4 duration-500">
             <div className="text-center mb-10">
                <h1 className="font-serif text-4xl font-bold mb-4">Share Your Story</h1>
                <p className="text-slate-500">Craft a new post and inspire the community with your words.</p>
             </div>
             <form 
              onSubmit={handleCreatePost}
              className={`p-8 rounded-3xl shadow-2xl space-y-6 ${isDarkMode ? 'bg-slate-900 border border-slate-800' : 'bg-white'}`}
             >
                <div>
                  <label className="block text-xs font-bold uppercase tracking-widest text-slate-400 mb-2">Title</label>
                  <input 
                    required
                    type="text" 
                    placeholder="Enter your post title here..."
                    value={newTitle}
                    onChange={(e) => setNewTitle(e.target.value)}
                    className={`w-full p-4 rounded-xl border-2 outline-none transition-all ${
                      isDarkMode 
                        ? 'bg-slate-800 border-slate-700 focus:border-indigo-500' 
                        : 'bg-slate-50 border-slate-200 focus:border-blue-500'
                    }`}
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold uppercase tracking-widest text-slate-400 mb-2">Content</label>
                  <textarea 
                    required
                    rows={8}
                    placeholder="Write your story or article content here..."
                    value={newContent}
                    onChange={(e) => setNewContent(e.target.value)}
                    className={`w-full p-4 rounded-xl border-2 outline-none transition-all resize-none ${
                      isDarkMode 
                        ? 'bg-slate-800 border-slate-700 focus:border-indigo-500' 
                        : 'bg-slate-50 border-slate-200 focus:border-blue-500'
                    }`}
                  />
                </div>
                <button 
                  type="submit"
                  className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-xl shadow-indigo-500/20 transition-all hover:scale-[1.01] active:scale-95"
                >
                  Publish My Story
                </button>
             </form>
          </section>
        )}

        {(currentPage === 'login' || currentPage === 'register') && (
          <section className="max-w-md mx-auto py-10 text-center animate-in fade-in zoom-in-95 duration-300">
             <h2 className="text-3xl font-serif font-bold mb-2">
                {currentPage === 'login' ? 'Welcome Back' : 'Create Account'}
             </h2>
             <p className="text-slate-500 mb-8">
                {currentPage === 'login' 
                  ? 'Join the conversation in the StoryVerse.' 
                  : 'Start your journey as a storyteller today.'}
             </p>

             {authError && (
               <div className="mb-6 p-3 bg-red-100 border border-red-200 text-red-600 text-sm rounded-lg font-medium">
                 {authError}
               </div>
             )}

             <div className={`p-8 rounded-3xl shadow-2xl space-y-6 ${isDarkMode ? 'bg-slate-900 border border-slate-800' : 'bg-white'}`}>
                {currentPage === 'login' && (
                  <div className={`flex p-1 rounded-xl mb-4 ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
                    <button 
                      onClick={() => setLoginMethod('username')}
                      className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${loginMethod === 'username' ? (isDarkMode ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600 shadow-sm') : 'text-slate-500'}`}
                    >
                      Username
                    </button>
                    <button 
                      onClick={() => setLoginMethod('email')}
                      className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${loginMethod === 'email' ? (isDarkMode ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600 shadow-sm') : 'text-slate-500'}`}
                    >
                      Email
                    </button>
                  </div>
                )}

                <form onSubmit={currentPage === 'login' ? handleLogin : handleRegister} className="space-y-4">
                    {/* Only show username if registering or loginMethod is username */}
                    {(currentPage === 'register' || loginMethod === 'username') && (
                      <div className="text-left animate-in slide-in-from-left-2 duration-200">
                        <label className="text-[10px] font-bold uppercase text-slate-400 ml-1">Username</label>
                        <input 
                          type="text" 
                          placeholder="e.g. StoryTeller99" 
                          required
                          value={authUsername}
                          onChange={(e) => setAuthUsername(e.target.value)}
                          className={`w-full p-4 rounded-xl border-2 outline-none transition-all ${
                            isDarkMode ? 'bg-slate-900 border-slate-800 focus:border-indigo-500' : 'bg-white border-slate-200 focus:border-indigo-400'
                          }`}
                        />
                      </div>
                    )}

                    {/* Only show email if registering or loginMethod is email */}
                    {(currentPage === 'register' || loginMethod === 'email') && (
                      <div className="text-left animate-in slide-in-from-right-2 duration-200">
                        <label className="text-[10px] font-bold uppercase text-slate-400 ml-1">Email Address</label>
                        <input 
                          type="email" 
                          placeholder="name@example.com" 
                          required
                          value={authEmail}
                          onChange={(e) => setAuthEmail(e.target.value)}
                          className={`w-full p-4 rounded-xl border-2 outline-none transition-all ${
                            isDarkMode ? 'bg-slate-900 border-slate-800 focus:border-indigo-500' : 'bg-white border-slate-200 focus:border-indigo-400'
                          }`}
                        />
                      </div>
                    )}

                    <div className="text-left">
                      <label className="text-[10px] font-bold uppercase text-slate-400 ml-1">Password</label>
                      <input 
                        type="password" 
                        placeholder="••••••••" 
                        required
                        value={authPassword}
                        onChange={(e) => setAuthPassword(e.target.value)}
                        className={`w-full p-4 rounded-xl border-2 outline-none transition-all ${
                          isDarkMode ? 'bg-slate-900 border-slate-800 focus:border-indigo-500' : 'bg-white border-slate-200 focus:border-indigo-400'
                        }`}
                      />
                    </div>

                    {currentPage === 'register' && (
                      <div className="text-left animate-in fade-in duration-300">
                        <label className="text-[10px] font-bold uppercase text-slate-400 ml-1">Confirm Password</label>
                        <input 
                          type="password" 
                          placeholder="••••••••" 
                          required
                          value={authConfirmPassword}
                          onChange={(e) => setAuthConfirmPassword(e.target.value)}
                          className={`w-full p-4 rounded-xl border-2 outline-none transition-all ${
                            isDarkMode ? 'bg-slate-900 border-slate-800 focus:border-indigo-500' : 'bg-white border-slate-200 focus:border-indigo-400'
                          }`}
                        />
                      </div>
                    )}

                    <button 
                      type="submit"
                      className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-500/20 active:scale-95"
                    >
                      {currentPage === 'login' ? `Login with ${loginMethod === 'username' ? 'Username' : 'Email'}` : 'Register Account'}
                    </button>
                </form>
             </div>

             <div className="mt-8 text-sm">
                {currentPage === 'login' ? (
                  <p className="text-slate-500">
                    Don't have an account? {' '}
                    <button onClick={() => switchAuthPage('register')} className="text-indigo-600 font-bold hover:underline">Register Now</button>
                  </p>
                ) : (
                  <p className="text-slate-500">
                    Already have an account? {' '}
                    <button onClick={() => switchAuthPage('login')} className="text-indigo-600 font-bold hover:underline">Login instead</button>
                  </p>
                )}
             </div>
          </section>
        )}
      </main>

      <footer className={`py-12 border-t text-center ${isDarkMode ? 'border-slate-800 text-slate-500' : 'border-slate-100 text-slate-400'}`}>
        <p className="font-serif text-lg font-bold mb-2">StoryVerse - Where Stories Come Alive</p>
        <p className="text-xs">© {new Date().getFullYear()} StoryVerse Collective. All rights reserved.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo } from 'react';
// Added BadgeTier to the imports from ../types
import { Post, User, BadgeTier } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';

interface PostCardProps {
  post: Post;
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (post: Post) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ post, currentUser, isDarkMode, onPostUpdate }) => {
  const [commentText, setCommentText] = useState('');
  const [showComments, setShowComments] = useState(false);
  const [isAnimatingLike, setIsAnimatingLike] = useState(false);
  const [likeParticles, setLikeParticles] = useState<{ id: number; x: number; y: number }[]>([]);

  const isLiked = useMemo(() => {
    return currentUser ? post.likedBy?.includes(currentUser.id) : false;
  }, [post.likedBy, currentUser]);

  const handleLike = useCallback(() => {
    if (!currentUser) return alert('Please login to like');

    const hasLiked = post.likedBy?.includes(currentUser.id);
    const likeDelta = hasLiked ? -1 : 1;

    // Calculate new likedBy list
    const newLikedBy = hasLiked 
      ? (post.likedBy || []).filter(id => id !== currentUser.id)
      : [...(post.likedBy || []), currentUser.id];

    // Trigger animations only on like
    if (!hasLiked) {
      setIsAnimatingLike(true);
      setTimeout(() => setIsAnimatingLike(false), 400);

      const newParticles = Array.from({ length: 5 }).map((_, i) => ({
        id: Date.now() + i,
        x: (Math.random() - 0.5) * 40,
        y: (Math.random() - 0.5) * 40,
      }));
      setLikeParticles(prev => [...prev, ...newParticles]);
      setTimeout(() => {
        setLikeParticles(prev => prev.filter(p => !newParticles.includes(p)));
      }, 800);
    }

    const updatedPost: Post = { 
      ...post, 
      likes: Math.max(0, post.likes + likeDelta),
      likedBy: newLikedBy
    };

    db.updatePost(updatedPost);
    db.updateUserLikes(post.userId, likeDelta);
    onPostUpdate(updatedPost);
  }, [post, currentUser, onPostUpdate]);

  const handleShare = () => {
    const updatedPost = { ...post, shares: post.shares + 1 };
    db.updatePost(updatedPost);
    onPostUpdate(updatedPost);
    navigator.clipboard.writeText(window.location.href);
    alert('Link copied to clipboard!');
  };

  const handleAddComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return alert('Please login to comment');
    if (!commentText.trim()) return;

    const newComment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      content: commentText,
      createdAt: new Date().toISOString()
    };

    const updatedPost = {
      ...post,
      comments: [...post.comments, newComment]
    };

    db.updatePost(updatedPost);
    onPostUpdate(updatedPost);
    setCommentText('');
  };

  const authorBadge = useMemo(() => {
    const users = db.getUsers();
    // BadgeTier is now correctly imported
    return users.find(u => u.id === post.userId)?.badge || BadgeTier.NOVICE;
  }, [post.userId, post.likes]); // Use post.likes to trigger badge recalculation if likes change significantly

  return (
    <div className={`rounded-xl shadow-sm border transition-all duration-300 overflow-hidden ${
      isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-200'
    }`}>
      <div className="p-6">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-3">
            <img src={post.userAvatar} className="w-10 h-10 rounded-full bg-slate-200" alt={post.username} />
            <div>
              <div className="flex items-center gap-2">
                <span className="font-bold text-sm">@{post.username}</span>
                <BadgeIcon tier={authorBadge} />
              </div>
              <span className="text-[10px] text-slate-500 uppercase font-bold tracking-tight">
                {new Date(post.createdAt).toLocaleDateString()}
              </span>
            </div>
          </div>
          <button className="text-slate-400 hover:text-indigo-500">
            <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M12 8c1.1 0 2-.9 2-2s-.9-2-2-2-2 .9-2 2 .9 2 2 2zm0 2c-1.1 0-2 .9-2 2 s.9 2 2 2 2-.9 2-2-.9-2-2-2zm0 6c-1.1 0-2 .9-2 2 s.9 2 2 2 2-.9 2-2-.9-2-2-2z"/></svg>
          </button>
        </div>

        <h3 className={`font-serif text-xl font-bold mb-3 ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>
          {post.title}
        </h3>

        <p className={`text-sm leading-relaxed mb-6 ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
          {post.content}
        </p>

        <div className={`flex items-center gap-6 pt-4 border-t ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}`}>
          <div className="relative inline-flex items-center">
            <button 
              onClick={handleLike}
              className={`group flex items-center gap-1.5 text-sm font-medium transition-all ${
                isLiked || isAnimatingLike ? 'text-red-500' : 'text-slate-500 hover:text-red-500'
              }`}
            >
              <div className={`relative ${isAnimatingLike ? 'animate-heart-pop' : ''}`}>
                <svg 
                  className={`w-5 h-5 transition-all ${isLiked || isAnimatingLike ? 'fill-red-500 stroke-red-500' : 'fill-none stroke-current'}`} 
                  viewBox="0 0 24 24"
                >
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/>
                </svg>
              </div>
              <span className={isLiked || isAnimatingLike ? 'font-bold' : ''}>{post.likes}</span>
            </button>
            {/* Burst particles */}
            {likeParticles.map(p => (
              <div 
                key={p.id} 
                className="like-particle"
                style={{ 
                  left: '10px', 
                  top: '0px', 
                  marginLeft: `${p.x}px`, 
                  marginTop: `${p.y}px` 
                }}
              >
                <svg className="w-3 h-3 text-red-500 fill-current" viewBox="0 0 24 24">
                  <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/>
                </svg>
              </div>
            ))}
          </div>

          <button 
            onClick={() => setShowComments(!showComments)}
            className="flex items-center gap-1.5 text-sm font-medium text-slate-500 hover:text-blue-500 transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
            <span>{post.comments.length}</span>
          </button>

          <button 
            onClick={handleShare}
            className="flex items-center gap-1.5 text-sm font-medium text-slate-500 hover:text-emerald-500 transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"/></svg>
            <span>{post.shares}</span>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-6 border-t animate-in slide-in-from-top-2 duration-300 ${isDarkMode ? 'bg-slate-900/50 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
          <div className="space-y-4 mb-6">
            {post.comments.length === 0 ? (
              <p className="text-xs text-center text-slate-500 italic">No comments yet. Be the first to share your thoughts!</p>
            ) : (
              post.comments.map(c => (
                <div key={c.id} className="flex gap-3 animate-in fade-in slide-in-from-bottom-1">
                  <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 font-bold text-xs uppercase">
                    {c.username[0]}
                  </div>
                  <div className={`p-3 rounded-2xl flex-1 text-sm ${isDarkMode ? 'bg-slate-800' : 'bg-white shadow-sm'}`}>
                    <div className="flex justify-between mb-1">
                      <span className="font-bold">@{c.username}</span>
                      <span className="text-[10px] text-slate-500">{new Date(c.createdAt).toLocaleTimeString()}</span>
                    </div>
                    <p className={isDarkMode ? 'text-slate-300' : 'text-slate-600'}>{c.content}</p>
                  </div>
                </div>
              ))
            )}
          </div>

          <form onSubmit={handleAddComment} className="flex gap-2">
            <input
              type="text"
              placeholder="Write a comment..."
              value={commentText}
              onChange={(e) => setCommentText(e.target.value)}
              className={`flex-1 px-4 py-2 rounded-full text-sm outline-none transition-all ${
                isDarkMode 
                  ? 'bg-slate-800 border-slate-700 focus:border-indigo-500 text-white' 
                  : 'bg-white border-slate-200 focus:border-blue-500 border text-slate-900'
              }`}
            />
            <button 
              type="submit"
              disabled={!commentText.trim()}
              className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-full text-sm font-bold transition-colors"
            >
              Post
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const aiService = {
  async fixGrammar(content: string): Promise<string> {
    if (!content.trim()) return content;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Fix any grammatical, spelling, or punctuation errors in the following text. Keep the tone and style exactly the same, only fix mistakes. Output ONLY the corrected text: "${content}"`,
      });
      return response.text || content;
    } catch (error) {
      console.error("AI Grammar fix failed:", error);
      return content;
    }
  },

  async getSuggestion(title: string, content: string): Promise<string> {
    const prompt = title 
      ? `I'm writing a story titled "${title}". Here is what I have so far: "${content}". Suggest the next 2-3 sentences to continue the story in a creative way.`
      : `I'm writing a story. Here is what I have so far: "${content}". Suggest a creative next 2-3 sentences.`;

    try {
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
      });
      return response.text || "Keep writing! You're doing great.";
    } catch (error) {
      console.error("AI Suggestion failed:", error);
      return "The words are within you; keep exploring.";
    }
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Post, User } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { PostCard } from './components/PostCard';
import { aiService } from './services/ai';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<'home' | 'create' | 'login' | 'register' | 'my-stories'>('home');
  const [searchQuery, setSearchQuery] = useState('');

  // Post form state
  const [newTitle, setNewTitle] = useState('');
  const [newContent, setNewContent] = useState('');

  // AI Helper state
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiSuggestion, setAiSuggestion] = useState<string | null>(null);

  // Auth form states
  const [loginMethod, setLoginMethod] = useState<'username' | 'email'>('username');
  const [authUsername, setAuthUsername] = useState('');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authConfirmPassword, setAuthConfirmPassword] = useState('');
  const [authError, setAuthError] = useState('');

  useEffect(() => {
    setCurrentUser(db.getCurrentUser());
    setPosts(db.getPosts());

    // Particles background
    const particlesCount = 20;
    const existingParticles = document.querySelectorAll('.particle');
    if (existingParticles.length === 0) {
      const body = document.body;
      for(let i=0; i<particlesCount; i++) {
          const p = document.createElement('div');
          p.className = 'particle';
          p.style.left = Math.random() * 100 + 'vw';
          p.style.top = Math.random() * 100 + 'vh';
          p.style.animationDelay = Math.random() * 5 + 's';
          p.style.opacity = (Math.random() * 0.3 + 0.1).toString();
          body.appendChild(p);
      }
    }
  }, []);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');
    const identifier = loginMethod === 'username' ? authUsername : authEmail;
    const result = db.login(identifier, authPassword, loginMethod);
    if (result.success && result.user) {
      setCurrentUser(result.user);
      setCurrentPage('home');
      setAuthUsername('');
      setAuthEmail('');
      setAuthPassword('');
    } else {
      setAuthError(result.error || 'Login failed');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');

    if (authPassword !== authConfirmPassword) {
      setAuthError('Passwords do not match');
      return;
    }

    const result = db.register(authUsername, authEmail, authPassword);
    if (result.success && result.user) {
      setCurrentUser(result.user);
      setCurrentPage('home');
      setAuthUsername('');
      setAuthEmail('');
      setAuthPassword('');
      setAuthConfirmPassword('');
    } else {
      setAuthError(result.error || 'Registration failed');
    }
  };

  const handleCreatePost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    const newPost: Post = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      title: newTitle,
      content: newContent,
      likes: 0,
      likedBy: [],
      shares: 0,
      comments: [],
      createdAt: new Date().toISOString(),
      userAvatar: currentUser.avatar
    };

    db.savePost(newPost);
    setPosts(db.getPosts());
    setNewTitle('');
    setNewContent('');
    setCurrentPage('home');
  };

  const handlePostUpdate = (updatedPost: Post) => {
    setPosts(prev => prev.map(p => p.id === updatedPost.id ? updatedPost : p));
    setCurrentUser(db.getCurrentUser());
  };

  const handleAiFixGrammar = async () => {
    if (!newContent.trim()) return;
    setIsAiLoading(true);
    const corrected = await aiService.fixGrammar(newContent);
    setNewContent(corrected);
    setIsAiLoading(false);
  };

  const handleAiGetSuggestion = async () => {
    setIsAiLoading(true);
    const suggestion = await aiService.getSuggestion(newTitle, newContent);
    setAiSuggestion(suggestion);
    setIsAiLoading(false);
  };

  const handleApplySuggestion = () => {
    if (aiSuggestion) {
      setNewContent(prev => prev.trim() + " " + aiSuggestion);
      setAiSuggestion(null);
    }
  };

  const switchAuthPage = (page: 'login' | 'register') => {
    setAuthError('');
    setAuthUsername('');
    setAuthEmail('');
    setAuthPassword('');
    setAuthConfirmPassword('');
    setCurrentPage(page);
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={(page) => {
          setAuthError('');
          setCurrentPage(page as any);
        }}
      />

      <main className="max-w-4xl mx-auto px-4 py-12">
        {(currentPage === 'home' || currentPage === 'my-stories') && (
          <section className="space-y-8 animate-in fade-in duration-500">
            <div className="text-center mb-12">
              <h1 className="font-serif text-4xl md:text-5xl font-bold mb-4">
                {currentPage === 'my-stories' ? 'Your Stories' : 'Latest Stories & Novels'}
              </h1>
              <p className="text-slate-500 max-w-lg mx-auto">
                {currentPage === 'my-stories' 
                  ? 'Review and manage the stories you have brought to life.'
                  : 'Explore the worlds created by our talented community of writers.'}
              </p>
            </div>

            {filteredPosts.length === 0 ? (
              <div className={`p-16 border-2 border-dashed rounded-3xl text-center ${isDarkMode ? 'border-slate-800' : 'border-slate-200 bg-white shadow-xl'}`}>
                <h2 className="text-3xl font-serif font-bold mb-2">No Stories Found</h2>
                <p className="text-slate-500 mb-8">Ready to make your mark? Share your creative masterpiece with the world!</p>
                <button 
                  onClick={() => currentUser ? setCurrentPage('create') : setCurrentPage('login')}
                  className="px-8 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-bold shadow-lg shadow-indigo-500/30 transition-all hover:-translate-y-1"
                >
                  Create Your First Story
                </button>
              </div>
            ) : (
              <div className="grid gap-8">
                {filteredPosts.map(post => (
                  <PostCard 
                    key={post.id} 
                    post={post} 
                    currentUser={currentUser} 
                    isDarkMode={isDarkMode} 
                    onPostUpdate={handlePostUpdate}
                  />
                ))}
              </div>
            )}
          </section>
        )}

        {currentPage === 'create' && (
          <section className="animate-in fade-in slide-in-from-bottom-4 duration-500 flex flex-col md:flex-row gap-8 items-start">
             <div className="flex-1 w-full">
               <div className="text-center md:text-left mb-10">
                  <h1 className="font-serif text-4xl font-bold mb-4">Share Your Story</h1>
                  <p className="text-slate-500">Craft a new post and inspire the community with your words.</p>
               </div>
               <form 
                onSubmit={handleCreatePost}
                className={`p-8 rounded-3xl shadow-2xl space-y-6 ${isDarkMode ? 'bg-slate-900 border border-slate-800' : 'bg-white'}`}
               >
                  <div>
                    <label className="block text-xs font-bold uppercase tracking-widest text-slate-400 mb-2">Title</label>
                    <input 
                      required
                      type="text" 
                      placeholder="Enter your post title here..."
                      value={newTitle}
                      onChange={(e) => setNewTitle(e.target.value)}
                      className={`w-full p-4 rounded-xl border-2 outline-none transition-all ${
                        isDarkMode 
                          ? 'bg-slate-800 border-slate-700 focus:border-indigo-500 text-white' 
                          : 'bg-slate-50 border-slate-200 focus:border-blue-500'
                      }`}
                    />
                  </div>
                  <div>
                    <label className="block text-xs font-bold uppercase tracking-widest text-slate-400 mb-2">Content</label>
                    <textarea 
                      required
                      rows={12}
                      placeholder="Write your story or article content here..."
                      value={newContent}
                      onChange={(e) => setNewContent(e.target.value)}
                      className={`w-full p-4 rounded-xl border-2 outline-none transition-all resize-none ${
                        isDarkMode 
                          ? 'bg-slate-800 border-slate-700 focus:border-indigo-500 text-white' 
                          : 'bg-slate-50 border-slate-200 focus:border-blue-500'
                      }`}
                    />
                  </div>
                  <button 
                    type="submit"
                    className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-xl shadow-indigo-500/20 transition-all hover:scale-[1.01] active:scale-95"
                  >
                    Publish My Story
                  </button>
               </form>
             </div>

             {/* AI SIDEBAR HELPER */}
             <div className={`w-full md:w-80 p-6 rounded-3xl shadow-xl transition-all duration-300 ${
               isDarkMode ? 'bg-slate-900/50 border border-slate-800' : 'bg-indigo-50/50 border border-indigo-100'
             }`}>
               <div className="flex items-center gap-2 mb-6">
                 <span className="text-2xl">✨</span>
                 <h2 className="font-bold text-lg">AI Writing Assistant</h2>
               </div>

               <div className="space-y-4">
                 <button 
                  onClick={handleAiFixGrammar}
                  disabled={isAiLoading || !newContent.trim()}
                  className="w-full flex items-center justify-between p-3 rounded-xl bg-white dark:bg-slate-800 border dark:border-slate-700 hover:border-indigo-500 transition-all text-sm font-semibold disabled:opacity-50"
                 >
                   <span>Fix Grammar & Style</span>
                   {isAiLoading ? '⌛' : '🪄'}
                 </button>

                 <button 
                  onClick={handleAiGetSuggestion}
                  disabled={isAiLoading}
                  className="w-full flex items-center justify-between p-3 rounded-xl bg-white dark:bg-slate-800 border dark:border-slate-700 hover:border-indigo-500 transition-all text-sm font-semibold disabled:opacity-50"
                 >
                   <span>Inspire Next Sentence</span>
                   {isAiLoading ? '⌛' : '💡'}
                 </button>

                 {aiSuggestion && (
                   <div className="mt-6 p-4 rounded-2xl bg-white dark:bg-slate-800 border-2 border-indigo-200 dark:border-indigo-900 shadow-sm animate-in zoom-in-95 duration-300">
                     <p className="text-sm italic mb-4 line-clamp-4">"{aiSuggestion}"</p>
                     <div className="flex gap-2">
                       <button 
                        onClick={handleApplySuggestion}
                        className="flex-1 py-1.5 bg-indigo-600 text-white rounded-lg text-xs font-bold hover:bg-indigo-700 transition-colors"
                       >
                         Apply
                       </button>
                       <button 
                        onClick={() => setAiSuggestion(null)}
                        className="px-3 py-1.5 border border-slate-200 dark:border-slate-700 rounded-lg text-xs font-bold hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
                       >
                         Dismiss
                       </button>
                     </div>
                   </div>
                 )}

                 {isAiLoading && (
                   <div className="flex flex-col items-center justify-center py-8 text-slate-400">
                     <div className="w-8 h-8 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-3"></div>
                     <p className="text-xs font-medium animate-pulse">Gemini is thinking...</p>
                   </div>
