            className={`text-sm font-bold flex items-center gap-2 transition-all group mb-8 py-2 px-4 rounded-xl ${
              isDarkMode 
                ? 'text-indigo-400 hover:bg-indigo-500/10' 
                : 'text-indigo-600 hover:bg-indigo-50'
            }`}
          >
            <span className="tracking-tight">{isExpanded ? 'Collapse Story' : 'Dive into full story'}</span>
            <svg 
              className={`w-4 h-4 transition-transform duration-500 ${isExpanded ? 'rotate-180' : 'group-hover:translate-y-1'}`} 
              fill="none" 
              stroke="currentColor" 
              viewBox="0 0 24 24"
            >
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"/>
            </svg>
          </button>
        )}

        <div className={`flex items-center gap-8 pt-6 border-t ${isDarkMode ? 'border-slate-800/50' : 'border-slate-100'}`}>
          <div className="relative inline-flex items-center">
            <button 
              onClick={handleLike}
              className={`group flex items-center gap-2.5 text-sm font-bold transition-all ${
                isLiked || isAnimatingLike ? 'text-rose-500 scale-110' : 'text-slate-400 hover:text-rose-500'
              }`}
            >
              <div className={`relative ${isAnimatingLike ? 'animate-heart-pop' : ''}`}>
                <svg 
                  className={`w-6 h-6 transition-all ${isLiked || isAnimatingLike ? 'fill-rose-500 stroke-rose-500' : 'fill-none stroke-current'}`} 
                  viewBox="0 0 24 24"
                >
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/>
                </svg>
              </div>
              <span className="tabular-nums">{post.likes}</span>
            </button>
            {likeParticles.map(p => (
              <div 
                key={p.id} 
                className="like-particle"
                style={{ 
                  left: '12px', 
                  top: '-4px', 
                  marginLeft: `${p.x}px`, 
                  marginTop: `${p.y}px` 
                }}
              >
                <svg className="w-3 h-3 text-rose-500 fill-current" viewBox="0 0 24 24">
                  <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/>
                </svg>
              </div>
            ))}
          </div>

          <button 
            onClick={() => setShowComments(!showComments)}
            className={`flex items-center gap-2.5 text-sm font-bold transition-all ${
              showComments ? 'text-indigo-500 scale-105' : 'text-slate-400 hover:text-indigo-500'
            }`}
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/>
            </svg>
            <span className="tabular-nums">{post.comments.length}</span>
          </button>

          <button 
            onClick={handleShare}
            className="flex items-center gap-2 text-sm font-bold text-slate-400 hover:text-emerald-500 transition-all ml-auto p-2 hover:bg-emerald-500/5 rounded-xl"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"/>
            </svg>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-8 border-t animate-in slide-in-from-top-4 duration-500 ${isDarkMode ? 'bg-slate-900/60 border-slate-800/80' : 'bg-slate-50 border-slate-100'}`}>
          <div className="space-y-6 mb-8">
            {post.comments.length === 0 ? (
              <div className="text-center py-8">
                <div className="text-3xl mb-2 opacity-50">💬</div>
                <p className="text-sm text-slate-500 font-medium">Be the first to leave a comment</p>
              </div>
            ) : (
              post.comments.map(c => (
                <div key={c.id} className="flex gap-4 group">
                  <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-indigo-500 to-purple-500 flex items-center justify-center text-white font-black text-sm shrink-0 shadow-lg shadow-indigo-500/20">
                    {c.username[0].toUpperCase()}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between mb-1.5">
                      <span className="font-bold text-sm tracking-tight">@{c.username}</span>
                      <span className="text-[10px] text-slate-500 font-bold uppercase opacity-60">{new Date(c.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                    </div>
                    <p className={`text-sm leading-relaxed ${isDarkMode ? 'text-slate-300' : 'text-slate-700'}`}>{c.content}</p>
                  </div>
                </div>
              ))
            )}
          </div>

          <form onSubmit={handleAddComment} className="relative">
            <input
              type="text"
              placeholder="Add to the discussion..."
              value={commentText}
              onChange={(e) => setCommentText(e.target.value)}
              className={`w-full pl-6 pr-24 py-3.5 rounded-2xl text-sm outline-none transition-all ${
                isDarkMode 
                  ? 'bg-slate-800 border-slate-700 focus:border-indigo-500 text-white' 
                  : 'bg-white border-slate-200 focus:border-indigo-500 border text-slate-900 shadow-sm'
              }`}
            />
            <button 
              type="submit"
              disabled={!commentText.trim()}
              className="absolute right-1.5 top-1.5 bottom-1.5 px-6 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-30 text-white rounded-xl text-xs font-bold transition-all active:scale-95"
            >
              Reply
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Post, User } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { PostCard } from './components/PostCard';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<'home' | 'create' | 'login' | 'register' | 'my-stories'>('home');
  const [searchQuery, setSearchQuery] = useState('');

  // Post form state
  const [newTitle, setNewTitle] = useState('');
  const [newContent, setNewContent] = useState('');

  // Auth form states
  const [loginMethod, setLoginMethod] = useState<'username' | 'email'>('username');
  const [authUsername, setAuthUsername] = useState('');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authConfirmPassword, setAuthConfirmPassword] = useState('');
  const [authError, setAuthError] = useState('');

  useEffect(() => {
    setCurrentUser(db.getCurrentUser());
    setPosts(db.getPosts());

    // Better Particles background
    const particlesCount = 30;
    const existingParticles = document.querySelectorAll('.particle');
    if (existingParticles.length === 0) {
      const body = document.body;
      for(let i=0; i<particlesCount; i++) {
          const p = document.createElement('div');
          p.className = 'particle animate-float';
          p.style.left = Math.random() * 100 + 'vw';
          p.style.top = Math.random() * 100 + 'vh';
          const size = Math.random() * 4 + 2;
          p.style.width = size + 'px';
          p.style.height = size + 'px';
          p.style.animationDelay = (Math.random() * 8) + 's';
          p.style.animationDuration = (8 + Math.random() * 10) + 's';
          p.style.opacity = (Math.random() * 0.2 + 0.1).toString();
          body.appendChild(p);
      }
    }
  }, []);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');
    const identifier = loginMethod === 'username' ? authUsername : authEmail;
    const result = db.login(identifier, authPassword, loginMethod);
    if (result.success && result.user) {
      setCurrentUser(result.user);
      setCurrentPage('home');
      setAuthUsername('');
      setAuthEmail('');
      setAuthPassword('');
    } else {
      setAuthError(result.error || 'Login failed');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');

    if (authPassword !== authConfirmPassword) {
      setAuthError('Passwords do not match');
      return;
    }

    const result = db.register(authUsername, authEmail, authPassword);
    if (result.success && result.user) {
      setCurrentUser(result.user);
      setCurrentPage('home');
      setAuthUsername('');
      setAuthEmail('');
      setAuthPassword('');
      setAuthConfirmPassword('');
    } else {
      setAuthError(result.error || 'Registration failed');
    }
  };

  const handleCreatePost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    const newPost: Post = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      title: newTitle,
      content: newContent,
      likes: 0,
      likedBy: [],
      shares: 0,
      comments: [],
      createdAt: new Date().toISOString(),
      userAvatar: currentUser.avatar
    };

    db.savePost(newPost);
    setPosts(db.getPosts());
    setNewTitle('');
    setNewContent('');
    setCurrentPage('home');
  };

  const handlePostUpdate = (updatedPost: Post) => {
    setPosts(prev => prev.map(p => p.id === updatedPost.id ? updatedPost : p));
    setCurrentUser(db.getCurrentUser());
  };

  const switchAuthPage = (page: 'login' | 'register') => {
    setAuthError('');
    setAuthUsername('');
    setAuthEmail('');
    setAuthPassword('');
    setAuthConfirmPassword('');
    setCurrentPage(page);
  };

  return (
    <div className={`min-h-screen ${isDarkMode ? 'dark' : ''}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={(page) => {
          setAuthError('');
          setCurrentPage(page as any);
        }}
      />

      <main className="max-w-5xl mx-auto px-6 py-16 lg:py-24">
        {(currentPage === 'home' || currentPage === 'my-stories') && (
          <section className="space-y-16 animate-in fade-in duration-700">
            <div className="text-center max-w-2xl mx-auto mb-20 stagger-item" style={{ animationDelay: '0s' }}>
              <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-indigo-500/10 text-indigo-500 text-xs font-black uppercase tracking-widest mb-6">
                 <span>✨</span> Discover Originality <span>✨</span>
              </div>
              <h1 className="font-serif text-5xl md:text-7xl font-black mb-6 tracking-tight text-slate-900 dark:text-white leading-[1.1]">
                {currentPage === 'my-stories' ? 'Personal Archives' : 'Endless Tales.'}
              </h1>
              <p className="text-lg md:text-xl text-slate-500 dark:text-slate-400 font-medium leading-relaxed">
                {currentPage === 'my-stories' 
                  ? 'A curated collection of your own creative journeys.'
                  : 'Join the world\'s most vibrant community of modern storytellers and visionaries.'}
              </p>
            </div>

            {filteredPosts.length === 0 ? (
              <div className={`p-20 rounded-[3rem] text-center glass border-2 border-dashed border-indigo-500/20 shadow-2xl stagger-item`} style={{ animationDelay: '0.2s' }}>
                <div className="text-6xl mb-6 grayscale opacity-50">🖋️</div>
                <h2 className="text-3xl font-serif font-black mb-4 dark:text-white">The page is blank.</h2>
                <p className="text-slate-500 dark:text-slate-400 mb-10 text-lg max-w-md mx-auto">This story is waiting for your unique perspective. Why not start today?</p>
                <button 
                  onClick={() => currentUser ? setCurrentPage('create') : setCurrentPage('login')}
                  className="px-10 py-4 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-700 hover:to-purple-700 text-white rounded-2xl font-black shadow-xl shadow-indigo-500/30 transition-all hover:-translate-y-1 active:scale-95"
                >
                  Write First Entry
                </button>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-1 lg:grid-cols-1 gap-12">
                {filteredPosts.map((post, idx) => (
                  <PostCard 
                    key={post.id} 
                    post={post} 
                    currentUser={currentUser} 
                    isDarkMode={isDarkMode} 
                    onPostUpdate={handlePostUpdate}
                    index={idx}
                  />
                ))}
              </div>
            )}
          </section>
        )}

        {currentPage === 'create' && (
          <section className="animate-in fade-in slide-in-from-bottom-8 duration-700 max-w-3xl mx-auto">
             <div className="text-center mb-16">
                <h1 className="font-serif text-5xl font-black mb-6 tracking-tight dark:text-white leading-tight">Manifest Your Vision</h1>
                <p className="text-lg text-slate-500 dark:text-slate-400 font-medium">Capture the thoughts that matter most and share them with the Universe.</p>
             </div>
             <form 
              onSubmit={handleCreatePost}
              className={`p-10 md:p-14 rounded-[3rem] shadow-2xl space-y-10 glass hover:shadow-indigo-500/10 transition-shadow border border-white/20`}
             >
                <div className="group">
                  <label className="block text-[11px] font-black uppercase tracking-[0.2em] text-indigo-500 mb-4 ml-1">Composition Title</label>
                  <input 
                    required
                    type="text" 
                    placeholder="E.g., The Midnight Echo of Silence..."
                    value={newTitle}
                    onChange={(e) => setNewTitle(e.target.value)}
                    className={`w-full p-6 rounded-2xl text-xl font-bold outline-none transition-all shadow-inner ${
                      isDarkMode 
                        ? 'bg-slate-800/50 border-0 ring-1 ring-slate-700 focus:ring-2 focus:ring-indigo-500 text-white' 
                        : 'bg-slate-50 border-0 ring-1 ring-slate-200 focus:ring-2 focus:ring-indigo-500 text-slate-900'
                    }`}
                  />
                </div>
                <div className="group">
                  <label className="block text-[11px] font-black uppercase tracking-[0.2em] text-indigo-500 mb-4 ml-1">The Narrative</label>
                  <textarea 
                    required
                    rows={12}
                    placeholder="Begin your journey here..."
                    value={newContent}
                    onChange={(e) => setNewContent(e.target.value)}
                    className={`w-full p-6 rounded-3xl text-lg leading-relaxed outline-none transition-all resize-none shadow-inner ${
                      isDarkMode 
                        ? 'bg-slate-800/50 border-0 ring-1 ring-slate-700 focus:ring-2 focus:ring-indigo-500 text-white' 
                        : 'bg-slate-50 border-0 ring-1 ring-slate-200 focus:ring-2 focus:ring-indigo-500 text-slate-900'
                    }`}
                  />
                </div>
                <button 
                  type="submit"
                  className="w-full py-6 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-700 hover:to-purple-700 text-white rounded-3xl font-black text-lg shadow-2xl shadow-indigo-500/20 transition-all hover:scale-[1.02] active:scale-95"
                >
                  Publish to Verse
                </button>
             </form>
          </section>
        )}

        {(currentPage === 'login' || currentPage === 'register') && (
          <section className="max-w-lg mx-auto py-10 text-center animate-in fade-in zoom-in-95 duration-500">
             <h2 className="text-4xl font-serif font-black mb-4 dark:text-white tracking-tight">
                {currentPage === 'login' ? 'Welcome Traveler' : 'Begin Your Odyssey'}
             </h2>
             <p className="text-slate-500 dark:text-slate-400 font-medium mb-12">
                {currentPage === 'login' 
                  ? 'Sign in to reconnect with your creative spark.' 
                  : 'Create a sanctuary for your thoughts and ideas.'}
             </p>

             {authError && (
               <div className="mb-10 p-4 bg-rose-500/10 border border-rose-500/20 text-rose-500 text-sm rounded-2xl font-bold animate-pulse">
                 {authError}
               </div>
             )}

             <div className={`p-10 md:p-12 rounded-[2.5rem] shadow-2xl space-y-10 glass border border-white/20`}>
                {currentPage === 'login' && (
                  <div className={`flex p-1.5 rounded-2xl mb-6 ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
                    <button 
                      onClick={() => setLoginMethod('username')}
                      className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${loginMethod === 'username' ? (isDarkMode ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-indigo-600 shadow-sm') : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                    >
                      Username
                    </button>
                    <button 
                      onClick={() => setLoginMethod('email')}
                      className={`flex-1 py-3 text-xs font-black uppercase tracking-widest rounded-xl transition-all ${loginMethod === 'email' ? (isDarkMode ? 'bg-indigo-600 text-white shadow-lg' : 'bg-white text-indigo-600 shadow-sm') : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
                    >
                      Email
                    </button>
                  </div>
                )}

                <form onSubmit={currentPage === 'login' ? handleLogin : handleRegister} className="space-y-6">
                    {(currentPage === 'register' || loginMethod === 'username') && (
                      <div className="text-left">
                        <label className="text-[10px] font-black uppercase tracking-widest text-indigo-500 ml-1 mb-2 block">Username</label>
                        <input 
                          type="text" 
                          placeholder="Explorer01" 
                          required
                          value={authUsername}
                          onChange={(e) => setAuthUsername(e.target.value)}
                          className={`w-full p-4.5 rounded-2xl border-0 outline-none transition-all shadow-inner ring-1 ${
                            isDarkMode ? 'bg-slate-900 border-0 ring-slate-800 focus:ring-indigo-500 text-white' : 'bg-white border-0 ring-slate-200 focus:ring-indigo-500 text-slate-900'
                          }`}
                        />
                      </div>
                    )}

                    {(currentPage === 'register' || loginMethod === 'email') && (
                      <div className="text-left">
                        <label className="text-[10px] font-black uppercase tracking-widest text-indigo-500 ml-1 mb-2 block">Email Address</label>
                        <input 
                          type="email" 
                          placeholder="traveler@verse.com" 
                          required
                          value={authEmail}
                          onChange={(e) => setAuthEmail(e.target.value)}
                          className={`w-full p-4.5 rounded-2xl border-0 outline-none transition-all shadow-inner ring-1 ${
                            isDarkMode ? 'bg-slate-900 border-0 ring-slate-800 focus:ring-indigo-500 text-white' : 'bg-white border-0 ring-slate-200 focus:ring-indigo-500 text-slate-900'
                          }`}
                        />
                      </div>
                    )}

                    <div className="text-left">
                      <label className="text-[10px] font-black uppercase tracking-widest text-indigo-500 ml-1 mb-2 block">Secret Phrase</label>
                      <input 
                        type="password" 
                        placeholder="••••••••" 
                        required
                        value={authPassword}
                        onChange={(e) => setAuthPassword(e.target.value)}
                        className={`w-full p-4.5 rounded-2xl border-0 outline-none transition-all shadow-inner ring-1 ${
                          isDarkMode ? 'bg-slate-900 border-0 ring-slate-800 focus:ring-indigo-500 text-white' : 'bg-white border-0 ring-slate-200 focus:ring-indigo-500 text-slate-900'
                        }`}
                      />
                    </div>

                    {currentPage === 'register' && (
                      <div className="text-left">
                        <label className="text-[10px] font-black uppercase tracking-widest text-indigo-500 ml-1 mb-2 block">Validate Phrase</label>
                        <input 
                          type="password" 
                          placeholder="••••••••" 
                          required
                          value={authConfirmPassword}
                          onChange={(e) => setAuthConfirmPassword(e.target.value)}
                          className={`w-full p-4.5 rounded-2xl border-0 outline-none transition-all shadow-inner ring-1 ${
                            isDarkMode ? 'bg-slate-900 border-0 ring-slate-800 focus:ring-indigo-500 text-white' : 'bg-white border-0 ring-slate-200 focus:ring-indigo-500 text-slate-900'
                          }`}
                        />
                      </div>
                    )}

                    <button 
                      type="submit"
                      className="w-full py-5 bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-700 hover:to-purple-700 text-white rounded-2xl font-black shadow-xl shadow-indigo-500/20 transition-all hover:scale-[1.02] active:scale-95 mt-4"
                    >
                      {currentPage === 'login' ? `Explore Now` : 'Launch Account'}
                    </button>
                </form>
             </div>

             <div className="mt-12 text-sm">
                {currentPage === 'login' ? (
                  <p className="text-slate-500 font-medium">
                    New to the Universe? {' '}
                    <button onClick={() => switchAuthPage('register')} className="text-indigo-500 font-black hover:underline underline-offset-4">Join the Expedition</button>
                  </p>
                ) : (
                  <p className="text-slate-500 font-medium">
                    Returning traveler? {' '}
                    <button onClick={() => switchAuthPage('login')} className="text-indigo-500 font-black hover:underline underline-offset-4">Resume Session</button>
                  </p>
                )}
             </div>
          </section>
        )}
      </main>

      <footer className={`py-20 border-t relative overflow-hidden transition-colors ${isDarkMode ? 'border-slate-800/50 text-slate-500' : 'border-slate-100 text-slate-400'}`}>
        <div className="max-w-7xl mx-auto px-6 text-center z-10 relative">
          <p className="font-serif text-2xl font-black mb-4 dark:text-white bg-clip-text text-transparent bg-gradient-to-r from-indigo-500 to-purple-600 inline-block">StoryVerse</p>
          <p className="text-sm font-medium tracking-wide mb-8">Crafting digital dimensions for modern writers.</p>
          <div className="flex justify-center gap-6 mb-12">
             {['Twitter', 'Discord', 'Github', 'Instagram'].map(platform => (
               <a key={platform} href="#" className="text-xs font-black uppercase tracking-widest hover:text-indigo-500 transition-colors">{platform}</a>
             ))}
          </div>
          <p className="text-[10px] font-bold uppercase tracking-[0.3em] opacity-40">© {new Date().getFullYear()} StoryVerse Collective. All rights reserved.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { User } from '../types';
import { LOGO_SVG } from '../constants';

interface NavbarProps {
  user: User | null;
  isDarkMode: boolean;
  toggleDarkMode: () => void;
  onSearch: (query: string) => void;
  onLogout: () => void;
  onNavigate: (page: 'home' | 'create' | 'login' | 'register' | 'my-stories') => void;
}

export const Navbar: React.FC<NavbarProps> = ({ 
  user, 
  isDarkMode, 
  toggleDarkMode, 
  onSearch, 
  onLogout,
  onNavigate 
}) => {
