          />
          <button type="submit" className="absolute right-3 top-2.5 text-slate-400">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"/></svg>
          </button>
        </form>

        {/* Desktop Links */}
        <div className="flex items-center gap-4">
          <div className="hidden md:flex items-center gap-4 text-sm font-medium">
            {user ? (
              <>
                <button onClick={() => onNavigate('home')} className="hover:text-indigo-600">Home</button>
                <button onClick={() => onNavigate('create')} className="hover:text-indigo-600">Write</button>
                <button onClick={() => onNavigate('my-stories')} className="hover:text-indigo-600">My Stories</button>
                <button onClick={onLogout} className="text-slate-500 hover:text-red-500">Logout</button>
              </>
            ) : (
              <>
                <button onClick={() => onNavigate('login')} className="hover:text-indigo-600">Login</button>
                <button onClick={() => onNavigate('register')} className="px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors">Register</button>
              </>
            )}
          </div>

          <button
            onClick={toggleDarkMode}
            className={`p-2 rounded-lg border transition-colors ${
              isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-200 shadow-sm'
            }`}
          >
            {isDarkMode ? '☀️' : '🌙'}
          </button>

          {user && (
            <div className="flex items-center gap-2 border-l pl-4 ml-2 border-slate-200">
              <img src={user.avatar} className="w-8 h-8 rounded-full bg-slate-200" alt="Avatar" />
              <div className="hidden lg:block text-left leading-none">
                <p className="text-xs font-bold">{user.username}</p>
                <p className="text-[10px] text-indigo-500 font-bold uppercase">{user.badge}</p>
              </div>
            </div>
          )}
        </div>
      </div>
    </nav>
  );
};

import React, { useState, useCallback, useMemo } from 'react';
import { Post, User, BadgeTier } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';

interface PostCardProps {
  post: Post;
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (post: Post) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ post, currentUser, isDarkMode, onPostUpdate }) => {
  const [commentText, setCommentText] = useState('');
  const [showComments, setShowComments] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [isAnimatingLike, setIsAnimatingLike] = useState(false);
  const [likeParticles, setLikeParticles] = useState<{ id: number; x: number; y: number }[]>([]);

  const CONTENT_THRESHOLD = 250;
  const isLongContent = post.content.length > CONTENT_THRESHOLD;

  const isLiked = useMemo(() => {
    return currentUser ? post.likedBy?.includes(currentUser.id) : false;
  }, [post.likedBy, currentUser]);

  const handleLike = useCallback(() => {
    if (!currentUser) return alert('Please login to like');

    const hasLiked = post.likedBy?.includes(currentUser.id);
    const likeDelta = hasLiked ? -1 : 1;

    const newLikedBy = hasLiked 
      ? (post.likedBy || []).filter(id => id !== currentUser.id)
      : [...(post.likedBy || []), currentUser.id];

    if (!hasLiked) {
      setIsAnimatingLike(true);
      setTimeout(() => setIsAnimatingLike(false), 400);

      const newParticles = Array.from({ length: 5 }).map((_, i) => ({
        id: Date.now() + i,
        x: (Math.random() - 0.5) * 40,
        y: (Math.random() - 0.5) * 40,
      }));
      setLikeParticles(prev => [...prev, ...newParticles]);
      setTimeout(() => {
        setLikeParticles(prev => prev.filter(p => !newParticles.includes(p)));
      }, 800);
    }

    const updatedPost: Post = { 
      ...post, 
      likes: Math.max(0, post.likes + likeDelta),
      likedBy: newLikedBy
    };

    db.updatePost(updatedPost);
    db.updateUserLikes(post.userId, likeDelta);
    onPostUpdate(updatedPost);
  }, [post, currentUser, onPostUpdate]);

  const handleShare = () => {
    const updatedPost = { ...post, shares: post.shares + 1 };
    db.updatePost(updatedPost);
    onPostUpdate(updatedPost);
    navigator.clipboard.writeText(window.location.href);
    alert('Link copied to clipboard!');
  };

  const handleAddComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return alert('Please login to comment');
    if (!commentText.trim()) return;

    const newComment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      content: commentText,
      createdAt: new Date().toISOString()
    };

    const updatedPost = {
      ...post,
      comments: [...post.comments, newComment]
    };

    db.updatePost(updatedPost);
    onPostUpdate(updatedPost);
    setCommentText('');
  };

  const authorBadge = useMemo(() => {
    const users = db.getUsers();
    return users.find(u => u.id === post.userId)?.badge || BadgeTier.NOVICE;
  }, [post.userId, post.likes]);

  return (
    <div className={`rounded-xl shadow-sm border transition-all overflow-hidden h-fit flex flex-col ${
      isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-200'
    }`}>
      <div className="p-6 flex-1">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-3">
            <img src={post.userAvatar} className="w-10 h-10 rounded-full bg-slate-200" alt={post.username} />
            <div>
              <div className="flex items-center gap-2">
                <span className="font-bold text-sm">@{post.username}</span>
                <BadgeIcon tier={authorBadge} />
              </div>
              <span className="text-[10px] text-slate-500 uppercase font-bold tracking-tight">
                {new Date(post.createdAt).toLocaleDateString()}
              </span>
            </div>
          </div>
          <button className="text-slate-400 hover:text-indigo-500">
            <svg className="w-6 h-6" fill="currentColor" viewBox="0 0 24 24"><path d="M12 8c1.1 0 2-.9 2-2s-.9-2-2-2-2 .9-2 2 .9 2 2 2zm0 2c-1.1 0-2 .9-2 2 s.9 2 2 2 2-.9 2-2-.9-2-2-2zm0 6c-1.1 0-2 .9-2 2 s.9 2 2 2 2-.9 2-2-.9-2-2-2z"/></svg>
          </button>
        </div>

        <h3 className={`font-serif text-xl font-bold mb-3 ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>
          {post.title}
        </h3>

        <div className="relative">
          <p className={`text-base leading-relaxed whitespace-pre-wrap mb-2 transition-all ${
            isDarkMode ? 'text-slate-400' : 'text-slate-600'
          }`}>
            {isExpanded || !isLongContent 
              ? post.content 
              : `${post.content.substring(0, CONTENT_THRESHOLD)}...`}
          </p>

          {!isExpanded && isLongContent && (
            <div className={`absolute bottom-0 left-0 right-0 h-10 bg-gradient-to-t pointer-events-none ${
              isDarkMode ? 'from-slate-800' : 'from-white'
            } to-transparent opacity-60`}></div>
          )}
        </div>

        {isLongContent && (
          <button 
            onClick={() => setIsExpanded(!isExpanded)}
            className={`text-xs font-bold transition-colors ${
              isDarkMode ? 'text-indigo-400 hover:text-indigo-300' : 'text-indigo-600 hover:text-indigo-700'
            } mb-4`}
          >
            {isExpanded ? 'Show less ↑' : 'Read more ↓'}
          </button>
        )}

        <div className={`flex items-center gap-6 pt-4 border-t ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}`}>
          <div className="relative inline-flex items-center">
            <button 
              onClick={handleLike}
              className={`group flex items-center gap-1.5 text-sm font-medium transition-all ${
                isLiked || isAnimatingLike ? 'text-red-500' : 'text-slate-500 hover:text-red-500'
              }`}
            >
              <div className={`relative ${isAnimatingLike ? 'animate-heart-pop' : ''}`}>
                <svg 
                  className={`w-5 h-5 transition-all ${isLiked || isAnimatingLike ? 'fill-red-500 stroke-red-500' : 'fill-none stroke-current'}`} 
                  viewBox="0 0 24 24"
                >
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/>
                </svg>
              </div>
              <span className={isLiked || isAnimatingLike ? 'font-bold' : ''}>{post.likes}</span>
            </button>
            {likeParticles.map(p => (
              <div 
                key={p.id} 
                className="like-particle"
                style={{ 
                  left: '10px', 
                  top: '0px', 
                  marginLeft: `${p.x}px`, 
                  marginTop: `${p.y}px` 
                }}
              >
                <svg className="w-3 h-3 text-red-500 fill-current" viewBox="0 0 24 24">
                  <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/>
                </svg>
              </div>
            ))}
          </div>

          <button 
            onClick={() => setShowComments(!showComments)}
            className="flex items-center gap-1.5 text-sm font-medium text-slate-500 hover:text-blue-500 transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
            <span>{post.comments.length}</span>
          </button>

          <button 
            onClick={handleShare}
            className="flex items-center gap-1.5 text-sm font-medium text-slate-500 hover:text-emerald-500 transition-colors"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"/></svg>
            <span>{post.shares}</span>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-6 border-t animate-in slide-in-from-top-2 duration-300 ${isDarkMode ? 'bg-slate-900/50 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
          <div className="space-y-4 mb-6">
            {post.comments.length === 0 ? (
              <p className="text-xs text-center text-slate-500 italic">No comments yet. Be the first to share your thoughts!</p>
            ) : (
              post.comments.map(c => (
                <div key={c.id} className="flex gap-3">
                  <div className="w-8 h-8 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-600 font-bold text-xs uppercase">
                    {c.username[0]}
                  </div>
                  <div className={`p-3 rounded-2xl flex-1 text-sm ${isDarkMode ? 'bg-slate-800' : 'bg-white shadow-sm'}`}>
                    <div className="flex justify-between mb-1">
                      <span className="font-bold">@{c.username}</span>
                      <span className="text-[10px] text-slate-500">{new Date(c.createdAt).toLocaleTimeString()}</span>
                    </div>
                    <p className={isDarkMode ? 'text-slate-300' : 'text-slate-600'}>{c.content}</p>
                  </div>
                </div>
              ))
            )}
          </div>

          <form onSubmit={handleAddComment} className="flex gap-2">
            <input
              type="text"
              placeholder="Write a comment..."
              value={commentText}
              onChange={(e) => setCommentText(e.target.value)}
              className={`flex-1 px-4 py-2 rounded-full text-sm outline-none transition-all ${
                isDarkMode 
                  ? 'bg-slate-800 border-slate-700 focus:border-indigo-500 text-white' 
                  : 'bg-white border-slate-200 focus:border-blue-500 border text-slate-900'
              }`}
            />
            <button 
              type="submit"
              disabled={!commentText.trim()}
              className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white rounded-full text-sm font-bold transition-colors"
            >
              Post
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Post, User } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { PostCard } from './components/PostCard';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<'home' | 'create' | 'login' | 'register' | 'my-stories'>('home');
  const [searchQuery, setSearchQuery] = useState('');

  // Post form state
  const [newTitle, setNewTitle] = useState('');
  const [newContent, setNewContent] = useState('');

  // Auth form states
  const [loginMethod, setLoginMethod] = useState<'username' | 'email'>('username');
  const [authUsername, setAuthUsername] = useState('');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authConfirmPassword, setAuthConfirmPassword] = useState('');
  const [authError, setAuthError] = useState('');

  useEffect(() => {
    setCurrentUser(db.getCurrentUser());
    setPosts(db.getPosts());
  }, []);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');
    const identifier = loginMethod === 'username' ? authUsername : authEmail;
    const result = db.login(identifier, authPassword, loginMethod);
    if (result.success && result.user) {
      setCurrentUser(result.user);
      setCurrentPage('home');
      setAuthUsername('');
      setAuthEmail('');
      setAuthPassword('');
    } else {
      setAuthError(result.error || 'Login failed');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');

    if (authPassword !== authConfirmPassword) {
      setAuthError('Passwords do not match');
      return;
    }

    const result = db.register(authUsername, authEmail, authPassword);
    if (result.success && result.user) {
      setCurrentUser(result.user);
      setCurrentPage('home');
      setAuthUsername('');
      setAuthEmail('');
      setAuthPassword('');
      setAuthConfirmPassword('');
    } else {
      setAuthError(result.error || 'Registration failed');
    }
  };

  const handleCreatePost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    const newPost: Post = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      title: newTitle,
      content: newContent,
      likes: 0,
      likedBy: [],
      shares: 0,
      comments: [],
      createdAt: new Date().toISOString(),
      userAvatar: currentUser.avatar
    };

    db.savePost(newPost);
    setPosts(db.getPosts());
    setNewTitle('');
    setNewContent('');
    setCurrentPage('home');
  };

  const handlePostUpdate = (updatedPost: Post) => {
    setPosts(prev => prev.map(p => p.id === updatedPost.id ? updatedPost : p));
    setCurrentUser(db.getCurrentUser());
  };

  const switchAuthPage = (page: 'login' | 'register') => {
    setAuthError('');
    setAuthUsername('');
    setAuthEmail('');
    setAuthPassword('');
    setAuthConfirmPassword('');
    setCurrentPage(page);
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={(page) => {
          setAuthError('');
          setCurrentPage(page as any);
        }}
      />

      <main className="max-w-4xl mx-auto px-4 py-12">
        {(currentPage === 'home' || currentPage === 'my-stories') && (
          <section className="space-y-8">
            <div className="text-center mb-12">
              <h1 className="font-serif text-4xl md:text-5xl font-bold mb-4">
                {currentPage === 'my-stories' ? 'My Stories' : 'Latest Stories'}
              </h1>
              <p className="text-slate-500 max-w-lg mx-auto">
                {currentPage === 'my-stories' 
                  ? 'A collection of your creative journeys.'
                  : 'Join our community of modern storytellers and visionaries.'}
              </p>
            </div>

            {filteredPosts.length === 0 ? (
              <div className={`p-16 border-2 border-dashed rounded-3xl text-center ${isDarkMode ? 'border-slate-800' : 'border-slate-200 bg-white shadow-md'}`}>
                <h2 className="text-2xl font-serif font-bold mb-4">No stories found.</h2>
                <button 
                  onClick={() => currentUser ? setCurrentPage('create') : setCurrentPage('login')}
                  className="px-6 py-2 bg-indigo-600 text-white rounded-lg font-bold hover:bg-indigo-700 transition-colors"
                >
                  Write Your First Story
                </button>
              </div>
            ) : (
              <div className="grid gap-8">
                {filteredPosts.map(post => (
                  <PostCard 
                    key={post.id} 
                    post={post} 
                    currentUser={currentUser} 
                    isDarkMode={isDarkMode} 
                    onPostUpdate={handlePostUpdate}
                  />
                ))}
              </div>
            )}
          </section>
        )}

        {currentPage === 'create' && (
          <section className="max-w-2xl mx-auto">
             <h1 className="font-serif text-3xl font-bold mb-8 text-center">Share Your Vision</h1>
             <form 
              onSubmit={handleCreatePost}
              className={`p-8 rounded-2xl shadow-xl space-y-6 ${isDarkMode ? 'bg-slate-900 border border-slate-800' : 'bg-white'}`}
             >
                <div>
                  <label className="block text-xs font-bold uppercase tracking-widest text-slate-400 mb-2">Title</label>
                  <input 
                    required
                    type="text" 
                    placeholder="Story Title"
                    value={newTitle}
                    onChange={(e) => setNewTitle(e.target.value)}
                    className={`w-full p-4 rounded-xl border outline-none transition-all ${
                      isDarkMode 
                        ? 'bg-slate-800 border-slate-700 focus:border-indigo-500 text-white' 
                        : 'bg-slate-50 border-slate-200 focus:border-blue-500'
                    }`}
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold uppercase tracking-widest text-slate-400 mb-2">Narrative</label>
                  <textarea 
                    required
                    rows={10}
                    placeholder="Once upon a time..."
                    value={newContent}
                    onChange={(e) => setNewContent(e.target.value)}
                    className={`w-full p-4 rounded-xl border outline-none transition-all resize-none ${
                      isDarkMode 
                        ? 'bg-slate-800 border-slate-700 focus:border-indigo-500 text-white' 
                        : 'bg-slate-50 border-slate-200 focus:border-blue-500'
                    }`}
                  />
                </div>
                <button 
                  type="submit"
                  className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-lg transition-all"
                >
                  Publish Story
                </button>
             </form>
          </section>
        )}

        {(currentPage === 'login' || currentPage === 'register') && (
          <section className="max-w-md mx-auto py-10 text-center">
             <h2 className="text-3xl font-serif font-bold mb-8">
                {currentPage === 'login' ? 'Welcome Back' : 'Join StoryVerse'}
             </h2>

             {authError && (
               <div className="mb-6 p-3 bg-red-100 border border-red-200 text-red-600 text-sm rounded-lg font-medium">
                 {authError}
               </div>
             )}

             <div className={`p-8 rounded-2xl shadow-xl space-y-6 text-left ${isDarkMode ? 'bg-slate-900 border border-slate-800' : 'bg-white'}`}>
                {currentPage === 'login' && (
                  <div className={`flex p-1 rounded-xl mb-4 ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
                    <button 
                      onClick={() => setLoginMethod('username')}
                      className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${loginMethod === 'username' ? (isDarkMode ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600 shadow-sm') : 'text-slate-500'}`}
                    >
                      Username
                    </button>
                    <button 
                      onClick={() => setLoginMethod('email')}
                      className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${loginMethod === 'email' ? (isDarkMode ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600 shadow-sm') : 'text-slate-500'}`}
                    >
                      Email
                    </button>
                  </div>
                )}

                <form onSubmit={currentPage === 'login' ? handleLogin : handleRegister} className="space-y-4">
                    {(currentPage === 'register' || loginMethod === 'username') && (
                      <div>
                        <label className="text-xs font-bold uppercase text-slate-400 block mb-1">Username</label>
                        <input 
                          type="text" 
                          required
                          value={authUsername}
                          onChange={(e) => setAuthUsername(e.target.value)}
                          className={`w-full p-3 rounded-xl border outline-none transition-all ${
                            isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'
                          }`}
                        />
                      </div>
                    )}

                    {(currentPage === 'register' || loginMethod === 'email') && (
                      <div>
                        <label className="text-xs font-bold uppercase text-slate-400 block mb-1">Email Address</label>
                        <input 
                          type="email" 
                          required
                          value={authEmail}
                          onChange={(e) => setAuthEmail(e.target.value)}
                          className={`w-full p-3 rounded-xl border outline-none transition-all ${
                            isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'
                          }`}
                        />
                      </div>
                    )}

                    <div>
                      <label className="text-xs font-bold uppercase text-slate-400 block mb-1">Password</label>
                      <input 
                        type="password" 
                        required
                        value={authPassword}
                        onChange={(e) => setAuthPassword(e.target.value)}
                        className={`w-full p-3 rounded-xl border outline-none transition-all ${
                          isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'
                        }`}
                      />
                    </div>

                    {currentPage === 'register' && (
                      <div>
                        <label className="text-xs font-bold uppercase text-slate-400 block mb-1">Confirm Password</label>
                        <input 
                          type="password" 
                          required
                          value={authConfirmPassword}
                          onChange={(e) => setAuthConfirmPassword(e.target.value)}
                          className={`w-full p-3 rounded-xl border outline-none transition-all ${
                            isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'
                          }`}
                        />
                      </div>
                    )}

                    <button 
                      type="submit"
                      className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-md mt-2"
                    >
                      {currentPage === 'login' ? 'Login' : 'Register'}
                    </button>
                </form>
             </div>

             <div className="mt-8 text-sm">
                {currentPage === 'login' ? (
                  <p className="text-slate-500">
                    Need an account? {' '}
                    <button onClick={() => switchAuthPage('register')} className="text-indigo-600 font-bold hover:underline">Register</button>
                  </p>
                ) : (
                  <p className="text-slate-500">
                    Already have an account? {' '}
                    <button onClick={() => switchAuthPage('login')} className="text-indigo-600 font-bold hover:underline">Login</button>
                  </p>
                )}
             </div>
          </section>
        )}
      </main>

      <footer className={`py-12 border-t text-center transition-colors ${isDarkMode ? 'border-slate-800 text-slate-500' : 'border-slate-100 text-slate-400'}`}>
        <p className="font-serif text-lg font-bold mb-2">StoryVerse</p>
        <p className="text-xs">© {new Date().getFullYear()} StoryVerse. All rights reserved.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Post, User } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { PostCard } from './components/PostCard';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<'home' | 'create' | 'login' | 'register' | 'my-stories'>('home');
  const [searchQuery, setSearchQuery] = useState('');

  // Post form state
  const [newTitle, setNewTitle] = useState('');
  const [newContent, setNewContent] = useState('');

  // Auth form states
  const [loginMethod, setLoginMethod] = useState<'username' | 'email'>('username');
  const [authUsername, setAuthUsername] = useState('');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authConfirmPassword, setAuthConfirmPassword] = useState('');
  const [authError, setAuthError] = useState('');

  // Password visibility states
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  useEffect(() => {
    setCurrentUser(db.getCurrentUser());
    setPosts(db.getPosts());
  }, []);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');
    const identifier = loginMethod === 'username' ? authUsername : authEmail;
    const result = db.login(identifier, authPassword, loginMethod);
    if (result.success && result.user) {
      setCurrentUser(result.user);
      setCurrentPage('home');
      setAuthUsername('');
      setAuthEmail('');
      setAuthPassword('');
      setShowPassword(false);
    } else {
      setAuthError(result.error || 'Login failed');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');

    if (authPassword !== authConfirmPassword) {
      setAuthError('Passwords do not match');
      return;
    }

    const result = db.register(authUsername, authEmail, authPassword);
    if (result.success && result.user) {
      setCurrentUser(result.user);
      setCurrentPage('home');
      setAuthUsername('');
      setAuthEmail('');
      setAuthPassword('');
      setAuthConfirmPassword('');
      setShowPassword(false);
      setShowConfirmPassword(false);
    } else {
      setAuthError(result.error || 'Registration failed');
    }
  };

  const handleCreatePost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;

    const newPost: Post = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      title: newTitle,
      content: newContent,
      likes: 0,
      likedBy: [],
      shares: 0,
      comments: [],
      createdAt: new Date().toISOString(),
      userAvatar: currentUser.avatar
    };

    db.savePost(newPost);
    setPosts(db.getPosts());
    setNewTitle('');
    setNewContent('');
    setCurrentPage('home');
  };

  const handlePostUpdate = (updatedPost: Post) => {
    setPosts(prev => prev.map(p => p.id === updatedPost.id ? updatedPost : p));
    setCurrentUser(db.getCurrentUser());
  };

  const switchAuthPage = (page: 'login' | 'register') => {
    setAuthError('');
    setAuthUsername('');
    setAuthEmail('');
    setAuthPassword('');
    setAuthConfirmPassword('');
    setShowPassword(false);
    setShowConfirmPassword(false);
    setCurrentPage(page);
  };

  const EyeIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
    </svg>
  );

  const EyeOffIcon = () => (
    <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13.875 18.825A10.05 10.05 0 0112 19c-4.478 0-8.268-2.943-9.542-7a9.97 9.97 0 011.563-3.029m5.858.908a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l18 18" />
    </svg>
  );

  return (
    <div className={`min-h-screen transition-colors duration-300 ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={(page) => {
          setAuthError('');
          setCurrentPage(page as any);
        }}
      />

      <main className="max-w-4xl mx-auto px-4 py-12">
        {(currentPage === 'home' || currentPage === 'my-stories') && (
          <section className="space-y-8">
            <div className="text-center mb-12">
              <h1 className="font-serif text-4xl md:text-5xl font-bold mb-4">
                {currentPage === 'my-stories' ? 'My Stories' : 'Latest Stories'}
              </h1>
              <p className="text-slate-500 max-w-lg mx-auto">
                {currentPage === 'my-stories' 
                  ? 'A collection of your creative journeys.'
                  : 'Join our community of modern storytellers and visionaries.'}
              </p>
            </div>

            {filteredPosts.length === 0 ? (
              <div className={`p-16 border-2 border-dashed rounded-3xl text-center ${isDarkMode ? 'border-slate-800' : 'border-slate-200 bg-white shadow-md'}`}>
                <h2 className="text-2xl font-serif font-bold mb-4">No stories found.</h2>
                <button 
                  onClick={() => currentUser ? setCurrentPage('create') : setCurrentPage('login')}
                  className="px-6 py-2 bg-indigo-600 text-white rounded-lg font-bold hover:bg-indigo-700 transition-colors"
                >
                  Write Your First Story
                </button>
              </div>
            ) : (
              <div className="grid gap-8">
                {filteredPosts.map(post => (
                  <PostCard 
                    key={post.id} 
                    post={post} 
                    currentUser={currentUser} 
                    isDarkMode={isDarkMode} 
                    onPostUpdate={handlePostUpdate}
                  />
                ))}
              </div>
            )}
          </section>
        )}

        {currentPage === 'create' && (
          <section className="max-w-2xl mx-auto">
             <h1 className="font-serif text-3xl font-bold mb-8 text-center">Share Your Vision</h1>
             <form 
              onSubmit={handleCreatePost}
              className={`p-8 rounded-2xl shadow-xl space-y-6 ${isDarkMode ? 'bg-slate-900 border border-slate-800' : 'bg-white'}`}
             >
                <div>
                  <label className="block text-xs font-bold uppercase tracking-widest text-slate-400 mb-2">Title</label>
                  <input 
                    required
                    type="text" 
                    placeholder="Story Title"
                    value={newTitle}
                    onChange={(e) => setNewTitle(e.target.value)}
                    className={`w-full p-4 rounded-xl border outline-none transition-all ${
                      isDarkMode 
                        ? 'bg-slate-800 border-slate-700 focus:border-indigo-500 text-white' 
                        : 'bg-slate-50 border-slate-200 focus:border-blue-500'
                    }`}
                  />
                </div>
                <div>
                  <label className="block text-xs font-bold uppercase tracking-widest text-slate-400 mb-2">Narrative</label>
                  <textarea 
                    required
                    rows={10}
                    placeholder="Once upon a time..."
                    value={newContent}
                    onChange={(e) => setNewContent(e.target.value)}
                    className={`w-full p-4 rounded-xl border outline-none transition-all resize-none ${
                      isDarkMode 
                        ? 'bg-slate-800 border-slate-700 focus:border-indigo-500 text-white' 
                        : 'bg-slate-50 border-slate-200 focus:border-blue-500'
                    }`}
                  />
                </div>
                <button 
                  type="submit"
                  className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-lg transition-all"
                >
                  Publish Story
                </button>
             </form>
          </section>
        )}

        {(currentPage === 'login' || currentPage === 'register') && (
          <section className="max-w-md mx-auto py-10 text-center">
             <h2 className="text-3xl font-serif font-bold mb-8">
                {currentPage === 'login' ? 'Welcome Back' : 'Join StoryVerse'}
             </h2>

             {authError && (
               <div className="mb-6 p-3 bg-red-100 border border-red-200 text-red-600 text-sm rounded-lg font-medium">
                 {authError}
               </div>
             )}

             <div className={`p-8 rounded-2xl shadow-xl space-y-6 text-left ${isDarkMode ? 'bg-slate-900 border border-slate-800' : 'bg-white'}`}>
                {currentPage === 'login' && (
                  <div className={`flex p-1 rounded-xl mb-4 ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
                    <button 
                      onClick={() => setLoginMethod('username')}
                      className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${loginMethod === 'username' ? (isDarkMode ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600 shadow-sm') : 'text-slate-500'}`}
                    >
                      Username
                    </button>
                    <button 
                      onClick={() => setLoginMethod('email')}
                      className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${loginMethod === 'email' ? (isDarkMode ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600 shadow-sm') : 'text-slate-500'}`}
                    >
                      Email
                    </button>
                  </div>
                )}

                <form onSubmit={currentPage === 'login' ? handleLogin : handleRegister} className="space-y-4">
                    {(currentPage === 'register' || loginMethod === 'username') && (
                      <div>
                        <label className="text-xs font-bold uppercase text-slate-400 block mb-1">Username</label>
                        <input 
                          type="text" 
                          required
                          value={authUsername}
                          onChange={(e) => setAuthUsername(e.target.value)}
                          className={`w-full p-3 rounded-xl border outline-none transition-all ${
                            isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'
                          }`}
                        />
                      </div>
                    )}

                    {(currentPage === 'register' || loginMethod === 'email') && (
                      <div>
                        <label className="text-xs font-bold uppercase text-slate-400 block mb-1">Email Address</label>
                        <input 
                          type="email" 
                          required
                          value={authEmail}
                          onChange={(e) => setAuthEmail(e.target.value)}
                          className={`w-full p-3 rounded-xl border outline-none transition-all ${
                            isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'
                          }`}
                        />
                      </div>
                    )}

                    <div>
                      <label className="text-xs font-bold uppercase text-slate-400 block mb-1">Password</label>
                      <div className="relative">
                        <input 
                          type={showPassword ? "text" : "password"} 
                          required
                          value={authPassword}
                          onChange={(e) => setAuthPassword(e.target.value)}
                          className={`w-full p-3 pr-10 rounded-xl border outline-none transition-all ${
                            isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'
                          }`}
                        />
                        <button
                          type="button"
                          onClick={() => setShowPassword(!showPassword)}
                          className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-indigo-500 transition-colors"
                          aria-label={showPassword ? "Hide password" : "Show password"}
                        >
                          {showPassword ? <EyeOffIcon /> : <EyeIcon />}
                        </button>
                      </div>
                    </div>

                    {currentPage === 'register' && (
                      <div>
                        <label className="text-xs font-bold uppercase text-slate-400 block mb-1">Confirm Password</label>
                        <div className="relative">
                          <input 
                            type={showConfirmPassword ? "text" : "password"} 
                            required
                            value={authConfirmPassword}
                            onChange={(e) => setAuthConfirmPassword(e.target.value)}
                            className={`w-full p-3 pr-10 rounded-xl border outline-none transition-all ${
                              isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'
                            }`}
                          />
                          <button
                            type="button"
                            onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                            className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-indigo-500 transition-colors"
                            aria-label={showConfirmPassword ? "Hide password" : "Show password"}
                          >
                            {showConfirmPassword ? <EyeOffIcon /> : <EyeIcon />}
                          </button>
                        </div>
                      </div>
                    )}

                    <button 
                      type="submit"
                      className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-md mt-2"
                    >
                      {currentPage === 'login' ? 'Login' : 'Register'}
                    </button>
                </form>
             </div>

             <div className="mt-8 text-sm">
                {currentPage === 'login' ? (
                  <p className="text-slate-500">
                    Need an account? {' '}
                    <button onClick={() => switchAuthPage('register')} className="text-indigo-600 font-bold hover:underline">Register</button>
                  </p>
                ) : (
                  <p className="text-slate-500">
                    Already have an account? {' '}
                    <button onClick={() => switchAuthPage('login')} className="text-indigo-600 font-bold hover:underline">Login</button>
                  </p>
                )}
             </div>
          </section>
        )}
      </main>

      <footer className={`py-12 border-t text-center transition-colors ${isDarkMode ? 'border-slate-800 text-slate-500' : 'border-slate-100 text-slate-400'}`}>
        <p className="font-serif text-lg font-bold mb-2">StoryVerse</p>
        <p className="text-xs">© {new Date().getFullYear()} StoryVerse. All rights reserved.</p>
      </footer>
    </div>
  );
};

