import { createClient } from '@supabase/supabase-js';
import { Post, User, BadgeTier, Comment } from '../types';

// Provided Supabase Credentials
const SUPABASE_URL = (process.env as any).SUPABASE_URL || 'https://uvjavqzhhqxkfuklkxdo.supabase.co';
const SUPABASE_ANON_KEY = (process.env as any).SUPABASE_ANON_KEY || 'sb_publishable_-GDZiq_v45oEVhlly7tG-w_cKockqn6';

// Check if we are using the real project URL or the initial placeholder
const isConfigured = SUPABASE_URL !== 'https://your-project-url.supabase.co' && SUPABASE_ANON_KEY !== 'your-anon-key';

const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

const SESSION_KEY = 'storyverse_session';

export const getBadge = (likes: number): BadgeTier => {
  if (likes >= 500) return BadgeTier.PLATINUM;
  if (likes >= 100) return BadgeTier.GOLD;
  if (likes >= 25) return BadgeTier.SILVER;
  if (likes >= 5) return BadgeTier.BRONZE;
  return BadgeTier.NOVICE;
};

export const db = {
  async getPosts(): Promise<Post[]> {
    if (!isConfigured) return [];
    try {
      const { data, error } = await supabase
        .from('posts')
        .select(`
          *,
          comments (*)
        `)
        .order('created_at', { ascending: false });

      if (error) throw error;

      return (data || []).map(post => ({
        id: post.id,
        userId: post.user_id,
        username: post.username,
        title: post.title,
        content: post.content,
        likes: post.likes || 0,
        likedBy: post.liked_by || [],
        shares: post.shares || 0,
        createdAt: post.created_at,
        userAvatar: post.user_avatar,
        comments: (post.comments || []).map((c: any) => ({
          id: c.id,
          userId: c.user_id,
          username: c.username,
          content: c.content,
          createdAt: c.created_at
        }))
      }));
    } catch (err) {
      console.error('Failed to fetch posts:', err);
      return [];
    }
  },

  async savePost(post: Post): Promise<void> {
    if (!isConfigured) return;
    try {
      const { error } = await supabase
        .from('posts')
        .insert([{
          id: post.id,
          user_id: post.userId,
          username: post.username,
          title: post.title,
          content: post.content,
          likes: post.likes,
          liked_by: post.likedBy,
          shares: post.shares,
          user_avatar: post.userAvatar,
          created_at: post.createdAt
        }]);
      if (error) throw error;
    } catch (err) {
      console.error('Error saving post:', err);
    }
  },

  async updatePost(updatedPost: Post): Promise<void> {
    if (!isConfigured) return;
    try {
      const { error } = await supabase
        .from('posts')
        .update({
          likes: updatedPost.likes,
          liked_by: updatedPost.likedBy,
          shares: updatedPost.shares,
          title: updatedPost.title,
          content: updatedPost.content
        })
        .eq('id', updatedPost.id);
      if (error) throw error;
    } catch (err) {
      console.error('Error updating post:', err);
    }
  },

  async deletePost(postId: string): Promise<{ success: boolean; error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not configured.' };
    try {
      // 1. Delete comments for this post
      const { error: commentError } = await supabase
        .from('comments')
        .delete()
        .eq('post_id', postId);
      if (commentError) throw commentError;

      // 2. Delete the post itself
      const { error: postError } = await supabase
        .from('posts')
        .delete()
        .eq('id', postId);
      if (postError) throw postError;

      return { success: true };
    } catch (err: any) {
      console.error("Supabase Delete Post Error:", err);
      return { success: false, error: err.message };
    }
  },

  async addComment(postId: string, comment: Comment): Promise<void> {
    if (!isConfigured) return;
    try {
      const { error } = await supabase
        .from('comments')
        .insert([{
          id: comment.id,
          post_id: postId,
          user_id: comment.userId,
          username: comment.username,
          content: comment.content,
          created_at: comment.createdAt
        }]);
      if (error) throw error;
    } catch (err) {
      console.error('Error adding comment:', err);
    }
  },

  async getUsers(): Promise<User[]> {
    if (!isConfigured) return [];
    try {
      const { data, error } = await supabase.from('users').select('*');
      if (error) throw error;
      return (data || []).map(u => ({
        id: u.id,
        username: u.username,
        email: u.email,
        avatar: u.avatar,
        totalLikes: u.total_likes,
        badge: u.badge as BadgeTier
      }));
    } catch (err) {
      console.error('Error fetching users:', err);
      return [];
    }
  },

  async updateUserLikes(userId: string, delta: number): Promise<void> {
    if (!isConfigured) return;
    try {
      const { data: user, error: fetchError } = await supabase
        .from('users')
        .select('*')
        .eq('id', userId)
        .single();

      if (fetchError || !user) return;

      const newTotalLikes = (user.total_likes || 0) + delta;
      const newBadge = getBadge(newTotalLikes);

      const { error } = await supabase
        .from('users')
        .update({
          total_likes: newTotalLikes,
          badge: newBadge
        })
        .eq('id', userId);

      if (error) throw error;

      const session = this.getCurrentUser();
      if (session && session.id === userId) {
        const updatedSessionUser = { ...session, totalLikes: newTotalLikes, badge: newBadge };
        localStorage.setItem(SESSION_KEY, JSON.stringify(updatedSessionUser));
      }
    } catch (err) {
      console.error('Error updating user likes:', err);
    }
  },

  getCurrentUser(): User | null {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  },

  async register(username: string, email: string, password: string): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) {
      return { success: false, error: 'Cloud Verse is not fully linked. Check backend credentials.' };
    }
    try {
      // Check if user exists
      const { data: existingUser, error: checkError } = await supabase
        .from('users')
        .select('id')
        .or(`username.ilike.${username},email.ilike.${email}`)
        .maybeSingle();

      if (checkError) throw checkError;
      if (existingUser) {
        return { success: false, error: 'Username or Email already exists in the Verse.' };
      }

      const newUser: User = {
        id: Math.random().toString(36).substr(2, 9),
        username,
        email,
        avatar: `https://picsum.photos/seed/${username}/100`,
        totalLikes: 0,
        badge: BadgeTier.NOVICE
      };

      const { error: insertError } = await supabase
        .from('users')
        .insert([{
          id: newUser.id,
          username: newUser.username,
          email: newUser.email,
          password: password,
          avatar: newUser.avatar,
          total_likes: 0,
          badge: BadgeTier.NOVICE
        }]);

      if (insertError) throw insertError;

      localStorage.setItem(SESSION_KEY, JSON.stringify(newUser));
      return { success: true, user: newUser };
    } catch (err: any) {
      console.error("Supabase Register Error:", err);
      return { 
        success: false, 
        error: err.message.includes('fetch') 
          ? 'Network connection failed. Ensure Supabase tables (users, posts, comments) are created.' 
          : err.message 
      };
    }
  },

  async login(identifier: string, password: string, method: 'username' | 'email'): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) {
      return { success: false, error: 'Cloud Verse is not fully linked. Check backend credentials.' };
    }
    try {
      const field = method === 'username' ? 'username' : 'email';
      const { data, error } = await supabase
        .from('users')
        .select('*')
        .ilike(field, identifier)
        .eq('password', password)
        .maybeSingle();

      if (error) throw error;
      if (!data) return { success: false, error: 'The Verse does not recognize these credentials.' };

      const user: User = {
        id: data.id,
        username: data.username,
        email: data.email,
        avatar: data.avatar,
        totalLikes: data.total_likes,
        badge: data.badge as BadgeTier
      };

      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return { success: true, user };
    } catch (err: any) {
      console.error("Supabase Login Error:", err);
      return { 
        success: false, 
        error: err.message.includes('fetch') 
          ? 'Connection to Cloud failed. Ensure Supabase project is active and tables exist.' 
          : err.message 
      };
    }
  },

  async deleteAccount(userId: string): Promise<{ success: boolean, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not configured.' };
    try {
      // 1. Delete comments made by user
      const { error: commentError } = await supabase
        .from('comments')
        .delete()
        .eq('user_id', userId);
      if (commentError) throw commentError;

      // 2. Delete posts made by user
      const { error: postError } = await supabase
        .from('posts')
        .delete()
        .eq('user_id', userId);
      if (postError) throw postError;

      // 3. Delete user
      const { error: userError } = await supabase
        .from('users')
        .delete()
        .eq('id', userId);
      if (userError) throw userError;

      this.logout();
      return { success: true };
    } catch (err: any) {
      console.error("Supabase Delete Error:", err);
      return { success: false, error: err.message };
    }
  },

  logout() {
    localStorage.removeItem(SESSION_KEY);
  }
};

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Post, User, BadgeTier } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';

interface PostCardProps {
  post: Post;
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (post: Post) => void;
  onPostDeleted: () => void;
}

export const PostCard: React.FC<PostCardProps> = ({ post, currentUser, isDarkMode, onPostUpdate, onPostDeleted }) => {
  const [commentText, setCommentText] = useState('');
  const [showComments, setShowComments] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [isAnimatingLike, setIsAnimatingLike] = useState(false);
  const [showMenu, setShowMenu] = useState(false);
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [authorBadge, setAuthorBadge] = useState<BadgeTier>(BadgeTier.NOVICE);

  const isOwner = currentUser?.id === post.userId;
  const CONTENT_THRESHOLD = 250;
  const isLongContent = post.content.length > CONTENT_THRESHOLD;

  useEffect(() => {
    const fetchAuthorInfo = async () => {
      const users = await db.getUsers();
      const author = users.find(u => u.id === post.userId);
      if (author) setAuthorBadge(author.badge);
    };
    fetchAuthorInfo();
  }, [post.userId, post.likes]);

  const isLiked = useMemo(() => {
    return currentUser ? post.likedBy?.includes(currentUser.id) : false;
  }, [post.likedBy, currentUser]);

  const handleLike = useCallback(async () => {
    if (!currentUser) return alert('Please login to like');

    const hasLiked = post.likedBy?.includes(currentUser.id);
    const likeDelta = hasLiked ? -1 : 1;

    const newLikedBy = hasLiked 
      ? (post.likedBy || []).filter(id => id !== currentUser.id)
      : [...(post.likedBy || []), currentUser.id];

    if (!hasLiked) {
      setIsAnimatingLike(true);
      setTimeout(() => setIsAnimatingLike(false), 400);
    }

    const updatedPost: Post = { 
      ...post, 
      likes: Math.max(0, post.likes + likeDelta),
      likedBy: newLikedBy
    };

    await db.updatePost(updatedPost);
    await db.updateUserLikes(post.userId, likeDelta);
    onPostUpdate(updatedPost);
  }, [post, currentUser, onPostUpdate]);

  const handleDeletePost = async () => {
    setIsDeleting(true);
    try {
      const result = await db.deletePost(post.id);
      if (result.success) {
        onPostDeleted();
      } else {
        alert(result.error || 'Failed to delete story');
        setIsDeleting(false);
        setShowConfirmDelete(false);
      }
    } catch (err) {
      alert('An error occurred while deleting');
      setIsDeleting(false);
    }
  };

  const handleAddComment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return alert('Please login to comment');
    if (!commentText.trim()) return;

    const newComment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      content: commentText,
      createdAt: new Date().toISOString()
    };

    await db.addComment(post.id, newComment);

    const updatedPost = {
      ...post,
      comments: [...post.comments, newComment]
    };

    onPostUpdate(updatedPost);
    setCommentText('');
  };

  return (
    <div className={`rounded-xl md:rounded-2xl shadow-sm border transition-all overflow-hidden h-fit flex flex-col hover:shadow-md ${
      isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-100'
    }`}>
      <div className="p-4 md:p-6 flex-1">
        <div className="flex items-center justify-between mb-4 md:mb-6">
          <div className="flex items-center gap-3">
            <img src={post.userAvatar} className="w-10 h-10 md:w-11 md:h-11 rounded-xl bg-slate-200 object-cover" alt={post.username} />
            <div>
              <div className="flex items-center gap-1.5 md:gap-2 mb-0.5">
                <span className="font-bold text-xs md:text-sm truncate max-w-[100px] md:max-w-none">@{post.username}</span>
                <BadgeIcon tier={authorBadge} />
              </div>
              <span className="text-[9px] md:text-[10px] text-slate-500 uppercase font-black tracking-widest opacity-80">
                {new Date(post.createdAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
              </span>
            </div>
          </div>

          <div className="relative">
            <button 
              onClick={() => setShowMenu(!showMenu)}
              className="text-slate-400 p-1.5 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z"/></svg>
            </button>

            {showMenu && (
              <div className={`absolute right-0 top-10 w-48 rounded-xl shadow-xl border z-20 animate-in fade-in zoom-in-95 duration-200 ${
                isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-white border-slate-100'
              }`}>
                {isOwner ? (
                  <button 
                    onClick={() => { setShowConfirmDelete(true); setShowMenu(false); }}
                    className="w-full text-left px-4 py-3 text-xs font-bold text-red-500 hover:bg-red-500/10 rounded-xl transition-colors flex items-center gap-2"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                    Remove Story
                  </button>
                ) : (
                  <div className="px-4 py-3 text-xs font-bold text-slate-400 uppercase tracking-widest italic">No Actions</div>
                )}
              </div>
            )}
          </div>
        </div>

        {showConfirmDelete && (
          <div className={`mb-4 p-4 rounded-xl border animate-in slide-in-from-top-2 duration-200 ${
            isDarkMode ? 'bg-red-500/10 border-red-500/20' : 'bg-red-50 border-red-100'
          }`}>
            <p className={`text-[11px] font-bold mb-3 ${isDarkMode ? 'text-red-400' : 'text-red-700'}`}>
              Delete this story permanently from the Verse?
            </p>
            <div className="flex gap-2">
              <button 
                disabled={isDeleting}
                onClick={handleDeletePost}
                className="px-3 py-1.5 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest"
              >
                {isDeleting ? 'Erasing...' : 'Confirm'}
              </button>
              <button 
                disabled={isDeleting}
                onClick={() => setShowConfirmDelete(false)}
                className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest border ${
                  isDarkMode ? 'border-slate-700 text-slate-400' : 'border-slate-200 bg-white text-slate-500'
                }`}
              >
                Cancel
              </button>
            </div>
          </div>
        )}

        <h3 className={`font-serif text-xl md:text-2xl font-bold mb-3 md:mb-4 tracking-tight leading-snug ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>
          {post.title}
        </h3>

        <div className="relative">
          <p className={`text-sm md:text-base leading-relaxed whitespace-pre-wrap mb-4 transition-all ${
            isDarkMode ? 'text-slate-400 font-light' : 'text-slate-600'
          }`}>
            {isExpanded || !isLongContent 
              ? post.content 
              : `${post.content.substring(0, CONTENT_THRESHOLD)}...`}
          </p>

          {!isExpanded && isLongContent && (
            <div className={`absolute bottom-0 left-0 right-0 h-8 bg-gradient-to-t pointer-events-none ${
              isDarkMode ? 'from-slate-800' : 'from-white'
            } to-transparent opacity-60`}></div>
          )}
        </div>

        {isLongContent && (
          <button 
            onClick={() => setIsExpanded(!isExpanded)}
            className={`text-[10px] font-black uppercase tracking-widest transition-colors inline-flex items-center gap-1 ${
              isDarkMode ? 'text-indigo-400' : 'text-indigo-600'
            } mb-4 md:mb-6`}
          >
            {isExpanded ? 'Collapse ↑' : 'Read Full Journey ↓'}
          </button>
        )}

        <div className={`flex items-center gap-4 md:gap-6 pt-4 md:pt-5 border-t ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}`}>
          <button 
            onClick={handleLike}
            className={`group flex items-center gap-2 text-xs md:text-sm font-bold transition-all p-1 ${
              isLiked || isAnimatingLike ? 'text-red-500 scale-105' : 'text-slate-400'
            }`}
          >
            <div className={`relative ${isAnimatingLike ? 'animate-heart-pop' : ''}`}>
              <svg 
                className={`w-5 h-5 md:w-6 md:h-6 transition-all ${isLiked || isAnimatingLike ? 'fill-red-500 stroke-red-500' : 'fill-none stroke-current'}`} 
                viewBox="0 0 24 24"
              >
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/>
              </svg>
            </div>
            <span className="tabular-nums">{post.likes}</span>
          </button>

          <button 
            onClick={() => setShowComments(!showComments)}
            className="flex items-center gap-2 text-xs md:text-sm font-bold text-slate-400 p-1"
          >
            <svg className="w-5 h-5 md:w-6 md:h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
            <span className="tabular-nums">{post.comments.length}</span>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-4 md:p-6 border-t animate-in slide-in-from-top-2 duration-300 ${isDarkMode ? 'bg-slate-900/50 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
          <div className="space-y-4 mb-4">
            {post.comments.length === 0 ? (
              <p className="text-[10px] md:text-xs text-center text-slate-500 italic py-2">No resonance found yet.</p>
            ) : (
              post.comments.map(c => (
                <div key={c.id} className="flex gap-3">
                  <div className="w-7 h-7 md:w-8 md:h-8 rounded-lg bg-indigo-500 flex items-center justify-center text-white font-black text-[9px] md:text-[10px] shrink-0 uppercase">
                    {c.username[0]}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between mb-0.5">
                      <span className="font-bold text-[11px] md:text-xs truncate">@{c.username}</span>
                      <span className="text-[8px] md:text-[9px] text-slate-500 uppercase font-bold">{new Date(c.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                    </div>
                    <p className={`text-xs md:text-sm leading-relaxed ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}>{c.content}</p>
                  </div>
                </div>
              ))
            )}
          </div>

          <form onSubmit={handleAddComment} className="flex gap-2">
            <input
              type="text"
              placeholder="Your reply..."
              value={commentText}
              onChange={(e) => setCommentText(e.target.value)}
              className={`flex-1 px-4 py-2 rounded-xl text-xs md:text-sm outline-none transition-all ${
                isDarkMode 
                  ? 'bg-slate-800 border-slate-700 focus:border-indigo-500 text-white' 
                  : 'bg-white border-slate-200 focus:border-indigo-500 border text-slate-900'
              }`}
            />
            <button 
              type="submit"
              disabled={!commentText.trim()}
              className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white rounded-xl text-xs font-bold transition-all shadow-md"
            >
              Reply
            </button>
          </form>
        </div>
      )}
    </div>
  );
};

