import { createClient } from '@supabase/supabase-js';
import { Post, User, BadgeTier, Comment } from '../types';

/**
 * DATABASE SCHEMA (Run this in your Supabase SQL Editor):
 * 
 * -- Users
 * CREATE TABLE users (id TEXT PRIMARY KEY, username TEXT UNIQUE, email TEXT UNIQUE, password TEXT, avatar TEXT, bio TEXT DEFAULT '', total_likes INT DEFAULT 0, badge TEXT DEFAULT 'Novice');
 * 
 * -- Posts
 * CREATE TABLE posts (id TEXT PRIMARY KEY, user_id TEXT REFERENCES users(id) ON DELETE CASCADE, username TEXT, title TEXT, content TEXT, likes INT DEFAULT 0, liked_by TEXT[] DEFAULT '{}', user_avatar TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
 * 
 * -- Comments
 * CREATE TABLE comments (id TEXT PRIMARY KEY, post_id TEXT REFERENCES posts(id) ON DELETE CASCADE, user_id TEXT REFERENCES users(id) ON DELETE CASCADE, username TEXT, content TEXT, created_at TIMESTAMPTZ DEFAULT NOW());
 * 
 * -- Follows
 * CREATE TABLE follows (
 *   follower_id TEXT REFERENCES users(id) ON DELETE CASCADE, 
 *   following_id TEXT REFERENCES users(id) ON DELETE CASCADE, 
 *   PRIMARY KEY (follower_id, following_id),
 *   CONSTRAINT no_self_follow CHECK (follower_id <> following_id)
 * );
 */

const SUPABASE_URL = (process.env as any).SUPABASE_URL || 'https://uvjavqzhhqxkfuklkxdo.supabase.co';
const SUPABASE_ANON_KEY = (process.env as any).SUPABASE_ANON_KEY || 'sb_publishable_-GDZiq_v45oEVhlly7tG-w_cKockqn6';

const isConfigured = SUPABASE_URL !== 'https://your-project-url.supabase.co' && SUPABASE_ANON_KEY !== 'your-anon-key';
const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);
const SESSION_KEY = 'storyverse_session';

export const getBadge = (likes: number): BadgeTier => {
  if (likes >= 500) return BadgeTier.PLATINUM;
  if (likes >= 100) return BadgeTier.GOLD;
  if (likes >= 25) return BadgeTier.SILVER;
  if (likes >= 5) return BadgeTier.BRONZE;
  return BadgeTier.NOVICE;
};

export const db = {
  async getPosts(): Promise<Post[]> {
    if (!isConfigured) return [];
    try {
      const { data, error } = await supabase
        .from('posts')
        .select(`*, comments (*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      return (data || []).map(post => ({
        id: post.id,
        userId: post.user_id,
        username: post.username,
        title: post.title,
        content: post.content,
        likes: post.likes || 0,
        likedBy: post.liked_by || [],
        shares: post.shares || 0,
        createdAt: post.created_at,
        userAvatar: post.user_avatar,
        comments: (post.comments || []).map((c: any) => ({
          id: c.id,
          userId: c.user_id,
          username: c.username,
          content: c.content,
          createdAt: c.created_at
        }))
      }));
    } catch (err) {
      console.error("Fetch posts failed:", err);
      return [];
    }
  },

  async savePost(post: Post): Promise<void> {
    if (!isConfigured) return;
    await supabase.from('posts').insert([{
      id: post.id,
      user_id: post.userId,
      username: post.username,
      title: post.title,
      content: post.content,
      likes: post.likes,
      liked_by: post.likedBy,
      shares: post.shares,
      user_avatar: post.userAvatar,
      created_at: post.createdAt
    }]);
  },

  async updatePost(updatedPost: Post): Promise<void> {
    if (!isConfigured) return;
    await supabase.from('posts').update({
      likes: updatedPost.likes,
      liked_by: updatedPost.likedBy,
      shares: updatedPost.shares,
      title: updatedPost.title,
      content: updatedPost.content
    }).eq('id', updatedPost.id);
  },

  async deletePost(postId: string): Promise<{ success: boolean; error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not configured.' };
    try {
      await supabase.from('comments').delete().eq('post_id', postId);
      await supabase.from('posts').delete().eq('id', postId);
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async addComment(postId: string, comment: Comment): Promise<void> {
    if (!isConfigured) return;
    await supabase.from('comments').insert([{
      id: comment.id,
      post_id: postId,
      user_id: comment.userId,
      username: comment.username,
      content: comment.content,
      created_at: comment.createdAt
    }]);
  },

  async getUserById(userId: string): Promise<User | null> {
    if (!isConfigured) return null;
    try {
      const { data, error } = await supabase.from('users').select('*').eq('id', userId).maybeSingle();
      if (error || !data) return null;

      const stats = await this.getFollowStats(data.id);
      return {
        id: data.id,
        username: data.username,
        email: data.email,
        avatar: data.avatar,
        bio: data.bio || '',
        totalLikes: data.total_likes || 0,
        badge: (data.badge as BadgeTier) || BadgeTier.NOVICE,
        followerCount: stats.followers,
        followingCount: stats.following
      };
    } catch (err) {
      console.error("Get user failed:", err);
      return null;
    }
  },

  async getUsers(): Promise<User[]> {
    if (!isConfigured) return [];
    try {
      const { data, error } = await supabase.from('users').select('*');
      if (error) throw error;

      const users = await Promise.all((data || []).map(async u => {
        const stats = await this.getFollowStats(u.id);
        return {
          id: u.id,
          username: u.username,
          email: u.email,
          avatar: u.avatar,
          bio: u.bio || '',
          totalLikes: u.total_likes || 0,
          badge: u.badge as BadgeTier,
          followerCount: stats.followers,
          followingCount: stats.following
        };
      }));
      return users;
    } catch (err) {
      return [];
    }
  },

  async getFollowStats(userId: string): Promise<{ followers: number, following: number }> {
    if (!isConfigured) return { followers: 0, following: 0 };
    try {
      const { count: followers } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('following_id', userId);
      const { count: following } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('follower_id', userId);
      return { followers: followers || 0, following: following || 0 };
    } catch (err) {
      return { followers: 0, following: 0 };
    }
  },

  async isFollowing(followerId: string, followingId: string): Promise<boolean> {
    if (!isConfigured) return false;
    try {
      const { data } = await supabase.from('follows').select('*').eq('follower_id', followerId).eq('following_id', followingId).maybeSingle();
      return !!data;
    } catch (err) {
      return false;
    }
  },

  async followUser(followerId: string, followingId: string): Promise<User | null> {
    if (!isConfigured || followerId === followingId) return null;
    try {
      const { error } = await supabase.from('follows').insert([{ follower_id: followerId, following_id: followingId }]);
      if (error) throw error;
      return await this.refreshUser(followerId);
    } catch (err) {
      console.error("Follow failed:", err);
      return null;
    }
  },

  async unfollowUser(followerId: string, followingId: string): Promise<User | null> {
    if (!isConfigured) return null;
    try {
      const { error } = await supabase.from('follows').delete().eq('follower_id', followerId).eq('following_id', followingId);
      if (error) throw error;
      return await this.refreshUser(followerId);
    } catch (err) {
      console.error("Unfollow failed:", err);
      return null;
    }
  },

  async refreshUser(userId: string): Promise<User | null> {
    const user = await this.getUserById(userId);
    if (user) {
      const session = this.getCurrentUser();
      if (session && session.id === userId) {
        localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      }
    }
    return user;
  },

  async updateUserLikes(userId: string, delta: number): Promise<void> {
    if (!isConfigured) return;
    const { data: user } = await supabase.from('users').select('*').eq('id', userId).single();
    if (!user) return;
    const newTotalLikes = (user.total_likes || 0) + delta;
    const newBadge = getBadge(newTotalLikes);
    await supabase.from('users').update({ total_likes: newTotalLikes, badge: newBadge }).eq('id', userId);
    const session = this.getCurrentUser();
    if (session && session.id === userId) {
      const updatedSessionUser = { ...session, totalLikes: newTotalLikes, badge: newBadge };
      localStorage.setItem(SESSION_KEY, JSON.stringify(updatedSessionUser));
    }
  },

  async updateUserBio(userId: string, bio: string): Promise<User | null> {
    if (!isConfigured) return null;
    try {
      const { error } = await supabase.from('users').update({ bio }).eq('id', userId);
      if (error) throw error;
      return await this.refreshUser(userId);
    } catch (err) {
      console.error("Update bio failed:", err);
      return null;
    }
  },

  getCurrentUser(): User | null {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  },

  async register(username: string, email: string, password: string): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      username,
      email,
      avatar: `https://picsum.photos/seed/${username}/100`,
      bio: '',
      totalLikes: 0,
      badge: BadgeTier.NOVICE,
      followerCount: 0,
      followingCount: 0
    };
    const { error } = await supabase.from('users').insert([{
      id: newUser.id,
      username: newUser.username,
      email: newUser.email,
      password: password,
      avatar: newUser.avatar,
      bio: '',
      total_likes: 0,
      badge: BadgeTier.NOVICE
    }]);
    if (error) return { success: false, error: error.message };
    localStorage.setItem(SESSION_KEY, JSON.stringify(newUser));
    return { success: true, user: newUser };
  },

  async login(identifier: string, password: string, method: 'username' | 'email'): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };
    const field = method === 'username' ? 'username' : 'email';
    const { data, error } = await supabase.from('users').select('*').ilike(field, identifier).eq('password', password).maybeSingle();
    if (error) return { success: false, error: error.message };
    if (!data) return { success: false, error: 'User not found.' };

    const user = await this.refreshUser(data.id);
    return user ? { success: true, user } : { success: false, error: 'Failed to fetch user data.' };
  },

  async deleteAccount(userId: string): Promise<{ success: boolean, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not configured.' };
    try {
      await supabase.from('follows').delete().or(`follower_id.eq.${userId},following_id.eq.${userId}`);
      await supabase.from('comments').delete().eq('user_id', userId);
      await supabase.from('posts').delete().eq('user_id', userId);
      await supabase.from('users').delete().eq('id', userId);
      this.logout();
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  logout() {
    localStorage.removeItem(SESSION_KEY);
  }
};

import React, { useState, useEffect } from 'react';
import { User, Post } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';

interface ProfileProps {
  user: User;
  currentUser: User | null;
  posts: Post[];
  isDarkMode: boolean;
  onAccountDeleted: () => void;
  onLogout: () => void;
  onUserUpdate: (updatedUser: User) => void;
}

export const Profile: React.FC<ProfileProps> = ({ 
  user, 
  currentUser, 
  posts, 
  isDarkMode, 
  onAccountDeleted, 
  onLogout,
  onUserUpdate
}) => {
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [deleteError, setDeleteError] = useState('');
  const [isEditingBio, setIsEditingBio] = useState(false);
  const [bioText, setBioText] = useState(user.bio || '');
  const [isSavingBio, setIsSavingBio] = useState(false);

  const isOwnProfile = currentUser?.id === user.id;
  const userPosts = posts.filter(p => p.userId === user.id);
  const totalReceivedLikes = userPosts.reduce((acc, post) => acc + post.likes, 0);

  useEffect(() => {
    setBioText(user.bio || '');
  }, [user.bio]);

  const handleDeleteAccount = async () => {
    setIsDeleting(true);
    setDeleteError('');
    try {
      const result = await db.deleteAccount(user.id);
      if (result.success) onAccountDeleted(); else {
        setDeleteError(result.error || 'Failed to delete account');
        setIsDeleting(false);
      }
    } catch (err) {
      setDeleteError('An unexpected error occurred');
      setIsDeleting(false);
    }
  };

  const handleSaveBio = async () => {
    setIsSavingBio(true);
    const updated = await db.updateUserBio(user.id, bioText);
    if (updated) {
      onUserUpdate(updated);
      setIsEditingBio(false);
    }
    setIsSavingBio(false);
  };

  return (
    <div className="max-w-3xl mx-auto py-4 md:py-8">
      <div className={`p-6 md:p-8 rounded-2xl md:rounded-3xl border transition-all relative ${
        isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-xl'
      }`}>
        {isOwnProfile && (
          <button 
            onClick={onLogout}
            className="absolute top-4 right-4 md:top-6 md:right-6 text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 hover:text-indigo-500 transition-colors flex items-center gap-2"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
            Logout
          </button>
        )}

        <div className="flex flex-col md:flex-row items-center gap-6 md:gap-8 mb-8 md:mb-10">
          <img src={user.avatar} alt={user.username} className="w-24 h-24 md:w-32 md:h-32 rounded-2xl md:rounded-3xl object-cover shadow-2xl ring-4 ring-indigo-500/20" />
          <div className="text-center md:text-left w-full">
            <h1 className="text-2xl md:text-3xl font-serif font-bold mb-2 truncate">@{user.username}</h1>
            <div className="flex flex-wrap justify-center md:justify-start gap-2 md:gap-3 mb-4">
              <BadgeIcon tier={user.badge} size="md" />
              <span className="text-[10px] font-black uppercase tracking-widest text-slate-400 py-1 px-3 bg-slate-100 dark:bg-slate-800 rounded-full">
                Member since 2024
              </span>
            </div>

            <div className="mt-4 max-w-lg mx-auto md:mx-0">
              {isEditingBio ? (
                <div className="space-y-3">
                  <textarea
                    value={bioText}
                    onChange={(e) => setBioText(e.target.value)}
                    placeholder="Tell your story in a few words..."
                    rows={3}
                    className={`w-full p-3 text-sm rounded-xl border outline-none resize-none transition-all ${
                      isDarkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-slate-50 border-slate-200'
                    }`}
                  />
                  <div className="flex justify-center md:justify-start gap-2">
                    <button 
                      onClick={handleSaveBio}
                      disabled={isSavingBio}
                      className="px-4 py-1.5 bg-indigo-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest"
                    >
                      {isSavingBio ? 'Saving...' : 'Save Bio'}
                    </button>
                    <button 
                      onClick={() => { setIsEditingBio(false); setBioText(user.bio || ''); }}
                      className="px-4 py-1.5 border border-slate-200 rounded-lg text-[10px] font-black uppercase tracking-widest dark:bg-slate-800"
                    >
                      Cancel
                    </button>
                  </div>
                </div>
              ) : (
                <div className="group relative">
                  <p className={`text-sm leading-relaxed ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
                    {user.bio || (isOwnProfile ? "No bio yet. Add one to describe your creative journey!" : "")}
                  </p>
                  {isOwnProfile && (
                    <button 
                      onClick={() => setIsEditingBio(true)}
                      className="mt-2 text-[10px] font-black uppercase tracking-widest text-indigo-500 hover:text-indigo-400 transition-colors inline-flex items-center gap-1.5"
                    >
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                      {user.bio ? 'Edit Bio' : 'Add Bio'}
                    </button>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="grid grid-cols-5 gap-1 md:gap-4 py-6 border-y border-slate-100 dark:border-slate-800">
          <div className="text-center">
            <p className="text-lg md:text-xl font-bold">{userPosts.length}</p>
            <p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Stories</p>
          </div>
          <div className="text-center border-l border-slate-100 dark:border-slate-800">
            <p className="text-lg md:text-xl font-bold">{totalReceivedLikes}</p>
            <p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Likes</p>
          </div>
          <div className="text-center border-l border-slate-100 dark:border-slate-800">
            <p className="text-lg md:text-xl font-bold">{user.followingCount}</p>
            <p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Following</p>
          </div>
          <div className="text-center border-l border-slate-100 dark:border-slate-800">
            <p className="text-lg md:text-xl font-bold">{user.followerCount}</p>
            <p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Followers</p>
          </div>
          <div className="text-center border-l border-slate-100 dark:border-slate-800">
            <p className="text-lg md:text-xl font-bold">{userPosts.reduce((acc, p) => acc + p.comments.length, 0)}</p>
            <p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Notes</p>
          </div>
        </div>

        {isOwnProfile && (
          <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800">
            {!showConfirmDelete ? (
              <button onClick={() => setShowConfirmDelete(true)} className="text-[10px] font-bold text-slate-400 hover:text-red-500 transition-colors uppercase tracking-widest flex items-center gap-2">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                Delete Account
              </button>
            ) : (
              <div className="p-4 rounded-xl border bg-red-50 dark:bg-red-900/20 border-red-100 dark:border-red-900/40">
                <p className="text-xs font-bold text-red-600 mb-4">Confirm permanent account deletion?</p>
                <div className="flex gap-3">
                  <button onClick={handleDeleteAccount} className="px-4 py-2 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest shadow-lg">Yes, Delete</button>
                  <button onClick={() => setShowConfirmDelete(false)} className="px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest border border-slate-200 bg-white">Cancel</button>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Post, User } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { AuthForm } from './components/AuthForm';
import { CreatePostForm } from './components/CreatePostForm';
import { PostList } from './components/PostList';
import { Profile } from './components/Profile';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<'home' | 'create' | 'login' | 'register' | 'my-stories' | 'profile'>('home');
  const [viewingUser, setViewingUser] = useState<User | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  const fetchPosts = useCallback(async () => {
    setIsLoading(true);
    const data = await db.getPosts();
    setPosts(data);
    setIsLoading(false);
  }, []);

  const refreshCurrentUser = useCallback(async () => {
    const user = db.getCurrentUser();
    if (user) {
      const refreshedUser = await db.refreshUser(user.id);
      if (refreshedUser) {
        setCurrentUser(refreshedUser);
      }
    }
  }, []);

  useEffect(() => {
    const user = db.getCurrentUser();
    if (user) {
      setCurrentUser(user);
      refreshCurrentUser(); // Sync stats on initial load
    }
    fetchPosts();
  }, [fetchPosts, refreshCurrentUser]);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
    setViewingUser(null);
  };

  const handleAccountDeleted = () => {
    setCurrentUser(null);
    setCurrentPage('home');
    setViewingUser(null);
    fetchPosts();
  };

  const handleAuthSuccess = (user: User) => {
    setCurrentUser(user);
    setCurrentPage('home');
  };

  const handlePostUpdate = async (updatedPost: Post) => {
    await db.updatePost(updatedPost);
    const data = await db.getPosts();
    setPosts(data);
    refreshCurrentUser();
  };

  const handlePostDeleted = async () => {
    await fetchPosts();
    refreshCurrentUser();
  };

  const handlePostCreated = async () => {
    await fetchPosts();
    setCurrentPage('home');
    refreshCurrentUser();
  };

  const handleFollowToggle = (updatedUser: User) => {
    setCurrentUser(updatedUser);
    // If we are viewing the profile of the person we just followed/unfollowed, update it
    if (viewingUser && viewingUser.id === updatedUser.id) {
       setViewingUser(updatedUser);
    }
  };

  const handleNavigate = async (page: 'home' | 'create' | 'login' | 'register' | 'my-stories' | 'profile', userId?: string) => {
    if (page === 'profile') {
      const id = userId || currentUser?.id;
      if (id) {
        const userToView = await db.getUserById(id);
        setViewingUser(userToView);
        setCurrentPage('profile');
      } else {
        setCurrentPage('login');
      }
    } else {
      setCurrentPage(page);
      setViewingUser(null);
    }
  };

  const handleUserUpdate = (updated: User) => {
    if (currentUser?.id === updated.id) {
      setCurrentUser(updated);
    }
    if (viewingUser?.id === updated.id) {
      setViewingUser(updated);
    }
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={handleNavigate}
      />

      <main className={`max-w-4xl mx-auto px-4 pt-8 pb-24 md:pb-12`}>
        {isLoading && (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Connecting to Cloud Verse...</p>
          </div>
        )}

        {!isLoading && (currentPage === 'home' || currentPage === 'my-stories') && (
          <PostList 
            posts={filteredPosts}
            currentUser={currentUser}
            isDarkMode={isDarkMode}
            onPostUpdate={handlePostUpdate}
            onPostDeleted={handlePostDeleted}
            onFollowToggle={handleFollowToggle}
            onActionClick={() => currentUser ? setCurrentPage('create') : setCurrentPage('login')}
            onUserClick={(id) => handleNavigate('profile', id)}
            title={currentPage === 'my-stories' ? 'Personal Archives' : 'Discover the Verse'}
            description={currentPage === 'my-stories' ? 'A private collection of your digital echoes.' : 'Where the world shares its hidden stories.'}
          />
        )}

        {currentPage === 'create' && currentUser && (
          <CreatePostForm 
            currentUser={currentUser}
            isDarkMode={isDarkMode}
            onPostCreated={handlePostCreated}
          />
        )}

        {currentPage === 'profile' && viewingUser && (
          <Profile 
            user={viewingUser}
            currentUser={currentUser}
            posts={posts}
            isDarkMode={isDarkMode}
            onAccountDeleted={handleAccountDeleted}
            onLogout={handleLogout}
            onUserUpdate={handleUserUpdate}
          />
        )}

        {(currentPage === 'login' || currentPage === 'register') && (
          <AuthForm 
            mode={currentPage}
            isDarkMode={isDarkMode}
            onAuthSuccess={handleAuthSuccess}
            onSwitchMode={(mode) => setCurrentPage(mode)}
          />
        )}
      </main>

      <footer className={`hidden md:block py-12 border-t text-center transition-colors ${isDarkMode ? 'border-slate-800 text-slate-500' : 'border-slate-100 text-slate-400'}`}>
        <p className="font-serif text-lg font-bold mb-3">StoryVerse</p>
        <div className="flex items-center justify-center gap-4 text-[10px] font-black uppercase tracking-[0.2em] mb-6">
          <span className="flex items-center gap-1.5 text-blue-500">
            <span className="w-2 h-2 bg-current rounded-full animate-pulse"></span>
            Cloud Database: Supabase Connected
          </span>
        </div>
        <p className="text-[10px] opacity-60">© {new Date().getFullYear()} StoryVerse Collective. All stories are synchronized with the cloud.</p>
      </footer>
    </div>
  );
};

export default App;

