import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Post, User } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { AuthForm } from './components/AuthForm';
import { CreatePostForm } from './components/CreatePostForm';
import { PostList } from './components/PostList';
import { Profile } from './components/Profile';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<'home' | 'create' | 'login' | 'register' | 'my-stories' | 'profile' | 'bookmarks'>('home');
  const [viewingUser, setViewingUser] = useState<User | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  const fetchPosts = useCallback(async () => {
    setIsLoading(true);
    const data = await db.getPosts();
    setPosts(data);
    setIsLoading(false);
  }, []);

  const refreshCurrentUser = useCallback(async () => {
    const user = db.getCurrentUser();
    if (user) {
      const refreshedUser = await db.refreshUser(user.id);
      if (refreshedUser) {
        setCurrentUser(refreshedUser);
      } else {
        // CRITICAL FIX: If the user record is missing from the DB, log them out
        // This clears the stale ID from localStorage and fixes bookmark/follow errors.
        db.logout();
        setCurrentUser(null);
        setCurrentPage('home');
      }
    }
  }, []);

  useEffect(() => {
    const user = db.getCurrentUser();
    if (user) {
      setCurrentUser(user);
      refreshCurrentUser();
    }
    fetchPosts();
  }, [fetchPosts, refreshCurrentUser]);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    } else if (currentPage === 'bookmarks' && currentUser) {
      result = result.filter(p => currentUser.bookmarks?.includes(p.id));
    }

    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
    setViewingUser(null);
  };

  const handleAccountDeleted = () => {
    setCurrentUser(null);
    setCurrentPage('home');
    setViewingUser(null);
    fetchPosts();
  };

  const handleAuthSuccess = (user: User) => {
    setCurrentUser(user);
    setCurrentPage('home');
  };

  const handlePostUpdate = async (updatedPost: Post) => {
    await db.updatePost(updatedPost);
    const data = await db.getPosts();
    setPosts(data);
    refreshCurrentUser();
  };

  const handlePostDeleted = async () => {
    await fetchPosts();
    refreshCurrentUser();
  };

  const handlePostCreated = async () => {
    await fetchPosts();
    setCurrentPage('home');
    refreshCurrentUser();
  };

  const handleFollowToggle = (updatedUser: User) => {
    setCurrentUser(updatedUser);
    if (viewingUser && viewingUser.id === updatedUser.id) {
       setViewingUser(updatedUser);
    }
  };

  const handleBookmarkToggle = (updatedUser: User) => {
    setCurrentUser(updatedUser);
  };

  const handleNavigate = async (page: 'home' | 'create' | 'login' | 'register' | 'my-stories' | 'profile' | 'bookmarks', userId?: string) => {
    if (page === 'profile') {
      const id = userId || currentUser?.id;
      if (id) {
        const userToView = await db.getUserById(id);
        setViewingUser(userToView);
        setCurrentPage('profile');
      } else {
        setCurrentPage('login');
      }
    } else {
      setCurrentPage(page);
      setViewingUser(null);
    }
  };

  const handleUserUpdate = (updated: User) => {
    if (currentUser?.id === updated.id) {
      setCurrentUser(updated);
    }
    if (viewingUser?.id === updated.id) {
      setViewingUser(updated);
    }
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={handleNavigate}
      />

      <main className={`max-w-4xl mx-auto px-4 pt-8 pb-24 md:pb-12`}>
        {isLoading && (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Connecting to Cloud Verse...</p>
          </div>
        )}

        {!isLoading && (currentPage === 'home' || currentPage === 'my-stories' || currentPage === 'bookmarks') && (
          <PostList 
            posts={filteredPosts}
            currentUser={currentUser}
            isDarkMode={isDarkMode}
            onPostUpdate={handlePostUpdate}
            onPostDeleted={handlePostDeleted}
            onFollowToggle={handleFollowToggle}
            onBookmarkToggle={handleBookmarkToggle}
            onActionClick={() => currentUser ? (currentPage === 'bookmarks' ? handleNavigate('home') : handleNavigate('create')) : handleNavigate('login')}
            onUserClick={(id) => handleNavigate('profile', id)}
            title={
              currentPage === 'my-stories' ? 'Personal Archives' : 
              currentPage === 'bookmarks' ? 'Saved Journeys' : 'Discover the Verse'
            }
            description={
              currentPage === 'my-stories' ? 'A private collection of your digital echoes.' : 
              currentPage === 'bookmarks' ? 'Stories you have saved for the path ahead.' : 'Where the world shares its hidden stories.'
            }
          />
        )}

        {currentPage === 'create' && currentUser && (
          <CreatePostForm 
            currentUser={currentUser}
            isDarkMode={isDarkMode}
            onPostCreated={handlePostCreated}
          />
        )}

        {currentPage === 'profile' && viewingUser && (
          <Profile 
            user={viewingUser}
            currentUser={currentUser}
            posts={posts}
            isDarkMode={isDarkMode}
            onAccountDeleted={handleAccountDeleted}
            onLogout={handleLogout}
            onUserUpdate={handleUserUpdate}
          />
        )}

        {(currentPage === 'login' || currentPage === 'register') && (
          <AuthForm 
            mode={currentPage}
            isDarkMode={isDarkMode}
            onAuthSuccess={handleAuthSuccess}
            onSwitchMode={(mode) => setCurrentPage(mode)}
          />
        )}
      </main>

      <footer className={`hidden md:block py-12 border-t text-center transition-colors ${isDarkMode ? 'border-slate-800 text-slate-500' : 'border-slate-100 text-slate-400'}`}>
        <p className="font-serif text-lg font-bold mb-3">StoryVerse</p>
        <div className="flex items-center justify-center gap-4 text-[10px] font-black uppercase tracking-[0.2em] mb-6">
          <span className="flex items-center gap-1.5 text-blue-500">
            <span className="w-2 h-2 bg-current rounded-full animate-pulse"></span>
            Cloud Database: Supabase Connected
          </span>
        </div>
        <p className="text-[10px] opacity-60">© {new Date().getFullYear()} StoryVerse Collective. All stories are synchronized with the cloud.</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Post, User, BadgeTier } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';

interface PostCardProps {
  post: Post;
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (post: Post) => void;
  onPostDeleted: () => void;
  onFollowToggle?: (updatedUser: User) => void;
  onUserClick?: (userId: string) => void;
  onBookmarkToggle?: (updatedUser: User) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  isDarkMode, 
  onPostUpdate, 
  onPostDeleted,
  onFollowToggle,
  onUserClick,
  onBookmarkToggle
}) => {
  const [commentText, setCommentText] = useState('');
  const [showComments, setShowComments] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [isAnimatingLike, setIsAnimatingLike] = useState(false);
  const [showMenu, setShowMenu] = useState(false);
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);
  const [authorBadge, setAuthorBadge] = useState<BadgeTier>(BadgeTier.NOVICE);
  const [isFollowing, setIsFollowing] = useState(false);
  const [isFollowLoading, setIsFollowLoading] = useState(false);
  const [isBookmarkLoading, setIsBookmarkLoading] = useState(false);

  // Optimistic UI state for bookmarks
  const [isOptimisticBookmarked, setIsOptimisticBookmarked] = useState(false);

  const isOwner = currentUser?.id === post.userId;

  // Real bookmark state from the current user object
  const isActuallyBookmarked = useMemo(() => currentUser?.bookmarks?.includes(post.id) || false, [currentUser, post.id]);

  // Sync optimistic state whenever the real user object updates
  useEffect(() => {
    setIsOptimisticBookmarked(isActuallyBookmarked);
  }, [isActuallyBookmarked]);

  const CONTENT_THRESHOLD = 250;
  const isLongContent = post.content.length > CONTENT_THRESHOLD;

  useEffect(() => {
    let isMounted = true;
    const fetchAuthorData = async () => {
      const author = await db.getUserById(post.userId);
      if (isMounted && author) {
        setAuthorBadge(author.badge);
      }

      if (isMounted && currentUser && !isOwner) {
        const following = await db.isFollowing(currentUser.id, post.userId);
        setIsFollowing(following);
      }
    };
    fetchAuthorData();
    return () => { isMounted = false; };
  }, [post.userId, currentUser, isOwner]);

  const isLiked = useMemo(() => {
    return currentUser ? post.likedBy?.includes(currentUser.id) : false;
  }, [post.likedBy, currentUser]);

  const handleFollow = async () => {
    if (!currentUser) return alert('Login to follow authors');
    if (isFollowLoading) return;

    setIsFollowLoading(true);
    try {
      let updatedUser: User | null = null;
      if (isFollowing) {
        updatedUser = await db.unfollowUser(currentUser.id, post.userId);
        setIsFollowing(false);
      } else {
        updatedUser = await db.followUser(currentUser.id, post.userId);
        setIsFollowing(true);
      }
      if (updatedUser && onFollowToggle) {
        onFollowToggle(updatedUser);
      }
    } catch (err) {
      console.error("Follow action failed:", err);
    } finally {
      setIsFollowLoading(false);
    }
  };

  const handleBookmark = async () => {
    if (!currentUser) return alert('Login to save stories');
    if (isBookmarkLoading) return;

    // 1. Optimistic Update: Toggle state immediately
    const previousState = isOptimisticBookmarked;
    setIsOptimisticBookmarked(!previousState);
    setIsBookmarkLoading(true);

    try {
      const updatedUser = await db.toggleBookmark(currentUser.id, post.id);
      if (updatedUser && onBookmarkToggle) {
        onBookmarkToggle(updatedUser);
      } else {
        // Rollback on failure if db returned null (likely session mismatch)
        setIsOptimisticBookmarked(previousState);
        alert('Your session has expired or is invalid. Please refresh and log in again.');
      }
    } catch (err) {
      console.error("Bookmark failed:", err);
      // 2. Rollback: If request fails, revert state
      setIsOptimisticBookmarked(previousState);
    } finally {
      setIsBookmarkLoading(false);
    }
  };

  const handleLike = useCallback(async () => {
    if (!currentUser) return alert('Please login to like');
    const hasLiked = post.likedBy?.includes(currentUser.id);
    const likeDelta = hasLiked ? -1 : 1;
    const newLikedBy = hasLiked 
      ? (post.likedBy || []).filter(id => id !== currentUser.id)
      : [...(post.likedBy || []), currentUser.id];

    if (!hasLiked) {
      setIsAnimatingLike(true);
      setTimeout(() => setIsAnimatingLike(false), 400);
    }

    const updatedPost: Post = { ...post, likes: Math.max(0, post.likes + likeDelta), likedBy: newLikedBy };
    await db.updatePost(updatedPost);
    await db.updateUserLikes(post.userId, likeDelta);
    onPostUpdate(updatedPost);
  }, [post, currentUser, onPostUpdate]);

  const handleDeletePost = async () => {
    const result = await db.deletePost(post.id);
    if (result.success) onPostDeleted();
  };

  const handleAddComment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser || !commentText.trim()) return;
    const newComment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      content: commentText,
      createdAt: new Date().toISOString()
    };
    await db.addComment(post.id, newComment);
    onPostUpdate({ ...post, comments: [...post.comments, newComment] });
    setCommentText('');
  };

  const handleProfileClick = () => {
    if (onUserClick) onUserClick(post.userId);
  };

  return (
    <div className={`rounded-xl md:rounded-2xl shadow-sm border transition-all overflow-hidden h-fit flex flex-col hover:shadow-md ${
      isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-100'
    }`}>
      <div className="p-4 md:p-6 flex-1">
        <div className="flex items-start justify-between mb-4 md:mb-6">
          <div className="flex items-center gap-3">
            <img 
              src={post.userAvatar} 
              className="w-10 h-10 md:w-11 md:h-11 rounded-xl bg-slate-200 object-cover cursor-pointer hover:opacity-80 transition-opacity" 
              alt={post.username} 
              onClick={handleProfileClick}
            />
            <div>
              <div className="flex items-center gap-1.5 md:gap-2 mb-0.5">
                <span 
                  className="font-bold text-xs md:text-sm truncate max-w-[100px] md:max-w-none cursor-pointer hover:underline"
                  onClick={handleProfileClick}
                >
                  @{post.username}
                </span>
                <BadgeIcon tier={authorBadge} />
              </div>
              <div className="flex items-center gap-2">
                <span className="text-[9px] md:text-[10px] text-slate-500 uppercase font-black tracking-widest opacity-80">
                  {new Date(post.createdAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
                </span>
                {!isOwner && currentUser && (
                  <>
                    <span className="text-slate-300">•</span>
                    <button 
                      onClick={handleFollow}
                      disabled={isFollowLoading}
                      className={`text-[10px] font-black uppercase tracking-widest transition-all ${
                        isFollowLoading ? 'opacity-50 cursor-not-allowed' : ''
                      } ${
                        isFollowing ? 'text-slate-400' : 'text-indigo-600 hover:text-indigo-400'
                      }`}
                    >
                      {isFollowing ? 'Following' : 'Follow'}
                    </button>
                  </>
                )}
              </div>
            </div>
          </div>

          <div className="relative">
            <button onClick={() => setShowMenu(!showMenu)} className="text-slate-400 p-1.5 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z"/></svg>
            </button>
            {showMenu && (
              <div className={`absolute right-0 top-10 w-48 rounded-xl shadow-xl border z-20 ${isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-white border-slate-100'}`}>
                {isOwner ? (
                  <button onClick={() => { setShowConfirmDelete(true); setShowMenu(false); }} className="w-full text-left px-4 py-3 text-xs font-bold text-red-500 hover:bg-red-500/10 rounded-xl transition-colors flex items-center gap-2">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                    Remove Story
                  </button>
                ) : (
                  <>
                    <button onClick={handleProfileClick} className="w-full text-left px-4 py-3 text-xs font-bold text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-xl transition-colors">
                      View Profile
                    </button>
                    <button onClick={handleFollow} className="w-full text-left px-4 py-3 text-xs font-bold text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-xl transition-colors">
                      {isFollowing ? 'Unfollow Author' : 'Follow Author'}
                    </button>
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        {showConfirmDelete && (
          <div className={`mb-4 p-4 rounded-xl border ${isDarkMode ? 'bg-red-500/10 border-red-500/20' : 'bg-red-50 border-red-100'}`}>
            <p className="text-[11px] font-bold mb-3 text-red-600">Delete this story permanently?</p>
            <div className="flex gap-2">
              <button onClick={handleDeletePost} className="px-3 py-1.5 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest">Confirm</button>
              <button onClick={() => setShowConfirmDelete(false)} className="px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest border border-slate-200 bg-white">Cancel</button>
            </div>
          </div>
        )}

        <h3 className={`font-serif text-xl md:text-2xl font-bold mb-3 md:mb-4 leading-snug ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>{post.title}</h3>
        <p className={`text-sm md:text-base leading-relaxed whitespace-pre-wrap mb-4 font-light ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
          {isExpanded || !isLongContent ? post.content : `${post.content.substring(0, CONTENT_THRESHOLD)}...`}
        </p>
        {isLongContent && (
          <button onClick={() => setIsExpanded(!isExpanded)} className={`text-[10px] font-black uppercase tracking-widest ${isDarkMode ? 'text-indigo-400' : 'text-indigo-600'} mb-4 md:mb-6`}>
            {isExpanded ? 'Collapse ↑' : 'Read Full Journey ↓'}
          </button>
        )}

        <div className={`flex items-center justify-between pt-4 md:pt-5 border-t ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}`}>
          <div className="flex items-center gap-4 md:gap-6">
            <button onClick={handleLike} className={`group flex items-center gap-2 text-xs md:text-sm font-bold transition-all p-1 ${isLiked || isAnimatingLike ? 'text-red-500 scale-105' : 'text-slate-400'}`}>
              <svg className={`w-5 h-5 md:w-6 md:h-6 transition-all ${isLiked || isAnimatingLike ? 'fill-red-500 stroke-red-500' : 'fill-none stroke-current'}`} viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/>
              </svg>
              <span className="tabular-nums">{post.likes}</span>
            </button>
            <button onClick={() => setShowComments(!showComments)} className="flex items-center gap-2 text-xs md:text-sm font-bold text-slate-400 p-1">
              <svg className="w-5 h-5 md:w-6 md:h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
              <span className="tabular-nums">{post.comments.length}</span>
            </button>
          </div>

          <button 
            onClick={handleBookmark} 
            disabled={isBookmarkLoading}
            className={`p-1 transition-all ${isBookmarkLoading ? 'opacity-80' : 'active:scale-125'} ${isOptimisticBookmarked ? 'text-indigo-600' : 'text-slate-400 hover:text-indigo-400'}`}
            title={isOptimisticBookmarked ? "Remove from saved" : "Save story"}
          >
            <svg className={`w-5 h-5 md:w-6 md:h-6 ${isOptimisticBookmarked ? 'fill-current' : 'fill-none stroke-current'}`} viewBox="0 0 24 24" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" />
            </svg>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-4 md:p-6 border-t ${isDarkMode ? 'bg-slate-900/50 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
          <div className="space-y-4 mb-4">
            {post.comments.length === 0 ? (<p className="text-[10px] text-center text-slate-500 italic py-2">No resonance found yet.</p>) : (
              post.comments.map(c => (
                <div key={c.id} className="flex gap-3 text-left">
                  <div className="w-7 h-7 rounded-lg bg-indigo-500 flex items-center justify-center text-white font-black text-[9px] shrink-0 uppercase">{c.username[0]}</div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between mb-0.5">
                      <span className="font-bold text-[11px] truncate">@{c.username}</span>
                      <span className="text-[8px] text-slate-500 uppercase font-bold">{new Date(c.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                    </div>
                    <p className={`text-xs ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}>{c.content}</p>
                  </div>
                </div>
              ))
            )}
          </div>
          <form onSubmit={handleAddComment} className="flex gap-2">
            <input type="text" placeholder="Your reply..." value={commentText} onChange={(e) => setCommentText(e.target.value)} className={`flex-1 px-4 py-2 rounded-xl text-xs outline-none transition-all ${isDarkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-white border-slate-200'}`} />
            <button type="submit" disabled={!commentText.trim()} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-xs font-bold transition-all shadow-md">Reply</button>
          </form>
        </div>
      )}
    </div>
  );
};

import { createClient } from '@supabase/supabase-js';
import { Post, User, BadgeTier, Comment } from '../types';

/**
 * !!! IMPORTANT: RUN THIS SQL IN YOUR SUPABASE SQL EDITOR !!!
 * 
 * CREATE TABLE IF NOT EXISTS users (
 *   id TEXT PRIMARY KEY, 
 *   username TEXT UNIQUE, 
 *   email TEXT UNIQUE, 
 *   password TEXT, 
 *   avatar TEXT, 
 *   bio TEXT DEFAULT '', 
 *   bookmarks TEXT[] DEFAULT '{}',
 *   total_likes INT DEFAULT 0, 
 *   badge TEXT DEFAULT 'Novice'
 * );
 * 
 * ALTER TABLE users ADD COLUMN IF NOT EXISTS bookmarks TEXT[] DEFAULT '{}';
 * 
 * -- Disable RLS so your frontend can communicate with Supabase without complex policies
 * ALTER TABLE users DISABLE ROW LEVEL SECURITY;
 * ALTER TABLE posts DISABLE ROW LEVEL SECURITY;
 */

const SUPABASE_URL = (process.env as any).SUPABASE_URL || 'https://uvjavqzhhqxkfuklkxdo.supabase.co';
const SUPABASE_ANON_KEY = (process.env as any).SUPABASE_ANON_KEY || 'sb_publishable_-GDZiq_v45oEVhlly7tG-w_cKockqn6';

const isConfigured = SUPABASE_URL !== 'https://your-project-url.supabase.co' && SUPABASE_ANON_KEY !== 'your-anon-key';
const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);
const SESSION_KEY = 'storyverse_session';

export const getBadge = (likes: number): BadgeTier => {
  if (likes >= 500) return BadgeTier.PLATINUM;
  if (likes >= 100) return BadgeTier.GOLD;
  if (likes >= 25) return BadgeTier.SILVER;
  if (likes >= 5) return BadgeTier.BRONZE;
  return BadgeTier.NOVICE;
};

export const db = {
  async getPosts(): Promise<Post[]> {
    if (!isConfigured) return [];
    try {
      const { data, error } = await supabase
        .from('posts')
        .select(`*, comments (*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      return (data || []).map(post => ({
        id: post.id,
        userId: post.user_id,
        username: post.username,
        title: post.title,
        content: post.content,
        likes: post.likes || 0,
        likedBy: post.liked_by || [],
        shares: post.shares || 0,
        createdAt: post.created_at,
        userAvatar: post.user_avatar,
        comments: (post.comments || []).map((c: any) => ({
          id: c.id,
          userId: c.user_id,
          username: c.username,
          content: c.content,
          createdAt: c.created_at
        }))
      }));
    } catch (err) {
      console.error("Fetch posts failed:", err);
      return [];
    }
  },

  async savePost(post: Post): Promise<void> {
    if (!isConfigured) return;
    await supabase.from('posts').insert([{
      id: post.id,
      user_id: post.userId,
      username: post.username,
      title: post.title,
      content: post.content,
      likes: post.likes,
      liked_by: post.likedBy,
      shares: post.shares,
      user_avatar: post.userAvatar,
      created_at: post.createdAt
    }]);
  },

  async updatePost(updatedPost: Post): Promise<void> {
    if (!isConfigured) return;
    await supabase.from('posts').update({
      likes: updatedPost.likes,
      liked_by: updatedPost.likedBy,
      shares: updatedPost.shares,
      title: updatedPost.title,
      content: updatedPost.content
    }).eq('id', updatedPost.id);
  },

  async deletePost(postId: string): Promise<{ success: boolean; error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not configured.' };
    try {
      await supabase.from('comments').delete().eq('post_id', postId);
      await supabase.from('posts').delete().eq('id', postId);
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async addComment(postId: string, comment: Comment): Promise<void> {
    if (!isConfigured) return;
    await supabase.from('comments').insert([{
      id: comment.id,
      post_id: postId,
      user_id: comment.userId,
      username: comment.username,
      content: comment.content,
      created_at: comment.createdAt
    }]);
  },

  async getUserById(userId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data, error } = await supabase.from('users').select('*').eq('id', userId).maybeSingle();
      if (error || !data) return null;

      const stats = await this.getFollowStats(data.id);
      return {
        id: data.id,
        username: data.username,
        email: data.email,
        avatar: data.avatar,
        bio: data.bio || '',
        bookmarks: data.bookmarks || [],
        totalLikes: data.total_likes || 0,
        badge: (data.badge as BadgeTier) || BadgeTier.NOVICE,
        followerCount: stats.followers,
        followingCount: stats.following
      };
    } catch (err) {
      console.error("Get user failed:", err);
      return null;
    }
  },

  async refreshUser(userId: string): Promise<User | null> {
    if (!userId) return null;
    const user = await this.getUserById(userId);
    if (user) {
      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
    return user;
  },

  async toggleBookmark(userId: string, postId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      // 1. Fetch the user directly from Supabase
      const { data: user, error: fetchError } = await supabase
        .from('users')
        .select('*')
        .eq('id', userId)
        .maybeSingle();

      if (fetchError) throw fetchError;

      // 2. If user is not found, the session is invalid
      if (!user) {
        console.error("Bookmark toggle failed: User ID does not exist in Supabase database.");
        return null;
      }

      // 3. Handle the array logic
      let bookmarks = Array.isArray(user.bookmarks) ? user.bookmarks : [];
      const isBookmarked = bookmarks.includes(postId);

      const newBookmarks = isBookmarked
        ? bookmarks.filter((id: string) => id !== postId)
        : [...bookmarks, postId];

      // 4. Update Supabase
      const { error: updateError } = await supabase
        .from('users')
        .update({ bookmarks: newBookmarks })
        .eq('id', userId);

      if (updateError) throw updateError;

      // 5. Return the refreshed user
      return await this.refreshUser(userId);
    } catch (err) {
      console.error("Critical Bookmark Toggle Error:", err);
      return null;
    }
  },

  async updateUserLikes(userId: string, delta: number): Promise<void> {
    if (!isConfigured) return;
    const { data: user } = await supabase.from('users').select('*').eq('id', userId).maybeSingle();
    if (!user) return;
    const newTotalLikes = (user.total_likes || 0) + delta;
    const newBadge = getBadge(newTotalLikes);
    await supabase.from('users').update({ total_likes: newTotalLikes, badge: newBadge }).eq('id', userId);
    await this.refreshUser(userId);
  },

  async updateUserBio(userId: string, bio: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { error } = await supabase.from('users').update({ bio }).eq('id', userId);
      if (error) throw error;
      return await this.refreshUser(userId);
    } catch (err) {
      console.error("Update bio failed:", err);
      return null;
    }
  },

  getCurrentUser(): User | null {
    const session = localStorage.getItem(SESSION_KEY);
    return session ? JSON.parse(session) : null;
  },

  async register(username: string, email: string, password: string): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      username,
      email,
      avatar: `https://picsum.photos/seed/${username}/100`,
      bio: '',
      bookmarks: [],
      totalLikes: 0,
      badge: BadgeTier.NOVICE,
      followerCount: 0,
      followingCount: 0
    };
    const { error } = await supabase.from('users').insert([{
      id: newUser.id,
      username: newUser.username,
      email: newUser.email,
      password: password,
      avatar: newUser.avatar,
      bio: '',
      bookmarks: [],
      total_likes: 0,
      badge: BadgeTier.NOVICE
    }]);
    if (error) return { success: false, error: error.message };
    localStorage.setItem(SESSION_KEY, JSON.stringify(newUser));
    return { success: true, user: newUser };
  },

  async login(identifier: string, password: string, method: 'username' | 'email'): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };
    const field = method === 'username' ? 'username' : 'email';
    const { data, error } = await supabase.from('users').select('*').ilike(field, identifier).eq('password', password).maybeSingle();
    if (error) return { success: false, error: error.message };
    if (!data) return { success: false, error: 'User not found.' };

    const user = await this.refreshUser(data.id);
    return user ? { success: true, user } : { success: false, error: 'Failed to fetch user data.' };
  },

  async getFollowStats(userId: string): Promise<{ followers: number, following: number }> {
    if (!isConfigured) return { followers: 0, following: 0 };
    try {
      const { count: followers } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('following_id', userId);
      const { count: following } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('follower_id', userId);
      return { followers: followers || 0, following: following || 0 };
    } catch (err) {
      return { followers: 0, following: 0 };
    }
  },

  async isFollowing(followerId: string, followingId: string): Promise<boolean> {
    if (!isConfigured) return false;
    try {
      const { data } = await supabase.from('follows').select('*').eq('follower_id', followerId).eq('following_id', followingId).maybeSingle();
      return !!data;
    } catch (err) {
      return false;
    }
  },

  async followUser(followerId: string, followingId: string): Promise<User | null> {
    if (!isConfigured || followerId === followingId) return null;
    try {
      const { error } = await supabase.from('follows').insert([{ follower_id: followerId, following_id: followingId }]);
      if (error) throw error;
      return await this.refreshUser(followerId);
    } catch (err) {
      console.error("Follow failed:", err);
      return null;
    }
  },

  async unfollowUser(followerId: string, followingId: string): Promise<User | null> {
    if (!isConfigured) return null;
    try {
      const { error } = await supabase.from('follows').delete().eq('follower_id', followerId).eq('following_id', followingId);
      if (error) throw error;
      return await this.refreshUser(followerId);
    } catch (err) {
      console.error("Unfollow failed:", err);
      return null;
    }
  },

  async deleteAccount(userId: string): Promise<{ success: boolean, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not configured.' };
    try {
      await supabase.from('follows').delete().or(`follower_id.eq.${userId},following_id.eq.${userId}`);
      await supabase.from('comments').delete().eq('user_id', userId);
      await supabase.from('posts').delete().eq('user_id', userId);
      await supabase.from('users').delete().eq('id', userId);
      this.logout();
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  logout() {
    localStorage.removeItem(SESSION_KEY);
  }
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Post, User } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { AuthForm } from './components/AuthForm';
import { CreatePostForm } from './components/CreatePostForm';
import { PostList } from './components/PostList';
import { Profile } from './components/ Profile';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<'home' | 'create' | 'login' | 'register' | 'my-stories' | 'profile' | 'bookmarks'>('home');
  const [viewingUser, setViewingUser] = useState<User | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  const fetchPosts = useCallback(async () => {
    setIsLoading(true);
    const data = await db.getPosts();
    setPosts(data);
    setIsLoading(false);
  }, []);

  const refreshCurrentUser = useCallback(async () => {
    const user = db.getCurrentUser();
    if (user) {
      const refreshedUser = await db.refreshUser(user.id);
      if (refreshedUser) {
        setCurrentUser(refreshedUser);
      } else {
        // If the user is missing from DB, log them out to prevent stale session errors
        db.logout();
        setCurrentUser(null);
        setCurrentPage('home');
      }
    }
  }, []);

  useEffect(() => {
    const user = db.getCurrentUser();
    if (user) {
      setCurrentUser(user);
      refreshCurrentUser();
    }
    fetchPosts();
  }, [fetchPosts, refreshCurrentUser]);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    } else if (currentPage === 'bookmarks' && currentUser) {
      const bookmarkIds = currentUser.bookmarks || [];
      result = result.filter(p => bookmarkIds.includes(p.id));
    }

    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
    setViewingUser(null);
  };

  const handleAccountDeleted = () => {
    setCurrentUser(null);
    setCurrentPage('home');
    setViewingUser(null);
    fetchPosts();
  };

  const handleAuthSuccess = (user: User) => {
    setCurrentUser(user);
    setCurrentPage('home');
  };

  const handlePostUpdate = async (updatedPost: Post) => {
    await db.updatePost(updatedPost);
    const data = await db.getPosts();
    setPosts(data);
    refreshCurrentUser();
  };

  const handlePostDeleted = async () => {
    await fetchPosts();
    refreshCurrentUser();
  };

  const handlePostCreated = async () => {
    await fetchPosts();
    setCurrentPage('home');
    refreshCurrentUser();
  };

  const handleFollowToggle = (updatedUser: User) => {
    setCurrentUser(updatedUser);
    if (viewingUser && viewingUser.id === updatedUser.id) {
       setViewingUser(updatedUser);
    }
  };

  const handleBookmarkToggle = (updatedUser: User) => {
    setCurrentUser(updatedUser);
  };

  const handleNavigate = async (page: 'home' | 'create' | 'login' | 'register' | 'my-stories' | 'profile' | 'bookmarks', userId?: string) => {
    if (page === 'profile') {
      const id = userId || currentUser?.id;
      if (id) {
        const userToView = await db.getUserById(id);
        setViewingUser(userToView);
        setCurrentPage('profile');
      } else {
        setCurrentPage('login');
      }
    } else {
      setCurrentPage(page);
      setViewingUser(null);
    }
  };

  const handleUserUpdate = (updated: User) => {
    if (currentUser?.id === updated.id) {
      setCurrentUser(updated);
    }
    if (viewingUser?.id === updated.id) {
      setViewingUser(updated);
    }
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={handleNavigate}
      />

      <main className={`max-w-4xl mx-auto px-4 pt-8 pb-24 md:pb-12`}>
        {isLoading && (
          <div className="flex flex-col items-center justify-center py-20 space-y-4">
            <div className="w-12 h-12 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
            <p className="text-sm font-bold text-slate-500 uppercase tracking-widest">Connecting to Cloud Verse...</p>
          </div>
        )}

        {!isLoading && (currentPage === 'home' || currentPage === 'my-stories' || currentPage === 'bookmarks') && (
          <PostList 
            posts={filteredPosts}
            currentUser={currentUser}
            isDarkMode={isDarkMode}
            onPostUpdate={handlePostUpdate}
            onPostDeleted={handlePostDeleted}
            onFollowToggle={handleFollowToggle}
            onBookmarkToggle={handleBookmarkToggle}
            onActionClick={() => currentUser ? (currentPage === 'bookmarks' ? handleNavigate('home') : handleNavigate('create')) : handleNavigate('login')}
            onUserClick={(id) => handleNavigate('profile', id)}
            title={
              currentPage === 'my-stories' ? 'Personal Archives' : 
              currentPage === 'bookmarks' ? 'Saved Journeys' : 'Discover the Verse'
            }
            description={
              currentPage === 'my-stories' ? 'A private collection of your digital echoes.' : 
              currentPage === 'bookmarks' ? 'Stories you have saved for the path ahead.' : 'Where the world shares its hidden stories.'
            }
          />
        )}

        {currentPage === 'create' && currentUser && (
          <CreatePostForm 
            currentUser={currentUser}
            isDarkMode={isDarkMode}
            onPostCreated={handlePostCreated}
          />
        )}

        {currentPage === 'profile' && viewingUser && (
          <Profile 
            user={viewingUser}
            currentUser={currentUser}
            posts={posts}
            isDarkMode={isDarkMode}
            onAccountDeleted={handleAccountDeleted}
            onLogout={handleLogout}
            onUserUpdate={handleUserUpdate}
          />
        )}

        {(currentPage === 'login' || currentPage === 'register') && (
          <AuthForm 
            mode={currentPage}
            isDarkMode={isDarkMode}
            onAuthSuccess={handleAuthSuccess}
            onSwitchMode={(mode) => setCurrentPage(mode)}
          />
        )}
      </main>

      <footer className={`hidden md:block py-12 border-t text-center transition-colors ${isDarkMode ? 'border-slate-800 text-slate-500' : 'border-slate-100 text-slate-400'}`}>
        <p className="font-serif text-lg font-bold mb-3">StoryVerse</p>
        <div className="flex items-center justify-center gap-4 text-[10px] font-black uppercase tracking-[0.2em] mb-6">
          <span className="flex items-center gap-1.5 text-blue-500">
            <span className="w-2 h-2 bg-current rounded-full animate-pulse"></span>
            Cloud Database: Supabase Connected
          </span>
        </div>
        <p className="text-[10px] opacity-60">© {new Date().getFullYear()} StoryVerse Collective. All stories are synchronized with the cloud.</p>
      </footer>
    </div>
  );
};

