import { createClient } from '@supabase/supabase-js';
import { Post, User, BadgeTier, Comment, ReportType } from '../types';

const SUPABASE_URL = (process.env as any).SUPABASE_URL || 'https://uvjavqzhhqxkfuklkxdo.supabase.co';
const SUPABASE_ANON_KEY = (process.env as any).SUPABASE_ANON_KEY || 'sb_publishable_-GDZiq_v45oEVhlly7tG-w_cKockqn6';

const isConfigured = SUPABASE_URL !== 'https://your-project-url.supabase.co' && SUPABASE_ANON_KEY !== 'your-anon-key';
const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);
const SESSION_KEY = 'storyverse_session';

export const getBadge = (likes: number): BadgeTier => {
  if (likes >= 500) return BadgeTier.PLATINUM;
  if (likes >= 100) return BadgeTier.GOLD;
  if (likes >= 25) return BadgeTier.SILVER;
  if (likes >= 5) return BadgeTier.BRONZE;
  return BadgeTier.NOVICE;
};

const BAN_THRESHOLD = 100;
const BAN_DURATION_DAYS = 3;

export const db = {
  isBanned(user: User | null): boolean {
    if (!user || !user.bannedUntil) return false;
    return new Date(user.bannedUntil) > new Date();
  },

  async hasAlreadyReported(reporterId: string, targetType: ReportType, targetId: string): Promise<boolean> {
    if (!isConfigured || !reporterId) return false;
    try {
      const { data, error } = await supabase
        .from('reports')
        .select('id')
        .eq('reporter_id', reporterId)
        .eq('target_type', targetType)
        .eq('target_id', targetId)
        .maybeSingle();

      return !!data && !error;
    } catch {
      return false;
    }
  },

  async reportEntity(reporterId: string, targetType: ReportType, targetId: string, reason: string): Promise<{ success: boolean; message: string }> {
    if (!isConfigured) return { success: false, message: 'Backend not configured.' };

    try {
      // 1. Check existing report
      const alreadyReported = await this.hasAlreadyReported(reporterId, targetType, targetId);
      if (alreadyReported) {
        return { success: false, message: 'You have already reported this item.' };
      }

      // 2. Prevent self-reporting
      let table = targetType === 'user' ? 'users' : (targetType === 'post' ? 'posts' : 'comments');
      let ownerId: string | undefined;

      const { data: entityData } = await supabase.from(table).select(targetType === 'user' ? 'id' : 'user_id').eq('id', targetId).maybeSingle();
      ownerId = targetType === 'user' ? entityData?.id : entityData?.user_id;

      if (ownerId === reporterId) {
        return { success: false, message: 'You cannot report your own content.' };
      }

      // 3. Log the report
      const { error: insertError } = await supabase.from('reports').insert([{
        id: Math.random().toString(36).substr(2, 9),
        reporter_id: reporterId,
        target_type: targetType,
        target_id: targetId,
        reason
      }]);

      if (insertError) {
        if (insertError.code === '23505') return { success: false, message: 'You have already reported this item.' };
        throw insertError;
      }

      // 4. Increment report count
      const { data: currentCountData } = await supabase.from(table).select('report_count').eq('id', targetId).maybeSingle();
      const newCount = (currentCountData?.report_count || 0) + 1;

      let updatePayload: any = { report_count: newCount };

      if (targetType === 'user' && newCount >= BAN_THRESHOLD) {
        const bannedUntil = new Date();
        bannedUntil.setDate(bannedUntil.getDate() + BAN_DURATION_DAYS);
        updatePayload.banned_until = bannedUntil.toISOString();
      }

      await supabase.from(table).update(updatePayload).eq('id', targetId);

      // 5. Auto-report linked user
      if (targetType !== 'user' && ownerId) {
        const ownerReported = await this.hasAlreadyReported(reporterId, 'user', ownerId);
        if (!ownerReported) {
          // Fire and forget auto-report
          this.reportEntity(reporterId, 'user', ownerId, `Linked report from ${targetType} violation.`);
        }
      }

      return { success: true, message: 'Thank you. Report submitted successfully.' };
    } catch (err) {
      console.error("Report failed:", err);
      return { success: false, message: 'Submission failed. Please try again.' };
    }
  },

  async getPosts(): Promise<Post[]> {
    if (!isConfigured) return [];
    try {
      const { data, error } = await supabase
        .from('posts')
        .select(`*, comments (*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      return (data || []).map(post => ({
        id: post.id,
        userId: post.user_id,
        username: post.username,
        title: post.title,
        content: post.content,
        likes: post.likes || 0,
        likedBy: post.liked_by || [],
        shares: post.shares || 0,
        createdAt: post.created_at,
        userAvatar: post.user_avatar,
        reportCount: post.report_count || 0,
        comments: (post.comments || []).map((c: any) => ({
          id: c.id,
          userId: c.user_id,
          username: c.username,
          content: c.content,
          createdAt: c.created_at,
          reportCount: c.report_count || 0
        }))
      }));
    } catch (err) {
      console.error("Fetch posts failed:", err);
      return [];
    }
  },

  async savePost(post: Post): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Your account is currently suspended.");
    if (!isConfigured) return;
    await supabase.from('posts').insert([{
      id: post.id,
      user_id: post.userId,
      username: post.username,
      title: post.title,
      content: post.content,
      likes: post.likes,
      liked_by: post.likedBy,
      shares: post.shares,
      user_avatar: post.userAvatar,
      created_at: post.createdAt,
      report_count: 0
    }]);
  },

  async updatePost(updatedPost: Post): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Your account is currently suspended.");
    if (!isConfigured) return;
    await supabase.from('posts').update({
      likes: updatedPost.likes,
      liked_by: updatedPost.likedBy,
      shares: updatedPost.shares,
      title: updatedPost.title,
      content: updatedPost.content
    }).eq('id', updatedPost.id);
  },

  async deletePost(postId: string): Promise<{ success: boolean; error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not configured.' };
    try {
      await supabase.from('comments').delete().eq('post_id', postId);
      await supabase.from('posts').delete().eq('id', postId);
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async addComment(postId: string, comment: Comment): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Your account is currently suspended.");
    if (!isConfigured) return;
    await supabase.from('comments').insert([{
      id: comment.id,
      post_id: postId,
      user_id: comment.userId,
      username: comment.username,
      content: comment.content,
      created_at: comment.createdAt,
      report_count: 0
    }]);
  },

  async getUserById(userId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data, error } = await supabase.from('users').select('*').eq('id', userId).maybeSingle();
      if (error || !data) return null;

      const stats = await this.getFollowStats(data.id);
      return {
        id: data.id,
        username: data.username,
        email: data.email,
        avatar: data.avatar,
        bio: data.bio || '',
        bookmarks: data.bookmarks || [],
        totalLikes: data.total_likes || 0,
        badge: (data.badge as BadgeTier) || BadgeTier.NOVICE,
        followerCount: stats.followers,
        followingCount: stats.following,
        reportCount: data.report_count || 0,
        bannedUntil: data.banned_until
      };
    } catch (err) {
      console.error("Get user failed:", err);
      return null;
    }
  },

  async refreshUser(userId: string): Promise<User | null> {
    if (!userId) return null;
    const user = await this.getUserById(userId);
    if (user) {
      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
    return user;
  },

  async toggleBookmark(userId: string, postId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data: user } = await supabase.from('users').select('bookmarks').eq('id', userId).maybeSingle();
      if (!user) return null;

      let bookmarks = Array.isArray(user.bookmarks) ? user.bookmarks : [];
      const newBookmarks = bookmarks.includes(postId)
        ? bookmarks.filter((id: string) => id !== postId)
        : [...bookmarks, postId];

      await supabase.from('users').update({ bookmarks: newBookmarks }).eq('id', userId);
      return await this.refreshUser(userId);
    } catch (err) {
      console.error("Bookmark Toggle Error:", err);
      return null;
    }
  },

  async updateUserLikes(userId: string, delta: number): Promise<void> {
    if (!isConfigured) return;
    const { data: dbUser } = await supabase.from('users').select('total_likes').eq('id', userId).maybeSingle();
    if (!dbUser) return;
    const newTotalLikes = (dbUser.total_likes || 0) + delta;
    const newBadge = getBadge(newTotalLikes);
    await supabase.from('users').update({ total_likes: newTotalLikes, badge: newBadge }).eq('id', userId);
  },

  async updateUserBio(userId: string, bio: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { error } = await supabase.from('users').update({ bio }).eq('id', userId);
      if (error) throw error;
      return await this.refreshUser(userId);
    } catch (err) {
      console.error("Update bio failed:", err);
      return await this.refreshUser(userId);
    }
  },

  getCurrentUser(): User | null {
    try {
      const session = localStorage.getItem(SESSION_KEY);
      return session ? JSON.parse(session) : null;
    } catch {
      return null;
    }
  },

  async register(username: string, email: string, password: string): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };

    try {
      const userId = Math.random().toString(36).substr(2, 9);
      const userPayload = {
        id: userId,
        username,
        email,
        password: password,
        avatar: `https://picsum.photos/seed/${username}/100`,
        bookmarks: [],
        total_likes: 0,
        badge: BadgeTier.NOVICE,
        report_count: 0
      };

      const { error } = await supabase.from('users').insert([userPayload]);

      if (error) {
        if (error.code === '23505') return { success: false, error: 'Username or Email already exists.' };
        return { success: false, error: error.message };
      }

      const user: User = {
        id: userId,
        username,
        email,
        avatar: userPayload.avatar,
        bookmarks: [],
        totalLikes: 0,
        badge: BadgeTier.NOVICE,
        followerCount: 0,
        followingCount: 0,
        reportCount: 0
      };

      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return { success: true, user };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async login(identifier: string, password: string, method: 'username' | 'email'): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };
    const field = method === 'username' ? 'username' : 'email';
    try {
      const { data, error } = await supabase.from('users').select('*').ilike(field, identifier).eq('password', password).maybeSingle();
      if (error) return { success: false, error: error.message };
      if (!data) return { success: false, error: 'Invalid credentials.' };

      const user = await this.refreshUser(data.id);
      return user ? { success: true, user } : { success: false, error: 'Session failed to load.' };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async getFollowStats(userId: string): Promise<{ followers: number, following: number }> {
    if (!isConfigured) return { followers: 0, following: 0 };
    try {
      const { count: followers } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('following_id', userId);
      const { count: following } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('follower_id', userId);
      return { followers: followers || 0, following: following || 0 };
    } catch {
      return { followers: 0, following: 0 };
    }
  },

  async isFollowing(followerId: string, followingId: string): Promise<boolean> {
    if (!isConfigured) return false;
    try {
      const { data } = await supabase.from('follows').select('*').eq('follower_id', followerId).eq('following_id', followingId).maybeSingle();
      return !!data;
    } catch {
      return false;
    }
  },

  async followUser(followerId: string, followingId: string): Promise<User | null> {
    if (!isConfigured || followerId === followingId) return null;
    try {
      await supabase.from('follows').insert([{ follower_id: followerId, following_id: followingId }]);
      return await this.refreshUser(followerId);
    } catch {
      return null;
    }
  },

  async unfollowUser(followerId: string, followingId: string): Promise<User | null> {
    if (!isConfigured) return null;
    try {
      await supabase.from('follows').delete().eq('follower_id', followerId).eq('following_id', followingId);
      return await this.refreshUser(followerId);
    } catch {
      return null;
    }
  },

  async deleteAccount(userId: string): Promise<{ success: boolean, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not configured.' };
    try {
      await supabase.from('follows').delete().or(`follower_id.eq.${userId},following_id.eq.${userId}`);
      await supabase.from('comments').delete().eq('user_id', userId);
      await supabase.from('posts').delete().eq('user_id', userId);
      await supabase.from('users').delete().eq('id', userId);
      this.logout();
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  logout() {
    localStorage.removeItem(SESSION_KEY);
  }
};

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Post, User, BadgeTier } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';
import { ReportModal } from './ReportModal';

interface PostCardProps {
  post: Post;
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (post: Post) => void;
  onPostDeleted: () => void;
  onFollowToggle?: (updatedUser: User) => void;
  onUserClick?: (userId: string) => void;
  onBookmarkToggle?: (updatedUser: User) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  isDarkMode, 
  onPostUpdate, 
  onPostDeleted,
  onFollowToggle,
  onUserClick,
  onBookmarkToggle
}) => {
  const [commentText, setCommentText] = useState('');
  const [showComments, setShowComments] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [isAnimatingLike, setIsAnimatingLike] = useState(false);
  const [showMenu, setShowMenu] = useState(false);
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);
  const [authorBadge, setAuthorBadge] = useState<BadgeTier>(BadgeTier.NOVICE);
  const [isFollowing, setIsFollowing] = useState(false);
  const [isFollowLoading, setIsFollowLoading] = useState(false);
  const [isBookmarkLoading, setIsBookmarkLoading] = useState(false);

  // Local reporting state tracking
  const [hasReportedPost, setHasReportedPost] = useState(false);
  const [reportedCommentIds, setReportedCommentIds] = useState<Set<string>>(new Set());

  const [reportTarget, setReportTarget] = useState<{type: 'post' | 'comment', id: string} | null>(null);

  const isOwner = currentUser?.id === post.userId;
  const isBanned = db.isBanned(currentUser);

  const isActuallyBookmarked = useMemo(() => currentUser?.bookmarks?.includes(post.id) || false, [currentUser, post.id]);
  const [isOptimisticBookmarked, setIsOptimisticBookmarked] = useState(false);

  useEffect(() => {
    setIsOptimisticBookmarked(isActuallyBookmarked);
  }, [isActuallyBookmarked]);

  const CONTENT_THRESHOLD = 250;
  const isLongContent = post.content.length > CONTENT_THRESHOLD;

  useEffect(() => {
    let isMounted = true;
    const fetchData = async () => {
      const author = await db.getUserById(post.userId);
      if (isMounted && author) {
        setAuthorBadge(author.badge);
      }

      if (isMounted && currentUser) {
        if (!isOwner) {
          const following = await db.isFollowing(currentUser.id, post.userId);
          setIsFollowing(following);
        }

        // Check if current user has already reported this post
        const alreadyReported = await db.hasAlreadyReported(currentUser.id, 'post', post.id);
        if (isMounted) setHasReportedPost(alreadyReported);

        // Check comments reporting status
        const commReports = new Set<string>();
        for (const comment of post.comments) {
          const isCommReported = await db.hasAlreadyReported(currentUser.id, 'comment', comment.id);
          if (isCommReported) commReports.add(comment.id);
        }
        if (isMounted) setReportedCommentIds(commReports);
      }
    };
    fetchData();
    return () => { isMounted = false; };
  }, [post.userId, currentUser, isOwner, post.id, post.comments]);

  const isLiked = useMemo(() => {
    return currentUser ? post.likedBy?.includes(currentUser.id) : false;
  }, [post.likedBy, currentUser]);

  const handleFollow = async () => {
    if (!currentUser) return alert('Login to follow authors');
    if (isFollowLoading) return;

    setIsFollowLoading(true);
    try {
      let updatedUser: User | null = null;
      if (isFollowing) {
        updatedUser = await db.unfollowUser(currentUser.id, post.userId);
        setIsFollowing(false);
      } else {
        updatedUser = await db.followUser(currentUser.id, post.userId);
        setIsFollowing(true);
      }
      if (updatedUser && onFollowToggle) {
        onFollowToggle(updatedUser);
      }
    } catch (err) {
      console.error("Follow action failed:", err);
    } finally {
      setIsFollowLoading(false);
    }
  };

  const handleBookmark = async () => {
    if (!currentUser) return alert('Login to save stories');
    if (isBookmarkLoading) return;
    const previousState = isOptimisticBookmarked;
    setIsOptimisticBookmarked(!previousState);
    setIsBookmarkLoading(true);
    try {
      const updatedUser = await db.toggleBookmark(currentUser.id, post.id);
      if (updatedUser && onBookmarkToggle) {
        onBookmarkToggle(updatedUser);
      } else {
        setIsOptimisticBookmarked(previousState);
      }
    } catch (err) {
      setIsOptimisticBookmarked(previousState);
    } finally {
      setIsBookmarkLoading(false);
    }
  };

  const handleLike = useCallback(async () => {
    if (!currentUser) return alert('Please login to like');
    if (isBanned) return alert('You are currently suspended from performing this action.');

    const hasLiked = post.likedBy?.includes(currentUser.id);
    const likeDelta = hasLiked ? -1 : 1;
    const newLikedBy = hasLiked 
      ? (post.likedBy || []).filter(id => id !== currentUser.id)
      : [...(post.likedBy || []), currentUser.id];

    if (!hasLiked) {
      setIsAnimatingLike(true);
      setTimeout(() => setIsAnimatingLike(false), 400);
    }

    const updatedPost: Post = { ...post, likes: Math.max(0, post.likes + likeDelta), likedBy: newLikedBy };
    await db.updatePost(updatedPost);
    await db.updateUserLikes(post.userId, likeDelta);
    onPostUpdate(updatedPost);
  }, [post, currentUser, onPostUpdate, isBanned]);

  const handleDeletePost = async () => {
    const result = await db.deletePost(post.id);
    if (result.success) onPostDeleted();
  };

  const handleAddComment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser || !commentText.trim()) return;
    if (isBanned) return alert('You are currently suspended from commenting.');

    const newComment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      content: commentText,
      createdAt: new Date().toISOString()
    };
    await db.addComment(post.id, newComment);
    onPostUpdate({ ...post, comments: [...post.comments, newComment] });
    setCommentText('');
  };

  const handleReport = async (reason: string) => {
    if (!currentUser || !reportTarget) return;

    const result = await db.reportEntity(currentUser.id, reportTarget.type, reportTarget.id, reason);
    if (result.success) {
      if (reportTarget.type === 'post') setHasReportedPost(true);
      else setReportedCommentIds(prev => new Set([...Array.from(prev), reportTarget.id]));
    }
    setReportTarget(null);
    alert(result.message);
  };

  const handleProfileClick = () => {
    if (onUserClick) onUserClick(post.userId);
  };

  return (
    <div className={`rounded-xl md:rounded-2xl shadow-sm border transition-all overflow-hidden h-fit flex flex-col hover:shadow-md ${
      isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-100'
    }`}>
      <div className="p-4 md:p-6 flex-1">
        <div className="flex items-start justify-between mb-4 md:mb-6">
          <div className="flex items-center gap-3">
            <img 
              src={post.userAvatar} 
              className="w-10 h-10 md:w-11 md:h-11 rounded-xl bg-slate-200 object-cover cursor-pointer hover:opacity-80 transition-opacity" 
              alt={post.username} 
              onClick={handleProfileClick}
            />
            <div>
              <div className="flex items-center gap-1.5 md:gap-2 mb-0.5">
                <span 
                  className="font-bold text-xs md:text-sm truncate max-w-[100px] md:max-w-none cursor-pointer hover:underline"
                  onClick={handleProfileClick}
                >
                  @{post.username}
                </span>
                <BadgeIcon tier={authorBadge} />
              </div>
              <div className="flex items-center gap-2">
                <span className="text-[9px] md:text-[10px] text-slate-500 uppercase font-black tracking-widest opacity-80">
                  {new Date(post.createdAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
                </span>
                {!isOwner && currentUser && (
                  <>
                    <span className="text-slate-300">•</span>
                    <button 
                      onClick={handleFollow}
                      disabled={isFollowLoading}
                      className={`text-[10px] font-black uppercase tracking-widest transition-all ${
                        isFollowLoading ? 'opacity-50 cursor-not-allowed' : ''
                      } ${
                        isFollowing ? 'text-slate-400' : 'text-indigo-600 hover:text-indigo-400'
                      }`}
                    >
                      {isFollowing ? 'Following' : 'Follow'}
                    </button>
                  </>
                )}
              </div>
            </div>
          </div>

          <div className="relative">
            <button onClick={() => setShowMenu(!showMenu)} className="text-slate-400 p-1.5 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z"/></svg>
            </button>
            {showMenu && (
              <div className={`absolute right-0 top-10 w-48 rounded-xl shadow-xl border z-20 ${isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-white border-slate-100'}`}>
                {isOwner ? (
                  <button onClick={() => { setShowConfirmDelete(true); setShowMenu(false); }} className="w-full text-left px-4 py-3 text-xs font-bold text-red-500 hover:bg-red-500/10 rounded-xl transition-colors flex items-center gap-2">
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                    Remove Story
                  </button>
                ) : (
                  <>
                    <button onClick={handleProfileClick} className="w-full text-left px-4 py-3 text-xs font-bold text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-xl transition-colors">
                      View Profile
                    </button>
                    {currentUser && (
                      <button 
                        disabled={hasReportedPost}
                        onClick={() => { setReportTarget({type: 'post', id: post.id}); setShowMenu(false); }} 
                        className={`w-full text-left px-4 py-3 text-xs font-bold rounded-xl transition-colors ${hasReportedPost ? 'text-slate-400 opacity-50 cursor-not-allowed' : 'text-red-400 hover:bg-red-500/10'}`}
                      >
                        {hasReportedPost ? 'Already Reported' : 'Report Story'}
                      </button>
                    )}
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        {showConfirmDelete && (
          <div className={`mb-4 p-4 rounded-xl border ${isDarkMode ? 'bg-red-500/10 border-red-500/20' : 'bg-red-50 border-red-100'}`}>
            <p className="text-[11px] font-bold mb-3 text-red-600">Delete this story permanently?</p>
            <div className="flex gap-2">
              <button onClick={handleDeletePost} className="px-3 py-1.5 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest">Confirm</button>
              <button onClick={() => setShowConfirmDelete(false)} className="px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest border border-slate-200 bg-white">Cancel</button>
            </div>
          </div>
        )}

        <h3 className={`font-serif text-xl md:text-2xl font-bold mb-3 md:mb-4 leading-snug ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>{post.title}</h3>
        <p className={`text-sm md:text-base leading-relaxed whitespace-pre-wrap mb-4 font-light ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
          {isExpanded || !isLongContent ? post.content : `${post.content.substring(0, CONTENT_THRESHOLD)}...`}
        </p>
        {isLongContent && (
          <button onClick={() => setIsExpanded(!isExpanded)} className={`text-[10px] font-black uppercase tracking-widest ${isDarkMode ? 'text-indigo-400' : 'text-indigo-600'} mb-4 md:mb-6`}>
            {isExpanded ? 'Collapse ↑' : 'Read Full Journey ↓'}
          </button>
        )}

        <div className={`flex items-center justify-between pt-4 md:pt-5 border-t ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}`}>
          <div className="flex items-center gap-4 md:gap-6">
            <button 
              onClick={handleLike} 
              disabled={isBanned}
              className={`group flex items-center gap-2 text-xs md:text-sm font-bold transition-all p-1 ${isLiked || isAnimatingLike ? 'text-red-500 scale-105' : 'text-slate-400'} ${isBanned ? 'opacity-30 cursor-not-allowed' : ''}`}
            >
              <svg className={`w-5 h-5 md:w-6 md:h-6 transition-all ${isLiked || isAnimatingLike ? 'fill-red-500 stroke-red-500' : 'fill-none stroke-current'}`} viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/>
              </svg>
              <span className="tabular-nums">{post.likes}</span>
            </button>
            <button onClick={() => setShowComments(!showComments)} className="flex items-center gap-2 text-xs md:text-sm font-bold text-slate-400 p-1">
              <svg className="w-5 h-5 md:w-6 md:h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
              <span className="tabular-nums">{post.comments.length}</span>
            </button>
          </div>

          <button 
            onClick={handleBookmark} 
            disabled={isBookmarkLoading}
            className={`p-1 transition-all ${isBookmarkLoading ? 'opacity-80' : 'active:scale-125'} ${isOptimisticBookmarked ? 'text-indigo-600' : 'text-slate-400 hover:text-indigo-400'}`}
            title={isOptimisticBookmarked ? "Remove from saved" : "Save story"}
          >
            <svg className={`w-5 h-5 md:w-6 md:h-6 ${isOptimisticBookmarked ? 'fill-current' : 'fill-none stroke-current'}`} viewBox="0 0 24 24" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" />
            </svg>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-4 md:p-6 border-t ${isDarkMode ? 'bg-slate-900/50 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
          <div className="space-y-4 mb-4">
            {post.comments.length === 0 ? (<p className="text-[10px] text-center text-slate-500 italic py-2">No resonance found yet.</p>) : (
              post.comments.map(c => {
                const isReported = reportedCommentIds.has(c.id);
                return (
                  <div key={c.id} className="group flex gap-3 text-left">
                    <div className="w-7 h-7 rounded-lg bg-indigo-500 flex items-center justify-center text-white font-black text-[9px] shrink-0 uppercase">{c.username[0]}</div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-0.5">
                        <span className="font-bold text-[11px] truncate">@{c.username}</span>
                        <div className="flex items-center gap-2">
                          <span className="text-[8px] text-slate-500 uppercase font-bold">{new Date(c.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                          {currentUser && c.userId !== currentUser.id && (
                            <button 
                              disabled={isReported}
                              onClick={() => setReportTarget({type: 'comment', id: c.id})}
                              className={`text-[8px] font-black uppercase tracking-widest transition-all ${isReported ? 'text-slate-400 opacity-50 cursor-not-allowed' : 'opacity-0 group-hover:opacity-100 text-red-400 hover:text-red-500'}`}
                            >
                              {isReported ? 'Reported' : 'Report'}
                            </button>
                          )}
                        </div>
                      </div>
                      <p className={`text-xs ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}>{c.content}</p>
                    </div>
                  </div>
                );
              })
            )}
          </div>
          <form onSubmit={handleAddComment} className="flex gap-2">
            <input 
              type="text" 
              placeholder={isBanned ? "Commenting suspended..." : "Your reply..."}
              disabled={isBanned}
              value={commentText} 
              onChange={(e) => setCommentText(e.target.value)} 
              className={`flex-1 px-4 py-2 rounded-xl text-xs outline-none transition-all ${isDarkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-white border-slate-200'} ${isBanned ? 'opacity-50' : ''}`} 
            />
            <button 
              type="submit" 
              disabled={!commentText.trim() || isBanned} 
              className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-xs font-bold transition-all shadow-md disabled:opacity-50"
            >
              Reply
            </button>
          </form>
        </div>
      )}

      {reportTarget && (
        <ReportModal 
          targetType={reportTarget.type} 
          targetId={reportTarget.id} 
          onClose={() => setReportTarget(null)} 
          onSubmit={handleReport} 
          isDarkMode={isDarkMode} 
        />
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { User, Post } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';
import { ReportModal } from './ReportModal';

interface ProfileProps {
  user: User;
  currentUser: User | null;
  posts: Post[];
  isDarkMode: boolean;
  onAccountDeleted: () => void;
  onLogout: () => void;
  onUserUpdate: (updatedUser: User) => void;
}

export const Profile: React.FC<ProfileProps> = ({ 
  user, 
  currentUser, 
  posts, 
  isDarkMode, 
  onAccountDeleted, 
  onLogout,
  onUserUpdate
}) => {
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [deleteError, setDeleteError] = useState('');
  const [isEditingBio, setIsEditingBio] = useState(false);
  const [bioText, setBioText] = useState(user.bio || '');
  const [isSavingBio, setIsSavingBio] = useState(false);
  const [showReportModal, setShowReportModal] = useState(false);
  const [hasReportedUser, setHasReportedUser] = useState(false);

  const isOwnProfile = currentUser?.id === user.id;
  const isBanned = db.isBanned(user);
  const userPosts = posts.filter(p => p.userId === user.id);
  const totalReceivedLikes = userPosts.reduce((acc, post) => acc + post.likes, 0);

  useEffect(() => {
    setBioText(user.bio || '');

    // Check report status for the viewed user
    const checkReportStatus = async () => {
      if (currentUser && !isOwnProfile) {
        const reported = await db.hasAlreadyReported(currentUser.id, 'user', user.id);
        setHasReportedUser(reported);
      }
    };
    checkReportStatus();
  }, [user.bio, currentUser, isOwnProfile, user.id]);

  const handleDeleteAccount = async () => {
    setIsDeleting(true);
    setDeleteError('');
    try {
      const result = await db.deleteAccount(user.id);
      if (result.success) onAccountDeleted(); else {
        setDeleteError(result.error || 'Failed to delete account');
        setIsDeleting(false);
      }
    } catch (err) {
      setDeleteError('An unexpected error occurred');
      setIsDeleting(false);
    }
  };

  const handleSaveBio = async () => {
    setIsSavingBio(true);
    const updated = await db.updateUserBio(user.id, bioText);
    if (updated) {
      onUserUpdate(updated);
      setIsEditingBio(false);
    }
    setIsSavingBio(false);
  };

  const handleReportUser = async (reason: string) => {
    if (!currentUser) return;
    const result = await db.reportEntity(currentUser.id, 'user', user.id, reason);
    if (result.success) setHasReportedUser(true);
    setShowReportModal(false);
    alert(result.message);
  };

  return (
    <div className="max-w-3xl mx-auto py-4 md:py-8">
      {isBanned && (
        <div className="mb-6 p-4 rounded-2xl bg-red-600 text-white font-bold flex items-center justify-between shadow-lg animate-in slide-in-from-top">
          <div className="flex items-center gap-3">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
            <div>
              <p className="text-sm">Account Suspended</p>
              <p className="text-[10px] opacity-80 uppercase tracking-widest font-black">Suspension ends: {new Date(user.bannedUntil!).toLocaleString()}</p>
            </div>
          </div>
        </div>
      )}

      <div className={`p-6 md:p-8 rounded-2xl md:rounded-3xl border transition-all relative ${
        isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-xl'
      }`}>
        <div className="absolute top-4 right-4 md:top-6 md:right-6 flex gap-4">
          {!isOwnProfile && currentUser && (
            <button 
              disabled={hasReportedUser}
              onClick={() => setShowReportModal(true)}
              className={`text-[10px] font-black uppercase tracking-[0.2em] transition-colors flex items-center gap-2 ${hasReportedUser ? 'text-slate-400 opacity-50 cursor-not-allowed' : 'text-red-400 hover:text-red-500'}`}
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 21v-4m0 0V5a2 2 0 012-2h6.5l1 1H21l-3 6 3 6h-8.5l-1-1H5a2 2 0 00-2 2zm9-13.5V9" /></svg>
              {hasReportedUser ? 'Reported' : 'Report'}
            </button>
          )}
          {isOwnProfile && (
            <button 
              onClick={onLogout}
              className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 hover:text-indigo-500 transition-colors flex items-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
              Logout
            </button>
          )}
        </div>

        <div className="flex flex-col md:flex-row items-center gap-6 md:gap-8 mb-8 md:mb-10">
          <div className="relative">
            <img src={user.avatar} alt={user.username} className={`w-24 h-24 md:w-32 md:h-32 rounded-2xl md:rounded-3xl object-cover shadow-2xl ring-4 ${isBanned ? 'ring-red-500/50 grayscale' : 'ring-indigo-500/20'}`} />
            {isBanned && <div className="absolute inset-0 flex items-center justify-center bg-red-600/20 rounded-2xl md:rounded-3xl"><svg className="w-8 h-8 text-white" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M13.477 14.89A6 6 0 015.11 6.524l8.367 8.368zm1.414-1.414L6.524 5.11a6 6 0 018.367 8.367zM18 10a8 8 0 11-16 0 8 8 0 0116 0z" clipRule="evenodd" /></svg></div>}
          </div>
          <div className="text-center md:text-left w-full">
            <h1 className="text-2xl md:text-3xl font-serif font-bold mb-2 truncate">@{user.username}</h1>
            <div className="flex flex-wrap justify-center md:justify-start gap-2 md:gap-3 mb-4">
              <BadgeIcon tier={user.badge} size="md" />
              {user.reportCount! > 0 && (
                <span className="text-[10px] font-black uppercase tracking-widest text-red-500 py-1 px-3 bg-red-500/10 rounded-full">
                  Reports: {user.reportCount}
                </span>
              )}
            </div>

            <div className="mt-4 max-w-lg mx-auto md:mx-0">
              {isEditingBio ? (
                <div className="space-y-3">
                  <textarea
                    value={bioText}
                    onChange={(e) => setBioText(e.target.value)}
                    placeholder="Tell your story in a few words..."
                    rows={3}
                    className={`w-full p-3 text-sm rounded-xl border outline-none resize-none transition-all ${
                      isDarkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-slate-50 border-slate-200'
                    }`}
                  />
                  <div className="flex justify-center md:justify-start gap-2">
                    <button 
                      onClick={handleSaveBio}
                      disabled={isSavingBio}
                      className="px-4 py-1.5 bg-indigo-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest"
                    >
                      {isSavingBio ? 'Saving...' : 'Save Bio'}
                    </button>
                    <button 
                      onClick={() => { setIsEditingBio(false); setBioText(user.bio || ''); }}
                      className="px-4 py-1.5 border border-slate-200 rounded-lg text-[10px] font-black uppercase tracking-widest dark:bg-slate-800"
                    >
                      Cancel
                    </button>
                  </div>
                </div>
              ) : (
                <div className="group relative">
                  <p className={`text-sm leading-relaxed ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
                    {user.bio || (isOwnProfile ? "No bio yet. Add one to describe your creative journey!" : "")}
                  </p>
                  {isOwnProfile && (
                    <button 
                      onClick={() => setIsEditingBio(true)}
                      className="mt-2 text-[10px] font-black uppercase tracking-widest text-indigo-500 hover:text-indigo-400 transition-colors inline-flex items-center gap-1.5"
                    >
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                      {user.bio ? 'Edit Bio' : 'Add Bio'}
                    </button>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="grid grid-cols-5 gap-1 md:gap-4 py-6 border-y border-slate-100 dark:border-slate-800">
          <div className="text-center">
            <p className="text-lg md:text-xl font-bold">{userPosts.length}</p>
            <p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Stories</p>
          </div>
          <div className="text-center border-l border-slate-100 dark:border-slate-800">
            <p className="text-lg md:text-xl font-bold">{totalReceivedLikes}</p>
            <p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Likes</p>
          </div>
          <div className="text-center border-l border-slate-100 dark:border-slate-800">
            <p className="text-lg md:text-xl font-bold">{user.followingCount}</p>
            <p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Following</p>
          </div>
          <div className="text-center border-l border-slate-100 dark:border-slate-800">
            <p className="text-lg md:text-xl font-bold">{user.followerCount}</p>
            <p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Followers</p>
          </div>
          <div className="text-center border-l border-slate-100 dark:border-slate-800">
            <p className="text-lg md:text-xl font-bold">{userPosts.reduce((acc, p) => acc + p.comments.length, 0)}</p>
            <p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Notes</p>
          </div>
        </div>

        {isOwnProfile && (
          <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800">
            {!showConfirmDelete ? (
              <button onClick={() => setShowConfirmDelete(true)} className="text-[10px] font-bold text-slate-400 hover:text-red-500 transition-colors uppercase tracking-widest flex items-center gap-2">
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                Delete Account
              </button>
            ) : (
              <div className="p-4 rounded-xl border bg-red-50 dark:bg-red-900/20 border-red-100 dark:border-red-900/40">
                <p className="text-xs font-bold text-red-600 mb-4">Confirm permanent account deletion?</p>
                <div className="flex gap-3">
                  <button onClick={handleDeleteAccount} className="px-4 py-2 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest shadow-lg">Yes, Delete</button>
                  <button onClick={() => setShowConfirmDelete(false)} className="px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest border border-slate-200 bg-white">Cancel</button>
                </div>
              </div>
            )}
          </div>
        )}
      </div>

      {showReportModal && (
        <ReportModal 
          targetType="user" 
          targetId={user.id} 
          onClose={() => setShowReportModal(false)} 
          onSubmit={handleReportUser} 
          isDarkMode={isDarkMode} 
        />
      )}
    </div>
  );
};

import { createClient } from '@supabase/supabase-js';
import { Post, User, BadgeTier, Comment, ReportType } from '../types';

const SUPABASE_URL = (process.env as any).SUPABASE_URL || 'https://uvjavqzhhqxkfuklkxdo.supabase.co';
const SUPABASE_ANON_KEY = (process.env as any).SUPABASE_ANON_KEY || 'sb_publishable_-GDZiq_v45oEVhlly7tG-w_cKockqn6';

const isConfigured = SUPABASE_URL !== 'https://your-project-url.supabase.co' && SUPABASE_ANON_KEY !== 'your-anon-key';
const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);
const SESSION_KEY = 'storyverse_session';

export const getBadge = (likes: number): BadgeTier => {
  if (likes >= 500) return BadgeTier.PLATINUM;
  if (likes >= 100) return BadgeTier.GOLD;
  if (likes >= 25) return BadgeTier.SILVER;
  if (likes >= 5) return BadgeTier.BRONZE;
  return BadgeTier.NOVICE;
};

const BAN_THRESHOLD = 100;
const BAN_DURATION_DAYS = 3;

export const db = {
  isBanned(user: User | null): boolean {
    if (!user || !user.bannedUntil) return false;
    return new Date(user.bannedUntil) > new Date();
  },

  async hasAlreadyReported(reporterId: string, targetType: ReportType, targetId: string): Promise<boolean> {
    if (!isConfigured || !reporterId) return false;
    try {
      const { data, error } = await supabase
        .from('reports')
        .select('id')
        .eq('reporter_id', reporterId)
        .eq('target_type', targetType)
        .eq('target_id', targetId)
        .maybeSingle();

      return !!data && !error;
    } catch {
      return false;
    }
  },

  async reportEntity(reporterId: string, targetType: ReportType, targetId: string, reason: string): Promise<{ success: boolean; message: string }> {
    if (!isConfigured) return { success: false, message: 'Backend not configured.' };

    try {
      const alreadyReported = await this.hasAlreadyReported(reporterId, targetType, targetId);
      if (alreadyReported) {
        return { success: false, message: 'You have already reported this item.' };
      }

      let table = targetType === 'user' ? 'users' : (targetType === 'post' ? 'posts' : 'comments');
      const { data: entityData } = await supabase.from(table).select(targetType === 'user' ? 'id' : 'user_id').eq('id', targetId).maybeSingle();
      const ownerId = targetType === 'user' ? entityData?.id : entityData?.user_id;

      if (ownerId === reporterId) {
        return { success: false, message: 'You cannot report your own content.' };
      }

      const { error: insertError } = await supabase.from('reports').insert([{
        id: Math.random().toString(36).substr(2, 9),
        reporter_id: reporterId,
        target_type: targetType,
        target_id: targetId,
        reason
      }]);

      if (insertError) {
        if (insertError.code === '23505') return { success: false, message: 'You have already reported this item.' };
        throw insertError;
      }

      const { data: currentCountData } = await supabase.from(table).select('report_count').eq('id', targetId).maybeSingle();
      const newCount = (currentCountData?.report_count || 0) + 1;

      let updatePayload: any = { report_count: newCount };

      if (targetType === 'user' && newCount >= BAN_THRESHOLD) {
        const bannedUntil = new Date();
        bannedUntil.setDate(bannedUntil.getDate() + BAN_DURATION_DAYS);
        updatePayload.banned_until = bannedUntil.toISOString();
      }

      await supabase.from(table).update(updatePayload).eq('id', targetId);

      if (targetType !== 'user' && ownerId) {
        const ownerReported = await this.hasAlreadyReported(reporterId, 'user', ownerId);
        if (!ownerReported) {
          this.reportEntity(reporterId, 'user', ownerId, `Linked report from ${targetType} violation.`);
        }
      }

      return { success: true, message: 'Thank you. Report submitted successfully.' };
    } catch (err) {
      console.error("Report failed:", err);
      return { success: false, message: 'Submission failed. Please try again.' };
    }
  },

  async getPosts(): Promise<Post[]> {
    if (!isConfigured) return [];
    try {
      const { data, error } = await supabase
        .from('posts')
        .select(`*, comments (*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      return (data || []).map(post => ({
        id: post.id,
        userId: post.user_id,
        username: post.username,
        title: post.title,
        content: post.content,
        likes: post.likes || 0,
        likedBy: post.liked_by || [],
        shares: post.shares || 0,
        createdAt: post.created_at,
        userAvatar: post.user_avatar,
        reportCount: post.report_count || 0,
        comments: (post.comments || []).map((c: any) => ({
          id: c.id,
          userId: c.user_id,
          username: c.username,
          content: c.content,
          createdAt: c.created_at,
          reportCount: c.report_count || 0
        }))
      }));
    } catch (err) {
      console.error("Fetch posts failed:", err);
      return [];
    }
  },

  async savePost(post: Post): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Your account is currently suspended.");
    if (!isConfigured) return;
    await supabase.from('posts').insert([{
      id: post.id,
      user_id: post.userId,
      username: post.username,
      title: post.title,
      content: post.content,
      likes: post.likes,
      liked_by: post.likedBy,
      shares: post.shares,
      user_avatar: post.userAvatar,
      created_at: post.createdAt,
      report_count: 0
    }]);
  },

  async updatePost(updatedPost: Post): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Your account is currently suspended.");
    if (!isConfigured) return;
    await supabase.from('posts').update({
      likes: updatedPost.likes,
      liked_by: updatedPost.likedBy,
      shares: updatedPost.shares,
      title: updatedPost.title,
      content: updatedPost.content
    }).eq('id', updatedPost.id);
  },

  async updatePostContent(postId: string, title: string, content: string): Promise<boolean> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Your account is currently suspended.");
    if (!isConfigured) return false;
    try {
      const { error } = await supabase.from('posts').update({
        title,
        content,
        last_edited_at: new Date().toISOString()
      }).eq('id', postId);
      return !error;
    } catch {
      return false;
    }
  },

  async updateUserAvatar(userId: string, avatarUrl: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      // 1. Update user table
      await supabase.from('users').update({ avatar: avatarUrl }).eq('id', userId);
      // 2. Update all posts by this user to reflect new avatar
      await supabase.from('posts').update({ user_avatar: avatarUrl }).eq('user_id', userId);
      return await this.refreshUser(userId);
    } catch {
      return null;
    }
  },

  async updateUserSettings(userId: string, settings: any): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      await supabase.from('users').update({ settings }).eq('id', userId);
      return await this.refreshUser(userId);
    } catch {
      return null;
    }
  },

  async deletePost(postId: string): Promise<{ success: boolean; error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not configured.' };
    try {
      await supabase.from('comments').delete().eq('post_id', postId);
      await supabase.from('posts').delete().eq('id', postId);
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async addComment(postId: string, comment: Comment): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Your account is currently suspended.");
    if (!isConfigured) return;
    await supabase.from('comments').insert([{
      id: comment.id,
      post_id: postId,
      user_id: comment.userId,
      username: comment.username,
      content: comment.content,
      created_at: comment.createdAt,
      report_count: 0
    }]);
  },

  async getUserById(userId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data, error } = await supabase.from('users').select('*').eq('id', userId).maybeSingle();
      if (error || !data) return null;

      const stats = await this.getFollowStats(data.id);
      return {
        id: data.id,
        username: data.username,
        email: data.email,
        avatar: data.avatar,
        bio: data.bio || '',
        bookmarks: data.bookmarks || [],
        totalLikes: data.total_likes || 0,
        badge: (data.badge as BadgeTier) || BadgeTier.NOVICE,
        followerCount: stats.followers,
        followingCount: stats.following,
        reportCount: data.report_count || 0,
        bannedUntil: data.banned_until,
        settings: data.settings || { showReportCount: true, showStats: true }
      };
    } catch (err) {
      console.error("Get user failed:", err);
      return null;
    }
  },

  async refreshUser(userId: string): Promise<User | null> {
    if (!userId) return null;
    const user = await this.getUserById(userId);
    if (user) {
      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    } else {
      localStorage.removeItem(SESSION_KEY);
    }
    return user;
  },

  async toggleBookmark(userId: string, postId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data: user } = await supabase.from('users').select('bookmarks').eq('id', userId).maybeSingle();
      if (!user) return null;

      let bookmarks = Array.isArray(user.bookmarks) ? user.bookmarks : [];
      const newBookmarks = bookmarks.includes(postId)
        ? bookmarks.filter((id: string) => id !== postId)
        : [...bookmarks, postId];

      await supabase.from('users').update({ bookmarks: newBookmarks }).eq('id', userId);
      return await this.refreshUser(userId);
    } catch (err) {
      console.error("Bookmark Toggle Error:", err);
      return null;
    }
  },

  async updateUserLikes(userId: string, delta: number): Promise<void> {
    if (!isConfigured) return;
    const { data: dbUser } = await supabase.from('users').select('total_likes').eq('id', userId).maybeSingle();
    if (!dbUser) return;
    const newTotalLikes = (dbUser.total_likes || 0) + delta;
    const newBadge = getBadge(newTotalLikes);
    await supabase.from('users').update({ total_likes: newTotalLikes, badge: newBadge }).eq('id', userId);
  },

  async updateUserBio(userId: string, bio: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { error } = await supabase.from('users').update({ bio }).eq('id', userId);
      if (error) throw error;
      return await this.refreshUser(userId);
    } catch (err) {
      console.error("Update bio failed:", err);
      return await this.refreshUser(userId);
    }
  },

  getCurrentUser(): User | null {
    try {
      const session = localStorage.getItem(SESSION_KEY);
      return session ? JSON.parse(session) : null;
    } catch {
      return null;
    }
  },

  async register(username: string, email: string, password: string): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };

    try {
      const userId = Math.random().toString(36).substr(2, 9);
      const userPayload = {
        id: userId,
        username,
        email,
        password: password,
        avatar: `https://picsum.photos/seed/${username}/100`,
        bookmarks: [],
        total_likes: 0,
        badge: BadgeTier.NOVICE,
        report_count: 0,
        settings: { showReportCount: true, showStats: true }
      };

      const { error } = await supabase.from('users').insert([userPayload]);

      if (error) {
        if (error.code === '23505') return { success: false, error: 'Username or Email already exists.' };
        return { success: false, error: error.message };
      }

      const user: User = {
        id: userId,
        username,
        email,
        avatar: userPayload.avatar,
        bookmarks: [],
        totalLikes: 0,
        badge: BadgeTier.NOVICE,
        followerCount: 0,
        followingCount: 0,
        reportCount: 0,
        settings: userPayload.settings
      };

      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return { success: true, user };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async login(identifier: string, password: string, method: 'username' | 'email'): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };
    const field = method === 'username' ? 'username' : 'email';
    try {
      const { data, error } = await supabase.from('users').select('*').ilike(field, identifier).eq('password', password).maybeSingle();
      if (error) return { success: false, error: error.message };
      if (!data) return { success: false, error: 'Invalid credentials.' };

      const user = await this.refreshUser(data.id);
      return user ? { success: true, user } : { success: false, error: 'Session failed to load.' };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async getFollowStats(userId: string): Promise<{ followers: number, following: number }> {
    if (!isConfigured) return { followers: 0, following: 0 };
    try {
      const { count: followers } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('following_id', userId);
      const { count: following } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('follower_id', userId);
      return { followers: followers || 0, following: following || 0 };
    } catch {
      return { followers: 0, following: 0 };
    }
  },

  async isFollowing(followerId: string, followingId: string): Promise<boolean> {
    if (!isConfigured) return false;
    try {
      const { data } = await supabase.from('follows').select('*').eq('follower_id', followerId).eq('following_id', followingId).maybeSingle();
      return !!data;
    } catch {
      return false;
    }
  },

  async followUser(followerId: string, followingId: string): Promise<User | null> {
    if (!isConfigured || followerId === followingId) return null;
    try {
      await supabase.from('follows').insert([{ follower_id: followerId, following_id: followingId }]);
      return await this.refreshUser(followerId);
    } catch {
      return null;
    }
  },

  async unfollowUser(followerId: string, followingId: string): Promise<User | null> {
    if (!isConfigured) return null;
    try {
      await supabase.from('follows').delete().eq('follower_id', followerId).eq('following_id', followingId);
      return await this.refreshUser(followerId);
    } catch {
      return null;
    }
  },

  async deleteAccount(userId: string): Promise<{ success: boolean, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not configured.' };
    try {
      await supabase.from('follows').delete().or(`follower_id.eq.${userId},following_id.eq.${userId}`);
      await supabase.from('reports').delete().or(`reporter_id.eq.${userId},target_id.eq.${userId}`);
      await supabase.from('comments').delete().eq('user_id', userId);
      await supabase.from('posts').delete().eq('user_id', userId);
      await supabase.from('users').delete().eq('id', userId);
      this.logout();
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  logout() {
    localStorage.removeItem(SESSION_KEY);
  }
};

import React, { useState } from 'react';
import { Post } from '../types';
import { aiService } from '../services/ai';
import { db } from '../services/db';

interface EditPostModalProps {
  post: Post;
  isDarkMode: boolean;
  onClose: () => void;
  onUpdate: (updatedPost: Post) => void;
}

export const EditPostModal: React.FC<EditPostModalProps> = ({ post, isDarkMode, onClose, onUpdate }) => {
  const [title, setTitle] = useState(post.title);
  const [content, setContent] = useState(post.content);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiStatus, setAiStatus] = useState('');
  const [isSaving, setIsSaving] = useState(false);

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim() || !content.trim()) return;

    setIsSaving(true);
    const success = await db.updatePostContent(post.id, title, content);
    if (success) {
      onUpdate({ ...post, title, content });
      onClose();
    } else {
      alert("Failed to save changes. Please try again.");
    }
    setIsSaving(false);
  };

  const handleFixGrammar = async () => {
    setIsAiLoading(true);
    setAiStatus('Refining...');
    const corrected = await aiService.fixGrammar(content);
    setContent(corrected);
    setIsAiLoading(false);
    setAiStatus('Polished!');
    setTimeout(() => setAiStatus(''), 2000);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 backdrop-blur-md bg-black/40 animate-in fade-in duration-200">
      <div className={`w-full max-w-2xl rounded-3xl shadow-2xl p-6 md:p-8 overflow-y-auto max-h-[90vh] ${isDarkMode ? 'bg-slate-900 border border-slate-800 text-white' : 'bg-white border border-slate-100 text-slate-900'}`}>
        <div className="flex items-center justify-between mb-8">
          <h2 className="font-serif text-2xl font-bold">Refine Your Story</h2>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
          </button>
        </div>

        <form onSubmit={handleSave} className="space-y-6">
          <div>
            <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 block mb-2">Title</label>
            <input 
              required
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className={`w-full p-4 rounded-xl border outline-none transition-all font-serif text-lg ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-200'}`}
            />
          </div>

          <div className="relative">
            <div className="flex items-center justify-between mb-2">
              <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Narrative</label>
              <div className="flex items-center gap-2">
                {aiStatus && <span className="text-[9px] font-black uppercase text-indigo-500 animate-pulse">{aiStatus}</span>}
                <button
                  type="button"
                  onClick={handleFixGrammar}
                  disabled={isAiLoading}
                  className="px-3 py-1 bg-indigo-500/10 text-indigo-500 rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-indigo-500/20 transition-all"
                >
                  {isAiLoading ? '...' : '✨ Polish'}
                </button>
              </div>
            </div>
            <textarea 
              required
              rows={10}
              value={content}
              onChange={(e) => setContent(e.target.value)}
              className={`w-full p-4 rounded-xl border outline-none transition-all resize-none text-sm md:text-base leading-relaxed ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-200'}`}
            />
          </div>

          <div className="flex gap-3 pt-4">
            <button 
              type="button"
              onClick={onClose}
              className="flex-1 py-4 text-xs font-black uppercase tracking-[0.2em] rounded-xl border border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-800"
            >
              Cancel
            </button>
            <button 
              type="submit"
              disabled={isSaving}
              className="flex-1 py-4 bg-indigo-600 text-white rounded-xl text-xs font-black uppercase tracking-[0.2em] shadow-xl active:scale-95 transition-all disabled:opacity-50"
            >
              {isSaving ? 'Saving Changes...' : 'Update Journey'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { Post, User, BadgeTier } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';
import { ReportModal } from './ReportModal';
import { EditPostModal } from './EditPostModal';

interface PostCardProps {
  post: Post;
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (post: Post) => void;
  onPostDeleted: () => void;
  onFollowToggle?: (updatedUser: User) => void;
  onUserClick?: (userId: string) => void;
  onBookmarkToggle?: (updatedUser: User) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  isDarkMode, 
  onPostUpdate, 
  onPostDeleted,
  onFollowToggle,
  onUserClick,
  onBookmarkToggle
}) => {
  const [commentText, setCommentText] = useState('');
  const [showComments, setShowComments] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [isAnimatingLike, setIsAnimatingLike] = useState(false);
  const [showMenu, setShowMenu] = useState(false);
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [authorBadge, setAuthorBadge] = useState<BadgeTier>(BadgeTier.NOVICE);
  const [isFollowing, setIsFollowing] = useState(false);
  const [isFollowLoading, setIsFollowLoading] = useState(false);
  const [isBookmarkLoading, setIsBookmarkLoading] = useState(false);

  const [hasReportedPost, setHasReportedPost] = useState(false);
  const [reportedCommentIds, setReportedCommentIds] = useState<Set<string>>(new Set());
  const [reportTarget, setReportTarget] = useState<{type: 'post' | 'comment', id: string} | null>(null);

  const isOwner = currentUser?.id === post.userId;
  const isBanned = db.isBanned(currentUser);

  const isActuallyBookmarked = useMemo(() => currentUser?.bookmarks?.includes(post.id) || false, [currentUser, post.id]);
  const [isOptimisticBookmarked, setIsOptimisticBookmarked] = useState(false);

  useEffect(() => {
    setIsOptimisticBookmarked(isActuallyBookmarked);
  }, [isActuallyBookmarked]);

  const CONTENT_THRESHOLD = 250;
  const isLongContent = post.content.length > CONTENT_THRESHOLD;

  useEffect(() => {
    let isMounted = true;
    const fetchData = async () => {
      const author = await db.getUserById(post.userId);
      if (isMounted && author) {
        setAuthorBadge(author.badge);
      }

      if (isMounted && currentUser) {
        if (!isOwner) {
          const following = await db.isFollowing(currentUser.id, post.userId);
          setIsFollowing(following);
        }
        const alreadyReported = await db.hasAlreadyReported(currentUser.id, 'post', post.id);
        if (isMounted) setHasReportedPost(alreadyReported);
        const commReports = new Set<string>();
        for (const comment of post.comments) {
          const isCommReported = await db.hasAlreadyReported(currentUser.id, 'comment', comment.id);
          if (isCommReported) commReports.add(comment.id);
        }
        if (isMounted) setReportedCommentIds(commReports);
      }
    };
    fetchData();
    return () => { isMounted = false; };
  }, [post.userId, currentUser, isOwner, post.id, post.comments]);

  const isLiked = useMemo(() => {
    return currentUser ? post.likedBy?.includes(currentUser.id) : false;
  }, [post.likedBy, currentUser]);

  const handleFollow = async () => {
    if (!currentUser) return alert('Login to follow authors');
    if (isFollowLoading) return;
    setIsFollowLoading(true);
    try {
      let updatedUser: User | null = null;
      if (isFollowing) {
        updatedUser = await db.unfollowUser(currentUser.id, post.userId);
        setIsFollowing(false);
      } else {
        updatedUser = await db.followUser(currentUser.id, post.userId);
        setIsFollowing(true);
      }
      if (updatedUser && onFollowToggle) onFollowToggle(updatedUser);
    } finally {
      setIsFollowLoading(false);
    }
  };

  const handleBookmark = async () => {
    if (!currentUser) return alert('Login to save stories');
    if (isBookmarkLoading) return;
    const previousState = isOptimisticBookmarked;
    setIsOptimisticBookmarked(!previousState);
    setIsBookmarkLoading(true);
    try {
      const updatedUser = await db.toggleBookmark(currentUser.id, post.id);
      if (updatedUser && onBookmarkToggle) onBookmarkToggle(updatedUser);
      else setIsOptimisticBookmarked(previousState);
    } catch {
      setIsOptimisticBookmarked(previousState);
    } finally {
      setIsBookmarkLoading(false);
    }
  };

  const handleLike = useCallback(async () => {
    if (!currentUser) return alert('Please login to like');
    if (isBanned) return alert('You are currently suspended from performing this action.');

    const hasLiked = post.likedBy?.includes(currentUser.id);
    const likeDelta = hasLiked ? -1 : 1;
    const newLikedBy = hasLiked 
      ? (post.likedBy || []).filter(id => id !== currentUser.id)
      : [...(post.likedBy || []), currentUser.id];

    if (!hasLiked) {
      setIsAnimatingLike(true);
      setTimeout(() => setIsAnimatingLike(false), 400);
    }

    const updatedPost: Post = { ...post, likes: Math.max(0, post.likes + likeDelta), likedBy: newLikedBy };
    await db.updatePost(updatedPost);
    await db.updateUserLikes(post.userId, likeDelta);
    onPostUpdate(updatedPost);
  }, [post, currentUser, onPostUpdate, isBanned]);

  const handleDeletePost = async () => {
    const result = await db.deletePost(post.id);
    if (result.success) onPostDeleted();
  };

  const handleAddComment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser || !commentText.trim()) return;
    if (isBanned) return alert('You are currently suspended from commenting.');

    const newComment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      content: commentText,
      createdAt: new Date().toISOString()
    };
    await db.addComment(post.id, newComment);
    onPostUpdate({ ...post, comments: [...post.comments, newComment] });
    setCommentText('');
  };

  const handleReport = async (reason: string) => {
    if (!currentUser || !reportTarget) return;
    const result = await db.reportEntity(currentUser.id, reportTarget.type, reportTarget.id, reason);
    if (result.success) {
      if (reportTarget.type === 'post') setHasReportedPost(true);
      else setReportedCommentIds(prev => new Set([...Array.from(prev), reportTarget.id]));
    }
    setReportTarget(null);
    alert(result.message);
  };

  return (
    <div className={`rounded-xl md:rounded-2xl shadow-sm border transition-all overflow-hidden h-fit flex flex-col hover:shadow-md ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-100'}`}>
      <div className="p-4 md:p-6 flex-1">
        <div className="flex items-start justify-between mb-4 md:mb-6">
          <div className="flex items-center gap-3">
            <img 
              src={post.userAvatar} 
              className="w-10 h-10 md:w-11 md:h-11 rounded-xl bg-slate-200 object-cover cursor-pointer hover:opacity-80 transition-opacity" 
              alt={post.username} 
              onClick={() => onUserClick?.(post.userId)}
            />
            <div>
              <div className="flex items-center gap-1.5 md:gap-2 mb-0.5">
                <span className="font-bold text-xs md:text-sm truncate cursor-pointer hover:underline" onClick={() => onUserClick?.(post.userId)}>@{post.username}</span>
                <BadgeIcon tier={authorBadge} />
              </div>
              <div className="flex items-center gap-2">
                <span className="text-[9px] md:text-[10px] text-slate-500 uppercase font-black tracking-widest opacity-80">{new Date(post.createdAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}</span>
                {!isOwner && currentUser && (
                  <button onClick={handleFollow} disabled={isFollowLoading} className={`text-[10px] font-black uppercase tracking-widest transition-all ${isFollowing ? 'text-slate-400' : 'text-indigo-600'}`}>
                    {isFollowing ? 'Following' : 'Follow'}
                  </button>
                )}
              </div>
            </div>
          </div>

          <div className="relative">
            <button onClick={() => setShowMenu(!showMenu)} className="text-slate-400 p-1.5 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z"/></svg>
            </button>
            {showMenu && (
              <div className={`absolute right-0 top-10 w-48 rounded-xl shadow-xl border z-20 overflow-hidden ${isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-white border-slate-100'}`}>
                {isOwner ? (
                  <>
                    <button onClick={() => { setShowEditModal(true); setShowMenu(false); }} className="w-full text-left px-4 py-3 text-xs font-bold hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors flex items-center gap-2">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"/></svg>
                      Edit Story
                    </button>
                    <button onClick={() => { setShowConfirmDelete(true); setShowMenu(false); }} className="w-full text-left px-4 py-3 text-xs font-bold text-red-500 hover:bg-red-500/10 transition-colors flex items-center gap-2">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                      Remove Story
                    </button>
                  </>
                ) : (
                  <>
                    <button onClick={() => { onUserClick?.(post.userId); setShowMenu(false); }} className="w-full text-left px-4 py-3 text-xs font-bold hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">View Profile</button>
                    {currentUser && (
                      <button disabled={hasReportedPost} onClick={() => { setReportTarget({type: 'post', id: post.id}); setShowMenu(false); }} className={`w-full text-left px-4 py-3 text-xs font-bold transition-colors ${hasReportedPost ? 'text-slate-500 opacity-50 cursor-not-allowed' : 'text-red-400 hover:bg-red-500/10'}`}>
                        {hasReportedPost ? 'Reported' : 'Report Story'}
                      </button>
                    )}
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        {showConfirmDelete && (
          <div className={`mb-4 p-4 rounded-xl border ${isDarkMode ? 'bg-red-500/10 border-red-500/20' : 'bg-red-50 border-red-100'}`}>
            <p className="text-[11px] font-bold mb-3 text-red-600">Delete this story permanently?</p>
            <div className="flex gap-2">
              <button onClick={handleDeletePost} className="px-3 py-1.5 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest">Confirm</button>
              <button onClick={() => setShowConfirmDelete(false)} className="px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest border border-slate-200 bg-white">Cancel</button>
            </div>
          </div>
        )}

        <h3 className={`font-serif text-xl md:text-2xl font-bold mb-3 md:mb-4 leading-snug ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>{post.title}</h3>
        <p className={`text-sm md:text-base leading-relaxed whitespace-pre-wrap mb-4 font-light ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
          {isExpanded || !isLongContent ? post.content : `${post.content.substring(0, CONTENT_THRESHOLD)}...`}
        </p>
        {isLongContent && (
          <button onClick={() => setIsExpanded(!isExpanded)} className={`text-[10px] font-black uppercase tracking-widest ${isDarkMode ? 'text-indigo-400' : 'text-indigo-600'} mb-4 md:mb-6`}>
            {isExpanded ? 'Collapse ↑' : 'Read Full Journey ↓'}
          </button>
        )}

        <div className={`flex items-center justify-between pt-4 md:pt-5 border-t ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}`}>
          <div className="flex items-center gap-4 md:gap-6">
            <button onClick={handleLike} disabled={isBanned} className={`group flex items-center gap-2 text-xs md:text-sm font-bold transition-all p-1 ${isLiked || isAnimatingLike ? 'text-red-500 scale-105' : 'text-slate-400'} ${isBanned ? 'opacity-30' : ''}`}>
              <svg className={`w-5 h-5 md:w-6 md:h-6 transition-all ${isLiked || isAnimatingLike ? 'fill-red-500 stroke-red-500' : 'fill-none stroke-current'}`} viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/>
              </svg>
              <span className="tabular-nums">{post.likes}</span>
            </button>
            <button onClick={() => setShowComments(!showComments)} className="flex items-center gap-2 text-xs md:text-sm font-bold text-slate-400 p-1">
              <svg className="w-5 h-5 md:w-6 md:h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
              <span className="tabular-nums">{post.comments.length}</span>
            </button>
          </div>

          <button onClick={handleBookmark} disabled={isBookmarkLoading} className={`p-1 transition-all ${isBookmarkLoading ? 'opacity-80' : 'active:scale-125'} ${isOptimisticBookmarked ? 'text-indigo-600' : 'text-slate-400 hover:text-indigo-400'}`}>
            <svg className={`w-5 h-5 md:w-6 md:h-6 ${isOptimisticBookmarked ? 'fill-current' : 'fill-none stroke-current'}`} viewBox="0 0 24 24" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" />
            </svg>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-4 md:p-6 border-t ${isDarkMode ? 'bg-slate-900/50 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
          <div className="space-y-4 mb-4">
            {post.comments.length === 0 ? (<p className="text-[10px] text-center text-slate-500 italic py-2">No resonance found yet.</p>) : (
              post.comments.map(c => {
                const isReported = reportedCommentIds.has(c.id);
                return (
                  <div key={c.id} className="group flex gap-3 text-left">
                    <div className="w-7 h-7 rounded-lg bg-indigo-500 flex items-center justify-center text-white font-black text-[9px] shrink-0 uppercase">{c.username[0]}</div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-0.5">
                        <span className="font-bold text-[11px] truncate">@{c.username}</span>
                        <div className="flex items-center gap-2">
                          <span className="text-[8px] text-slate-500 uppercase font-bold">{new Date(c.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                          {currentUser && c.userId !== currentUser.id && (
                            <button disabled={isReported} onClick={() => setReportTarget({type: 'comment', id: c.id})} className={`text-[8px] font-black uppercase tracking-widest transition-all ${isReported ? 'text-slate-400 opacity-50' : 'opacity-0 group-hover:opacity-100 text-red-400 hover:text-red-500'}`}>
                              {isReported ? 'Reported' : 'Report'}
                            </button>
                          )}
                        </div>
                      </div>
                      <p className={`text-xs ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}>{c.content}</p>
                    </div>
                  </div>
                );
              })
            )}
          </div>
          <form onSubmit={handleAddComment} className="flex gap-2">
            <input type="text" placeholder={isBanned ? "Commenting suspended..." : "Your reply..."} disabled={isBanned} value={commentText} onChange={(e) => setCommentText(e.target.value)} className={`flex-1 px-4 py-2 rounded-xl text-xs outline-none transition-all ${isDarkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-white border-slate-200'}`} />
            <button type="submit" disabled={!commentText.trim() || isBanned} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-xs font-bold transition-all shadow-md disabled:opacity-50">Reply</button>
          </form>
        </div>
      )}

      {reportTarget && <ReportModal targetType={reportTarget.type} targetId={reportTarget.id} onClose={() => setReportTarget(null)} onSubmit={handleReport} isDarkMode={isDarkMode} />}
      {showEditModal && <EditPostModal post={post} isDarkMode={isDarkMode} onClose={() => setShowEditModal(false)} onUpdate={onPostUpdate} />}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { User, Post } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';
import { ReportModal } from './ReportModal';

interface ProfileProps {
  user: User;
  currentUser: User | null;
  posts: Post[];
  isDarkMode: boolean;
  onAccountDeleted: () => void;
  onLogout: () => void;
  onUserUpdate: (updatedUser: User) => void;
}

export const Profile: React.FC<ProfileProps> = ({ 
  user, 
  currentUser, 
  posts, 
  isDarkMode, 
  onAccountDeleted, 
  onLogout,
  onUserUpdate
}) => {
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [deleteError, setDeleteError] = useState('');
  const [isEditingBio, setIsEditingBio] = useState(false);
  const [bioText, setBioText] = useState(user.bio || '');
  const [isSavingBio, setIsSavingBio] = useState(false);
  const [showReportModal, setShowReportModal] = useState(false);
  const [hasReportedUser, setHasReportedUser] = useState(false);

  // Avatar Editing State
  const [isEditingAvatar, setIsEditingAvatar] = useState(false);
  const [avatarUrl, setAvatarUrl] = useState(user.avatar);
  const [isSavingAvatar, setIsSavingAvatar] = useState(false);

  // Settings State
  const [settings, setSettings] = useState(user.settings || { showReportCount: true, showStats: true });
  const [isSavingSettings, setIsSavingSettings] = useState(false);

  const isOwnProfile = currentUser?.id === user.id;
  const isBanned = db.isBanned(user);
  const userPosts = posts.filter(p => p.userId === user.id);
  const totalReceivedLikes = userPosts.reduce((acc, post) => acc + post.likes, 0);

  useEffect(() => {
    setBioText(user.bio || '');
    setAvatarUrl(user.avatar);
    setSettings(user.settings || { showReportCount: true, showStats: true });

    const checkReportStatus = async () => {
      if (currentUser && !isOwnProfile) {
        const reported = await db.hasAlreadyReported(currentUser.id, 'user', user.id);
        setHasReportedUser(reported);
      }
    };
    checkReportStatus();
  }, [user.bio, user.avatar, user.settings, currentUser, isOwnProfile, user.id]);

  const handleSaveAvatar = async () => {
    setIsSavingAvatar(true);
    const updated = await db.updateUserAvatar(user.id, avatarUrl);
    if (updated) {
      onUserUpdate(updated);
      setIsEditingAvatar(false);
    }
    setIsSavingAvatar(false);
  };

  const handleToggleSetting = async (key: string) => {
    const newSettings = { ...settings, [key]: !settings[key] };
    setSettings(newSettings);
    setIsSavingSettings(true);
    const updated = await db.updateUserSettings(user.id, newSettings);
    if (updated) onUserUpdate(updated);
    setIsSavingSettings(false);
  };

  const handleReportUser = async (reason: string) => {
    if (!currentUser) return;
    const result = await db.reportEntity(currentUser.id, 'user', user.id, reason);
    if (result.success) setHasReportedUser(true);
    setShowReportModal(false);
    alert(result.message);
  };

  return (
    <div className="max-w-3xl mx-auto py-4 md:py-8 space-y-8">
      {isBanned && (
        <div className="p-4 rounded-2xl bg-red-600 text-white font-bold flex items-center justify-between shadow-lg">
          <div className="flex items-center gap-3">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
            <div>
              <p className="text-sm">Account Suspended</p>
              <p className="text-[10px] opacity-80 uppercase tracking-widest font-black">Ends: {new Date(user.bannedUntil!).toLocaleString()}</p>
            </div>
          </div>
        </div>
      )}

      <div className={`p-6 md:p-8 rounded-3xl border transition-all relative ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
        <div className="absolute top-4 right-4 md:top-6 md:right-6 flex gap-4">
          {!isOwnProfile && currentUser && (
            <button disabled={hasReportedUser} onClick={() => setShowReportModal(true)} className={`text-[10px] font-black uppercase tracking-[0.2em] transition-colors flex items-center gap-2 ${hasReportedUser ? 'text-slate-400 opacity-50 cursor-not-allowed' : 'text-red-400 hover:text-red-500'}`}>
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 21v-4m0 0V5a2 2 0 012-2h6.5l1 1H21l-3 6 3 6h-8.5l-1-1H5a2 2 0 00-2 2zm9-13.5V9" /></svg>
              {hasReportedUser ? 'Reported' : 'Report'}
            </button>
          )}
          {isOwnProfile && (
            <button onClick={onLogout} className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 hover:text-indigo-500 transition-colors flex items-center gap-2">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
              Logout
            </button>
          )}
        </div>

        <div className="flex flex-col md:flex-row items-center gap-6 md:gap-8 mb-8 md:mb-10">
          <div className="group relative">
            <img src={user.avatar} alt={user.username} className={`w-24 h-24 md:w-32 md:h-32 rounded-3xl object-cover shadow-2xl ring-4 transition-all ${isOwnProfile ? 'group-hover:opacity-75' : ''} ${isBanned ? 'ring-red-500 grayscale' : 'ring-indigo-500/20'}`} />
            {isOwnProfile && (
              <button 
                onClick={() => setIsEditingAvatar(true)} 
                className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity"
              >
                <div className="bg-black/60 text-white text-[10px] font-black uppercase tracking-widest px-3 py-1.5 rounded-xl backdrop-blur-sm">Change</div>
              </button>
            )}
          </div>
          <div className="text-center md:text-left w-full">
            <h1 className="text-2xl md:text-3xl font-serif font-bold mb-2 truncate">@{user.username}</h1>
            <div className="flex flex-wrap justify-center md:justify-start gap-2 md:gap-3 mb-4">
              <BadgeIcon tier={user.badge} size="md" />
              {(isOwnProfile || settings.showReportCount) && user.reportCount! > 0 && (
                <span className="text-[10px] font-black uppercase tracking-widest text-red-500 py-1 px-3 bg-red-500/10 rounded-full">Alerts: {user.reportCount}</span>
              )}
            </div>

            <div className="mt-4 max-w-lg mx-auto md:mx-0">
              {isEditingBio ? (
                <div className="space-y-3">
                  <textarea value={bioText} onChange={(e) => setBioText(e.target.value)} rows={3} className={`w-full p-3 text-sm rounded-xl border outline-none resize-none transition-all ${isDarkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-slate-50 border-slate-200'}`} />
                  <div className="flex justify-center md:justify-start gap-2">
                    <button onClick={async () => { setIsSavingBio(true); const u = await db.updateUserBio(user.id, bioText); if (u) onUserUpdate(u); setIsEditingBio(false); setIsSavingBio(false); }} disabled={isSavingBio} className="px-4 py-1.5 bg-indigo-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest">Save</button>
                    <button onClick={() => setIsEditingBio(false)} className="px-4 py-1.5 border border-slate-200 rounded-lg text-[10px] font-black uppercase tracking-widest dark:bg-slate-800">Cancel</button>
                  </div>
                </div>
              ) : (
                <div className="group relative">
                  <p className={`text-sm leading-relaxed ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>{user.bio || (isOwnProfile ? "A blank slate awaiting your story..." : "")}</p>
                  {isOwnProfile && <button onClick={() => setIsEditingBio(true)} className="mt-2 text-[10px] font-black uppercase tracking-widest text-indigo-500 hover:underline">Edit Bio</button>}
                </div>
              )}
            </div>
          </div>
        </div>

        {(isOwnProfile || settings.showStats) && (
          <div className="grid grid-cols-5 gap-1 md:gap-4 py-6 border-y border-slate-100 dark:border-slate-800">
            <div className="text-center"><p className="text-lg md:text-xl font-bold">{userPosts.length}</p><p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Stories</p></div>
            <div className="text-center border-l border-slate-100 dark:border-slate-800"><p className="text-lg md:text-xl font-bold">{totalReceivedLikes}</p><p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Likes</p></div>
            <div className="text-center border-l border-slate-100 dark:border-slate-800"><p className="text-lg md:text-xl font-bold">{user.followingCount}</p><p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Following</p></div>
            <div className="text-center border-l border-slate-100 dark:border-slate-800"><p className="text-lg md:text-xl font-bold">{user.followerCount}</p><p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Followers</p></div>
            <div className="text-center border-l border-slate-100 dark:border-slate-800"><p className="text-lg md:text-xl font-bold">{userPosts.reduce((acc, p) => acc + p.comments.length, 0)}</p><p className="text-[7px] md:text-[9px] font-black uppercase tracking-widest text-slate-400">Notes</p></div>
          </div>
        )}
      </div>

      {/* Account Settings Section (Owner Only) */}
      {isOwnProfile && (
        <div className={`p-6 md:p-8 rounded-3xl border ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-lg'}`}>
          <h2 className="font-serif text-xl font-bold mb-6">Account Settings</h2>
          <div className="space-y-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs font-bold uppercase tracking-widest">Public Stats</p>
                <p className="text-[10px] text-slate-500">Allow others to see your engagement numbers.</p>
              </div>
              <button 
                onClick={() => handleToggleSetting('showStats')}
                className={`w-10 h-5 rounded-full transition-all relative ${settings.showStats ? 'bg-indigo-600' : 'bg-slate-300'}`}
              >
                <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${settings.showStats ? 'right-1' : 'left-1'}`} />
              </button>
            </div>

            <div className="flex items-center justify-between">
              <div>
                <p className="text-xs font-bold uppercase tracking-widest">Report Visibility</p>
                <p className="text-[10px] text-slate-500">Show a public badge if your content has been reported.</p>
              </div>
              <button 
                onClick={() => handleToggleSetting('showReportCount')}
                className={`w-10 h-5 rounded-full transition-all relative ${settings.showReportCount ? 'bg-red-600' : 'bg-slate-300'}`}
              >
                <div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${settings.showReportCount ? 'right-1' : 'left-1'}`} />
              </button>
            </div>

            <div className="pt-4 border-t border-slate-100 dark:border-slate-800">
              {!showConfirmDelete ? (
                <button onClick={() => setShowConfirmDelete(true)} className="text-[10px] font-bold text-red-500 hover:underline uppercase tracking-widest">Delete Identity</button>
              ) : (
                <div className="flex items-center gap-4">
                  <p className="text-[10px] font-bold text-red-600">Are you sure? This is irreversible.</p>
                  <button onClick={async () => { setIsDeleting(true); const r = await db.deleteAccount(user.id); if (r.success) onAccountDeleted(); else alert(r.error); setIsDeleting(false); }} disabled={isDeleting} className="px-3 py-1.5 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest shadow-lg">Yes, Delete</button>
                  <button onClick={() => setShowConfirmDelete(false)} className="px-3 py-1.5 bg-slate-200 dark:bg-slate-700 rounded-lg text-[10px] font-black uppercase tracking-widest">No, Stay</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Modals */}
      {showReportModal && <ReportModal targetType="user" targetId={user.id} onClose={() => setShowReportModal(false)} onSubmit={handleReportUser} isDarkMode={isDarkMode} />}

      {isEditingAvatar && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 backdrop-blur-md bg-black/40 animate-in fade-in duration-200">
          <div className={`w-full max-w-sm rounded-3xl shadow-2xl p-6 ${isDarkMode ? 'bg-slate-900 border border-slate-800 text-white' : 'bg-white border border-slate-100'}`}>
            <h3 className="font-serif text-xl font-bold mb-6">Choose Your Mask</h3>
            <div className="space-y-4">
              <div className="flex justify-center mb-6">
                 <img src={avatarUrl} className="w-24 h-24 rounded-3xl object-cover shadow-xl ring-4 ring-indigo-500/20" alt="Preview" />
              </div>
              <div>
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 block mb-2">Image URL</label>
                <input 
                  value={avatarUrl} 
                  onChange={(e) => setAvatarUrl(e.target.value)}
                  className={`w-full p-3 rounded-xl border outline-none text-xs ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-200'}`}
                />
              </div>
              <button 
                onClick={() => setAvatarUrl(`https://picsum.photos/seed/${Math.random().toString(36).substring(7)}/400`)}
                className="w-full py-2 text-[10px] font-black uppercase tracking-widest text-indigo-500 bg-indigo-500/10 rounded-xl hover:bg-indigo-500/20 transition-all"
              >
                Generate Random
              </button>
              <div className="flex gap-2 pt-4">
                <button onClick={() => setIsEditingAvatar(false)} className="flex-1 py-3 text-[10px] font-black uppercase tracking-widest border border-slate-200 dark:border-slate-700 rounded-xl">Cancel</button>
                <button onClick={handleSaveAvatar} disabled={isSavingAvatar} className="flex-1 py-3 text-[10px] font-black uppercase tracking-widest bg-indigo-600 text-white rounded-xl shadow-lg active:scale-95 transition-all">
                  {isSavingAvatar ? 'Updating...' : 'Save'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

