export interface User {
  id: string;
  username: string;
  email: string;
  avatar: string;
  bio?: string;
  bookmarks: string[];
  totalLikes: number;
  badge: BadgeTier;
  followerCount: number;
  followingCount: number;
  password?: string;
  reportCount?: number;
  bannedUntil?: string;
  // Added settings property to support user preferences and fix type errors in services/db.ts
  settings?: {
    showReportCount: boolean;
    showStats: boolean;
  };
}

