  id: string;
  userId: string;
  username: string;
  content: string;
  createdAt: string;
  reportCount?: number;
}

export interface Post {
  id: string;
  userId: string;
  username: string;
  title: string;
  content: string;
  likes: number;
  likedBy: string[]; 
  comments: Comment[];
  shares: number;
  createdAt: string;
  userAvatar: string;
  reportCount?: number;
}

export interface AppState {
  currentUser: User | null;
  posts: Post[];
  isDarkMode: boolean;
  searchQuery: string;
}

