const SUPABASE_URL = (process.env as any).SUPABASE_URL || 'https://uvjavqzhhqxkfuklkxdo.supabase.co';
const SUPABASE_ANON_KEY = (process.env as any).SUPABASE_ANON_KEY || 'sb_publishable_-GDZiq_v45oEVhlly7tG-w_cKockqn6';

const isConfigured = SUPABASE_URL !== 'https://your-project-url.supabase.co' && SUPABASE_ANON_KEY !== 'your-anon-key';
const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);
const SESSION_KEY = 'storyverse_session';

export const getBadge = (likes: number): BadgeTier => {
  if (likes >= 500) return BadgeTier.PLATINUM;
  if (likes >= 100) return BadgeTier.GOLD;
  if (likes >= 25) return BadgeTier.SILVER;
  if (likes >= 5) return BadgeTier.BRONZE;
  return BadgeTier.NOVICE;
};

export const db = {
  // --- Auth ---
  async register(username: string, email: string, password: string): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };

    // STRICT EMAIL VALIDATION: Only gmail.com allowed
    if (!email.toLowerCase().endsWith('@gmail.com')) {
      return { success: false, error: 'Access denied. Only @gmail.com addresses are permitted for registration.' };
    }

    try {
      const userId = Math.random().toString(36).substr(2, 9);
      const userPayload = {
        id: userId,
        username: username.toLowerCase().trim(),
        email: email.toLowerCase().trim(),
        password: password,
        avatar: `https://picsum.photos/seed/${username}/100`,
        bio: '',
        bookmarks: [],
        total_likes: 0,
        badge: BadgeTier.NOVICE,
        report_count: 0,
        settings: { showReportCount: true, showStats: true }
      };

      const { error } = await supabase.from('users').insert([userPayload]);
      if (error) {
        if (error.message.includes('unique constraint')) return { success: false, error: 'Username or Email already taken.' };
        return { success: false, error: error.message };
      }

      const user: User = {
        id: userId,
        username: userPayload.username,
        email: userPayload.email,
        avatar: userPayload.avatar,
        bio: '',
        bookmarks: [],
        totalLikes: 0,
        badge: BadgeTier.NOVICE,
        followerCount: 0,
        followingCount: 0,
        reportCount: 0,
        settings: userPayload.settings
      };

      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return { success: true, user };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  // --- Profile & Settings Methods ---
  async updateUserAvatar(userId: string, avatarUrl: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      // Update user table
      const { error: userError } = await supabase.from('users').update({ avatar: avatarUrl }).eq('id', userId);
      if (userError) throw userError;

      // Propagate change to posts table (denormalized user_avatar)
      await supabase.from('posts').update({ user_avatar: avatarUrl }).eq('user_id', userId);

      return await this.refreshUser(userId);
    } catch (err) {
      console.error("Update avatar error:", err);
      return null;
    }
  },

  async updateUserSettings(userId: string, settings: any): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { error } = await supabase.from('users').update({ settings }).eq('id', userId);
      if (error) throw error;
      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  async updateUserProfile(userId: string, data: { username?: string; avatar?: string; bio?: string }): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const updatePayload: any = {};
      if (data.username !== undefined) updatePayload.username = data.username.toLowerCase();
      if (data.avatar !== undefined) updatePayload.avatar = data.avatar;
      if (data.bio !== undefined) updatePayload.bio = data.bio;

      const { error } = await supabase.from('users').update(updatePayload).eq('id', userId);
      if (error) throw error;

      if (data.username || data.avatar) {
        const postUpdate: any = {};
        if (data.username) postUpdate.username = data.username.toLowerCase();
        if (data.avatar) postUpdate.user_avatar = data.avatar;
        await supabase.from('posts').update(postUpdate).eq('user_id', userId);
      }

      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  // --- Post Methods ---
  async updatePostContent(postId: string, title: string, content: string): Promise<boolean> {
    if (!isConfigured) return false;
    try {
      const { error } = await supabase.from('posts').update({
        title,
        content,
        last_edited_at: new Date().toISOString()
      }).eq('id', postId);
      return !error;
    } catch {
      return false;
    }
  },

  isBanned(user: User | null): boolean {
    if (!user || !user.bannedUntil) return false;
    return new Date(user.bannedUntil) > new Date();
  },

  async getPosts(): Promise<Post[]> {
    if (!isConfigured) return [];
    try {
      const { data, error } = await supabase
        .from('posts')
        .select(`*, comments (*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      return (data || []).map(post => ({
        id: post.id,
        userId: post.user_id,
        username: post.username,
        title: post.title,
        content: post.content,
        likes: post.likes || 0,
        likedBy: post.liked_by || [],
        shares: post.shares || 0,
        createdAt: post.created_at,
        userAvatar: post.user_avatar,
        reportCount: post.report_count || 0,
        lastEditedAt: post.last_edited_at,
        comments: (post.comments || []).map((c: any) => ({
          id: c.id,
          userId: c.user_id,
          username: c.username,
          content: c.content,
          createdAt: c.created_at,
          reportCount: c.report_count || 0
        }))
      }));
    } catch (err) {
      return [];
    }
  },

  async savePost(post: Post): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Suspended account.");
    if (!isConfigured) return;
    await supabase.from('posts').insert([{
      id: post.id,
      user_id: post.userId,
      username: post.username,
      title: post.title,
      content: post.content,
      likes: post.likes,
      liked_by: post.likedBy,
      shares: post.shares,
      user_avatar: post.userAvatar,
      created_at: post.createdAt,
      report_count: 0
    }]);
  },

  async updatePost(updatedPost: Post): Promise<void> {
    if (!isConfigured) return;
    await supabase.from('posts').update({
      likes: updatedPost.likes,
      liked_by: updatedPost.likedBy,
      shares: updatedPost.shares,
      title: updatedPost.title,
      content: updatedPost.content
    }).eq('id', updatedPost.id);
  },

  async deletePost(postId: string): Promise<{ success: boolean; error?: string }> {
    if (!isConfigured) return { success: false };
    try {
      await supabase.from('comments').delete().eq('post_id', postId);
      await supabase.from('posts').delete().eq('id', postId);
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async addComment(postId: string, comment: Comment): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Suspended account.");
    if (!isConfigured) return;
    await supabase.from('comments').insert([{
      id: comment.id,
      post_id: postId,
      user_id: comment.userId,
      username: comment.username,
      content: comment.content,
      created_at: comment.createdAt,
      report_count: 0
    }]);
  },

  async getUserById(userId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data, error } = await supabase.from('users').select('*').eq('id', userId).maybeSingle();
      if (error || !data) return null;
      const stats = await this.getFollowStats(data.id);
      return {
        id: data.id,
        username: data.username,
        email: data.email,
        avatar: data.avatar,
        bio: data.bio || '',
        bookmarks: data.bookmarks || [],
        totalLikes: data.total_likes || 0,
        badge: (data.badge as BadgeTier) || BadgeTier.NOVICE,
        followerCount: stats.followers,
        followingCount: stats.following,
        reportCount: data.report_count || 0,
        bannedUntil: data.banned_until,
        settings: data.settings || { showReportCount: true, showStats: true }
      };
    } catch (err) {
      return null;
    }
  },

  async refreshUser(userId: string): Promise<User | null> {
    const user = await this.getUserById(userId);
    if (user) localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    return user;
  },

  async toggleBookmark(userId: string, postId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data: user } = await supabase.from('users').select('bookmarks').eq('id', userId).maybeSingle();
      if (!user) return null;
      let bookmarks = Array.isArray(user.bookmarks) ? user.bookmarks : [];
      const newBookmarks = bookmarks.includes(postId)
        ? bookmarks.filter((id: string) => id !== postId)
        : [...bookmarks, postId];
      await supabase.from('users').update({ bookmarks: newBookmarks }).eq('id', userId);
      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  async updateUserLikes(userId: string, delta: number): Promise<void> {
    if (!isConfigured) return;
    const { data: dbUser } = await supabase.from('users').select('total_likes').eq('id', userId).maybeSingle();
    if (!dbUser) return;
    const newTotalLikes = Math.max(0, (dbUser.total_likes || 0) + delta);
    const newBadge = getBadge(newTotalLikes);
    await supabase.from('users').update({ total_likes: newTotalLikes, badge: newBadge }).eq('id', userId);
  },

  async updateUserBio(userId: string, bio: string): Promise<User | null> {
    return this.updateUserProfile(userId, { bio });
  },

  async reportEntity(reporterId: string, targetType: ReportType, targetId: string, reason: string): Promise<{ success: boolean; message: string }> {
    if (!isConfigured) return { success: false, message: 'Backend not configured.' };
    try {
      const alreadyReported = await this.hasAlreadyReported(reporterId, targetType, targetId);
      if (alreadyReported) return { success: false, message: 'Already reported.' };
      let table = targetType === 'user' ? 'users' : (targetType === 'post' ? 'posts' : 'comments');
      await supabase.from('reports').insert([{ id: Math.random().toString(36).substr(2, 9), reporter_id: reporterId, target_type: targetType, target_id: targetId, reason }]);
      const { data } = await supabase.from(table).select('report_count').eq('id', targetId).maybeSingle();
      const newCount = (data?.report_count || 0) + 1;
      await supabase.from(table).update({ report_count: newCount }).eq('id', targetId);
      return { success: true, message: 'Report submitted.' };
    } catch {
      return { success: false, message: 'Error submitting report.' };
    }
  },

  async hasAlreadyReported(reporterId: string, targetType: ReportType, targetId: string): Promise<boolean> {
    const { data } = await supabase.from('reports').select('id').eq('reporter_id', reporterId).eq('target_type', targetType).eq('target_id', targetId).maybeSingle();
    return !!data;
  },

  getCurrentUser(): User | null {
    try {
      const session = localStorage.getItem(SESSION_KEY);
      return session ? JSON.parse(session) : null;
    } catch {
      return null;
    }
  },

  async login(identifier: string, password: string, method: 'username' | 'email'): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };
    const field = method === 'username' ? 'username' : 'email';
    try {
      const { data, error } = await supabase.from('users').select('*').ilike(field, identifier).eq('password', password).maybeSingle();
      if (error) return { success: false, error: error.message };
      if (!data) return { success: false, error: 'Invalid credentials.' };
      const user = await this.refreshUser(data.id);
      return user ? { success: true, user } : { success: false, error: 'Session error.' };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async getFollowStats(userId: string): Promise<{ followers: number, following: number }> {
    try {
      const { count: followers } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('following_id', userId);
      const { count: following } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('follower_id', userId);
      return { followers: followers || 0, following: following || 0 };
    } catch { return { followers: 0, following: 0 }; }
  },

  async isFollowing(followerId: string, followingId: string): Promise<boolean> {
    const { data } = await supabase.from('follows').select('*').eq('follower_id', followerId).eq('following_id', followingId).maybeSingle();
    return !!data;
  },

  async followUser(followerId: string, followingId: string): Promise<{ follower: User | null, following: User | null }> {
    await supabase.from('follows').insert([{ follower_id: followerId, following_id: followingId }]);
    return { follower: await this.refreshUser(followerId), following: await this.getUserById(followingId) };
  },

  async unfollowUser(followerId: string, followingId: string): Promise<{ follower: User | null, following: User | null }> {
    await supabase.from('follows').delete().eq('follower_id', followerId).eq('following_id', followingId);
    return { follower: await this.refreshUser(followerId), following: await this.getUserById(followingId) };
  },

  async deleteAccount(userId: string): Promise<{ success: boolean, error?: string }> {
    try {
      await supabase.from('users').delete().eq('id', userId);
      this.logout();
      return { success: true };
    } catch (err: any) { return { success: false, error: err.message }; }
  },

  logout() { localStorage.removeItem(SESSION_KEY); }
};

import React, { useState } from 'react';
import { Post } from '../types';
import { aiService } from '../services/ai';
import { db } from '../services/db';

interface EditPostModalProps {
  post: Post;
  isDarkMode: boolean;
  onClose: () => void;
  onUpdate: (updatedPost: Post) => void;
}

export const EditPostModal: React.FC<EditPostModalProps> = ({ post, isDarkMode, onClose, onUpdate }) => {
  const [title, setTitle] = useState(post.title);
  const [content, setContent] = useState(post.content);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiStatus, setAiStatus] = useState('');
  const [isSaving, setIsSaving] = useState(false);

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!title.trim() || !content.trim()) return;

    setIsSaving(true);
    const success = await db.updatePostContent(post.id, title, content);
    if (success) {
      onUpdate({ ...post, title, content, lastEditedAt: new Date().toISOString() });
      onClose();
    } else {
      alert("Failed to save changes. Please try again.");
    }
    setIsSaving(false);
  };

  const handleFixGrammar = async () => {
    setIsAiLoading(true);
    setAiStatus('Refining...');
    const corrected = await aiService.fixGrammar(content);
    setContent(corrected);
    setIsAiLoading(false);
    setAiStatus('Polished!');
    setTimeout(() => setAiStatus(''), 2000);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 backdrop-blur-md bg-black/40 animate-in fade-in duration-200">
      <div className={`w-full max-w-2xl rounded-3xl shadow-2xl p-6 md:p-8 overflow-y-auto max-h-[90vh] ${isDarkMode ? 'bg-slate-900 border border-slate-800 text-white' : 'bg-white border border-slate-100 text-slate-900'}`}>
        <div className="flex items-center justify-between mb-8">
          <h2 className="font-serif text-2xl font-bold">Refine Your Story</h2>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12"/></svg>
          </button>
        </div>

        <form onSubmit={handleSave} className="space-y-6">
          <div>
            <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 block mb-2">Title</label>
            <input 
              required
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              className={`w-full p-4 rounded-xl border outline-none transition-all font-serif text-lg ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-200'}`}
            />
          </div>

          <div className="relative">
            <div className="flex items-center justify-between mb-2">
              <label className="text-[10px] font-black uppercase tracking-widest text-slate-400">Narrative</label>
              <div className="flex items-center gap-2">
                {aiStatus && <span className="text-[9px] font-black uppercase text-indigo-500 animate-pulse">{aiStatus}</span>}
                <button
                  type="button"
                  onClick={handleFixGrammar}
                  disabled={isAiLoading}
                  className="px-3 py-1 bg-indigo-500/10 text-indigo-500 rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-indigo-500/20 transition-all"
                >
                  {isAiLoading ? '...' : '✨ Polish'}
                </button>
              </div>
            </div>
            <textarea 
              required
              rows={10}
              value={content}
              onChange={(e) => setContent(e.target.value)}
              className={`w-full p-4 rounded-xl border outline-none transition-all resize-none text-sm md:text-base leading-relaxed ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-200'}`}
            />
          </div>

          <div className="flex gap-3 pt-4">
            <button 
              type="button"
              onClick={onClose}
              className="flex-1 py-4 text-xs font-black uppercase tracking-[0.2em] rounded-xl border border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-800"
            >
              Cancel
            </button>
            <button 
              type="submit"
              disabled={isSaving}
              className="flex-1 py-4 bg-indigo-600 text-white rounded-xl text-xs font-black uppercase tracking-[0.2em] shadow-xl active:scale-95 transition-all disabled:opacity-50"
            >
              {isSaving ? 'Updating...' : 'Update Story'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
import { Post, User, BadgeTier } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';
import { ReportModal } from './ReportModal';
import { EditPostModal } from './EditPostModal';

interface PostCardProps {
  post: Post;
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (post: Post) => void;
  onPostDeleted: () => void;
  onFollowToggle?: (targetUserId: string) => void;
  onUserClick?: (userId: string) => void;
  onBookmarkToggle?: (updatedUser: User) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  isDarkMode, 
  onPostUpdate, 
  onPostDeleted,
  onFollowToggle,
  onUserClick,
  onBookmarkToggle
}) => {
  const [commentText, setCommentText] = useState('');
  const [showComments, setShowComments] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [isAnimatingLike, setIsAnimatingLike] = useState(false);
  const [showMenu, setShowMenu] = useState(false);
  const [showShareMenu, setShowShareMenu] = useState(false);
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [authorBadge, setAuthorBadge] = useState<BadgeTier>(BadgeTier.NOVICE);
  const [isFollowing, setIsFollowing] = useState(false);
  const [isFollowLoading, setIsFollowLoading] = useState(false);
  const [isBookmarkLoading, setIsBookmarkLoading] = useState(false);
  const [copySuccess, setCopySuccess] = useState(false);

  const [hasReportedPost, setHasReportedPost] = useState(false);
  const [reportedCommentIds, setReportedCommentIds] = useState<Set<string>>(new Set());
  const [reportTarget, setReportTarget] = useState<{type: 'post' | 'comment', id: string} | null>(null);

  const shareMenuRef = useRef<HTMLDivElement>(null);
  const isOwner = currentUser?.id === post.userId;
  const isBanned = db.isBanned(currentUser);

  const isActuallyBookmarked = useMemo(() => currentUser?.bookmarks?.includes(post.id) || false, [currentUser, post.id]);
  const [isOptimisticBookmarked, setIsOptimisticBookmarked] = useState(false);

  useEffect(() => {
    setIsOptimisticBookmarked(isActuallyBookmarked);
  }, [isActuallyBookmarked]);

  const CONTENT_THRESHOLD = 250;
  const isLongContent = post.content.length > CONTENT_THRESHOLD;

  const readTime = useMemo(() => {
    const wordsPerMinute = 225;
    const words = post.content.trim().split(/\s+/).length;
    return Math.max(1, Math.ceil(words / wordsPerMinute));
  }, [post.content]);

  useEffect(() => {
    let isMounted = true;
    const fetchData = async () => {
      const author = await db.getUserById(post.userId);
      if (isMounted && author) {
        setAuthorBadge(author.badge);
      }

      if (isMounted && currentUser) {
        if (!isOwner) {
          const following = await db.isFollowing(currentUser.id, post.userId);
          setIsFollowing(following);
        }

        const alreadyReported = await db.hasAlreadyReported(currentUser.id, 'post', post.id);
        if (isMounted) setHasReportedPost(alreadyReported);

        const commReports = new Set<string>();
        for (const comment of post.comments) {
          const isCommReported = await db.hasAlreadyReported(currentUser.id, 'comment', comment.id);
          if (isCommReported) commReports.add(comment.id);
        }
        if (isMounted) setReportedCommentIds(commReports);
      }
    };
    fetchData();

    const handleOutsideClick = (e: MouseEvent) => {
      if (shareMenuRef.current && !shareMenuRef.current.contains(e.target as Node)) {
        setShowShareMenu(false);
      }
    };
    document.addEventListener('mousedown', handleOutsideClick);

    return () => { 
      isMounted = false; 
      document.removeEventListener('mousedown', handleOutsideClick);
    };
  }, [post.userId, currentUser, isOwner, post.id, post.comments]);

  const isLiked = useMemo(() => {
    return currentUser ? post.likedBy?.includes(currentUser.id) : false;
  }, [post.likedBy, currentUser]);

  const handleFollow = async () => {
    if (!currentUser) return alert('Login to follow authors');
    if (isFollowLoading || !onFollowToggle) return;

    setIsFollowLoading(true);
    try {
      if (isFollowing) {
        await db.unfollowUser(currentUser.id, post.userId);
        setIsFollowing(false);
      } else {
        await db.followUser(currentUser.id, post.userId);
        setIsFollowing(true);
      }
      onFollowToggle(post.userId);
    } catch (err) {
      console.error("Follow action failed:", err);
    } finally {
      setIsFollowLoading(false);
    }
  };

  const handleBookmark = async () => {
    if (!currentUser) return alert('Login to save stories');
    if (isBookmarkLoading) return;
    const previousState = isOptimisticBookmarked;
    setIsOptimisticBookmarked(!previousState);
    setIsBookmarkLoading(true);
    try {
      const updatedUser = await db.toggleBookmark(currentUser.id, post.id);
      if (updatedUser && onBookmarkToggle) {
        onBookmarkToggle(updatedUser);
      } else {
        setIsOptimisticBookmarked(previousState);
      }
    } catch (err) {
      setIsOptimisticBookmarked(previousState);
    } finally {
      setIsBookmarkLoading(false);
    }
  };

  const handleLike = useCallback(async () => {
    if (!currentUser) return alert('Please login to like');
    if (isBanned) return alert('You are currently suspended from performing this action.');

    const hasLiked = post.likedBy?.includes(currentUser.id);
    const likeDelta = hasLiked ? -1 : 1;
    const newLikedBy = hasLiked 
      ? (post.likedBy || []).filter(id => id !== currentUser.id)
      : [...(post.likedBy || []), currentUser.id];

    if (!hasLiked) {
      setIsAnimatingLike(true);
      setTimeout(() => setIsAnimatingLike(false), 400);
    }

    const updatedPost: Post = { ...post, likes: Math.max(0, post.likes + likeDelta), likedBy: newLikedBy };
    await db.updatePost(updatedPost);
    await db.updateUserLikes(post.userId, likeDelta);
    onPostUpdate(updatedPost);
  }, [post, currentUser, onPostUpdate, isBanned]);

  const handleDeletePost = async () => {
    const result = await db.deletePost(post.id);
    if (result.success) onPostDeleted();
  };

  const handleAddComment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser || !commentText.trim()) return;
    if (isBanned) return alert('You are currently suspended from commenting.');

    const newComment = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      content: commentText,
      createdAt: new Date().toISOString()
    };
    await db.addComment(post.id, newComment);
    onPostUpdate({ ...post, comments: [...post.comments, newComment] });
    setCommentText('');
  };

  const handleReport = async (reason: string) => {
    if (!currentUser || !reportTarget) return;
    const result = await db.reportEntity(currentUser.id, reportTarget.type, reportTarget.id, reason);
    if (result.success) {
      if (reportTarget.type === 'post') setHasReportedPost(true);
      else setReportedCommentIds(prev => new Set([...Array.from(prev), reportTarget.id]));
    }
    setReportTarget(null);
    alert(result.message);
  };

  const handleProfileClick = () => {
    if (onUserClick) onUserClick(post.userId);
  };

  const handleSocialShare = (platform: 'twitter' | 'facebook' | 'linkedin') => {
    const url = window.location.origin + "?post=" + post.id;
    const text = `Check out "${post.title}" on StoryVerse!`;
    let shareUrl = '';

    switch (platform) {
      case 'twitter': shareUrl = `https://twitter.com/intent/tweet?text=${encodeURIComponent(text)}&url=${encodeURIComponent(url)}`; break;
      case 'facebook': shareUrl = `https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(url)}`; break;
      case 'linkedin': shareUrl = `https://www.linkedin.com/sharing/share-offsite/?url=${encodeURIComponent(url)}`; break;
    }

    window.open(shareUrl, '_blank', 'width=600,height=400');
    db.updatePost({ ...post, shares: (post.shares || 0) + 1 });
    setShowShareMenu(false);
  };

  const handleCopyLink = () => {
    const url = window.location.origin + "?post=" + post.id;
    navigator.clipboard.writeText(url);
    setCopySuccess(true);
    setTimeout(() => {
      setCopySuccess(false);
      setShowShareMenu(false);
    }, 2000);
  };

  return (
    <div className={`rounded-xl md:rounded-2xl shadow-sm border transition-all overflow-hidden h-fit flex flex-col hover:shadow-md ${
      isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-100'
    }`}>
      <div className="p-4 md:p-6 flex-1">
        <div className="flex items-start justify-between mb-4 md:mb-6">
          <div className="flex items-center gap-3">
            <img 
              src={post.userAvatar} 
              className="w-10 h-10 md:w-11 md:h-11 rounded-xl bg-slate-200 object-cover cursor-pointer hover:opacity-80 transition-opacity" 
              alt={post.username} 
              onClick={handleProfileClick}
            />
            <div>
              <div className="flex items-center gap-1.5 md:gap-2 mb-0.5">
                <span className="font-bold text-xs md:text-sm truncate max-w-[100px] md:max-w-none cursor-pointer hover:underline" onClick={handleProfileClick}>@{post.username}</span>
                <BadgeIcon tier={authorBadge} />
              </div>
              <div className="flex items-center gap-2">
                <span className="text-[9px] md:text-[10px] text-slate-500 uppercase font-black tracking-widest opacity-80">{new Date(post.createdAt).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}</span>
                <span className="text-slate-300 text-[10px]">•</span>
                <div className="flex items-center gap-1 text-[9px] md:text-[10px] text-slate-400 uppercase font-black tracking-widest opacity-80">
                  <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
                  <span>{readTime} min read</span>
                </div>
                {post.lastEditedAt && <span className="text-[8px] text-slate-500 font-bold uppercase italic">(Edited)</span>}
              </div>
            </div>
          </div>

          <div className="relative">
            <button onClick={() => setShowMenu(!showMenu)} className="text-slate-400 p-1.5 rounded-lg hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z"/></svg>
            </button>
            {showMenu && (
              <div className={`absolute right-0 top-10 w-48 rounded-xl shadow-xl border z-20 overflow-hidden ${isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-white border-slate-100'}`}>
                {isOwner ? (
                  <>
                    <button onClick={() => { setShowEditModal(true); setShowMenu(false); }} className="w-full text-left px-4 py-3 text-xs font-bold hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors flex items-center gap-2">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"/></svg>
                      Edit Story
                    </button>
                    <button onClick={() => { setShowConfirmDelete(true); setShowMenu(false); }} className="w-full text-left px-4 py-3 text-xs font-bold text-red-500 hover:bg-red-500/10 transition-colors flex items-center gap-2 border-t dark:border-slate-800">
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                      Delete
                    </button>
                  </>
                ) : (
                  <>
                    <button onClick={handleProfileClick} className="w-full text-left px-4 py-3 text-xs font-bold hover:bg-slate-50 dark:hover:bg-slate-800 transition-colors">View Profile</button>
                    {currentUser && (
                      <button disabled={hasReportedPost} onClick={() => { setReportTarget({type: 'post', id: post.id}); setShowMenu(false); }} className={`w-full text-left px-4 py-3 text-xs font-bold transition-colors ${hasReportedPost ? 'text-slate-400 opacity-50' : 'text-red-400 hover:bg-red-500/10'}`}>
                        {hasReportedPost ? 'Reported' : 'Report Story'}
                      </button>
                    )}
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        {showConfirmDelete && (
          <div className={`mb-4 p-4 rounded-xl border ${isDarkMode ? 'bg-red-500/10 border-red-500/20' : 'bg-red-50 border-red-100'}`}>
            <p className="text-[11px] font-bold mb-3 text-red-600">Delete permanently?</p>
            <div className="flex gap-2">
              <button onClick={handleDeletePost} className="px-3 py-1.5 bg-red-600 text-white rounded-lg text-[10px] font-black uppercase tracking-widest">Confirm</button>
              <button onClick={() => setShowConfirmDelete(false)} className="px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-widest border border-slate-200 bg-white">Cancel</button>
            </div>
          </div>
        )}

        <h3 className={`font-serif text-xl md:text-2xl font-bold mb-3 md:mb-4 leading-snug ${isDarkMode ? 'text-slate-100' : 'text-slate-900'}`}>{post.title}</h3>
        <p className={`text-sm md:text-base leading-relaxed whitespace-pre-wrap mb-4 font-light ${isDarkMode ? 'text-slate-400' : 'text-slate-600'}`}>
          {isExpanded || !isLongContent ? post.content : `${post.content.substring(0, CONTENT_THRESHOLD)}...`}
        </p>
        {isLongContent && (
          <button onClick={() => setIsExpanded(!isExpanded)} className={`text-[10px] font-black uppercase tracking-widest ${isDarkMode ? 'text-indigo-400' : 'text-indigo-600'} mb-4 md:mb-6`}>
            {isExpanded ? 'Collapse ↑' : 'Read Full Story ↓'}
          </button>
        )}

        <div className={`flex items-center justify-between pt-4 md:pt-5 border-t ${isDarkMode ? 'border-slate-700' : 'border-slate-100'}`}>
          <div className="flex items-center gap-4 md:gap-6">
            <button onClick={handleLike} disabled={isBanned} className={`group flex items-center gap-2 text-xs md:text-sm font-bold transition-all p-1 ${isLiked || isAnimatingLike ? 'text-red-500 scale-105' : 'text-slate-400'} ${isBanned ? 'opacity-30 cursor-not-allowed' : ''}`}>
              <svg className={`w-5 h-5 md:w-6 md:h-6 transition-all ${isLiked || isAnimatingLike ? 'fill-red-500 stroke-red-500' : 'fill-none stroke-current'}`} viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/>
              </svg>
              <span className="tabular-nums">{post.likes}</span>
            </button>
            <button onClick={() => setShowComments(!showComments)} className="flex items-center gap-2 text-xs md:text-sm font-bold text-slate-400 p-1">
              <svg className="w-5 h-5 md:w-6 md:h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
              <span className="tabular-nums">{post.comments.length}</span>
            </button>
            <div className="relative" ref={shareMenuRef}>
              <button onClick={() => setShowShareMenu(!showShareMenu)} className={`flex items-center gap-2 text-xs md:text-sm font-bold transition-all p-1 ${showShareMenu ? 'text-indigo-500' : 'text-slate-400 hover:text-indigo-500'}`}>
                <svg className="w-5 h-5 md:w-6 md:h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"/></svg>
              </button>
              {showShareMenu && (
                <div className={`absolute bottom-10 left-0 w-48 rounded-2xl shadow-2xl border z-30 overflow-hidden ${isDarkMode ? 'bg-slate-900 border-slate-700' : 'bg-white border-slate-100'}`}>
                  <div className="p-2 space-y-1">
                    <button onClick={() => handleSocialShare('twitter')} className="w-full text-left px-4 py-2.5 text-xs font-bold rounded-xl transition-all hover:bg-slate-50 dark:hover:bg-slate-800 flex items-center gap-3"><span className="text-blue-400">Twitter</span></button>
                    <button onClick={() => handleSocialShare('facebook')} className="w-full text-left px-4 py-2.5 text-xs font-bold rounded-xl transition-all hover:bg-slate-50 dark:hover:bg-slate-800 flex items-center gap-3"><span className="text-blue-600">Facebook</span></button>
                    <button onClick={handleCopyLink} className={`w-full text-left px-4 py-2.5 text-xs font-bold rounded-xl transition-all flex items-center gap-3 ${copySuccess ? 'text-emerald-500 bg-emerald-500/10' : 'hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-400'}`}>Copy Link</button>
                  </div>
                </div>
              )}
            </div>
          </div>
          <button onClick={handleBookmark} disabled={isBookmarkLoading} className={`p-1 transition-all ${isBookmarkLoading ? 'opacity-80' : 'active:scale-125'} ${isOptimisticBookmarked ? 'text-indigo-600' : 'text-slate-400 hover:text-indigo-400'}`}>
            <svg className={`w-5 h-5 md:w-6 md:h-6 ${isOptimisticBookmarked ? 'fill-current' : 'fill-none stroke-current'}`} viewBox="0 0 24 24" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" /></svg>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-4 md:p-6 border-t ${isDarkMode ? 'bg-slate-900/50 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
          <div className="space-y-4 mb-4">
            {post.comments.length === 0 ? (<p className="text-[10px] text-center text-slate-500 italic py-2">No response yet.</p>) : (
              post.comments.map(c => {
                const isReported = reportedCommentIds.has(c.id);
                return (
                  <div key={c.id} className="group flex gap-3 text-left">
                    <div className="w-7 h-7 rounded-lg bg-indigo-500 flex items-center justify-center text-white font-black text-[9px] shrink-0 uppercase">{c.username[0]}</div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between mb-0.5">
                        <span className="font-bold text-[11px] truncate">@{c.username}</span>
                        <div className="flex items-center gap-2">
                          <span className="text-[8px] text-slate-500 font-bold">{new Date(c.createdAt).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                          {currentUser && c.userId !== currentUser.id && (
                            <button disabled={isReported} onClick={() => setReportTarget({type: 'comment', id: c.id})} className={`text-[8px] font-black uppercase transition-all ${isReported ? 'text-slate-400 opacity-50' : 'opacity-0 group-hover:opacity-100 text-red-400 hover:text-red-500'}`}>{isReported ? 'Reported' : 'Report'}</button>
                          )}
                        </div>
                      </div>
                      <p className={`text-xs ${isDarkMode ? 'text-slate-300' : 'text-slate-600'}`}>{c.content}</p>
                    </div>
                  </div>
                );
              })
            )}
          </div>
          <form onSubmit={handleAddComment} className="flex gap-2">
            <input type="text" placeholder={isBanned ? "Suspended..." : "Your reply..."} disabled={isBanned} value={commentText} onChange={(e) => setCommentText(e.target.value)} className={`flex-1 px-4 py-2 rounded-xl text-xs outline-none transition-all ${isDarkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-white border-slate-200'} ${isBanned ? 'opacity-50' : ''}`} />
            <button type="submit" disabled={!commentText.trim() || isBanned} className="px-4 py-2 bg-indigo-600 text-white rounded-xl text-xs font-bold transition-all shadow-md disabled:opacity-50">Reply</button>
          </form>
        </div>
      )}

      {reportTarget && <ReportModal targetType={reportTarget.type} targetId={reportTarget.id} onClose={() => setReportTarget(null)} onSubmit={handleReport} isDarkMode={isDarkMode} />}
      {showEditModal && <EditPostModal post={post} isDarkMode={isDarkMode} onClose={() => setShowEditModal(false)} onUpdate={onPostUpdate} />}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { User, Post } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';
import { ReportModal } from './ReportModal';

interface ProfileProps {
  user: User;
  currentUser: User | null;
  posts: Post[];
  isDarkMode: boolean;
  onAccountDeleted: () => void;
  onLogout: () => void;
  onUserUpdate: (updatedUser: User) => void;
}

export const Profile: React.FC<ProfileProps> = ({ 
  user, 
  currentUser, 
  posts, 
  isDarkMode, 
  onAccountDeleted, 
  onLogout,
  onUserUpdate
}) => {
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [deleteError, setDeleteError] = useState('');

  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [editUsername, setEditUsername] = useState(user.username);
  const [editAvatar, setEditAvatar] = useState(user.avatar);
  const [editBio, setEditBio] = useState(user.bio || '');
  const [isSaving, setIsSaving] = useState(false);
  const [editError, setEditError] = useState('');

  const [showReportModal, setShowReportModal] = useState(false);
  const [hasReportedUser, setHasReportedUser] = useState(false);

  // App Options State
  const [settings, setSettings] = useState(user.settings || { showReportCount: true, showStats: true });
  const [isSavingSettings, setIsSavingSettings] = useState(false);

  const isOwnProfile = currentUser?.id === user.id;
  const isBanned = db.isBanned(user);
  const userPosts = posts.filter(p => p.userId === user.id);
  const totalReceivedLikes = userPosts.reduce((acc, post) => acc + post.likes, 0);

  useEffect(() => {
    if (!isEditingProfile) {
      setEditUsername(user.username);
      setEditAvatar(user.avatar);
      setEditBio(user.bio || '');
      setSettings(user.settings || { showReportCount: true, showStats: true });
      setEditError('');
    }

    const checkReportStatus = async () => {
      if (currentUser && !isOwnProfile) {
        const reported = await db.hasAlreadyReported(currentUser.id, 'user', user.id);
        setHasReportedUser(reported);
      }
    };
    checkReportStatus();
  }, [user.bio, user.username, user.avatar, user.settings, currentUser, isOwnProfile, user.id, isEditingProfile]);

  const handleDeleteAccount = async () => {
    setIsDeleting(true);
    setDeleteError('');
    try {
      const result = await db.deleteAccount(user.id);
      if (result.success) onAccountDeleted(); else {
        setDeleteError(result.error || 'Failed to delete account');
        setIsDeleting(false);
      }
    } catch (err) {
      setDeleteError('An unexpected error occurred');
      setIsDeleting(false);
    }
  };

  const handleShuffleAvatar = () => {
    const randomSeed = Math.random().toString(36).substring(7);
    setEditAvatar(`https://picsum.photos/seed/${randomSeed}/400`);
  };

  const handleSaveProfile = async () => {
    if (!editUsername.trim()) {
      setEditError("Username cannot be empty");
      return;
    }
    setIsSaving(true);
    try {
      const updated = await db.updateUserProfile(user.id, {
        username: editUsername,
        avatar: editAvatar,
        bio: editBio
      });
      if (updated) {
        onUserUpdate(updated);
        setIsEditingProfile(false);
      } else {
        setEditError("Username taken or network error.");
      }
    } finally {
      setIsSaving(false);
    }
  };

  const handleToggleSetting = async (key: 'showReportCount' | 'showStats') => {
    if (!isOwnProfile) return;
    const newSettings = { ...settings, [key]: !settings[key] };
    setSettings(newSettings);
    setIsSavingSettings(true);
    const updated = await db.updateUserSettings(user.id, newSettings);
    if (updated) onUserUpdate(updated);
    setIsSavingSettings(false);
  };

  const handleReportUser = async (reason: string) => {
    if (!currentUser) return;
    const result = await db.reportEntity(currentUser.id, 'user', user.id, reason);
    if (result.success) setHasReportedUser(true);
    setShowReportModal(false);
    alert(result.message);
  };

  return (
    <div className="max-w-3xl mx-auto py-4 md:py-8 space-y-6">
      {isBanned && (
        <div className="p-4 rounded-2xl bg-red-600 text-white font-bold flex items-center justify-between shadow-lg">
          <div className="flex items-center gap-3">
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
             <p className="text-sm">Account Suspended until {new Date(user.bannedUntil!).toLocaleString()}</p>
          </div>
        </div>
      )}

      <div className={`p-6 md:p-8 rounded-3xl border transition-all relative ${
        isDarkMode ? 'bg-slate-900 border-slate-800 text-white' : 'bg-white border-slate-100 shadow-xl text-slate-900'
      }`}>
        <div className="absolute top-4 right-4 md:top-6 md:right-6 flex gap-4">
          {!isOwnProfile && currentUser && (
            <button disabled={hasReportedUser} onClick={() => setShowReportModal(true)} className={`text-[10px] font-black uppercase transition-colors flex items-center gap-2 ${hasReportedUser ? 'text-slate-400 opacity-50' : 'text-red-400 hover:text-red-500'}`}>
              {hasReportedUser ? 'Reported' : 'Report'}
            </button>
          )}
          {isOwnProfile && (
            <button onClick={onLogout} className="text-[10px] font-black uppercase text-slate-400 hover:text-indigo-500 flex items-center gap-2">Logout</button>
          )}
        </div>

        {isEditingProfile ? (
          <div className="space-y-6">
            <h2 className="text-xl font-serif font-bold">Edit Identity</h2>
            <div className="flex flex-col md:flex-row gap-8">
               <div className="flex flex-col items-center gap-4">
                  <div className="relative group cursor-pointer" onClick={handleShuffleAvatar}>
                    <img src={editAvatar} className="w-32 h-32 rounded-3xl object-cover shadow-2xl ring-4 ring-indigo-500/20" alt="Preview" />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 rounded-3xl flex items-center justify-center transition-all">
                      <span className="text-white text-[10px] font-black uppercase">Shuffle</span>
                    </div>
                  </div>
                  <input type="text" value={editAvatar} onChange={(e) => setEditAvatar(e.target.value)} className="w-full p-2 text-[10px] rounded-lg border dark:bg-slate-800 dark:border-slate-700" placeholder="Avatar URL..." />
               </div>
               <div className="flex-1 space-y-4">
                  <div>
                    <label className="text-[10px] font-black uppercase text-slate-400 block mb-1">Username</label>
                    <input type="text" value={editUsername} onChange={(e) => setEditUsername(e.target.value.toLowerCase().replace(/\s/g, ''))} className="w-full p-3 text-sm rounded-xl border dark:bg-slate-800 dark:border-slate-700" />
                  </div>
                  <div>
                    <label className="text-[10px] font-black uppercase text-slate-400 block mb-1">Bio</label>
                    <textarea value={editBio} onChange={(e) => setEditBio(e.target.value)} maxLength={160} rows={3} className="w-full p-3 text-sm rounded-xl border dark:bg-slate-800 dark:border-slate-700 resize-none" />
                  </div>
               </div>
            </div>
            <div className="flex gap-3 pt-4">
              <button onClick={handleSaveProfile} disabled={isSaving} className="flex-1 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase shadow-lg disabled:opacity-50">Save Changes</button>
              <button onClick={() => setIsEditingProfile(false)} className="flex-1 py-3 border rounded-xl text-[10px] font-black uppercase">Cancel</button>
            </div>
          </div>
        ) : (
          <div className="flex flex-col items-center md:items-start text-center md:text-left">
            <div className="relative group mb-6">
              <img src={user.avatar} className={`w-24 h-24 md:w-32 md:h-32 rounded-3xl object-cover shadow-2xl ring-4 ${isBanned ? 'ring-red-500/50' : 'ring-indigo-500/20'}`} alt={user.username} />
              {isOwnProfile && (
                <button onClick={() => setIsEditingProfile(true)} className="absolute -bottom-2 -right-2 bg-indigo-600 text-white p-2 rounded-xl opacity-0 group-hover:opacity-100 transition-all">Edit</button>
              )}
            </div>
            <h1 className="text-2xl md:text-3xl font-serif font-bold mb-2">@{user.username}</h1>
            <div className="flex gap-2 mb-4">
              <BadgeIcon tier={user.badge} size="md" />
              {(isOwnProfile || settings.showReportCount) && user.reportCount! > 0 && (
                <span className="text-[10px] font-black uppercase text-red-500 py-1 px-3 bg-red-500/10 rounded-full">Alerts: {user.reportCount}</span>
              )}
            </div>
            <p className="text-sm text-slate-500 max-w-lg mb-8">{user.bio || (isOwnProfile ? "No bio yet." : "Mysterious storyteller.")}</p>

            {(isOwnProfile || settings.showStats) && (
              <div className="grid grid-cols-3 gap-8 w-full py-6 border-y border-slate-100 dark:border-slate-800">
                <div className="text-center"><p className="text-xl font-bold">{userPosts.length}</p><p className="text-[9px] font-black uppercase text-slate-400">Stories</p></div>
                <div className="text-center"><p className="text-xl font-bold">{totalReceivedLikes}</p><p className="text-[9px] font-black uppercase text-slate-400">Likes</p></div>
                <div className="text-center"><p className="text-xl font-bold">{user.followerCount}</p><p className="text-[9px] font-black uppercase text-slate-400">Followers</p></div>
              </div>
            )}
          </div>
        )}
      </div>

      {isOwnProfile && (
        <div className={`p-6 md:p-8 rounded-3xl border ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-lg'}`}>
          <h2 className="font-serif text-lg font-bold mb-4">Account Preferences</h2>
          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <div><p className="text-xs font-bold uppercase">Show Public Stats</p><p className="text-[10px] text-slate-400">Visibility of your follower count and total likes.</p></div>
              <button onClick={() => handleToggleSetting('showStats')} className={`w-10 h-5 rounded-full relative transition-all ${settings.showStats ? 'bg-indigo-600' : 'bg-slate-300'}`}><div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${settings.showStats ? 'right-1' : 'left-1'}`} /></button>
            </div>
            <div className="flex items-center justify-between border-t dark:border-slate-800 pt-4">
              <div><p className="text-xs font-bold uppercase">Report Visibility</p><p className="text-[10px] text-slate-400">Whether others can see your report count badge.</p></div>
              <button onClick={() => handleToggleSetting('showReportCount')} className={`w-10 h-5 rounded-full relative transition-all ${settings.showReportCount ? 'bg-red-600' : 'bg-slate-300'}`}><div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${settings.showReportCount ? 'right-1' : 'left-1'}`} /></button>
            </div>
            <div className="pt-6">
              {!showConfirmDelete ? (
                <button onClick={() => setShowConfirmDelete(true)} className="text-[10px] font-bold text-red-500 hover:underline uppercase">Delete Identity</button>
              ) : (
                <div className="flex gap-4 items-center">
                  <p className="text-[10px] text-red-600 font-bold">Irreversible. Proceed?</p>
                  <button onClick={handleDeleteAccount} className="px-3 py-1 bg-red-600 text-white rounded text-[10px] uppercase font-bold">Yes</button>
                  <button onClick={() => setShowConfirmDelete(false)} className="px-3 py-1 border rounded text-[10px] uppercase font-bold">No</button>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {showReportModal && <ReportModal targetType="user" targetId={user.id} onClose={() => setShowReportModal(false)} onSubmit={handleReportUser} isDarkMode={isDarkMode} />}
    </div>
  );
};

import { createClient } from '@supabase/supabase-js';
import { Post, User, BadgeTier, Comment, ReportType } from '../types';

const SUPABASE_URL = (process.env as any).SUPABASE_URL || 'https://uvjavqzhhqxkfuklkxdo.supabase.co';
const SUPABASE_ANON_KEY = (process.env as any).SUPABASE_ANON_KEY || 'sb_publishable_-GDZiq_v45oEVhlly7tG-w_cKockqn6';

const isConfigured = SUPABASE_URL !== 'https://your-project-url.supabase.co' && SUPABASE_ANON_KEY !== 'your-anon-key';
const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);
const SESSION_KEY = 'storyverse_session';

export const getBadge = (likes: number): BadgeTier => {
  if (likes >= 500) return BadgeTier.PLATINUM;
  if (likes >= 100) return BadgeTier.GOLD;
  if (likes >= 25) return BadgeTier.SILVER;
  if (likes >= 5) return BadgeTier.BRONZE;
  return BadgeTier.NOVICE;
};

export const db = {
  // --- Auth ---
  async register(username: string, email: string, password: string): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };

    // STRICT EMAIL VALIDATION: Only gmail.com allowed
    if (!email.toLowerCase().endsWith('@gmail.com')) {
      return { success: false, error: 'Access denied. Only @gmail.com addresses are permitted for registration.' };
    }

    try {
      const userId = Math.random().toString(36).substr(2, 9);
      const userPayload = {
        id: userId,
        username: username.toLowerCase().trim(),
        email: email.toLowerCase().trim(),
        password: password,
        avatar: `https://picsum.photos/seed/${username}/100`,
        bio: '',
        bookmarks: [],
        total_likes: 0,
        badge: BadgeTier.NOVICE,
        report_count: 0,
        settings: { showReportCount: true, showStats: true }
      };

      const { error } = await supabase.from('users').insert([userPayload]);
      if (error) {
        if (error.message.includes('unique constraint')) return { success: false, error: 'Username or Email already taken.' };
        return { success: false, error: error.message };
      }

      const user: User = {
        id: userId,
        username: userPayload.username,
        email: userPayload.email,
        avatar: userPayload.avatar,
        bio: '',
        bookmarks: [],
        totalLikes: 0,
        badge: BadgeTier.NOVICE,
        followerCount: 0,
        followingCount: 0,
        reportCount: 0,
        settings: userPayload.settings
      };

      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return { success: true, user };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  // --- Profile & Settings Methods ---
  async updateUserAvatar(userId: string, avatarUrl: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      // Update user table
      const { error: userError } = await supabase.from('users').update({ avatar: avatarUrl }).eq('id', userId);
      if (userError) throw userError;

      // Propagate change to posts table (denormalized user_avatar)
      await supabase.from('posts').update({ user_avatar: avatarUrl }).eq('user_id', userId);

      return await this.refreshUser(userId);
    } catch (err) {
      console.error("Update avatar error:", err);
      return null;
    }
  },

  async updateUserSettings(userId: string, settings: any): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { error } = await supabase.from('users').update({ settings }).eq('id', userId);
      if (error) throw error;
      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  async updateUserProfile(userId: string, data: { username?: string; avatar?: string; bio?: string }): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const updatePayload: any = {};
      if (data.username !== undefined) updatePayload.username = data.username.toLowerCase();
      if (data.avatar !== undefined) updatePayload.avatar = data.avatar;
      if (data.bio !== undefined) updatePayload.bio = data.bio;

      const { error } = await supabase.from('users').update(updatePayload).eq('id', userId);
      if (error) throw error;

      if (data.username || data.avatar) {
        const postUpdate: any = {};
        if (data.username) postUpdate.username = data.username.toLowerCase();
        if (data.avatar) postUpdate.user_avatar = data.avatar;
        await supabase.from('posts').update(postUpdate).eq('user_id', userId);
      }

      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  // --- Post Methods ---
  async updatePostContent(postId: string, title: string, content: string): Promise<boolean> {
    if (!isConfigured) return false;
    try {
      const { error } = await supabase.from('posts').update({
        title,
        content,
        last_edited_at: new Date().toISOString()
      }).eq('id', postId);
      return !error;
    } catch {
      return false;
    }
  },

  isBanned(user: User | null): boolean {
    if (!user || !user.bannedUntil) return false;
    return new Date(user.bannedUntil) > new Date();
  },

  async getPosts(): Promise<Post[]> {
    if (!isConfigured) return [];
    try {
      const { data, error } = await supabase
        .from('posts')
        .select(`*, comments (*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      return (data || []).map(post => ({
        id: post.id,
        userId: post.user_id,
        username: post.username,
        title: post.title,
        content: post.content,
        likes: post.likes || 0,
        likedBy: post.liked_by || [],
        shares: post.shares || 0,
        createdAt: post.created_at,
        userAvatar: post.user_avatar,
        reportCount: post.report_count || 0,
        lastEditedAt: post.last_edited_at,
        comments: (post.comments || []).map((c: any) => ({
          id: c.id,
          userId: c.user_id,
          username: c.username,
          content: c.content,
          createdAt: c.created_at,
          reportCount: c.report_count || 0
        }))
      }));
    } catch (err) {
      return [];
    }
  },

  async savePost(post: Post): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Suspended account.");
    if (!isConfigured) return;
    await supabase.from('posts').insert([{
      id: post.id,
      user_id: post.userId,
      username: post.username,
      title: post.title,
      content: post.content,
      likes: post.likes,
      liked_by: post.likedBy,
      shares: post.shares,
      user_avatar: post.userAvatar,
      created_at: post.createdAt,
      report_count: 0
    }]);
  },

  async updatePost(updatedPost: Post): Promise<void> {
    if (!isConfigured) return;
    await supabase.from('posts').update({
      likes: updatedPost.likes,
      liked_by: updatedPost.likedBy,
      shares: updatedPost.shares,
      title: updatedPost.title,
      content: updatedPost.content
    }).eq('id', updatedPost.id);
  },

  async deletePost(postId: string): Promise<{ success: boolean; error?: string }> {
    if (!isConfigured) return { success: false };
    try {
      await supabase.from('comments').delete().eq('post_id', postId);
      await supabase.from('posts').delete().eq('id', postId);
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async addComment(postId: string, comment: Comment): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Suspended account.");
    if (!isConfigured) return;
    await supabase.from('comments').insert([{
      id: comment.id,
      post_id: postId,
      user_id: comment.userId,
      username: comment.username,
      content: comment.content,
      created_at: comment.createdAt,
      report_count: 0
    }]);
  },

  async getUserById(userId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data, error } = await supabase.from('users').select('*').eq('id', userId).maybeSingle();
      if (error || !data) return null;
      const stats = await this.getFollowStats(data.id);
      return {
        id: data.id,
        username: data.username,
        email: data.email,
        avatar: data.avatar,
        bio: data.bio || '',
        bookmarks: data.bookmarks || [],
        totalLikes: data.total_likes || 0,
        badge: (data.badge as BadgeTier) || BadgeTier.NOVICE,
        followerCount: stats.followers,
        followingCount: stats.following,
        reportCount: data.report_count || 0,
        bannedUntil: data.banned_until,
        settings: data.settings || { showReportCount: true, showStats: true }
      };
    } catch (err) {
      return null;
    }
  },

  async refreshUser(userId: string): Promise<User | null> {
    const user = await this.getUserById(userId);
    if (user) localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    return user;
  },

  async toggleBookmark(userId: string, postId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data: user } = await supabase.from('users').select('bookmarks').eq('id', userId).maybeSingle();
      if (!user) return null;
      let bookmarks = Array.isArray(user.bookmarks) ? user.bookmarks : [];
      const newBookmarks = bookmarks.includes(postId)
        ? bookmarks.filter((id: string) => id !== postId)
        : [...bookmarks, postId];
      await supabase.from('users').update({ bookmarks: newBookmarks }).eq('id', userId);
      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  async updateUserLikes(userId: string, delta: number): Promise<void> {
    if (!isConfigured) return;
    const { data: dbUser } = await supabase.from('users').select('total_likes').eq('id', userId).maybeSingle();
    if (!dbUser) return;
    const newTotalLikes = Math.max(0, (dbUser.total_likes || 0) + delta);
    const newBadge = getBadge(newTotalLikes);
    await supabase.from('users').update({ total_likes: newTotalLikes, badge: newBadge }).eq('id', userId);
  },

  async updateUserBio(userId: string, bio: string): Promise<User | null> {
    return this.updateUserProfile(userId, { bio });
  },

  async reportEntity(reporterId: string, targetType: ReportType, targetId: string, reason: string): Promise<{ success: boolean; message: string }> {
    if (!isConfigured) return { success: false, message: 'Backend not configured.' };
    try {
      const alreadyReported = await this.hasAlreadyReported(reporterId, targetType, targetId);
      if (alreadyReported) return { success: false, message: 'Already reported.' };
      let table = targetType === 'user' ? 'users' : (targetType === 'post' ? 'posts' : 'comments');
      await supabase.from('reports').insert([{ id: Math.random().toString(36).substr(2, 9), reporter_id: reporterId, target_type: targetType, target_id: targetId, reason }]);
      const { data } = await supabase.from(table).select('report_count').eq('id', targetId).maybeSingle();
      const newCount = (data?.report_count || 0) + 1;
      await supabase.from(table).update({ report_count: newCount }).eq('id', targetId);
      return { success: true, message: 'Report submitted.' };
    } catch {
      return { success: false, message: 'Error submitting report.' };
    }
  },

  async hasAlreadyReported(reporterId: string, targetType: ReportType, targetId: string): Promise<boolean> {
    const { data } = await supabase.from('reports').select('id').eq('reporter_id', reporterId).eq('target_type', targetType).eq('target_id', targetId).maybeSingle();
    return !!data;
  },

  getCurrentUser(): User | null {
    try {
      const session = localStorage.getItem(SESSION_KEY);
      return session ? JSON.parse(session) : null;
    } catch {
      return null;
    }
  },

  async login(identifier: string, password: string, method: 'username' | 'email'): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };
    const field = method === 'username' ? 'username' : 'email';
    try {
      const { data, error } = await supabase.from('users').select('*').ilike(field, identifier).eq('password', password).maybeSingle();
      if (error) return { success: false, error: error.message };
      if (!data) return { success: false, error: 'Invalid credentials.' };
      const user = await this.refreshUser(data.id);
      return user ? { success: true, user } : { success: false, error: 'Session error.' };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async getFollowStats(userId: string): Promise<{ followers: number, following: number }> {
    try {
      const { count: followers } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('following_id', userId);
      const { count: following } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('follower_id', userId);
      return { followers: followers || 0, following: following || 0 };
    } catch { return { followers: 0, following: 0 }; }
  },

  async isFollowing(followerId: string, followingId: string): Promise<boolean> {
    const { data } = await supabase.from('follows').select('*').eq('follower_id', followerId).eq('following_id', followingId).maybeSingle();
    return !!data;
  },

  async followUser(followerId: string, followingId: string): Promise<{ follower: User | null, following: User | null }> {
    await supabase.from('follows').insert([{ follower_id: followerId, following_id: followingId }]);
    return { follower: await this.refreshUser(followerId), following: await this.getUserById(followingId) };
  },

  async unfollowUser(followerId: string, followingId: string): Promise<{ follower: User | null, following: User | null }> {
    await supabase.from('follows').delete().eq('follower_id', followerId).eq('following_id', followingId);
    return { follower: await this.refreshUser(followerId), following: await this.getUserById(followingId) };
  },

  async deleteAccount(userId: string): Promise<{ success: boolean, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Database not connected.' };
    try {
      // 1. Delete all follows involving this user
      await supabase.from('follows').delete().or(`follower_id.eq.${userId},following_id.eq.${userId}`);

      // 2. Delete all reports involving this user
      await supabase.from('reports').delete().or(`reporter_id.eq.${userId},target_id.eq.${userId}`);

      // 3. Delete comments by this user
      await supabase.from('comments').delete().eq('user_id', userId);

      // 4. Handle posts by this user
      const { data: userPosts } = await supabase.from('posts').select('id').eq('user_id', userId);
      if (userPosts && userPosts.length > 0) {
        const postIds = userPosts.map(p => p.id);
        // Delete comments on these posts first
        await supabase.from('comments').delete().in('post_id', postIds);
        // Delete the posts
        await supabase.from('posts').delete().in('id', postIds);
      }

      // 5. Delete user record
      const { error } = await supabase.from('users').delete().eq('id', userId);
      if (error) throw error;

      this.logout();
      return { success: true };
    } catch (err: any) {
      console.error("Critical Deletion Failure:", err);
      return { success: false, error: err.message };
    }
  },

  logout() { localStorage.removeItem(SESSION_KEY); }
};

import React, { useState, useEffect, useRef } from 'react';
import { User, Post } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';
import { ReportModal } from './ReportModal';

interface ProfileProps {
  user: User;
  currentUser: User | null;
  posts: Post[];
  isDarkMode: boolean;
  onAccountDeleted: () => void;
  onLogout: () => void;
  onUserUpdate: (updatedUser: User) => void;
}

export const Profile: React.FC<ProfileProps> = ({ 
  user, 
  currentUser, 
  posts, 
  isDarkMode, 
  onAccountDeleted, 
  onLogout,
  onUserUpdate
}) => {
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [deleteError, setDeleteError] = useState('');

  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [editUsername, setEditUsername] = useState(user.username);
  const [editAvatar, setEditAvatar] = useState(user.avatar);
  const [editBio, setEditBio] = useState(user.bio || '');
  const [isSaving, setIsSaving] = useState(false);
  const [editError, setEditError] = useState('');

  const [showReportModal, setShowReportModal] = useState(false);
  const [hasReportedUser, setHasReportedUser] = useState(false);

  // App Options State
  const [settings, setSettings] = useState(user.settings || { showReportCount: true, showStats: true });
  const [isSavingSettings, setIsSavingSettings] = useState(false);

  const isOwnProfile = currentUser?.id === user.id;
  const isBanned = db.isBanned(user);
  const userPosts = posts.filter(p => p.userId === user.id);
  const totalReceivedLikes = userPosts.reduce((acc, post) => acc + post.likes, 0);

  useEffect(() => {
    if (!isEditingProfile) {
      setEditUsername(user.username);
      setEditAvatar(user.avatar);
      setEditBio(user.bio || '');
      setSettings(user.settings || { showReportCount: true, showStats: true });
      setEditError('');
    }

    const checkReportStatus = async () => {
      if (currentUser && !isOwnProfile) {
        const reported = await db.hasAlreadyReported(currentUser.id, 'user', user.id);
        setHasReportedUser(reported);
      }
    };
    checkReportStatus();
  }, [user.bio, user.username, user.avatar, user.settings, currentUser, isOwnProfile, user.id, isEditingProfile]);

  const handleDeleteAccount = async () => {
    if (!window.confirm("CRITICAL: This will permanently erase your stories, comments, and identity from the Verse. Continue?")) {
      setShowConfirmDelete(false);
      return;
    }

    setIsDeleting(true);
    setDeleteError('');
    try {
      const result = await db.deleteAccount(user.id);
      if (result.success) {
        onAccountDeleted();
      } else {
        const msg = result.error || 'Failed to delete account';
        setDeleteError(msg);
        alert(`Error: ${msg}`);
        setIsDeleting(false);
      }
    } catch (err) {
      const msg = 'An unexpected error occurred during identity purging.';
      setDeleteError(msg);
      alert(msg);
      setIsDeleting(false);
    }
  };

  const handleShuffleAvatar = () => {
    const randomSeed = Math.random().toString(36).substring(7);
    setEditAvatar(`https://picsum.photos/seed/${randomSeed}/400`);
  };

  const handleSaveProfile = async () => {
    if (!editUsername.trim()) {
      setEditError("Username cannot be empty");
      return;
    }
    setIsSaving(true);
    try {
      const updated = await db.updateUserProfile(user.id, {
        username: editUsername,
        avatar: editAvatar,
        bio: editBio
      });
      if (updated) {
        onUserUpdate(updated);
        setIsEditingProfile(false);
      } else {
        setEditError("Username taken or network error.");
      }
    } finally {
      setIsSaving(false);
    }
  };

  const handleToggleSetting = async (key: 'showReportCount' | 'showStats') => {
    if (!isOwnProfile) return;
    const newSettings = { ...settings, [key]: !settings[key] };
    setSettings(newSettings);
    setIsSavingSettings(true);
    const updated = await db.updateUserSettings(user.id, newSettings);
    if (updated) onUserUpdate(updated);
    setIsSavingSettings(false);
  };

  const handleReportUser = async (reason: string) => {
    if (!currentUser) return;
    const result = await db.reportEntity(currentUser.id, 'user', user.id, reason);
    if (result.success) setHasReportedUser(true);
    setShowReportModal(false);
    alert(result.message);
