          <div className="flex flex-col items-center md:items-start text-center md:text-left">
            <div className="relative group mb-6">
              <img src={user.avatar} className={`w-24 h-24 md:w-32 md:h-32 rounded-3xl object-cover shadow-2xl ring-4 ${isBanned ? 'ring-red-500/50' : 'ring-indigo-500/20'}`} alt={user.username} />
              {isOwnProfile && (
                <button onClick={() => setIsEditingProfile(true)} className="absolute -bottom-2 -right-2 bg-indigo-600 text-white p-2 rounded-xl opacity-0 group-hover:opacity-100 transition-all">Edit</button>
              )}
            </div>
            <h1 className="text-2xl md:text-3xl font-serif font-bold mb-2">@{user.username}</h1>
            <div className="flex gap-2 mb-4">
              <BadgeIcon tier={user.badge} size="md" />
              {(isOwnProfile || settings.showReportCount) && user.reportCount! > 0 && (
                <span className="text-[10px] font-black uppercase text-red-500 py-1 px-3 bg-red-500/10 rounded-full">Alerts: {user.reportCount}</span>
              )}
            </div>
            <p className="text-sm text-slate-500 max-w-lg mb-8">{user.bio || (isOwnProfile ? "No bio yet." : "Mysterious storyteller.")}</p>

            {(isOwnProfile || settings.showStats) && (
              <div className="grid grid-cols-3 gap-8 w-full py-6 border-y border-slate-100 dark:border-slate-800">
                <div className="text-center"><p className="text-xl font-bold">{userPosts.length}</p><p className="text-[9px] font-black uppercase text-slate-400">Stories</p></div>
                <div className="text-center"><p className="text-xl font-bold">{totalReceivedLikes}</p><p className="text-[9px] font-black uppercase text-slate-400">Likes</p></div>
                <div className="text-center"><p className="text-xl font-bold">{user.followerCount}</p><p className="text-[9px] font-black uppercase text-slate-400">Followers</p></div>
              </div>
            )}
          </div>
        )}
      </div>

      {isOwnProfile && (
        <div className={`p-6 md:p-8 rounded-3xl border transition-all ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-lg'}`}>
          <h2 className="font-serif text-lg font-bold mb-6">Account Preferences</h2>
          <div className="space-y-6">
            <div className="flex items-center justify-between">
              <div><p className="text-xs font-bold uppercase tracking-tight">Show Public Stats</p><p className="text-[10px] text-slate-400">Visibility of your follower count and total likes.</p></div>
              <button onClick={() => handleToggleSetting('showStats')} className={`w-10 h-5 rounded-full relative transition-all ${settings.showStats ? 'bg-indigo-600' : 'bg-slate-300'}`}><div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${settings.showStats ? 'right-1' : 'left-1'}`} /></button>
            </div>
            <div className="flex items-center justify-between border-t dark:border-slate-800 pt-6">
              <div><p className="text-xs font-bold uppercase tracking-tight">Report Visibility</p><p className="text-[10px] text-slate-400">Whether others can see your report count badge.</p></div>
              <button onClick={() => handleToggleSetting('showReportCount')} className={`w-10 h-5 rounded-full relative transition-all ${settings.showReportCount ? 'bg-red-600' : 'bg-slate-300'}`}><div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${settings.showReportCount ? 'right-1' : 'left-1'}`} /></button>
            </div>

            <div className="pt-6 border-t dark:border-slate-800">
              {!showConfirmDelete ? (
                <button 
                  onClick={() => setShowConfirmDelete(true)} 
                  className="text-[11px] font-black uppercase tracking-[0.1em] text-red-500 hover:text-red-600 transition-colors"
                >
                  Delete Identity
                </button>
              ) : (
                <div className="flex flex-col sm:flex-row sm:items-center gap-4 animate-in slide-in-from-bottom-2 duration-300">
                  <p className="text-[11px] text-red-600 font-bold uppercase tracking-tight whitespace-nowrap">
                    Erase all data permanently?
                  </p>
                  <div className="flex gap-3">
                    <button 
                      onClick={handleDeleteAccount} 
                      disabled={isDeleting} 
                      className="px-5 py-2 bg-red-600 text-white rounded-xl text-[10px] uppercase font-black tracking-widest shadow-lg hover:bg-red-700 active:scale-95 transition-all flex items-center gap-2"
                    >
                      {isDeleting ? (
                        <>
                          <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                          Purging...
                        </>
                      ) : 'Confirm Purge'}
                    </button>
                    <button 
                      onClick={() => { setShowConfirmDelete(false); setDeleteError(''); }} 
                      disabled={isDeleting}
                      className={`px-5 py-2 rounded-xl text-[10px] uppercase font-black tracking-widest transition-all ${
                        isDarkMode ? 'bg-slate-800 text-white hover:bg-slate-700' : 'bg-slate-900 text-white hover:bg-slate-800'
                      }`}
                    >
                      Cancel
                    </button>
                  </div>
                  {deleteError && (
                    <div className="p-2 bg-red-500/10 border border-red-500/20 rounded-lg sm:ml-auto">
                      <p className="text-[10px] text-red-500 font-bold leading-tight">{deleteError}</p>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {showReportModal && <ReportModal targetType="user" targetId={user.id} onClose={() => setShowReportModal(false)} onSubmit={handleReportUser} isDarkMode={isDarkMode} />}
    </div>
  );
};

import { createClient } from '@supabase/supabase-js';
import { Post, User, BadgeTier, Comment, ReportType } from '../types';

const SUPABASE_URL = (process.env as any).SUPABASE_URL || 'https://uvjavqzhhqxkfuklkxdo.supabase.co';
const SUPABASE_ANON_KEY = (process.env as any).SUPABASE_ANON_KEY || 'sb_publishable_-GDZiq_v45oEVhlly7tG-w_cKockqn6';

const isConfigured = SUPABASE_URL !== 'https://your-project-url.supabase.co' && SUPABASE_ANON_KEY !== 'your-anon-key';
const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);
const SESSION_KEY = 'storyverse_session';

export const getBadge = (likes: number): BadgeTier => {
  if (likes >= 500) return BadgeTier.PLATINUM;
  if (likes >= 100) return BadgeTier.GOLD;
  if (likes >= 25) return BadgeTier.SILVER;
  if (likes >= 5) return BadgeTier.BRONZE;
  return BadgeTier.NOVICE;
};

export const db = {
  // --- Auth ---
  async register(username: string, email: string, password: string): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };

    const lowerEmail = email.toLowerCase().trim();
    if (!lowerEmail.endsWith('@gmail.com')) {
      return { success: false, error: 'Registration restricted to @gmail.com addresses only.' };
    }

    try {
      const userId = Math.random().toString(36).substr(2, 9);
      const userPayload = {
        id: userId,
        username: username.toLowerCase().trim(),
        email: lowerEmail,
        password: password,
        avatar: `https://picsum.photos/seed/${username}/100`,
        bio: '',
        bookmarks: [],
        total_likes: 0,
        badge: BadgeTier.NOVICE,
        report_count: 0
        // Removed settings from database payload to avoid "column not found" error
      };

      const { error } = await supabase.from('users').insert([userPayload]);
      if (error) {
        if (error.message.includes('unique constraint')) return { success: false, error: 'Username or Email already taken.' };
        return { success: false, error: error.message };
      }

      const user: User = {
        id: userId,
        username: userPayload.username,
        email: userPayload.email,
        avatar: userPayload.avatar,
        bio: '',
        bookmarks: [],
        totalLikes: 0,
        badge: BadgeTier.NOVICE,
        followerCount: 0,
        followingCount: 0,
        reportCount: 0,
        settings: { showReportCount: true, showStats: true } // Default local settings
      };

      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return { success: true, user };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async updateUserAvatar(userId: string, avatarUrl: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      await supabase.from('users').update({ avatar: avatarUrl }).eq('id', userId);
      await supabase.from('posts').update({ user_avatar: avatarUrl }).eq('user_id', userId);
      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  async updateUserSettings(userId: string, settings: any): Promise<User | null> {
    const currentUser = this.getCurrentUser();
    if (currentUser && currentUser.id === userId) {
      const updatedUser = { ...currentUser, settings };
      localStorage.setItem(SESSION_KEY, JSON.stringify(updatedUser));
      return updatedUser;
    }
    return null;
  },

  async updateUserProfile(userId: string, data: { username?: string; avatar?: string; bio?: string }): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const updatePayload: any = {};
      if (data.username !== undefined) updatePayload.username = data.username.toLowerCase();
      if (data.avatar !== undefined) updatePayload.avatar = data.avatar;
      if (data.bio !== undefined) updatePayload.bio = data.bio;

      await supabase.from('users').update(updatePayload).eq('id', userId);

      if (data.username || data.avatar) {
        const postUpdate: any = {};
        if (data.username) postUpdate.username = data.username.toLowerCase();
        if (data.avatar) postUpdate.user_avatar = data.avatar;
        await supabase.from('posts').update(postUpdate).eq('user_id', userId);
      }

      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  async updatePostContent(postId: string, title: string, content: string): Promise<boolean> {
    if (!isConfigured) return false;
    try {
      const { error } = await supabase.from('posts').update({
        title,
        content,
        last_edited_at: new Date().toISOString()
      }).eq('id', postId);
      return !error;
    } catch {
      return false;
    }
  },

  isBanned(user: User | null): boolean {
    if (!user || !user.bannedUntil) return false;
    return new Date(user.bannedUntil) > new Date();
  },

  async getPosts(): Promise<Post[]> {
    if (!isConfigured) return [];
    try {
      const { data, error } = await supabase
        .from('posts')
        .select(`*, comments (*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      return (data || []).map(post => ({
        id: post.id,
        userId: post.user_id,
        username: post.username,
        title: post.title,
        content: post.content,
        likes: post.likes || 0,
        likedBy: post.liked_by || [],
        shares: post.shares || 0,
        createdAt: post.created_at,
        userAvatar: post.user_avatar,
        reportCount: post.report_count || 0,
        lastEditedAt: post.last_edited_at,
        comments: (post.comments || []).map((c: any) => ({
          id: c.id,
          userId: c.user_id,
          username: c.username,
          content: c.content,
          createdAt: c.created_at,
          reportCount: c.report_count || 0
        }))
      }));
    } catch (err) {
      return [];
    }
  },

  async savePost(post: Post): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Suspended account.");
    if (!isConfigured) return;
    await supabase.from('posts').insert([{
      id: post.id,
      user_id: post.userId,
      username: post.username,
      title: post.title,
      content: post.content,
      likes: post.likes,
      liked_by: post.likedBy,
      shares: post.shares,
      user_avatar: post.userAvatar,
      created_at: post.createdAt,
      report_count: 0
    }]);
  },

  async updatePost(updatedPost: Post): Promise<void> {
    if (!isConfigured) return;
    await supabase.from('posts').update({
      likes: updatedPost.likes,
      liked_by: updatedPost.likedBy,
      shares: updatedPost.shares,
      title: updatedPost.title,
      content: updatedPost.content
    }).eq('id', updatedPost.id);
  },

  async deletePost(postId: string): Promise<{ success: boolean; error?: string }> {
    if (!isConfigured) return { success: false };
    try {
      const { error: commError } = await supabase.from('comments').delete().eq('post_id', postId);
      if (commError) throw commError;
      const { error: postError } = await supabase.from('posts').delete().eq('id', postId);
      if (postError) throw postError;
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async addComment(postId: string, comment: Comment): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Suspended account.");
    if (!isConfigured) return;
    await supabase.from('comments').insert([{
      id: comment.id,
      post_id: postId,
      user_id: comment.userId,
      username: comment.username,
      content: comment.content,
      created_at: comment.createdAt,
      report_count: 0
    }]);
  },

  async getUserById(userId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data, error } = await supabase.from('users').select('*').eq('id', userId).maybeSingle();
      if (error || !data) return null;
      const stats = await this.getFollowStats(data.id);
      return {
        id: data.id,
        username: data.username,
        email: data.email,
        avatar: data.avatar,
        bio: data.bio || '',
        bookmarks: data.bookmarks || [],
        totalLikes: data.total_likes || 0,
        badge: (data.badge as BadgeTier) || BadgeTier.NOVICE,
        followerCount: stats.followers,
        followingCount: stats.following,
        reportCount: data.report_count || 0,
        bannedUntil: data.banned_until,
        settings: { showReportCount: true, showStats: true } // Default settings as DB column is missing
      };
    } catch (err) {
      return null;
    }
  },

  async refreshUser(userId: string): Promise<User | null> {
    const user = await this.getUserById(userId);
    if (user) {
      const current = this.getCurrentUser();
      if (current && current.id === userId && current.settings) {
        user.settings = current.settings;
      }
      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    }
    return user;
  },

  async toggleBookmark(userId: string, postId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data: user } = await supabase.from('users').select('bookmarks').eq('id', userId).maybeSingle();
      if (!user) return null;
      let bookmarks = Array.isArray(user.bookmarks) ? user.bookmarks : [];
      const newBookmarks = bookmarks.includes(postId)
        ? bookmarks.filter((id: string) => id !== postId)
        : [...bookmarks, postId];
      await supabase.from('users').update({ bookmarks: newBookmarks }).eq('id', userId);
      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  async updateUserLikes(userId: string, delta: number): Promise<void> {
    if (!isConfigured) return;
    const { data: dbUser } = await supabase.from('users').select('total_likes').eq('id', userId).maybeSingle();
    if (!dbUser) return;
    const newTotalLikes = Math.max(0, (dbUser.total_likes || 0) + delta);
    const newBadge = getBadge(newTotalLikes);
    await supabase.from('users').update({ total_likes: newTotalLikes, badge: newBadge }).eq('id', userId);
  },

  async reportEntity(reporterId: string, targetType: ReportType, targetId: string, reason: string): Promise<{ success: boolean; message: string }> {
    if (!isConfigured) return { success: false, message: 'Backend not configured.' };
    try {
      const alreadyReported = await this.hasAlreadyReported(reporterId, targetType, targetId);
      if (alreadyReported) return { success: false, message: 'Already reported.' };
      let table = targetType === 'user' ? 'users' : (targetType === 'post' ? 'posts' : 'comments');
      await supabase.from('reports').insert([{ id: Math.random().toString(36).substr(2, 9), reporter_id: reporterId, target_type: targetType, target_id: targetId, reason }]);
      const { data } = await supabase.from(table).select('report_count').eq('id', targetId).maybeSingle();
      const newCount = (data?.report_count || 0) + 1;
      await supabase.from(table).update({ report_count: newCount }).eq('id', targetId);
      return { success: true, message: 'Report submitted.' };
    } catch {
      return { success: false, message: 'Error submitting report.' };
    }
  },

  async hasAlreadyReported(reporterId: string, targetType: ReportType, targetId: string): Promise<boolean> {
    const { data } = await supabase.from('reports').select('id').eq('reporter_id', reporterId).eq('target_type', targetType).eq('target_id', targetId).maybeSingle();
    return !!data;
  },

  getCurrentUser(): User | null {
    try {
      const session = localStorage.getItem(SESSION_KEY);
      return session ? JSON.parse(session) : null;
    } catch {
      return null;
    }
  },

  async login(identifier: string, password: string, method: 'username' | 'email'): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };
    const field = method === 'username' ? 'username' : 'email';
    try {
      const { data, error } = await supabase.from('users').select('*').ilike(field, identifier).eq('password', password).maybeSingle();
      if (error) return { success: false, error: error.message };
      if (!data) return { success: false, error: 'Invalid credentials.' };
      const user = await this.refreshUser(data.id);
      return user ? { success: true, user } : { success: false, error: 'Session error.' };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async getFollowStats(userId: string): Promise<{ followers: number, following: number }> {
    try {
      const { count: followers } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('following_id', userId);
      const { count: following } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('follower_id', userId);
      return { followers: followers || 0, following: following || 0 };
    } catch { return { followers: 0, following: 0 }; }
  },

  async isFollowing(followerId: string, followingId: string): Promise<boolean> {
    const { data } = await supabase.from('follows').select('*').eq('follower_id', followerId).eq('following_id', followingId).maybeSingle();
    return !!data;
  },

  async followUser(followerId: string, followingId: string): Promise<{ follower: User | null, following: User | null }> {
    await supabase.from('follows').insert([{ follower_id: followerId, following_id: followingId }]);
    return { follower: await this.refreshUser(followerId), following: await this.getUserById(followingId) };
  },

  async unfollowUser(followerId: string, followingId: string): Promise<{ follower: User | null, following: User | null }> {
    await supabase.from('follows').delete().eq('follower_id', followerId).eq('following_id', followingId);
    return { follower: await this.refreshUser(followerId), following: await this.getUserById(followingId) };
  },

  async deleteAccount(userId: string): Promise<{ success: boolean, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Database connection lost.' };

    try {
      // Step 1: Get user posts
      const { data: userPosts } = await supabase.from('posts').select('id').eq('user_id', userId);
      const postIds = (userPosts || []).map(p => p.id);

      // Step 2: Delete Reports
      if (postIds.length > 0) {
        await supabase.from('reports').delete().eq('target_type', 'post').in('target_id', postIds);
      }
      await supabase.from('reports').delete().eq('target_type', 'user').eq('target_id', userId);
      await supabase.from('reports').delete().eq('reporter_id', userId);

      // Step 3: Delete Comments on user's posts (made by others)
      if (postIds.length > 0) {
        await supabase.from('comments').delete().in('post_id', postIds);
      }

      // Step 4: Delete Comments made BY the user
      await supabase.from('comments').delete().eq('user_id', userId);

      // Step 5: Delete Follows
      await supabase.from('follows').delete().eq('follower_id', userId);
      await supabase.from('follows').delete().eq('following_id', userId);

      // Step 6: Delete user's posts
      await supabase.from('posts').delete().eq('user_id', userId);

      // Step 7: Delete user record
      const { error: finalError } = await supabase.from('users').delete().eq('id', userId);
      if (finalError) throw finalError;

      this.logout();
      return { success: true };
    } catch (err: any) {
      console.error("Deep Purge failed:", err);
      return { success: false, error: err.message || 'Identity purge failed.' };
    }
  },

  logout() { localStorage.removeItem(SESSION_KEY); }
};

import React, { useState, useEffect, useRef } from 'react';
import { User, Post } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';
import { ReportModal } from './ReportModal';

interface ProfileProps {
  user: User;
  currentUser: User | null;
  posts: Post[];
  isDarkMode: boolean;
  onAccountDeleted: () => void;
  onLogout: () => void;
  onUserUpdate: (updatedUser: User) => void;
}

export const Profile: React.FC<ProfileProps> = ({ 
  user, 
  currentUser, 
  posts, 
  isDarkMode, 
  onAccountDeleted, 
  onLogout,
  onUserUpdate
}) => {
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [deleteError, setDeleteError] = useState('');

  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [editUsername, setEditUsername] = useState(user.username);
  const [editAvatar, setEditAvatar] = useState(user.avatar);
  const [editBio, setEditBio] = useState(user.bio || '');
  const [isSaving, setIsSaving] = useState(false);
  const [editError, setEditError] = useState('');

  const [showReportModal, setShowReportModal] = useState(false);
  const [hasReportedUser, setHasReportedUser] = useState(false);

  // App Options State - Fallback to default if not present
  const [settings, setSettings] = useState(user.settings || { showReportCount: true, showStats: true });
  const [isSavingSettings, setIsSavingSettings] = useState(false);

  const isOwnProfile = currentUser?.id === user.id;
  const isBanned = db.isBanned(user);
  const userPosts = posts.filter(p => p.userId === user.id);
  const totalReceivedLikes = userPosts.reduce((acc, post) => acc + post.likes, 0);

  useEffect(() => {
    if (!isEditingProfile) {
      setEditUsername(user.username);
      setEditAvatar(user.avatar);
      setEditBio(user.bio || '');
      setSettings(user.settings || { showReportCount: true, showStats: true });
      setEditError('');
    }

    const checkReportStatus = async () => {
      if (currentUser && !isOwnProfile) {
        const reported = await db.hasAlreadyReported(currentUser.id, 'user', user.id);
        setHasReportedUser(reported);
      }
    };
    checkReportStatus();
  }, [user.bio, user.username, user.avatar, user.settings, currentUser, isOwnProfile, user.id, isEditingProfile]);

  const handleDeleteAccount = async () => {
    if (!window.confirm("CRITICAL WARNING: This will permanently purge your identity, stories, and data. This cannot be undone. Confirm deep purge?")) {
      setShowConfirmDelete(false);
      return;
    }

    setIsDeleting(true);
    setDeleteError('');

    try {
      const result = await db.deleteAccount(user.id);
      if (result.success) {
        onAccountDeleted();
      } else {
        const msg = result.error || 'Identity purge failed.';
        setDeleteError(msg);
        setIsDeleting(false);
      }
    } catch (err: any) {
      const msg = err.message || 'An unexpected error occurred during purging.';
      setDeleteError(msg);
      setIsDeleting(false);
    }
  };

  const handleShuffleAvatar = () => {
    const randomSeed = Math.random().toString(36).substring(7);
    setEditAvatar(`https://picsum.photos/seed/${randomSeed}/400`);
  };

  const handleSaveProfile = async () => {
    if (!editUsername.trim()) {
      setEditError("Username cannot be empty");
      return;
    }
    setIsSaving(true);
    try {
      const updated = await db.updateUserProfile(user.id, {
        username: editUsername,
        avatar: editAvatar,
        bio: editBio
      });
      if (updated) {
        onUserUpdate(updated);
        setIsEditingProfile(false);
      } else {
        setEditError("Username taken or network error.");
      }
    } finally {
      setIsSaving(false);
    }
  };

  const handleToggleSetting = async (key: 'showReportCount' | 'showStats') => {
    if (!isOwnProfile) return;
    const newSettings = { ...settings, [key]: !settings[key] };
    setSettings(newSettings);
    setIsSavingSettings(true);
    const updated = await db.updateUserSettings(user.id, newSettings);
    if (updated) onUserUpdate(updated);
    setIsSavingSettings(false);
  };

  const handleReportUser = async (reason: string) => {
    if (!currentUser) return;
    const result = await db.reportEntity(currentUser.id, 'user', user.id, reason);
    if (result.success) setHasReportedUser(true);
    setShowReportModal(false);
    alert(result.message);
  };

  return (
    <div className="max-w-3xl mx-auto py-4 md:py-8 space-y-6">
      {isBanned && (
        <div className="p-4 rounded-2xl bg-red-600 text-white font-bold flex items-center justify-between shadow-lg">
          <div className="flex items-center gap-3">
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
             <p className="text-sm">Account Suspended until {new Date(user.bannedUntil!).toLocaleString()}</p>
          </div>
        </div>
      )}

      <div className={`p-6 md:p-8 rounded-3xl border transition-all relative ${
        isDarkMode ? 'bg-slate-900 border-slate-800 text-white' : 'bg-white border-slate-100 shadow-xl text-slate-900'
      }`}>
        <div className="absolute top-4 right-4 md:top-6 md:right-6 flex gap-4">
          {!isOwnProfile && currentUser && (
            <button disabled={hasReportedUser} onClick={() => setShowReportModal(true)} className={`text-[10px] font-black uppercase transition-colors flex items-center gap-2 ${hasReportedUser ? 'text-slate-400 opacity-50' : 'text-red-400 hover:text-red-500'}`}>
              {hasReportedUser ? 'Reported' : 'Report'}
            </button>
          )}
          {isOwnProfile && (
            <button onClick={onLogout} className="text-[10px] font-black uppercase text-slate-400 hover:text-indigo-500 flex items-center gap-2">Logout</button>
          )}
        </div>

        {isEditingProfile ? (
          <div className="space-y-6">
            <h2 className="text-xl font-serif font-bold">Edit Identity</h2>
            <div className="flex flex-col md:flex-row gap-8">
               <div className="flex flex-col items-center gap-4">
                  <div className="relative group cursor-pointer" onClick={handleShuffleAvatar}>
                    <img src={editAvatar} className="w-32 h-32 rounded-3xl object-cover shadow-2xl ring-4 ring-indigo-500/20" alt="Preview" />
                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 rounded-3xl flex items-center justify-center transition-all">
                      <span className="text-white text-[10px] font-black uppercase">Shuffle</span>
                    </div>
                  </div>
                  <input type="text" value={editAvatar} onChange={(e) => setEditAvatar(e.target.value)} className="w-full p-2 text-[10px] rounded-lg border dark:bg-slate-800 dark:border-slate-700" placeholder="Avatar URL..." />
               </div>
               <div className="flex-1 space-y-4">
                  <div>
                    <label className="text-[10px] font-black uppercase text-slate-400 block mb-1">Username</label>
                    <input type="text" value={editUsername} onChange={(e) => setEditUsername(e.target.value.toLowerCase().replace(/\s/g, ''))} className="w-full p-3 text-sm rounded-xl border dark:bg-slate-800 dark:border-slate-700" />
                  </div>
                  <div>
                    <label className="text-[10px] font-black uppercase text-slate-400 block mb-1">Bio</label>
                    <textarea value={editBio} onChange={(e) => setEditBio(e.target.value)} maxLength={160} rows={3} className="w-full p-3 text-sm rounded-xl border dark:bg-slate-800 dark:border-slate-700 resize-none" />
                  </div>
               </div>
            </div>
            <div className="flex gap-3 pt-4">
              <button onClick={handleSaveProfile} disabled={isSaving} className="flex-1 py-3 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase shadow-lg disabled:opacity-50">Save Changes</button>
              <button onClick={() => setIsEditingProfile(false)} className="flex-1 py-3 border rounded-xl text-[10px] font-black uppercase">Cancel</button>
            </div>
          </div>
        ) : (
          <div className="flex flex-col items-center md:items-start text-center md:text-left">
            <div className="relative group mb-6">
              <img src={user.avatar} className={`w-24 h-24 md:w-32 md:h-32 rounded-3xl object-cover shadow-2xl ring-4 ${isBanned ? 'ring-red-500/50' : 'ring-indigo-500/20'}`} alt={user.username} />
              {isOwnProfile && (
                <button onClick={() => setIsEditingProfile(true)} className="absolute -bottom-2 -right-2 bg-indigo-600 text-white p-2 rounded-xl opacity-0 group-hover:opacity-100 transition-all">Edit</button>
              )}
            </div>
            <h1 className="text-2xl md:text-3xl font-serif font-bold mb-2">@{user.username}</h1>
            <div className="flex gap-2 mb-4">
              <BadgeIcon tier={user.badge} size="md" />
              {(isOwnProfile || settings.showReportCount) && user.reportCount! > 0 && (
                <span className="text-[10px] font-black uppercase text-red-500 py-1 px-3 bg-red-500/10 rounded-full">Alerts: {user.reportCount}</span>
              )}
            </div>
            <p className="text-sm text-slate-500 max-w-lg mb-8">{user.bio || (isOwnProfile ? "No bio yet." : "Mysterious storyteller.")}</p>

            {(isOwnProfile || settings.showStats) && (
              <div className="grid grid-cols-3 gap-8 w-full py-6 border-y border-slate-100 dark:border-slate-800">
                <div className="text-center"><p className="text-xl font-bold">{userPosts.length}</p><p className="text-[9px] font-black uppercase text-slate-400">Stories</p></div>
                <div className="text-center"><p className="text-xl font-bold">{totalReceivedLikes}</p><p className="text-[9px] font-black uppercase text-slate-400">Likes</p></div>
                <div className="text-center"><p className="text-xl font-bold">{user.followerCount}</p><p className="text-[9px] font-black uppercase text-slate-400">Followers</p></div>
              </div>
            )}
          </div>
        )}
      </div>

      {isOwnProfile && (
        <div className={`p-6 md:p-8 rounded-3xl border transition-all ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-lg'}`}>
          <h2 className="font-serif text-lg font-bold mb-6">Account Preferences</h2>
          <div className="space-y-6">
            <div className="flex items-center justify-between">
              <div><p className="text-xs font-bold uppercase tracking-tight">Show Public Stats</p><p className="text-[10px] text-slate-400">Visibility of your follower count and total likes.</p></div>
              <button onClick={() => handleToggleSetting('showStats')} className={`w-10 h-5 rounded-full relative transition-all ${settings.showStats ? 'bg-indigo-600' : 'bg-slate-300'}`}><div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${settings.showStats ? 'right-1' : 'left-1'}`} /></button>
            </div>
            <div className="flex items-center justify-between border-t dark:border-slate-800 pt-6">
              <div><p className="text-xs font-bold uppercase tracking-tight">Report Visibility</p><p className="text-[10px] text-slate-400">Whether others can see your report count badge.</p></div>
              <button onClick={() => handleToggleSetting('showReportCount')} className={`w-10 h-5 rounded-full relative transition-all ${settings.showReportCount ? 'bg-red-600' : 'bg-slate-300'}`}><div className={`absolute top-1 w-3 h-3 bg-white rounded-full transition-all ${settings.showReportCount ? 'right-1' : 'left-1'}`} /></button>
            </div>

            <div className="pt-6 border-t dark:border-slate-800">
              {!showConfirmDelete ? (
                <button 
                  onClick={() => setShowConfirmDelete(true)} 
                  className="text-[11px] font-black uppercase tracking-[0.1em] text-red-500 hover:text-red-600 transition-colors"
                >
                  Delete Identity
                </button>
              ) : (
                <div className="flex flex-col sm:flex-row sm:items-center gap-4 animate-in slide-in-from-bottom-2 duration-300">
                  <p className="text-[11px] text-red-600 font-bold uppercase tracking-tight whitespace-nowrap">
                    Erase all data permanently?
                  </p>
                  <div className="flex gap-3">
                    <button 
                      onClick={handleDeleteAccount} 
                      disabled={isDeleting} 
                      className="px-5 py-2 bg-red-600 text-white rounded-xl text-[10px] uppercase font-black tracking-widest shadow-lg hover:bg-red-700 active:scale-95 transition-all flex items-center gap-2"
                    >
                      {isDeleting ? (
                        <>
                          <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                          Purging...
                        </>
                      ) : 'Confirm Purge'}
                    </button>
                    <button 
                      onClick={() => { setShowConfirmDelete(false); setDeleteError(''); }} 
                      disabled={isDeleting}
                      className={`px-5 py-2 rounded-xl text-[10px] uppercase font-black tracking-widest transition-all ${
                        isDarkMode ? 'bg-slate-800 text-white hover:bg-slate-700' : 'bg-slate-900 text-white hover:bg-slate-800'
                      }`}
                    >
                      Cancel
                    </button>
                  </div>
                  {deleteError && (
                    <div className="p-2 bg-red-500/10 border border-red-500/20 rounded-lg sm:ml-auto">
                      <p className="text-[10px] text-red-500 font-bold leading-tight">{deleteError}</p>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {showReportModal && <ReportModal targetType="user" targetId={user.id} onClose={() => setShowReportModal(false)} onSubmit={handleReportUser} isDarkMode={isDarkMode} />}
    </div>
  );
};

