import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Post, User, Page, BadgeTier } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { AuthForm } from './components/AuthForm';
import { CreatePostForm } from './components/CreatePostForm';
import { PostList } from './components/PostList';
import { Profile } from './components/Profile';
import { BadgeIcon } from './components/BadgeIcon';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [viewingUser, setViewingUser] = useState<User | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      document.body.classList.replace('bg-slate-50', 'bg-slate-950');
      document.body.classList.replace('text-slate-900', 'text-slate-100');
    } else {
      document.documentElement.classList.remove('dark');
      document.body.classList.replace('bg-slate-950', 'bg-slate-50');
      document.body.classList.replace('text-slate-100', 'text-slate-900');
    }
  }, [isDarkMode]);

  const fetchPosts = useCallback(async () => {
    setIsLoading(true);
    const data = await db.getPosts();
    setPosts(data);
    setIsLoading(false);
  }, []);

  const refreshCurrentUser = useCallback(async () => {
    const user = db.getCurrentUser();
    if (user) {
      const refreshedUser = await db.refreshUser(user.id);
      if (refreshedUser) {
        setCurrentUser(refreshedUser);
      } else {
        db.logout();
        setCurrentUser(null);
        setCurrentPage('home');
      }
    }
  }, []);

  useEffect(() => {
    const user = db.getCurrentUser();
    if (user) {
      setCurrentUser(user);
      refreshCurrentUser();
    }
    fetchPosts();
  }, [fetchPosts, refreshCurrentUser]);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentUser) {
      const blockedIds = currentUser.blockedUsers || [];
      result = result.filter(p => !blockedIds.includes(p.userId));
    }
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    } else if (currentPage === 'bookmarks' && currentUser) {
      const bookmarkIds = currentUser.bookmarks || [];
      result = result.filter(p => bookmarkIds.includes(p.id));
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
    setViewingUser(null);
    setSearchQuery('');
  };

  const handleSearch = (query: string) => {
    setSearchQuery(query);
    if (currentPage !== 'home' && currentPage !== 'my-stories' && currentPage !== 'bookmarks') {
      setCurrentPage('home');
      setViewingUser(null);
    }
  };

  const handleNavigate = async (page: Page, userId?: string) => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setSearchQuery('');
    if (page === 'profile') {
      const id = userId || currentUser?.id;
      if (id) {
        setIsLoading(true);
        const userToView = await db.getUserById(id);
        setViewingUser(userToView);
        setCurrentPage('profile');
        setIsLoading(false);
      } else {
        setCurrentPage('login');
      }
    } else {
      setCurrentPage(page);
      setViewingUser(null);
    }
  };

  const handleUserUpdate = (updated: User) => {
    if (currentUser?.id === updated.id) setCurrentUser(updated);
    if (viewingUser?.id === updated.id) setViewingUser(updated);
  };

  const handleBlockToggle = async (targetId: string) => {
    if (!currentUser) return;
    setIsSyncing(true);
    try {
      const isCurrentlyBlocked = currentUser.blockedUsers?.includes(targetId);
      let updatedUser;
      if (isCurrentlyBlocked) {
        updatedUser = await db.unblockUser(currentUser.id, targetId);
      } else {
        updatedUser = await db.blockUser(currentUser.id, targetId);
      }
      if (updatedUser) {
        setCurrentUser(updatedUser);
      }
    } catch (err) {
      console.error("Block action failed", err);
    } finally {
      setIsSyncing(false);
    }
  };

  const getListHeader = () => {
    if (searchQuery) return { title: `Search Results`, description: `Displaying matches for "${searchQuery}".` };
    switch (currentPage) {
      case 'my-stories': return { title: 'My Narratives', description: 'Your personal collection of living stories.' };
      case 'bookmarks': return { title: 'Saved Stories', description: 'Stories you have preserved in your library.' };
      default: return { title: 'The Collective', description: 'Where the world shares its hidden stories.' };
    }
  };

  const { title, description } = getListHeader();

  return (
    <div className={`min-h-screen pb-20 md:pb-12 ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={handleSearch}
        onLogout={handleLogout}
        onNavigate={handleNavigate}
        isSyncing={isSyncing}
        currentPage={currentPage}
      />

      <main className="max-w-6xl mx-auto px-4 pt-6">
        <div className="grid grid-cols-1 lg:grid-cols-[1fr_320px] gap-10">
          <div className="min-w-0">
            {isLoading && (
              <div className="flex flex-col items-center justify-center py-32 space-y-6">
                <div className={`w-12 h-12 border-4 border-t-indigo-500 rounded-full animate-spin ${isDarkMode ? 'border-slate-800' : 'border-slate-200'}`}></div>
                <p className="text-[10px] font-black uppercase tracking-[0.4em] text-slate-400 animate-pulse">Loading Verse...</p>
              </div>
            )}

