  onBlockUser?: (targetUserId: string) => void;
  onClearSearch?: () => void;
  isSearchActive?: boolean;
  title: string;
  description: string;
}

export const PostList: React.FC<PostListProps> = ({ 
  posts, 
  currentUser, 
  isDarkMode, 
  onPostUpdate, 
  onPostDeleted,
  onActionClick,
  onUserClick,
  onFollowToggle,
  onBookmarkToggle,
  onBlockUser,
