import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Post, User, Page, BadgeTier } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { AuthForm } from './components/AuthForm';
import { CreatePostForm } from './components/CreatePostForm';
import { PostList } from './components/PostList';
import { Profile } from './components/Profile';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [viewingUser, setViewingUser] = useState<User | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      document.body.className = 'bg-slate-950 text-slate-100';
    } else {
      document.documentElement.classList.remove('dark');
      document.body.className = 'bg-slate-50 text-slate-900';
    }
  }, [isDarkMode]);

  const fetchPosts = useCallback(async () => {
    setIsLoading(true);
    const data = await db.getPosts();
    setPosts(data);
    setIsLoading(false);
  }, []);

  const refreshCurrentUser = useCallback(async () => {
    const user = db.getCurrentUser();
    if (user) {
      const refreshedUser = await db.refreshUser(user.id);
      if (refreshedUser) setCurrentUser(refreshedUser);
    }
  }, []);

  useEffect(() => {
    const user = db.getCurrentUser();
    if (user) {
      setCurrentUser(user);
      refreshCurrentUser();
    }
    fetchPosts();
  }, [fetchPosts, refreshCurrentUser]);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentUser) {
      const blockedIds = currentUser.blockedUsers || [];
      result = result.filter(p => !blockedIds.includes(p.userId));
    }
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    } else if (currentPage === 'bookmarks' && currentUser) {
      const bookmarkIds = currentUser.bookmarks || [];
      result = result.filter(p => bookmarkIds.includes(p.id));
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
    setViewingUser(null);
  };

  const handleNavigate = async (page: Page, userId?: string) => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setSearchQuery('');
    if (page === 'profile') {
      const id = userId || currentUser?.id;
      if (id) {
        setIsLoading(true);
        const userToView = await db.getUserById(id);
        setViewingUser(userToView);
        setCurrentPage('profile');
        setIsLoading(false);
      } else {
        setCurrentPage('login');
      }
    } else {
      setCurrentPage(page);
      setViewingUser(null);
    }
  };

  const handleUserUpdate = (updated: User) => {
    if (currentUser?.id === updated.id) setCurrentUser(updated);
    if (viewingUser?.id === updated.id) setViewingUser(updated);
  };

  const handleFollowToggle = async (targetUserId: string) => {
    if (!currentUser) {
      setCurrentPage('login');
      return;
    }

    const isFollowing = await db.isFollowing(currentUser.id, targetUserId);
    const result = isFollowing 
      ? await db.unfollowUser(currentUser.id, targetUserId)
      : await db.followUser(currentUser.id, targetUserId);

    if (result.follower) setCurrentUser(result.follower);
    if (result.following && viewingUser?.id === targetUserId) setViewingUser(result.following);
  };

  const getListHeader = () => {
    if (searchQuery) return { title: `Search Results`, description: `Displaying matches for "${searchQuery}".` };
    switch (currentPage) {
      case 'my-stories': return { title: 'My Narratives', description: 'Your personal collection of living stories.' };
      case 'bookmarks': return { title: 'Saved Stories', description: 'Stories you have preserved in your library.' };
      default: return { title: 'Discover the Verse', description: 'Where the world shares its hidden stories.' };
    }
  };

  const { title, description } = getListHeader();

  return (
    <div className={`min-h-screen flex flex-col ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={handleNavigate}
        currentPage={currentPage}
      />

      <main className="flex-1 w-full max-w-5xl mx-auto px-4 pt-12 pb-24">
        {isLoading ? (
          <div className="flex flex-col items-center justify-center py-40">
            <div className={`w-12 h-12 border-4 border-t-indigo-500 rounded-full animate-spin ${isDarkMode ? 'border-slate-800' : 'border-slate-200'}`}></div>
          </div>
        ) : (
          <div className="space-y-12">
            {(currentPage === 'home' || currentPage === 'my-stories' || currentPage === 'bookmarks') && (
              <>
                <div className="text-center mb-16">
                  <h1 className="font-serif text-5xl md:text-6xl font-bold mb-4 tracking-tight">{title}</h1>
                  <p className="text-sm md:text-base text-slate-400 font-medium">{description}</p>
                </div>
                <PostList 
                  posts={filteredPosts}
                  currentUser={currentUser}
                  isDarkMode={isDarkMode}
                  onPostUpdate={(upd) => setPosts(prev => prev.map(p => p.id === upd.id ? upd : p))}
                  onPostDeleted={fetchPosts}
                  onBookmarkToggle={handleUserUpdate}
                  onUserClick={(id) => handleNavigate('profile', id)}
                  onActionClick={() => handleNavigate('create')}
                  onFollowToggle={handleFollowToggle}
                  title="" 
                  description=""
                />
              </>
            )}

            {currentPage === 'create' && currentUser && (
              <CreatePostForm currentUser={currentUser} isDarkMode={isDarkMode} onPostCreated={() => { fetchPosts(); setCurrentPage('home'); }} />
            )}

            {currentPage === 'profile' && viewingUser && (
              <Profile user={viewingUser} currentUser={currentUser} posts={posts} isDarkMode={isDarkMode} onAccountDeleted={handleLogout} onLogout={handleLogout} onUserUpdate={handleUserUpdate} onFollowToggle={handleFollowToggle} />
            )}

            {(currentPage === 'login' || currentPage === 'register') && (
              <div className="max-w-md mx-auto pt-10">
                <AuthForm mode={currentPage} isDarkMode={isDarkMode} onAuthSuccess={(u) => { setCurrentUser(u); setCurrentPage('home'); }} onSwitchMode={setCurrentPage} />
              </div>
            )}
          </div>
        )}
      </main>

      <footer className={`w-full py-16 border-t text-center ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <div className="max-w-4xl mx-auto px-4 flex flex-col items-center">
          <h2 className="font-serif text-2xl font-bold mb-6">StoryVerse</h2>
          <div className="flex items-center gap-2 mb-8">
            <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-500">Connected to Supabase</span>
          </div>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">
            © 2026 StoryVerse Collective. Verified Global Sync.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Post, User, BadgeTier } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';
import { EditPostModal } from './EditPostModal';

interface PostCardProps {
  post: Post;
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (post: Post) => void;
  onPostDeleted: () => void;
  onUserClick?: (userId: string) => void;
  onBookmarkToggle?: (updatedUser: User) => void;
  onFollowToggle?: (targetUserId: string) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  isDarkMode,
  onPostUpdate, 
  onPostDeleted,
  onUserClick,
  onBookmarkToggle,
  onFollowToggle
}) => {
  const [showComments, setShowComments] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [showMenu, setShowMenu] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [authorBadge, setAuthorBadge] = useState<BadgeTier>(BadgeTier.NOVICE);
  const [isFollowing, setIsFollowing] = useState(false);
  const [isFollowLoading, setIsFollowLoading] = useState(false);

  const isOwner = currentUser?.id === post.userId;
  const isBookmarked = currentUser?.bookmarks?.includes(post.id);
  const isLiked = currentUser ? post.likedBy?.includes(currentUser.id) : false;

  useEffect(() => {
    db.getUserById(post.userId).then(u => u && setAuthorBadge(u.badge));
    if (currentUser && !isOwner) {
      db.isFollowing(currentUser.id, post.userId).then(setIsFollowing);
    }
  }, [post.userId, currentUser, isOwner]);

  const handleLike = async () => {
    if (!currentUser) return;
    const hasLiked = post.likedBy?.includes(currentUser.id);
    const updated = { 
      ...post, 
      likes: post.likes + (hasLiked ? -1 : 1), 
      likedBy: hasLiked ? post.likedBy.filter(id => id !== currentUser.id) : [...(post.likedBy || []), currentUser.id] 
    };
    onPostUpdate(updated);
    await db.updatePost(updated);
    await db.updateUserLikes(post.userId, hasLiked ? -1 : 1);
  };

  const handleFollowClick = async () => {
    if (!currentUser || !onFollowToggle || isFollowLoading) return;
    setIsFollowLoading(true);
    await onFollowToggle(post.userId);
    setIsFollowing(!isFollowing);
    setIsFollowLoading(false);
  };

  return (
    <div className={`rounded-[2rem] border transition-all mb-8 overflow-hidden ${
      isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-sm hover:shadow-md'
    }`}>
      <div className="p-8 md:p-10">
        <div className="flex items-start justify-between mb-8">
          <div className="flex items-center gap-4">
            <img 
              src={post.userAvatar} 
              className="w-12 h-12 rounded-xl object-cover cursor-pointer shadow-sm" 
              onClick={() => onUserClick?.(post.userId)}
            />
            <div>
              <div className="flex items-center gap-3 mb-1">
                <span className="font-bold text-sm cursor-pointer" onClick={() => onUserClick?.(post.userId)}>@{post.username}</span>
                <BadgeIcon tier={authorBadge} />

                {!isOwner && currentUser && (
                  <button 
                    onClick={handleFollowClick}
                    disabled={isFollowLoading}
                    className={`text-[9px] font-black uppercase tracking-widest px-3 py-1 rounded-full transition-all ${
                      isFollowing 
                        ? (isDarkMode ? 'bg-slate-800 text-slate-400' : 'bg-slate-100 text-slate-500')
                        : 'text-indigo-600 hover:text-indigo-700'
                    }`}
                  >
                    {isFollowLoading ? '...' : (isFollowing ? 'Following' : 'Follow')}
                  </button>
                )}
              </div>
              <div className="flex items-center gap-2 text-[9px] text-slate-400 font-bold uppercase tracking-widest">
                <span>{new Date(post.createdAt).toLocaleDateString(undefined, { day: 'numeric', month: 'short' }).toUpperCase()}</span>
                <span>•</span>
                <span>1 MIN READ</span>
              </div>
            </div>
          </div>
          <div className="relative">
            <button onClick={() => setShowMenu(!showMenu)} className="p-2 text-slate-300 hover:text-slate-600 transition-colors">
              <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M10 6a2 2 0 110-4 2 2 0 010 4zM10 12a2 2 0 110-4 2 2 0 010 4zM10 18a2 2 0 110-4 2 2 0 010 4z"/></svg>
            </button>
            {showMenu && (
              <div className={`absolute right-0 top-10 w-44 rounded-2xl shadow-2xl border z-20 ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-100'}`}>
                <button onClick={() => { onUserClick?.(post.userId); setShowMenu(false); }} className="w-full text-left px-4 py-3 text-[10px] font-black uppercase tracking-widest hover:bg-slate-50 dark:hover:bg-slate-700">View Profile</button>
                {isOwner && (
                  <>
                    <button onClick={() => { setShowEditModal(true); setShowMenu(false); }} className="w-full text-left px-4 py-3 text-[10px] font-black uppercase tracking-widest border-t dark:border-slate-700">Edit Story</button>
                    <button onClick={async () => { await db.deletePost(post.id); onPostDeleted(); }} className="w-full text-left px-4 py-3 text-[10px] font-black uppercase tracking-widest text-red-500 border-t dark:border-slate-700">Delete</button>
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        <h3 className="font-serif text-3xl font-bold mb-6 leading-tight">{post.title}</h3>
        <p className={`text-base leading-relaxed mb-6 ${isDarkMode ? 'text-slate-400' : 'text-slate-500'} ${isExpanded ? '' : 'line-clamp-4'}`}>
          {post.content}
        </p>

        <button onClick={() => setIsExpanded(!isExpanded)} className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-600 mb-10 flex items-center gap-1 hover:underline group">
          {isExpanded ? 'Collapse Story ↑' : 'Read Full Story ↓'}
        </button>

        <div className="flex items-center justify-between pt-8 border-t dark:border-slate-800">
          <div className="flex items-center gap-8">
            <button onClick={handleLike} className={`flex items-center gap-2.5 text-xs font-bold transition-all ${isLiked ? 'text-red-500' : 'text-slate-400 hover:text-slate-600'}`}>
              <svg className={`w-5 h-5 ${isLiked ? 'fill-current' : 'fill-none stroke-current'}`} strokeWidth="2.5" viewBox="0 0 24 24"><path d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/></svg>
              <span>{post.likes}</span>
            </button>
            <button onClick={() => setShowComments(!showComments)} className="flex items-center gap-2.5 text-xs font-bold text-slate-400 hover:text-slate-600">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
              <span>{post.comments.length}</span>
            </button>
            <button className="text-slate-400 hover:text-indigo-500 transition-colors">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 114.243 4.243M9.878 9.878l4.242 4.242M9.88 9.88l-3.29-3.29m7.532 7.532l3.29 3.29M3 3l18 18" /></svg>
            </button>
          </div>
          <button onClick={async () => {
             const updated = await db.toggleBookmark(currentUser!.id, post.id);
             if (updated && onBookmarkToggle) onBookmarkToggle(updated);
          }} className={`p-1 transition-all ${isBookmarked ? 'text-indigo-500 scale-110' : 'text-slate-300 hover:text-slate-500'}`}>
            <svg className={`w-5 h-5 ${isBookmarked ? 'fill-current' : 'fill-none stroke-current'}`} strokeWidth="2.5" viewBox="0 0 24 24"><path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" /></svg>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-8 border-t dark:border-slate-800 animate-in slide-in-from-top duration-300 ${isDarkMode ? 'bg-slate-900/50' : 'bg-slate-50'}`}>
          <div className="space-y-6 mb-8">
            {post.comments.map(c => (
              <div key={c.id} className="flex gap-4">
                <div className="w-9 h-9 rounded-xl bg-indigo-500/10 border border-indigo-500/10 flex items-center justify-center text-indigo-600 text-xs font-black shrink-0">{c.username[0].toUpperCase()}</div>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <p className="text-xs font-bold">@{c.username}</p>
                    <span className="text-[8px] text-slate-400 font-bold uppercase tracking-widest">{new Date(c.createdAt).toLocaleDateString()}</span>
                  </div>
                  <p className="text-sm text-slate-500 leading-relaxed">{c.content}</p>
                </div>
              </div>
            ))}
            {post.comments.length === 0 && <p className="text-center text-xs text-slate-400 italic py-6">No responses yet.</p>}
          </div>
          {currentUser && (
            <form onSubmit={async (e) => {
              e.preventDefault();
              const text = (e.target as any).reply.value;
              if (!text.trim() || !currentUser) return;
              const comm = { id: Math.random().toString(36).substr(2, 9), userId: currentUser.id, username: currentUser.username, content: text, createdAt: new Date().toISOString() };
              await db.addComment(post.id, comm);
              onPostUpdate({ ...post, comments: [...post.comments, comm] });
              (e.target as any).reply.value = '';
            }} className="flex gap-3">
              <input name="reply" placeholder="Add your response..." className={`flex-1 px-5 py-3 rounded-2xl text-xs border outline-none transition-all ${isDarkMode ? 'bg-slate-950 border-slate-700' : 'bg-white border-slate-200'}`} />
              <button type="submit" className="px-6 py-3 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">Reply</button>
            </form>
          )}
        </div>
      )}
      {showEditModal && <EditPostModal post={post} isDarkMode={isDarkMode} onClose={() => setShowEditModal(false)} onUpdate={onPostUpdate} />}
    </div>
  );
};

import React from 'react';
import { Post, User } from '../types';
import { PostCard } from './PostCard';

interface PostListProps {
  posts: Post[];
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (updatedPost: Post) => void;
  onPostDeleted: () => void;
  onActionClick: () => void;
  onUserClick?: (userId: string) => void;
  onFollowToggle?: (targetUserId: string) => void;
  onBookmarkToggle?: (updatedUser: User) => void;
  onBlockUser?: (targetUserId: string) => void;
  onClearSearch?: () => void;
  isSearchActive?: boolean;
  title: string;
  description: string;
}

export const PostList: React.FC<PostListProps> = ({ 
  posts, 
  currentUser, 
  isDarkMode, 
  onPostUpdate, 
  onPostDeleted,
  onActionClick,
  onUserClick,
  onFollowToggle,
  onBookmarkToggle,
  onBlockUser,
  title,
  description
}) => {
  return (
    <section className="animate-in fade-in slide-in-from-bottom-4 duration-700">
      {title && (
        <div className="mb-12">
          <h1 className={`font-serif text-5xl font-bold tracking-tight mb-3 capitalize ${
            isDarkMode ? 'text-white' : 'text-slate-900'
          }`}>
            {title}
          </h1>
          <p className={`text-sm md:text-base font-medium ${
            isDarkMode ? 'text-slate-400' : 'text-slate-500'
          }`}>
            {description}
          </p>
        </div>
      )}

      {posts.length === 0 ? (
        <div className={`rounded-[2.5rem] p-12 text-center border-2 border-dashed transition-all ${
          isDarkMode ? 'bg-slate-900/50 border-slate-800 text-slate-400' : 'bg-white border-slate-200 text-slate-500'
        }`}>
          <h2 className="text-xl font-serif font-bold mb-4">No stories found.</h2>
          <p className="text-xs mb-8 uppercase font-bold tracking-widest opacity-60">The verse is currently quiet.</p>
          <button 
            onClick={onActionClick}
            className="px-8 py-3 bg-indigo-600 text-white rounded-full text-xs font-black uppercase tracking-widest hover:bg-indigo-700 shadow-xl transition-all"
          >
            Start Narrating
          </button>
        </div>
      ) : (
        <div className="space-y-6">
          {posts.map(post => (
            <PostCard 
              key={post.id} 
              post={post} 
              currentUser={currentUser} 
              isDarkMode={isDarkMode} 
              onPostUpdate={onPostUpdate}
              onPostDeleted={onPostDeleted}
              onUserClick={onUserClick}
              onBookmarkToggle={onBookmarkToggle}
              onFollowToggle={onFollowToggle}
            />
          ))}
        </div>
      )}
    </section>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, Post } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';
import { ReportModal } from './ReportModal';

interface ProfileProps {
  user: User;
  currentUser: User | null;
  posts: Post[];
  isDarkMode: boolean;
  onAccountDeleted: () => void;
  onLogout: () => void;
  onUserUpdate: (updatedUser: User) => void;
  onBlockToggle?: (targetUserId: string) => void;
  onFollowToggle?: (targetUserId: string) => void;
}

export const Profile: React.FC<ProfileProps> = ({ 
  user, 
  currentUser, 
  posts, 
  isDarkMode, 
  onAccountDeleted, 
  onLogout,
  onUserUpdate,
  onBlockToggle,
  onFollowToggle
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [deleteError, setDeleteError] = useState('');

  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [editUsername, setEditUsername] = useState(user.username);
  const [editAvatar, setEditAvatar] = useState(user.avatar);
  const [editBio, setEditBio] = useState(user.bio || '');
  const [isSaving, setIsSaving] = useState(false);
  const [editError, setEditError] = useState('');

  const [isImportingLink, setIsImportingLink] = useState(false);
  const [linkInput, setLinkInput] = useState('');

  const [showReportModal, setShowReportModal] = useState(false);
  const [hasReportedUser, setHasReportedUser] = useState(false);
  const [isBlockLoading, setIsBlockLoading] = useState(false);
  const [isFollowLoading, setIsFollowLoading] = useState(false);
  const [isFollowing, setIsFollowing] = useState(false);

  const [showBlockedModal, setShowBlockedModal] = useState(false);
  const [blockedDetails, setBlockedDetails] = useState<User[]>([]);
  const [isLoadingBlocks, setIsLoadingBlocks] = useState(false);

  const [settings, setSettings] = useState(user.settings || { showReportCount: true, showStats: true });
  const [isSavingSettings, setIsSavingSettings] = useState(false);

  const isOwnProfile = currentUser?.id === user.id;
  const userPosts = posts.filter(p => p.userId === user.id);
  const totalReceivedLikes = userPosts.reduce((acc, post) => acc + post.likes, 0);

  const isBlocked = useMemo(() => currentUser?.blockedUsers?.includes(user.id) || false, [currentUser, user.id]);

  useEffect(() => {
    if (!isEditingProfile) {
      setEditUsername(user.username);
      setEditAvatar(user.avatar);
      setEditBio(user.bio || '');
      setSettings(user.settings || { showReportCount: true, showStats: true });
      setEditError('');
      setIsImportingLink(false);
      setLinkInput('');
    }

    const checkReportStatus = async () => {
      if (currentUser && !isOwnProfile) {
        const reported = await db.hasAlreadyReported(currentUser.id, 'user', user.id);
        setHasReportedUser(reported);
        const following = await db.isFollowing(currentUser.id, user.id);
        setIsFollowing(following);
      }
    };
    checkReportStatus();
  }, [user.bio, user.username, user.avatar, user.settings, currentUser, isOwnProfile, user.id, isEditingProfile]);

  useEffect(() => {
    if (showBlockedModal && currentUser?.blockedUsers) {
      const fetchBlockedUsers = async () => {
        setIsLoadingBlocks(true);
        const details = await Promise.all(
          currentUser.blockedUsers.map(id => db.getUserById(id))
        );
        setBlockedDetails(details.filter((u): u is User => u !== null));
        setIsLoadingBlocks(false);
      };
      fetchBlockedUsers();
    }
  }, [showBlockedModal, currentUser?.blockedUsers]);

  const handleDeleteAccount = async () => {
    if (!window.confirm("Purge identity? This is irreversible.")) {
      setShowConfirmDelete(false);
      return;
    }
    setIsDeleting(true);
    const result = await db.deleteAccount(user.id);
    if (result.success) onAccountDeleted();
    else { setDeleteError(result.error || 'Failed.'); setIsDeleting(false); }
  };

  const handleShuffleAvatar = () => {
    const randomSeed = Math.random().toString(36).substring(7);
    setEditAvatar(`https://picsum.photos/seed/${randomSeed}/400`);
    setIsImportingLink(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditAvatar(reader.result as string);
        setIsImportingLink(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleApplyLink = () => {
    if (linkInput.trim()) {
      setEditAvatar(linkInput.trim());
      setIsImportingLink(false);
      setLinkInput('');
    }
  };

  const handleBlockToggleAction = async (targetId?: string) => {
    const idToToggle = targetId || user.id;
    if (!currentUser || (idToToggle === currentUser.id && !targetId) || isBlockLoading) return;
    setIsBlockLoading(true);
    const isTargetBlocked = currentUser.blockedUsers?.includes(idToToggle);
    let updated = isTargetBlocked ? await db.unblockUser(currentUser.id, idToToggle) : await db.blockUser(currentUser.id, idToToggle);
    if (updated) {
      onUserUpdate(updated);
      if (onBlockToggle) onBlockToggle(idToToggle);
      if (isTargetBlocked) setBlockedDetails(prev => prev.filter(u => u.id !== idToToggle));
    }
    setIsBlockLoading(false);
  };

  const handleFollowClick = async () => {
    if (!currentUser || !onFollowToggle || isFollowLoading) return;
    setIsFollowLoading(true);
    await onFollowToggle(user.id);
    setIsFollowing(!isFollowing);
    setIsFollowLoading(false);
  };

  const handleSaveProfile = async () => {
    if (!editUsername.trim()) { setEditError("Username required"); return; }
    setIsSaving(true);
    const updated = await db.updateUserProfile(user.id, { username: editUsername, avatar: editAvatar, bio: editBio });
    if (updated) { 
      onUserUpdate(updated); 
      setIsEditingProfile(false); 
    } else {
      setEditError("Username taken or update failed.");
    }
    setIsSaving(false);
  };

  const handleToggleSetting = async (key: 'showReportCount' | 'showStats') => {
    if (!isOwnProfile) return;
    const newSettings = { ...settings, [key]: !settings[key] };
    setSettings(newSettings);
    setIsSavingSettings(true);
    const updated = await db.updateUserSettings(user.id, newSettings);
    if (updated) onUserUpdate(updated);
    setIsSavingSettings(false);
  };

  return (
    <div className="max-w-4xl mx-auto py-2 space-y-6">
      <div className={`p-8 md:p-12 rounded-[2.5rem] border transition-all relative text-center flex flex-col items-center ${
        isDarkMode ? 'bg-slate-900 border-slate-800 text-white' : 'bg-white border-slate-100 shadow-xl text-slate-900'
      }`}>
        {isOwnProfile && (
          <button onClick={onLogout} className="absolute top-8 right-8 text-[10px] font-black uppercase text-slate-400 hover:text-indigo-600 transition-colors">Logout</button>
        )}

        {isEditingProfile ? (
          <div className="w-full space-y-8 animate-in zoom-in-95 duration-200">
            <h2 className="text-2xl font-serif font-bold italic">Identity Refining</h2>

            <div className="flex flex-col items-center gap-6">
              <div className="flex flex-col items-center gap-4 w-full">
                <div className="relative group cursor-pointer" onClick={() => fileInputRef.current?.click()}>
                  <img src={editAvatar} className="w-32 h-32 rounded-[2.5rem] object-cover shadow-2xl ring-4 ring-indigo-500/10" alt="Preview" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 rounded-[2.5rem] flex items-center justify-center transition-all">
                    <span className="text-white text-[10px] font-black uppercase tracking-widest">Upload Photo</span>
                  </div>
                  <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
                </div>

                <div className="flex flex-wrap justify-center gap-2">
                  <button type="button" onClick={() => fileInputRef.current?.click()} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest border transition-all ${isDarkMode ? 'border-slate-700 text-slate-400 hover:text-white' : 'border-slate-200 text-slate-500 hover:text-indigo-600'}`}>Select Photo</button>
                  <button type="button" onClick={handleShuffleAvatar} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest border transition-all ${isDarkMode ? 'border-slate-700 text-slate-400 hover:text-white' : 'border-slate-200 text-slate-500 hover:text-indigo-600'}`}>Shuffle Random</button>
                  <button type="button" onClick={() => setIsImportingLink(!isImportingLink)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest border transition-all ${isImportingLink ? 'bg-indigo-600 border-indigo-600 text-white' : (isDarkMode ? 'border-slate-700 text-slate-400 hover:text-white' : 'border-slate-200 text-slate-500 hover:text-indigo-600')}`}>Import Link</button>
                </div>

                {isImportingLink && (
                  <div className="w-full max-w-sm mt-2">
                    <div className="flex gap-2">
                      <input type="url" placeholder="Paste image URL..." value={linkInput} onChange={(e) => setLinkInput(e.target.value)} className={`flex-1 p-3 text-xs rounded-xl border outline-none focus:border-indigo-500 transition-all ${isDarkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-slate-50 border-slate-200'}`} />
                      <button onClick={handleApplyLink} className="px-4 py-3 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg">Apply</button>
                    </div>
                  </div>
                )}
              </div>

              <div className="w-full max-w-sm space-y-4 text-left">
                {editError && <p className="text-[10px] font-bold text-red-500 uppercase text-center">{editError}</p>}
                <div>
                  <label className="text-[10px] font-black uppercase text-slate-400 block mb-1">Username</label>
                  <input type="text" value={editUsername} onChange={(e) => setEditUsername(e.target.value.toLowerCase().replace(/\s/g, ''))} className={`w-full p-4 text-sm rounded-2xl border outline-none focus:border-indigo-500 transition-all ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-200'}`} />
                </div>
                <div>
                  <label className="text-[10px] font-black uppercase text-slate-400 block mb-1">Bio</label>
                  <textarea value={editBio} onChange={(e) => setEditBio(e.target.value)} maxLength={160} rows={3} className={`w-full p-4 text-sm rounded-2xl border resize-none outline-none focus:border-indigo-500 transition-all ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-200'}`} />
                </div>
              </div>
            </div>

            <div className="flex gap-3 max-w-sm mx-auto">
              <button onClick={handleSaveProfile} disabled={isSaving} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase shadow-xl disabled:opacity-50">Save Profile</button>
              <button onClick={() => setIsEditingProfile(false)} className={`flex-1 py-4 border rounded-2xl text-[10px] font-black uppercase ${isDarkMode ? 'border-slate-700 hover:bg-slate-800' : 'border-slate-200 hover:bg-slate-50'}`}>Cancel</button>
            </div>
          </div>
        ) : (
          <div className="w-full flex flex-col items-center">
            <div className="relative group mb-8">
              <img src={user.avatar} className={`w-32 h-32 md:w-40 md:h-40 rounded-[3rem] object-cover shadow-2xl ring-4 ${isDarkMode ? 'ring-slate-800' : 'ring-indigo-50'}`} alt={user.username} />
              {isOwnProfile && (
                <button onClick={() => setIsEditingProfile(true)} className="absolute -bottom-2 -right-2 bg-white dark:bg-slate-800 p-3 rounded-2xl shadow-xl border dark:border-slate-700 hover:scale-110 transition-all">
                  <svg className="w-5 h-5 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                </button>
              )}
            </div>

            <h1 className="text-3xl font-serif font-bold mb-3">@{user.username}</h1>
            <div className="mb-6">
              <BadgeIcon tier={user.badge} size="md" />
            </div>

            {currentUser && !isOwnProfile && (
              <div className="mb-10 flex gap-4">
                <button 
                  onClick={handleFollowClick}
                  disabled={isFollowLoading}
                  className={`px-12 py-4 rounded-2xl text-[11px] font-black uppercase tracking-widest shadow-xl transition-all active:scale-95 ${
                    isFollowing 
                      ? (isDarkMode ? 'bg-slate-800 text-slate-400' : 'bg-slate-100 text-slate-500') 
                      : 'bg-indigo-600 text-white hover:bg-indigo-700'
                  }`}
                >
                  {isFollowLoading ? '...' : (isFollowing ? 'Following' : 'Follow')}
                </button>
                <button 
                  onClick={() => handleBlockToggleAction()}
                  disabled={isBlockLoading}
                  className={`px-6 py-4 rounded-2xl text-[11px] font-black uppercase tracking-widest border transition-all ${
                    isBlocked ? 'bg-red-500 border-red-500 text-white' : 'border-slate-200 dark:border-slate-700 text-slate-400 hover:text-red-500'
                  }`}
                >
                  {isBlocked ? 'Blocked' : 'Block'}
                </button>
              </div>
            )}

            <p className="text-sm text-slate-500 max-w-sm mx-auto mb-10 leading-relaxed font-medium">
              {user.bio || (isOwnProfile ? "You haven't told your story yet." : "This verse is waiting for a narrative.")}
            </p>

            <div className="w-full h-px bg-slate-100 dark:bg-slate-800 mb-8" />

            <div className="grid grid-cols-3 gap-4 w-full max-w-xl mb-8">
              <div className="text-center px-2">
                <p className="text-3xl font-bold tabular-nums">{userPosts.length}</p>
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mt-1">Stories</p>
              </div>
              <div className="text-center px-2 border-x dark:border-slate-800">
                <p className="text-3xl font-bold tabular-nums">{totalReceivedLikes}</p>
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mt-1">Likes</p>
              </div>
              <div className="text-center px-2">
                <p className="text-3xl font-bold tabular-nums">{user.followerCount}</p>
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mt-1">Followers</p>
              </div>
            </div>
          </div>
        )}
      </div>

      {isOwnProfile && (
        <div className={`p-8 md:p-10 rounded-[2.5rem] border ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
          <h2 className="font-serif text-2xl font-bold mb-8 italic">Account Preferences</h2>
          <div className="space-y-6">
            <div className="flex items-center justify-between group cursor-pointer" onClick={() => handleToggleSetting('showStats')}>
              <div>
                <p className="text-xs font-bold uppercase tracking-widest mb-1">Public Statistics</p>
                <p className="text-[10px] text-slate-400 font-medium">Show stories, likes, and follower counts.</p>
              </div>
              <button className={`w-12 h-6 rounded-full relative transition-all shadow-inner ${settings.showStats ? 'bg-indigo-600' : 'bg-slate-200 dark:bg-slate-800'}`}>
                <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all shadow-md ${settings.showStats ? 'right-1' : 'left-1'}`} />
              </button>
            </div>

            <div className="flex items-center justify-between group cursor-pointer pt-6 border-t dark:border-slate-800" onClick={() => setShowBlockedModal(true)}>
              <div>
                <p className="text-xs font-bold uppercase tracking-widest mb-1">Blocked Accounts</p>
                <p className="text-[10px] text-slate-400 font-medium">Manage restricted users in your feed.</p>
              </div>
              <div className="flex items-center gap-3">
                <span className={`px-2 py-0.5 rounded-lg text-[10px] font-black tabular-nums ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
                  {currentUser?.blockedUsers?.length || 0}
                </span>
                <svg className="w-5 h-5 text-slate-300" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7" /></svg>
              </div>
            </div>

            <div className="pt-10 flex flex-col items-center">
              {!showConfirmDelete ? (
                <button onClick={() => setShowConfirmDelete(true)} className="text-[11px] font-black uppercase tracking-[0.2em] text-red-400 hover:text-red-600 transition-colors">Terminate Account</button>
              ) : (
                <div className="flex flex-col items-center gap-4 animate-in slide-in-from-bottom-2 duration-300">
                  <p className="text-xs font-bold text-red-600 uppercase tracking-tight">Confirm permanent identity purge?</p>
                  <div className="flex gap-4">
                    <button onClick={handleDeleteAccount} disabled={isDeleting} className="px-6 py-2.5 bg-red-600 text-white rounded-2xl text-[10px] uppercase font-black tracking-widest shadow-xl">Purge</button>
                    <button onClick={() => setShowConfirmDelete(false)} disabled={isDeleting} className={`px-6 py-2.5 border rounded-2xl text-[10px] uppercase font-black tracking-widest ${isDarkMode ? 'bg-slate-800' : 'bg-white'}`}>Cancel</button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {showBlockedModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 backdrop-blur-md bg-black/50 animate-in fade-in duration-300">
          <div className={`w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200 ${isDarkMode ? 'bg-slate-900 border border-slate-800 text-white' : 'bg-white text-slate-900'}`}>
            <div className="p-8 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <div>
                <h3 className="font-serif text-2xl font-bold">Blocked Accounts</h3>
              </div>
              <button onClick={() => setShowBlockedModal(false)} className="p-2">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="max-h-[50vh] overflow-y-auto p-6 space-y-4">
              {blockedDetails.length === 0 ? (
                <p className="text-center text-xs text-slate-400 italic py-8">No blocked users.</p>
              ) : (
                blockedDetails.map(blockedUser => (
                  <div key={blockedUser.id} className={`flex items-center justify-between p-4 rounded-3xl border ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
                    <div className="flex items-center gap-3">
                      <img src={blockedUser.avatar} className="w-10 h-10 rounded-2xl object-cover" />
                      <p className="text-xs font-bold">@{blockedUser.username}</p>
                    </div>
                    <button onClick={() => handleBlockToggleAction(blockedUser.id)} className="px-4 py-2 rounded-xl bg-white dark:bg-slate-900 text-[9px] font-black uppercase border">Unblock</button>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}

      {showReportModal && <ReportModal targetType="user" targetId={user.id} onClose={() => setShowReportModal(false)} onSubmit={() => setHasReportedUser(true)} isDarkMode={isDarkMode} />}
    </div>
  );
};

import { createClient } from '@supabase/supabase-js';
import { Post, User, BadgeTier, Comment, ReportType } from '../types';

const getEnv = (key: string): string => {
  if (typeof process !== 'undefined' && process.env && (process.env as any)[key]) {
    return (process.env as any)[key];
  }
  return '';
};

const SUPABASE_URL = getEnv('SUPABASE_URL') || 'https://uvjavqzhhqxkfuklkxdo.supabase.co';
const SUPABASE_ANON_KEY = getEnv('SUPABASE_ANON_KEY') || 'sb_publishable_-GDZiq_v45oEVhlly7tG-w_cKockqn6';

const isConfigured = SUPABASE_URL !== '' && SUPABASE_ANON_KEY !== '';
const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);
const SESSION_KEY = 'storyverse_session';

export const getBadge = (likes: number): BadgeTier => {
  if (likes >= 500) return BadgeTier.PLATINUM;
  if (likes >= 100) return BadgeTier.GOLD;
  if (likes >= 25) return BadgeTier.SILVER;
  if (likes >= 5) return BadgeTier.BRONZE;
  return BadgeTier.NOVICE;
};

export const db = {
  // --- Auth & Identity ---
  async register(username: string, email: string, password: string): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };

    const lowerEmail = email.toLowerCase().trim();
    if (!lowerEmail.endsWith('@gmail.com')) {
      return { success: false, error: 'Registration restricted to @gmail.com addresses only.' };
    }

    try {
      const userId = Math.random().toString(36).substr(2, 9);
      const userPayload = {
        id: userId,
        username: username.toLowerCase().trim(),
        email: lowerEmail,
        password: password,
        avatar: `https://picsum.photos/seed/${username}/100`,
        bio: '',
        bookmarks: [],
        blocked_users: [],
        total_likes: 0,
        badge: BadgeTier.NOVICE,
        report_count: 0,
        settings: { showReportCount: true, showStats: true }
      };

      const { error } = await supabase.from('users').insert([userPayload]);
      if (error) {
        if (error.message.includes('unique constraint')) return { success: false, error: 'Username or Email already taken.' };
        return { success: false, error: error.message };
      }

      const user: User = {
        id: userId,
        username: userPayload.username,
        email: userPayload.email,
        avatar: userPayload.avatar,
        bio: '',
        bookmarks: [],
        blockedUsers: [],
        totalLikes: 0,
        badge: BadgeTier.NOVICE,
        followerCount: 0,
        followingCount: 0,
        reportCount: 0,
        settings: userPayload.settings
      };

      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return { success: true, user };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async login(identifier: string, password: string, method: 'username' | 'email'): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };
    const field = method === 'username' ? 'username' : 'email';
    try {
      const { data, error } = await supabase.from('users').select('*').ilike(field, identifier).eq('password', password).maybeSingle();
      if (error) return { success: false, error: error.message };
      if (!data) return { success: false, error: 'Invalid credentials.' };
      const user = await this.refreshUser(data.id);
      return user ? { success: true, user } : { success: false, error: 'Session error.' };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async updateUserProfile(userId: string, data: { username?: string; avatar?: string; bio?: string }): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const updatePayload: any = {};
      if (data.username !== undefined) updatePayload.username = data.username.toLowerCase();
      if (data.avatar !== undefined) updatePayload.avatar = data.avatar;
      if (data.bio !== undefined) updatePayload.bio = data.bio;

      await supabase.from('users').update(updatePayload).eq('id', userId);

      if (data.username || data.avatar) {
        const postUpdate: any = {};
        if (data.username) postUpdate.username = data.username.toLowerCase();
        if (data.avatar) postUpdate.user_avatar = data.avatar;
        await supabase.from('posts').update(postUpdate).eq('user_id', userId);
      }

      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  // --- Blocking System ---
  async blockUser(userId: string, targetId: string): Promise<User | null> {
    if (!isConfigured || !userId || !targetId) return null;
    try {
      const { data, error } = await supabase.from('users').select('blocked_users').eq('id', userId).maybeSingle();
      if (error) throw error;

      let blockedList = Array.isArray(data?.blocked_users) ? data.blocked_users : [];
      if (!blockedList.includes(targetId)) {
        blockedList = [...blockedList, targetId];
        const { error: updateError } = await supabase.from('users').update({ blocked_users: blockedList }).eq('id', userId);
        if (updateError) throw updateError;
      }
      return await this.refreshUser(userId);
    } catch (err) {
      console.error("blockUser failed:", err);
      return null;
    }
  },

  async unblockUser(userId: string, targetId: string): Promise<User | null> {
    if (!isConfigured || !userId || !targetId) return null;
    try {
      const { data, error } = await supabase.from('users').select('blocked_users').eq('id', userId).maybeSingle();
      if (error) throw error;

      let blockedList = Array.isArray(data?.blocked_users) ? data.blocked_users : [];
      const newBlockedList = blockedList.filter((id: string) => id !== targetId);

      const { error: updateError } = await supabase.from('users').update({ blocked_users: newBlockedList }).eq('id', userId);
      if (updateError) throw updateError;

      return await this.refreshUser(userId);
    } catch (err) {
      console.error("unblockUser failed:", err);
      return null;
    }
  },

  // --- Posts & Content ---
  async getPosts(): Promise<Post[]> {
    if (!isConfigured) return [];
    try {
      const { data, error } = await supabase
        .from('posts')
        .select(`*, comments (*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      return (data || []).map(post => ({
        id: post.id,
        userId: post.user_id,
        username: post.username,
        title: post.title,
        content: post.content,
        likes: post.likes || 0,
        likedBy: Array.isArray(post.liked_by) ? post.liked_by : [],
        shares: post.shares || 0,
        createdAt: post.created_at,
        userAvatar: post.user_avatar,
        reportCount: post.report_count || 0,
        lastEditedAt: post.last_edited_at,
        comments: (post.comments || []).map((c: any) => ({
          id: c.id,
          userId: c.user_id,
          username: c.username,
          content: c.content,
          createdAt: c.created_at,
          reportCount: c.report_count || 0
        }))
      }));
    } catch (err) {
      console.error("getPosts failed:", err);
      return [];
    }
  },

  async savePost(post: Post): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Suspended account.");
    if (!isConfigured) return;
    await supabase.from('posts').insert([{
      id: post.id,
      user_id: post.userId,
      username: post.username,
      title: post.title,
      content: post.content,
      likes: post.likes,
      liked_by: post.likedBy,
      shares: post.shares,
      user_avatar: post.userAvatar,
      created_at: post.createdAt,
      report_count: 0
    }]);
  },

  async updatePost(updatedPost: Post): Promise<void> {
    if (!isConfigured) return;
    await supabase.from('posts').update({
      likes: updatedPost.likes,
      liked_by: updatedPost.likedBy,
      shares: updatedPost.shares,
      title: updatedPost.title,
      content: updatedPost.content
    }).eq('id', updatedPost.id);
  },

  async updatePostContent(postId: string, title: string, content: string): Promise<boolean> {
    if (!isConfigured) return false;
    try {
      const { error } = await supabase.from('posts').update({
        title,
        content,
        last_edited_at: new Date().toISOString()
      }).eq('id', postId);
      return !error;
    } catch {
      return false;
    }
  },

  async deletePost(postId: string): Promise<{ success: boolean, error?: string }> {
    if (!isConfigured) return { success: false };
    try {
      await supabase.from('comments').delete().eq('post_id', postId);
      const { error } = await supabase.from('posts').delete().eq('id', postId);
      if (error) throw error;
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async addComment(postId: string, comment: Comment): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Suspended account.");
    if (!isConfigured) return;
    await supabase.from('comments').insert([{
      id: comment.id,
      post_id: postId,
      user_id: comment.userId,
      username: comment.username,
      content: comment.content,
      created_at: comment.createdAt,
      report_count: 0
    }]);
  },

  // --- Global Utility ---
  async getUserById(userId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data, error } = await supabase.from('users').select('*').eq('id', userId).maybeSingle();
      if (error || !data) return null;
      const stats = await this.getFollowStats(data.id);
      return {
        id: data.id,
        username: data.username,
        email: data.email,
        avatar: data.avatar,
        bio: data.bio || '',
        bookmarks: Array.isArray(data.bookmarks) ? data.bookmarks : [],
        blockedUsers: Array.isArray(data.blocked_users) ? data.blocked_users : [],
        totalLikes: data.total_likes || 0,
        badge: (data.badge as BadgeTier) || BadgeTier.NOVICE,
        followerCount: stats.followers,
        followingCount: stats.following,
        reportCount: data.report_count || 0,
        bannedUntil: data.banned_until,
        settings: data.settings || { showReportCount: true, showStats: true }
      };
    } catch (err) {
      console.error("getUserById error:", err);
      return null;
    }
  },

  async refreshUser(userId: string): Promise<User | null> {
    const user = await this.getUserById(userId);
    if (user) localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    return user;
  },

  getCurrentUser(): User | null {
    try {
      const session = localStorage.getItem(SESSION_KEY);
      return session ? JSON.parse(session) : null;
    } catch {
      return null;
    }
  },

  async toggleBookmark(userId: string, postId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data: user } = await supabase.from('users').select('bookmarks').eq('id', userId).maybeSingle();
      if (!user) return null;
      let bookmarks = Array.isArray(user.bookmarks) ? user.bookmarks : [];
      const newBookmarks = bookmarks.includes(postId)
        ? bookmarks.filter((id: string) => id !== postId)
        : [...bookmarks, postId];
      await supabase.from('users').update({ bookmarks: newBookmarks }).eq('id', userId);
      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  async updateUserLikes(userId: string, delta: number): Promise<void> {
    if (!isConfigured) return;
    const { data: dbUser } = await supabase.from('users').select('total_likes').eq('id', userId).maybeSingle();
    if (!dbUser) return;
    const newTotalLikes = Math.max(0, (dbUser.total_likes || 0) + delta);
    const newBadge = getBadge(newTotalLikes);
    await supabase.from('users').update({ total_likes: newTotalLikes, badge: newBadge }).eq('id', userId);
  },

  async updateUserSettings(userId: string, settings: any): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      await supabase.from('users').update({ settings }).eq('id', userId);
      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  async reportEntity(reporterId: string, targetType: ReportType, targetId: string, reason: string): Promise<{ success: boolean, message: string }> {
    if (!isConfigured) return { success: false, message: 'Backend not configured.' };
    try {
      const alreadyReported = await this.hasAlreadyReported(reporterId, targetType, targetId);
      if (alreadyReported) return { success: false, message: 'Already reported.' };
      let table = targetType === 'user' ? 'users' : (targetType === 'post' ? 'posts' : 'comments');
      await supabase.from('reports').insert([{ id: Math.random().toString(36).substr(2, 9), reporter_id: reporterId, target_type: targetType, target_id: targetId, reason }]);
      const { data } = await supabase.from(table).select('report_count').eq('id', targetId).maybeSingle();
      const newCount = (data?.report_count || 0) + 1;
      await supabase.from(table).update({ report_count: newCount }).eq('id', targetId);
      return { success: true, message: 'Report submitted.' };
    } catch {
      return { success: false, message: 'Error submitting report.' };
    }
  },

  async hasAlreadyReported(reporterId: string, targetType: ReportType, targetId: string): Promise<boolean> {
    const { data } = await supabase.from('reports').select('id').eq('reporter_id', reporterId).eq('target_type', targetType).eq('target_id', targetId).maybeSingle();
    return !!data;
  },

  async getFollowStats(userId: string): Promise<{ followers: number, following: number }> {
    try {
      const { count: followers } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('following_id', userId);
      const { count: following } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('follower_id', userId);
      return { followers: followers || 0, following: following || 0 };
    } catch { return { followers: 0, following: 0 }; }
  },

  async getFollowers(userId: string): Promise<User[]> {
    try {
      const { data } = await supabase.from('follows').select('follower_id').eq('following_id', userId);
      if (!data) return [];
      const ids = data.map(f => f.follower_id);
      if (ids.length === 0) return [];
      const users = await Promise.all(ids.map(id => this.getUserById(id)));
      return users.filter((u): u is User => u !== null);
    } catch { return []; }
  },

  async getFollowingList(userId: string): Promise<User[]> {
    try {
      const { data } = await supabase.from('follows').select('following_id').eq('follower_id', userId);
      if (!data) return [];
      const ids = data.map(f => f.following_id);
      if (ids.length === 0) return [];
      const users = await Promise.all(ids.map(id => this.getUserById(id)));
      return users.filter((u): u is User => u !== null);
    } catch { return []; }
  },

  async isFollowing(followerId: string, followingId: string): Promise<boolean> {
    const { data } = await supabase.from('follows').select('*').eq('follower_id', followerId).eq('following_id', followingId).maybeSingle();
    return !!data;
  },

  async followUser(followerId: string, followingId: string): Promise<{ follower: User | null, following: User | null }> {
    await supabase.from('follows').insert([{ follower_id: followerId, following_id: followingId }]);
    return { follower: await this.refreshUser(followerId), following: await this.getUserById(followingId) };
  },

  async unfollowUser(followerId: string, followingId: string): Promise<{ follower: User | null, following: User | null }> {
    await supabase.from('follows').delete().eq('follower_id', followerId).eq('following_id', followingId);
    return { follower: await this.refreshUser(followerId), following: await this.getUserById(followingId) };
  },

  async deleteAccount(userId: string): Promise<{ success: boolean, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Database connection lost.' };
    try {
      const { data: postsData } = await supabase.from('posts').select('id').eq('user_id', userId);
      const postIds = (postsData || []).map(p => p.id);
      if (postIds.length > 0) {
        await supabase.from('comments').delete().in('post_id', postIds);
      }
      await supabase.from('comments').delete().eq('user_id', userId);
      await supabase.from('posts').delete().eq('user_id', userId);
      await supabase.from('follows').delete().eq('follower_id', userId);
      await supabase.from('follows').delete().eq('following_id', userId);
      await supabase.from('reports').delete().eq('reporter_id', userId);
      await supabase.from('users').delete().eq('id', userId);
      this.logout();
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  isBanned(user: User | null): boolean {
    if (!user || !user.bannedUntil) return false;
    return new Date(user.bannedUntil) > new Date();
  },

  logout() {
    localStorage.removeItem(SESSION_KEY);
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { User, Post } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';
import { ReportModal } from './ReportModal';

interface ProfileProps {
  user: User;
  currentUser: User | null;
  posts: Post[];
  isDarkMode: boolean;
  onAccountDeleted: () => void;
  onLogout: () => void;
  onUserUpdate: (updatedUser: User) => void;
  onBlockToggle?: (targetUserId: string) => void;
  onFollowToggle?: (targetUserId: string) => void;
  onUserClick?: (userId: string) => void;
}

export const Profile: React.FC<ProfileProps> = ({ 
  user, 
  currentUser, 
  posts, 
  isDarkMode, 
  onAccountDeleted, 
  onLogout,
  onUserUpdate,
  onBlockToggle,
  onFollowToggle,
  onUserClick
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [showConfirmDelete, setShowConfirmDelete] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [deleteError, setDeleteError] = useState('');

  const [isEditingProfile, setIsEditingProfile] = useState(false);
  const [editUsername, setEditUsername] = useState(user.username);
  const [editAvatar, setEditAvatar] = useState(user.avatar);
  const [editBio, setEditBio] = useState(user.bio || '');
  const [isSaving, setIsSaving] = useState(false);
  const [editError, setEditError] = useState('');

  const [isImportingLink, setIsImportingLink] = useState(false);
  const [linkInput, setLinkInput] = useState('');

  const [showReportModal, setShowReportModal] = useState(false);
  const [hasReportedUser, setHasReportedUser] = useState(false);
  const [isBlockLoading, setIsBlockLoading] = useState(false);
  const [isFollowLoading, setIsFollowLoading] = useState(false);
  const [isFollowing, setIsFollowing] = useState(false);

  const [showBlockedModal, setShowBlockedModal] = useState(false);
  const [blockedDetails, setBlockedDetails] = useState<User[]>([]);
  const [isLoadingBlocks, setIsLoadingBlocks] = useState(false);

  const [settings, setSettings] = useState(user.settings || { showReportCount: true, showStats: true });
  const [isSavingSettings, setIsSavingSettings] = useState(false);

  // Connection Lists
  const [followersList, setFollowersList] = useState<User[]>([]);
  const [followingList, setFollowingList] = useState<User[]>([]);
  const [isLoadingConnections, setIsLoadingConnections] = useState(false);
  const [activeTab, setActiveTab] = useState<'followers' | 'following'>('followers');

  const isOwnProfile = currentUser?.id === user.id;
  const userPosts = posts.filter(p => p.userId === user.id);
  const totalReceivedLikes = userPosts.reduce((acc, post) => acc + post.likes, 0);

  const isBlocked = useMemo(() => currentUser?.blockedUsers?.includes(user.id) || false, [currentUser, user.id]);

  useEffect(() => {
    if (!isEditingProfile) {
      setEditUsername(user.username);
      setEditAvatar(user.avatar);
      setEditBio(user.bio || '');
      setSettings(user.settings || { showReportCount: true, showStats: true });
      setEditError('');
      setIsImportingLink(false);
      setLinkInput('');
    }

    const checkReportStatus = async () => {
      if (currentUser && !isOwnProfile) {
        const reported = await db.hasAlreadyReported(currentUser.id, 'user', user.id);
        setHasReportedUser(reported);
        const following = await db.isFollowing(currentUser.id, user.id);
        setIsFollowing(following);
      }
    };
    checkReportStatus();

    const fetchConnections = async () => {
      setIsLoadingConnections(true);
      const [followers, following] = await Promise.all([
        db.getFollowers(user.id),
        db.getFollowingList(user.id)
      ]);
      setFollowersList(followers);
      setFollowingList(following);
      setIsLoadingConnections(false);
    };
    fetchConnections();
  }, [user.bio, user.username, user.avatar, user.settings, currentUser, isOwnProfile, user.id, isEditingProfile]);

  useEffect(() => {
    if (showBlockedModal && currentUser?.blockedUsers) {
      const fetchBlockedUsers = async () => {
        setIsLoadingBlocks(true);
        const details = await Promise.all(
          currentUser.blockedUsers.map(id => db.getUserById(id))
        );
        setBlockedDetails(details.filter((u): u is User => u !== null));
        setIsLoadingBlocks(false);
      };
      fetchBlockedUsers();
    }
  }, [showBlockedModal, currentUser?.blockedUsers]);

  const handleDeleteAccount = async () => {
    if (!window.confirm("Purge identity? This is irreversible.")) {
      setShowConfirmDelete(false);
      return;
    }
    setIsDeleting(true);
    const result = await db.deleteAccount(user.id);
    if (result.success) onAccountDeleted();
    else { setDeleteError(result.error || 'Failed.'); setIsDeleting(false); }
  };

  const handleShuffleAvatar = () => {
    const randomSeed = Math.random().toString(36).substring(7);
    setEditAvatar(`https://picsum.photos/seed/${randomSeed}/400`);
    setIsImportingLink(false);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setEditAvatar(reader.result as string);
        setIsImportingLink(false);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleApplyLink = () => {
    if (linkInput.trim()) {
      setEditAvatar(linkInput.trim());
      setIsImportingLink(false);
      setLinkInput('');
    }
  };

  const handleBlockToggleAction = async (targetId?: string) => {
    const idToToggle = targetId || user.id;
    if (!currentUser || (idToToggle === currentUser.id && !targetId) || isBlockLoading) return;
    setIsBlockLoading(true);
    const isTargetBlocked = currentUser.blockedUsers?.includes(idToToggle);
    let updated = isTargetBlocked ? await db.unblockUser(currentUser.id, idToToggle) : await db.blockUser(currentUser.id, idToToggle);
    if (updated) {
      onUserUpdate(updated);
      if (onBlockToggle) onBlockToggle(idToToggle);
      if (isTargetBlocked) setBlockedDetails(prev => prev.filter(u => u.id !== idToToggle));
    }
    setIsBlockLoading(false);
  };

  const handleFollowClick = async () => {
    if (!currentUser || !onFollowToggle || isFollowLoading) return;
    setIsFollowLoading(true);
    await onFollowToggle(user.id);
    setIsFollowing(!isFollowing);
    setIsFollowLoading(false);
    // Refresh connections
    const updatedFollowers = await db.getFollowers(user.id);
    setFollowersList(updatedFollowers);
  };

  const handleSaveProfile = async () => {
    if (!editUsername.trim()) { setEditError("Username required"); return; }
    setIsSaving(true);
    const updated = await db.updateUserProfile(user.id, { username: editUsername, avatar: editAvatar, bio: editBio });
    if (updated) { 
      onUserUpdate(updated); 
      setIsEditingProfile(false); 
    } else {
      setEditError("Username taken or update failed.");
    }
    setIsSaving(false);
  };

  const handleToggleSetting = async (key: 'showReportCount' | 'showStats') => {
    if (!isOwnProfile) return;
    const newSettings = { ...settings, [key]: !settings[key] };
    setSettings(newSettings);
    setIsSavingSettings(true);
    const updated = await db.updateUserSettings(user.id, newSettings);
    if (updated) onUserUpdate(updated);
    setIsSavingSettings(false);
  };

  const ConnectionList = ({ users }: { users: User[] }) => (
    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
      {users.length === 0 ? (
        <p className="col-span-full text-center text-[10px] text-slate-400 font-bold uppercase tracking-widest py-8">No narrative connections yet.</p>
      ) : (
        users.map(u => (
          <div 
            key={u.id} 
            onClick={() => onUserClick?.(u.id)}
            className={`flex items-center gap-3 p-3 rounded-2xl border cursor-pointer hover:scale-[1.02] transition-all ${
              isDarkMode ? 'bg-slate-800/50 border-slate-700' : 'bg-white border-slate-100 shadow-sm'
            }`}
          >
            <img src={u.avatar} className="w-9 h-9 rounded-xl object-cover shadow-sm" />
            <div className="flex flex-col text-left overflow-hidden">
              <span className="text-[11px] font-bold leading-none truncate">@{u.username}</span>
              <div className="mt-1 transform scale-75 origin-left">
                <BadgeIcon tier={u.badge} />
              </div>
            </div>
          </div>
        ))
      )}
    </div>
  );

  return (
    <div className="max-w-4xl mx-auto py-2 space-y-8 pb-20">
      <div className={`p-8 md:p-12 rounded-[2.5rem] border transition-all relative text-center flex flex-col items-center ${
        isDarkMode ? 'bg-slate-900 border-slate-800 text-white' : 'bg-white border-slate-100 shadow-xl text-slate-900'
      }`}>
        {isOwnProfile && (
          <button onClick={onLogout} className="absolute top-8 right-8 text-[10px] font-black uppercase text-slate-400 hover:text-indigo-600 transition-colors">Logout</button>
        )}

        {isEditingProfile ? (
          <div className="w-full space-y-8 animate-in zoom-in-95 duration-200">
            <h2 className="text-2xl font-serif font-bold italic">Identity Refining</h2>

            <div className="flex flex-col items-center gap-6">
              <div className="flex flex-col items-center gap-4 w-full">
                <div className="relative group cursor-pointer" onClick={() => fileInputRef.current?.click()}>
                  <img src={editAvatar} className="w-32 h-32 rounded-[2.5rem] object-cover shadow-2xl ring-4 ring-indigo-500/10" alt="Preview" />
                  <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 rounded-[2.5rem] flex items-center justify-center transition-all">
                    <span className="text-white text-[10px] font-black uppercase tracking-widest">Upload Photo</span>
                  </div>
                  <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileChange} />
                </div>

                <div className="flex flex-wrap justify-center gap-2">
                  <button type="button" onClick={() => fileInputRef.current?.click()} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest border transition-all ${isDarkMode ? 'border-slate-700 text-slate-400 hover:text-white' : 'border-slate-200 text-slate-500 hover:text-indigo-600'}`}>Select Photo</button>
                  <button type="button" onClick={handleShuffleAvatar} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest border transition-all ${isDarkMode ? 'border-slate-700 text-slate-400 hover:text-white' : 'border-slate-200 text-slate-500 hover:text-indigo-600'}`}>Shuffle Random</button>
                  <button type="button" onClick={() => setIsImportingLink(!isImportingLink)} className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest border transition-all ${isImportingLink ? 'bg-indigo-600 border-indigo-600 text-white' : (isDarkMode ? 'border-slate-700 text-slate-400 hover:text-white' : 'border-slate-200 text-slate-500 hover:text-indigo-600')}`}>Import Link</button>
                </div>

                {isImportingLink && (
                  <div className="w-full max-w-sm mt-2">
                    <div className="flex gap-2">
                      <input type="url" placeholder="Paste image URL..." value={linkInput} onChange={(e) => setLinkInput(e.target.value)} className={`flex-1 p-3 text-xs rounded-xl border outline-none focus:border-indigo-500 transition-all ${isDarkMode ? 'bg-slate-800 border-slate-700 text-white' : 'bg-slate-50 border-slate-200'}`} />
                      <button onClick={handleApplyLink} className="px-4 py-3 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg">Apply</button>
                    </div>
                  </div>
                )}
              </div>

              <div className="w-full max-w-sm space-y-4 text-left">
                {editError && <p className="text-[10px] font-bold text-red-500 uppercase text-center">{editError}</p>}
                <div>
                  <label className="text-[10px] font-black uppercase text-slate-400 block mb-1">Username</label>
                  <input type="text" value={editUsername} onChange={(e) => setEditUsername(e.target.value.toLowerCase().replace(/\s/g, ''))} className={`w-full p-4 text-sm rounded-2xl border outline-none focus:border-indigo-500 transition-all ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-200'}`} />
                </div>
                <div>
                  <label className="text-[10px] font-black uppercase text-slate-400 block mb-1">Bio</label>
                  <textarea value={editBio} onChange={(e) => setEditBio(e.target.value)} maxLength={160} rows={3} className={`w-full p-4 text-sm rounded-2xl border resize-none outline-none focus:border-indigo-500 transition-all ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-200'}`} />
                </div>
              </div>
            </div>

            <div className="flex gap-3 max-w-sm mx-auto">
              <button onClick={handleSaveProfile} disabled={isSaving} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase shadow-xl disabled:opacity-50">Save Profile</button>
              <button onClick={() => setIsEditingProfile(false)} className={`flex-1 py-4 border rounded-2xl text-[10px] font-black uppercase ${isDarkMode ? 'border-slate-700 hover:bg-slate-800' : 'border-slate-200 hover:bg-slate-50'}`}>Cancel</button>
            </div>
          </div>
        ) : (
          <div className="w-full flex flex-col items-center">
            <div className="relative group mb-8">
              <img src={user.avatar} className={`w-32 h-32 md:w-40 md:h-40 rounded-[3rem] object-cover shadow-2xl ring-4 ${isDarkMode ? 'ring-slate-800' : 'ring-indigo-50'}`} alt={user.username} />
              {isOwnProfile && (
                <button onClick={() => setIsEditingProfile(true)} className="absolute -bottom-2 -right-2 bg-white dark:bg-slate-800 p-3 rounded-2xl shadow-xl border dark:border-slate-700 hover:scale-110 transition-all">
                  <svg className="w-5 h-5 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                </button>
              )}
            </div>

            <h1 className="text-3xl font-serif font-bold mb-3">@{user.username}</h1>
            <div className="mb-6">
              <BadgeIcon tier={user.badge} size="md" />
            </div>

            {currentUser && !isOwnProfile && (
              <div className="mb-10 flex gap-4">
                <button 
                  onClick={handleFollowClick}
                  disabled={isFollowLoading}
                  className={`px-12 py-4 rounded-2xl text-[11px] font-black uppercase tracking-widest shadow-xl transition-all active:scale-95 ${
                    isFollowing 
                      ? (isDarkMode ? 'bg-slate-800 text-slate-400' : 'bg-slate-100 text-slate-500') 
                      : 'bg-indigo-600 text-white hover:bg-indigo-700'
                  }`}
                >
                  {isFollowLoading ? '...' : (isFollowing ? 'Following' : 'Follow')}
                </button>
                <button 
                  onClick={() => handleBlockToggleAction()}
                  disabled={isBlockLoading}
                  className={`px-6 py-4 rounded-2xl text-[11px] font-black uppercase tracking-widest border transition-all ${
                    isBlocked ? 'bg-red-500 border-red-500 text-white' : 'border-slate-200 dark:border-slate-700 text-slate-400 hover:text-red-500'
                  }`}
                >
                  {isBlocked ? 'Blocked' : 'Block'}
                </button>
              </div>
            )}

            <p className="text-sm text-slate-500 max-w-sm mx-auto mb-10 leading-relaxed font-medium">
              {user.bio || (isOwnProfile ? "You haven't told your story yet." : "This verse is waiting for a narrative.")}
            </p>

            <div className="w-full h-px bg-slate-100 dark:bg-slate-800 mb-8" />

            <div className="grid grid-cols-3 gap-4 w-full max-w-xl">
              <div className="text-center px-2">
                <p className="text-3xl font-bold tabular-nums">{userPosts.length}</p>
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mt-1">Stories</p>
              </div>
              <div className="text-center px-2 border-x dark:border-slate-800">
                <p className="text-3xl font-bold tabular-nums">{totalReceivedLikes}</p>
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mt-1">Likes</p>
              </div>
              <div className="text-center px-2">
                <p className="text-3xl font-bold tabular-nums">{user.followerCount}</p>
                <p className="text-[10px] font-black uppercase text-slate-400 tracking-widest mt-1">Followers</p>
              </div>
            </div>
          </div>
        )}
      </div>

      {/* Connection Lists Section */}
      <div className={`p-8 md:p-10 rounded-[2.5rem] border ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
        <div className="text-center mb-8">
          <h2 className="font-serif text-2xl font-bold italic mb-4">The Collective Network</h2>
          <div className="flex justify-center gap-6">
            <button 
              onClick={() => setActiveTab('followers')}
              className={`pb-2 text-[10px] font-black uppercase tracking-widest border-b-2 transition-all ${
                activeTab === 'followers' 
                  ? 'border-indigo-600 text-indigo-600' 
                  : 'border-transparent text-slate-400 hover:text-slate-600'
              }`}
            >
              Followers ({followersList.length})
            </button>
            <button 
              onClick={() => setActiveTab('following')}
              className={`pb-2 text-[10px] font-black uppercase tracking-widest border-b-2 transition-all ${
                activeTab === 'following' 
                  ? 'border-indigo-600 text-indigo-600' 
                  : 'border-transparent text-slate-400 hover:text-slate-600'
              }`}
            >
              Following ({followingList.length})
            </button>
          </div>
        </div>

        {isLoadingConnections ? (
          <div className="flex justify-center py-10">
            <div className="w-6 h-6 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
          </div>
        ) : (
          <ConnectionList users={activeTab === 'followers' ? followersList : followingList} />
        )}
      </div>

      {isOwnProfile && (
        <div className={`p-8 md:p-10 rounded-[2.5rem] border ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-xl'}`}>
          <h2 className="font-serif text-2xl font-bold mb-8 italic">Account Preferences</h2>
          <div className="space-y-6">
            <div className="flex items-center justify-between group cursor-pointer" onClick={() => handleToggleSetting('showStats')}>
              <div>
                <p className="text-xs font-bold uppercase tracking-widest mb-1">Public Statistics</p>
                <p className="text-[10px] text-slate-400 font-medium">Show stories, likes, and follower counts.</p>
              </div>
              <button className={`w-12 h-6 rounded-full relative transition-all shadow-inner ${settings.showStats ? 'bg-indigo-600' : 'bg-slate-200 dark:bg-slate-800'}`}>
                <div className={`absolute top-1 w-4 h-4 bg-white rounded-full transition-all shadow-md ${settings.showStats ? 'right-1' : 'left-1'}`} />
              </button>
            </div>

            <div className="flex items-center justify-between group cursor-pointer pt-6 border-t dark:border-slate-800" onClick={() => setShowBlockedModal(true)}>
              <div>
                <p className="text-xs font-bold uppercase tracking-widest mb-1">Blocked Accounts</p>
                <p className="text-[10px] text-slate-400 font-medium">Manage restricted users in your feed.</p>
              </div>
              <div className="flex items-center gap-3">
                <span className={`px-2 py-0.5 rounded-lg text-[10px] font-black tabular-nums ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
                  {currentUser?.blockedUsers?.length || 0}
                </span>
                <svg className="w-5 h-5 text-slate-300" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7" /></svg>
              </div>
            </div>

            <div className="pt-10 flex flex-col items-center">
              {!showConfirmDelete ? (
                <button onClick={() => setShowConfirmDelete(true)} className="text-[11px] font-black uppercase tracking-[0.2em] text-red-400 hover:text-red-600 transition-colors">Terminate Account</button>
              ) : (
                <div className="flex flex-col items-center gap-4 animate-in slide-in-from-bottom-2 duration-300">
                  <p className="text-xs font-bold text-red-600 uppercase tracking-tight">Confirm permanent identity purge?</p>
                  <div className="flex gap-4">
                    <button onClick={handleDeleteAccount} disabled={isDeleting} className="px-6 py-2.5 bg-red-600 text-white rounded-2xl text-[10px] uppercase font-black tracking-widest shadow-xl">Purge</button>
                    <button onClick={() => setShowConfirmDelete(false)} disabled={isDeleting} className={`px-6 py-2.5 border rounded-2xl text-[10px] uppercase font-black tracking-widest ${isDarkMode ? 'bg-slate-800' : 'bg-white'}`}>Cancel</button>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {showBlockedModal && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center p-4 backdrop-blur-md bg-black/50 animate-in fade-in duration-300">
          <div className={`w-full max-w-md rounded-[2.5rem] shadow-2xl overflow-hidden animate-in zoom-in-95 duration-200 ${isDarkMode ? 'bg-slate-900 border border-slate-800 text-white' : 'bg-white text-slate-900'}`}>
            <div className="p-8 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <div>
                <h3 className="font-serif text-2xl font-bold">Blocked Accounts</h3>
              </div>
              <button onClick={() => setShowBlockedModal(false)} className="p-2">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
              </button>
            </div>

            <div className="max-h-[50vh] overflow-y-auto p-6 space-y-4">
              {blockedDetails.length === 0 ? (
                <p className="text-center text-xs text-slate-400 italic py-8">No blocked users.</p>
              ) : (
                blockedDetails.map(blockedUser => (
                  <div key={blockedUser.id} className={`flex items-center justify-between p-4 rounded-3xl border ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
                    <div className="flex items-center gap-3">
                      <img src={blockedUser.avatar} className="w-10 h-10 rounded-2xl object-cover" />
                      <p className="text-xs font-bold">@{blockedUser.username}</p>
                    </div>
                    <button onClick={() => handleBlockToggleAction(blockedUser.id)} className="px-4 py-2 rounded-xl bg-white dark:bg-slate-900 text-[9px] font-black uppercase border">Unblock</button>
                  </div>
                ))
              )}
            </div>
          </div>
        </div>
      )}

      {showReportModal && <ReportModal targetType="user" targetId={user.id} onClose={() => setShowReportModal(false)} onSubmit={() => setHasReportedUser(true)} isDarkMode={isDarkMode} />}
    </div>
  );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Post, User, Page, BadgeTier } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { AuthForm } from './components/AuthForm';
import { CreatePostForm } from './components/CreatePostForm';
import { PostList } from './components/PostList';
import { Profile } from './components/Profile';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [viewingUser, setViewingUser] = useState<User | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      document.body.className = 'bg-slate-950 text-slate-100';
    } else {
      document.documentElement.classList.remove('dark');
      document.body.className = 'bg-slate-50 text-slate-900';
    }
  }, [isDarkMode]);

  const fetchPosts = useCallback(async () => {
    setIsLoading(true);
    const data = await db.getPosts();
    setPosts(data);
    setIsLoading(false);
  }, []);

  const refreshCurrentUser = useCallback(async () => {
    const user = db.getCurrentUser();
    if (user) {
      const refreshedUser = await db.refreshUser(user.id);
      if (refreshedUser) setCurrentUser(refreshedUser);
    }
  }, []);

  useEffect(() => {
    const user = db.getCurrentUser();
    if (user) {
      setCurrentUser(user);
      refreshCurrentUser();
    }
    fetchPosts();
  }, [fetchPosts, refreshCurrentUser]);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentUser) {
      const blockedIds = currentUser.blockedUsers || [];
      result = result.filter(p => !blockedIds.includes(p.userId));
    }
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    } else if (currentPage === 'bookmarks' && currentUser) {
      const bookmarkIds = currentUser.bookmarks || [];
      result = result.filter(p => bookmarkIds.includes(p.id));
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
    setViewingUser(null);
  };

  const handleNavigate = async (page: Page, userId?: string) => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setSearchQuery('');
    if (page === 'profile') {
      const id = userId || currentUser?.id;
      if (id) {
        setIsLoading(true);
        const userToView = await db.getUserById(id);
        setViewingUser(userToView);
        setCurrentPage('profile');
        setIsLoading(false);
      } else {
        setCurrentPage('login');
      }
    } else {
      setCurrentPage(page);
      setViewingUser(null);
    }
  };

  const handleUserUpdate = (updated: User) => {
    if (currentUser?.id === updated.id) setCurrentUser(updated);
    if (viewingUser?.id === updated.id) setViewingUser(updated);
  };

  const handleFollowToggle = async (targetUserId: string) => {
    if (!currentUser) {
      setCurrentPage('login');
      return;
    }

    const isFollowing = await db.isFollowing(currentUser.id, targetUserId);
    const result = isFollowing 
      ? await db.unfollowUser(currentUser.id, targetUserId)
      : await db.followUser(currentUser.id, targetUserId);

    if (result.follower) setCurrentUser(result.follower);
    if (result.following && viewingUser?.id === targetUserId) setViewingUser(result.following);
  };

  const getListHeader = () => {
    if (searchQuery) return { title: `Search Results`, description: `Displaying matches for "${searchQuery}".` };
    switch (currentPage) {
      case 'my-stories': return { title: 'My Narratives', description: 'Your personal collection of living stories.' };
      case 'bookmarks': return { title: 'Saved Stories', description: 'Stories you have preserved in your library.' };
      default: return { title: 'Discover the Verse', description: 'Where the world shares its hidden stories.' };
    }
  };

  const { title, description } = getListHeader();

  return (
    <div className={`min-h-screen flex flex-col ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={handleNavigate}
        currentPage={currentPage}
      />

      <main className="flex-1 w-full max-w-5xl mx-auto px-4 pt-12 pb-24">
        {isLoading ? (
          <div className="flex flex-col items-center justify-center py-40">
            <div className={`w-12 h-12 border-4 border-t-indigo-500 rounded-full animate-spin ${isDarkMode ? 'border-slate-800' : 'border-slate-200'}`}></div>
          </div>
        ) : (
          <div className="space-y-12">
            {(currentPage === 'home' || currentPage === 'my-stories' || currentPage === 'bookmarks') && (
              <>
                <div className="text-center mb-16">
                  <h1 className="font-serif text-5xl md:text-6xl font-bold mb-4 tracking-tight">{title}</h1>
                  <p className="text-sm md:text-base text-slate-400 font-medium">{description}</p>
                </div>
                <PostList 
                  posts={filteredPosts}
                  currentUser={currentUser}
                  isDarkMode={isDarkMode}
                  onPostUpdate={(upd) => setPosts(prev => prev.map(p => p.id === upd.id ? upd : p))}
                  onPostDeleted={fetchPosts}
                  onBookmarkToggle={handleUserUpdate}
                  onUserClick={(id) => handleNavigate('profile', id)}
                  onActionClick={() => handleNavigate('create')}
                  onFollowToggle={handleFollowToggle}
                  title="" 
                  description=""
                />
              </>
            )}

            {currentPage === 'create' && currentUser && (
              <CreatePostForm currentUser={currentUser} isDarkMode={isDarkMode} onPostCreated={() => { fetchPosts(); setCurrentPage('home'); }} />
            )}

            {currentPage === 'profile' && viewingUser && (
              <Profile 
                user={viewingUser} 
                currentUser={currentUser} 
                posts={posts} 
                isDarkMode={isDarkMode} 
                onAccountDeleted={handleLogout} 
                onLogout={handleLogout} 
                onUserUpdate={handleUserUpdate} 
                onFollowToggle={handleFollowToggle}
                onUserClick={(id) => handleNavigate('profile', id)}
              />
            )}

            {(currentPage === 'login' || currentPage === 'register') && (
              <div className="max-w-md mx-auto pt-10">
                <AuthForm mode={currentPage} isDarkMode={isDarkMode} onAuthSuccess={(u) => { setCurrentUser(u); setCurrentPage('home'); }} onSwitchMode={setCurrentPage} />
              </div>
            )}
          </div>
        )}
      </main>

      <footer className={`w-full py-16 border-t text-center ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <div className="max-w-4xl mx-auto px-4 flex flex-col items-center">
          <h2 className="font-serif text-2xl font-bold mb-6">StoryVerse</h2>
          <div className="flex items-center gap-2 mb-8">
            <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-500">Connected to Supabase</span>
          </div>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">
            © 2026 StoryVerse Collective. Verified Global Sync.
          </p>
        </div>
      </footer>
    </div>
  );
};

