import React, { useState, useMemo, useEffect } from 'react';
import { Post, User, BadgeTier } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';
import { EditPostModal } from './EditPostModal';

interface PostCardProps {
  post: Post;
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (post: Post) => void;
  onPostDeleted: () => void;
  onUserClick?: (userId: string) => void;
  onBookmarkToggle?: (updatedUser: User) => void;
  onFollowToggle?: (targetUserId: string) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  isDarkMode,
  onPostUpdate, 
  onPostDeleted,
  onUserClick,
  onBookmarkToggle,
  onFollowToggle
}) => {
  const [showComments, setShowComments] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [showMenu, setShowMenu] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [authorBadge, setAuthorBadge] = useState<BadgeTier>(BadgeTier.NOVICE);
  const [isFollowing, setIsFollowing] = useState(false);
  const [isFollowLoading, setIsFollowLoading] = useState(false);
  const [showShareFeedback, setShowShareFeedback] = useState(false);
  const [isSharing, setIsSharing] = useState(false);

  const isOwner = currentUser?.id === post.userId;
  const isBookmarked = currentUser?.bookmarks?.includes(post.id);
  const isLiked = currentUser ? post.likedBy?.includes(currentUser.id) : false;

  useEffect(() => {
    db.getUserById(post.userId).then(u => u && setAuthorBadge(u.badge));
    if (currentUser && !isOwner) {
      db.isFollowing(currentUser.id, post.userId).then(setIsFollowing);
    }
  }, [post.userId, currentUser, isOwner]);

  const handleLike = async () => {
    if (!currentUser) return;
    const hasLiked = post.likedBy?.includes(currentUser.id);
    const updated = { 
      ...post, 
      likes: post.likes + (hasLiked ? -1 : 1), 
      likedBy: hasLiked ? post.likedBy.filter(id => id !== currentUser.id) : [...(post.likedBy || []), currentUser.id] 
    };
    onPostUpdate(updated);
    await db.updatePost(updated);
    await db.updateUserLikes(post.userId, hasLiked ? -1 : 1);
  };

  const handleFollowClick = async () => {
    if (!currentUser || !onFollowToggle || isFollowLoading) return;
    setIsFollowLoading(true);
    await onFollowToggle(post.userId);
    setIsFollowing(!isFollowing);
    setIsFollowLoading(false);
  };

  const handleShare = async () => {
    if (isSharing) return;
    const currentUrl = window.location.href.startsWith('http') 
      ? window.location.href 
      : window.location.origin;

    const shareData = {
      title: post.title,
      text: `Check out "${post.title}" by @${post.username} on StoryVerse!`,
      url: currentUrl,
    };

    setIsSharing(true);
    try {
      if (navigator.share && navigator.canShare && navigator.canShare(shareData)) {
        try {
          await navigator.share(shareData);
          return;
        } catch (err) {
          if ((err as Error).name === 'AbortError') return;
        }
      }
      try {
        await navigator.clipboard.writeText(currentUrl);
        setShowShareFeedback(true);
        setTimeout(() => setShowShareFeedback(false), 2000);
      } catch (err) {
        console.error('Clipboard copy failed:', err);
      }
    } finally {
      setIsSharing(false);
    }
  };

  return (
    <div className={`rounded-[2rem] border transition-all mb-6 overflow-hidden ${
      isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-sm'
    }`}>
      <div className="p-6 sm:p-8 md:p-10">
        <div className="flex items-start justify-between mb-4 sm:mb-8">
          <div className="flex items-center gap-3 sm:gap-4">
            <img 
              src={post.userAvatar} 
              className="w-10 h-10 sm:w-12 sm:h-12 rounded-xl object-cover cursor-pointer shadow-sm" 
              onClick={() => onUserClick?.(post.userId)}
            />
            <div>
              <div className="flex flex-wrap items-center gap-2 mb-0.5 sm:mb-1">
                <span className="font-bold text-xs sm:text-sm cursor-pointer" onClick={() => onUserClick?.(post.userId)}>@{post.username}</span>
                <BadgeIcon tier={authorBadge} />

                {!isOwner && currentUser && (
                  <button 
                    onClick={handleFollowClick}
                    disabled={isFollowLoading}
                    className={`text-[8px] sm:text-[9px] font-black uppercase tracking-widest px-2 py-0.5 sm:px-3 sm:py-1 rounded-full transition-all ${
                      isFollowing 
                        ? (isDarkMode ? 'bg-slate-800 text-slate-400' : 'bg-slate-100 text-slate-500')
                        : 'text-indigo-600 hover:text-indigo-700'
                    }`}
                  >
                    {isFollowLoading ? '...' : (isFollowing ? 'Following' : 'Follow')}
                  </button>
                )}
              </div>
              <div className="flex items-center gap-2 text-[8px] sm:text-[9px] text-slate-400 font-bold uppercase tracking-widest">
                <span>{new Date(post.createdAt).toLocaleDateString(undefined, { day: 'numeric', month: 'short' }).toUpperCase()}</span>
                <span>•</span>
                <span>READING NOW</span>
              </div>
            </div>
          </div>
          <div className="relative">
            <button onClick={() => setShowMenu(!showMenu)} className="p-2 text-slate-300 hover:text-slate-600 transition-colors">
              <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M10 6a2 2 0 110-4 2 2 0 010 4zM10 12a2 2 0 110-4 2 2 0 010 4zM10 18a2 2 0 110-4 2 2 0 010 4z"/></svg>
            </button>
            {showMenu && (
              <div className={`absolute right-0 top-10 w-44 rounded-2xl shadow-2xl border z-20 ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-100'}`}>
                <button onClick={() => { onUserClick?.(post.userId); setShowMenu(false); }} className="w-full text-left px-4 py-3 text-[10px] font-black uppercase tracking-widest hover:bg-slate-50 dark:hover:bg-slate-700">View Profile</button>
                {isOwner && (
                  <>
                    <button onClick={() => { setShowEditModal(true); setShowMenu(false); }} className="w-full text-left px-4 py-3 text-[10px] font-black uppercase tracking-widest border-t dark:border-slate-700">Edit Story</button>
                    <button onClick={async () => { await db.deletePost(post.id); onPostDeleted(); }} className="w-full text-left px-4 py-3 text-[10px] font-black uppercase tracking-widest text-red-500 border-t dark:border-slate-700">Delete</button>
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        <h3 className="font-serif text-xl sm:text-2xl md:text-3xl font-bold mb-3 sm:mb-6 leading-tight">{post.title}</h3>

        <div 
          className={`rich-content text-sm sm:text-base leading-relaxed mb-4 sm:mb-6 ${isDarkMode ? 'text-slate-400' : 'text-slate-500'} ${isExpanded ? '' : 'line-clamp-[8]'}`}
          dangerouslySetInnerHTML={{ __html: post.content }}
        />

        <button onClick={() => setIsExpanded(!isExpanded)} className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-600 mb-6 sm:mb-10 flex items-center gap-1 hover:underline group">
          {isExpanded ? 'Collapse Story ↑' : 'Read Full Story ↓'}
        </button>

        <div className="flex items-center justify-between pt-4 sm:pt-8 border-t dark:border-slate-800">
          <div className="flex items-center gap-6 sm:gap-8">
            <button onClick={handleLike} className={`flex items-center gap-1.5 sm:gap-2.5 text-xs font-bold transition-all ${isLiked ? 'text-red-500' : 'text-slate-400 hover:text-slate-600'}`}>
              <svg className={`w-5 h-5 sm:w-6 sm:h-6 ${isLiked ? 'fill-red-500 text-red-500' : 'fill-none stroke-current'}`} strokeWidth="2" viewBox="0 0 24 24"><path d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/></svg>
              <span className={isLiked ? 'text-red-500' : ''}>{post.likes}</span>
            </button>
            <button onClick={() => setShowComments(!showComments)} className="flex items-center gap-1.5 sm:gap-2.5 text-xs font-bold text-slate-400 hover:text-slate-600">
              <svg className="w-5 h-5 sm:w-6 sm:h-6" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
              <span>{post.comments.length}</span>
            </button>
            <button 
              onClick={handleShare}
              disabled={isSharing}
              className={`flex items-center gap-1 relative transition-all group ${showShareFeedback ? 'text-indigo-600 scale-110' : 'text-slate-400 hover:text-indigo-500'} disabled:opacity-50`}
              title="Share Story"
            >
              <svg className="w-5 h-5 sm:w-6 sm:h-6" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" d="M7.217 10.907a2.25 2.25 0 1 0 0 2.186m0-2.186c.18.324.283.696.283 1.093s-.103.77-.283 1.093m0-2.186 9.566-5.314m-9.566 7.5 9.566 5.314m0 0a2.25 2.25 0 1 0 3.935 2.186 2.25 2.25 0 0 0-3.935-2.186Zm0-12.814a2.25 2.25 0 1 0 3.933-2.185 2.25 2.25 0 0 0-3.933 2.185Z" />
              </svg>
              {showShareFeedback && (
                <span className="absolute -top-10 left-1/2 -translate-x-1/2 text-[9px] font-black uppercase bg-indigo-600 text-white px-3 py-1.5 rounded-xl shadow-xl animate-in fade-in slide-in-from-bottom-2 z-10 whitespace-nowrap">
                  Link Copied!
                </span>
              )}
            </button>
          </div>
          <button onClick={async () => {
             const updated = await db.toggleBookmark(currentUser!.id, post.id);
             if (updated && onBookmarkToggle) onBookmarkToggle(updated);
          }} className={`p-1 transition-all ${isBookmarked ? 'text-indigo-500 scale-110' : 'text-slate-300 hover:text-slate-500'}`}>
            <svg className={`w-5 h-5 sm:w-6 sm:h-6 ${isBookmarked ? 'fill-current' : 'fill-none stroke-current'}`} strokeWidth="2" viewBox="0 0 24 24"><path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" /></svg>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-6 sm:p-8 border-t dark:border-slate-800 animate-in slide-in-from-top duration-300 ${isDarkMode ? 'bg-slate-900/50' : 'bg-slate-50'}`}>
          <div className="space-y-4 sm:space-y-6 mb-6 sm:mb-8">
            {post.comments.map(c => (
              <div key={c.id} className="flex gap-3 sm:gap-4">
                <div className="w-8 h-8 sm:w-9 sm:h-9 rounded-xl bg-indigo-500/10 border border-indigo-500/10 flex items-center justify-center text-indigo-600 text-[10px] font-black shrink-0">{c.username[0].toUpperCase()}</div>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <p className="text-[10px] sm:text-xs font-bold">@{c.username}</p>
                    <span className="text-[8px] text-slate-400 font-bold uppercase tracking-widest">{new Date(c.createdAt).toLocaleDateString()}</span>
                  </div>
                  <p className="text-xs sm:text-sm text-slate-500 leading-relaxed">{c.content}</p>
                </div>
              </div>
            ))}
            {post.comments.length === 0 && <p className="text-center text-[10px] text-slate-400 italic py-4">No responses yet.</p>}
          </div>
          {currentUser && (
            <form onSubmit={async (e) => {
              e.preventDefault();
              const text = (e.target as any).reply.value;
              if (!text.trim() || !currentUser) return;
              const comm = { id: Math.random().toString(36).substr(2, 9), userId: currentUser.id, username: currentUser.username, content: text, createdAt: new Date().toISOString() };
              await db.addComment(post.id, comm);
              onPostUpdate({ ...post, comments: [...post.comments, comm] });
              (e.target as any).reply.value = '';
            }} className="flex gap-2 sm:gap-3">
              <input name="reply" placeholder="Add response..." className={`flex-1 px-4 py-2.5 rounded-xl text-xs border outline-none transition-all ${isDarkMode ? 'bg-slate-950 border-slate-700' : 'bg-white border-slate-200'}`} />
              <button type="submit" className="px-4 py-2.5 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">Reply</button>
            </form>
          )}
        </div>
      )}
      {showEditModal && <EditPostModal post={post} isDarkMode={isDarkMode} onClose={() => setShowEditModal(false)} onUpdate={onPostUpdate} />}
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { User, Post } from '../types';
import { db } from '../services/db';
import { aiService } from '../services/ai';

interface CreatePostFormProps {
  currentUser: User;
  isDarkMode: boolean;
  onPostCreated: () => void;
}

export const CreatePostForm: React.FC<CreatePostFormProps> = ({ currentUser, isDarkMode, onPostCreated }) => {
  const [newTitle, setNewTitle] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiStatus, setAiStatus] = useState('');
  const [error, setError] = useState('');
  const editorRef = useRef<HTMLDivElement>(null);

  const isBanned = db.isBanned(currentUser);

  const execCommand = (command: string, value: string | null = null) => {
    document.execCommand(command, false, value || '');
    if (editorRef.current) editorRef.current.focus();
  };

  const handleCreatePost = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser) return;
    setError('');

    const content = editorRef.current?.innerHTML || '';

    if (isBanned) {
      setError("Your account is currently suspended. You cannot publish stories.");
      return;
    }

    if (!content.trim() || content === '<br>') {
      setError("Please write something before publishing.");
      return;
    }

    const newPost: Post = {
      id: Math.random().toString(36).substr(2, 9),
      userId: currentUser.id,
      username: currentUser.username,
      title: newTitle,
      content: content,
      likes: 0,
      likedBy: [],
      shares: 0,
      comments: [],
      createdAt: new Date().toISOString(),
      userAvatar: currentUser.avatar
    };

    try {
      await db.savePost(newPost);
      setNewTitle('');
      if (editorRef.current) editorRef.current.innerHTML = '';
      onPostCreated();
    } catch (err: any) {
      setError(err.message || "Failed to publish.");
    }
  };

  const handleFixGrammar = async () => {
    const text = editorRef.current?.innerText || '';
    if (!text.trim()) return;
    setIsAiLoading(true);
    setAiStatus('Refining...');
    try {
      const corrected = await aiService.fixGrammar(text);
      if (editorRef.current) editorRef.current.innerText = corrected;
      setAiStatus('Polished!');
    } catch (error) {
      setAiStatus('Offline');
    } finally {
      setIsAiLoading(false);
      setTimeout(() => setAiStatus(''), 3000);
    }
  };

  const handleGetSuggestion = async () => {
    const text = editorRef.current?.innerText || '';
    if (!text.trim()) return;
    setIsAiLoading(true);
    setAiStatus('Thinking...');
    try {
      const suggestion = await aiService.getSuggestion(newTitle, text);
      if (editorRef.current) {
        editorRef.current.innerHTML += " " + suggestion;
      }
      setAiStatus('Inspired!');
    } catch (error) {
      setAiStatus('Silent');
    } finally {
      setIsAiLoading(false);
      setTimeout(() => setAiStatus(''), 3000);
    }
  };

  return (
    <section className="max-w-3xl mx-auto px-1">
      <h1 className="font-serif text-2xl md:text-4xl font-bold mb-6 md:mb-10 text-center italic">Craft Your Narrative</h1>

      {error && (
        <div className="mb-6 p-4 bg-red-600 text-white rounded-2xl font-bold text-xs flex items-center gap-3 shadow-lg animate-in slide-in-from-top">
           <svg className="w-5 h-5 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
           {error}
        </div>
      )}

      <form 
        onSubmit={handleCreatePost}
        className={`rounded-3xl shadow-2xl overflow-hidden flex flex-col ${isDarkMode ? 'bg-slate-900 border border-slate-800' : 'bg-white border border-slate-100'} ${isBanned ? 'opacity-50' : ''}`}
      >
        {/* Toolbar */}
        <div className={`p-3 border-b flex flex-wrap items-center gap-1.5 ${isDarkMode ? 'bg-slate-800/50 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
          <select 
            onChange={(e) => execCommand('fontName', e.target.value)}
            className={`px-2 py-1.5 text-[10px] font-bold rounded-lg outline-none cursor-pointer ${isDarkMode ? 'bg-slate-800 text-slate-300' : 'bg-white text-slate-600 shadow-sm'}`}
          >
            <option value="Inter">Modern Sans</option>
            <option value="Playfair Display">Classic Serif</option>
            <option value="monospace">Tech Mono</option>
          </select>

          <select 
            onChange={(e) => execCommand('fontSize', e.target.value)}
            className={`px-2 py-1.5 text-[10px] font-bold rounded-lg outline-none cursor-pointer ${isDarkMode ? 'bg-slate-800 text-slate-300' : 'bg-white text-slate-600 shadow-sm'}`}
            defaultValue="3"
          >
            <option value="1">Small</option>
            <option value="3">Normal</option>
            <option value="5">Large</option>
            <option value="7">Extra Large</option>
          </select>

          <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-1" />

          {[
            { cmd: 'bold', label: 'B', title: 'Bold' },
            { cmd: 'italic', label: 'I', title: 'Italic', class: 'italic' },
            { cmd: 'underline', label: 'U', title: 'Underline', class: 'underline' },
          ].map((tool) => (
            <button
              key={tool.cmd}
              type="button"
              title={tool.title}
              onClick={() => execCommand(tool.cmd)}
              className={`w-8 h-8 flex items-center justify-center rounded-lg text-xs font-black transition-all hover:scale-105 active:scale-95 ${isDarkMode ? 'bg-slate-800 text-slate-300 hover:bg-slate-700' : 'bg-white text-slate-600 shadow-sm hover:bg-slate-100'}`}
            >
              <span className={tool.class}>{tool.label}</span>
            </button>
          ))}

          <button
            type="button"
            title="Highlight"
            onClick={() => execCommand('hiliteColor', 'rgba(255, 255, 0, 0.4)')}
            className={`w-8 h-8 flex items-center justify-center rounded-lg text-xs font-black transition-all ${isDarkMode ? 'bg-slate-800 text-slate-300 hover:bg-slate-700' : 'bg-white text-slate-600 shadow-sm hover:bg-slate-100'}`}
          >
            H
          </button>

          <div className="w-px h-6 bg-slate-200 dark:bg-slate-700 mx-1" />

          <button
            type="button"
            title="Bullets"
            onClick={() => execCommand('insertUnorderedList')}
            className={`w-8 h-8 flex items-center justify-center rounded-lg text-xs font-black transition-all ${isDarkMode ? 'bg-slate-800 text-slate-300 hover:bg-slate-700' : 'bg-white text-slate-600 shadow-sm hover:bg-slate-100'}`}
          >
            •
          </button>
          <button
            type="button"
            title="Numbered List"
            onClick={() => execCommand('insertOrderedList')}
            className={`w-8 h-8 flex items-center justify-center rounded-lg text-xs font-black transition-all ${isDarkMode ? 'bg-slate-800 text-slate-300 hover:bg-slate-700' : 'bg-white text-slate-600 shadow-sm hover:bg-slate-100'}`}
          >
            1.
          </button>

          <div className="flex-1" />

          {aiStatus && (
            <span className={`text-[9px] font-black uppercase tracking-widest animate-pulse px-2 ${isDarkMode ? 'text-indigo-400' : 'text-indigo-600'}`}>
              {aiStatus}
            </span>
          )}
        </div>

        <div className="p-6 md:p-8 space-y-6">
          <div>
            <input 
              required
              disabled={isBanned}
              type="text" 
              placeholder="Give your story a title..."
              value={newTitle}
              onChange={(e) => setNewTitle(e.target.value)}
              className={`w-full p-2 text-2xl md:text-3xl font-serif font-bold bg-transparent outline-none border-b border-transparent focus:border-indigo-500/30 transition-all ${
                isDarkMode ? 'text-white' : 'text-slate-900'
              }`}
            />
          </div>

          <div 
            ref={editorRef}
            contentEditable={!isBanned}
            placeholder="Write something unforgettable..."
            className={`w-full min-h-[300px] outline-none text-sm md:text-base leading-relaxed rich-editor ${
              isDarkMode ? 'text-slate-300' : 'text-slate-600'
            }`}
          />
        </div>

        <div className={`p-4 border-t flex flex-col sm:flex-row gap-3 ${isDarkMode ? 'bg-slate-950 border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
          {!isBanned && (
            <div className="flex gap-2 flex-1">
              <button
                type="button"
                onClick={handleFixGrammar}
                disabled={isAiLoading}
                className={`flex-1 py-3 text-[9px] font-black uppercase tracking-widest rounded-xl border transition-all flex items-center justify-center gap-2 ${
                  isDarkMode ? 'border-slate-800 text-slate-400 hover:bg-slate-800' : 'border-slate-200 text-slate-500 hover:bg-white'
                }`}
              >
                ✨ AI Fix
              </button>
              <button
                type="button"
                onClick={handleGetSuggestion}
                disabled={isAiLoading}
                className={`flex-1 py-3 text-[9px] font-black uppercase tracking-widest rounded-xl border transition-all flex items-center justify-center gap-2 ${
                  isDarkMode ? 'border-slate-800 text-slate-400 hover:bg-slate-800' : 'border-slate-200 text-slate-500 hover:bg-white'
                }`}
              >
                 🖋️ AI Extend
              </button>
            </div>
          )}
          <button 
            type="submit"
            disabled={isBanned}
            className="flex-[1.5] py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-xl transition-all active:scale-[0.98] text-xs uppercase tracking-widest disabled:bg-slate-400"
          >
            {isBanned ? 'Publication Suspended' : 'Publish to Universe'}
          </button>
        </div>
      </form>
      <style>{`
        .rich-editor:empty:before {
          content: attr(placeholder);
          color: #94a3b8;
          font-style: italic;
        }
        .rich-editor ul { list-style-type: disc; padding-left: 20px; }
        .rich-editor ol { list-style-type: decimal; padding-left: 20px; }
        .rich-content ul { list-style-type: disc; padding-left: 20px; margin: 10px 0; }
        .rich-content ol { list-style-type: decimal; padding-left: 20px; margin: 10px 0; }
      `}</style>
    </section>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Post } from '../types';
import { aiService } from '../services/ai';
import { db } from '../services/db';

interface EditPostModalProps {
  post: Post;
  isDarkMode: boolean;
  onClose: () => void;
  onUpdate: (updatedPost: Post) => void;
}

export const EditPostModal: React.FC<EditPostModalProps> = ({ post, isDarkMode, onClose, onUpdate }) => {
  const [title, setTitle] = useState(post.title);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [aiStatus, setAiStatus] = useState('');
  const [isSaving, setIsSaving] = useState(false);
  const editorRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (editorRef.current) {
      editorRef.current.innerHTML = post.content;
    }
  }, [post.content]);

  const execCommand = (command: string, value: string | null = null) => {
    document.execCommand(command, false, value || '');
    if (editorRef.current) editorRef.current.focus();
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    const content = editorRef.current?.innerHTML || '';
    if (!title.trim() || !content.trim()) return;

    setIsSaving(true);
    const success = await db.updatePostContent(post.id, title, content);
    if (success) {
      onUpdate({ ...post, title, content, lastEditedAt: new Date().toISOString() });
      onClose();
    } else {
      alert("Failed to save changes. Please try again.");
    }
    setIsSaving(false);
  };

  const handleFixGrammar = async () => {
    const text = editorRef.current?.innerText || '';
    if (!text.trim()) return;
    setIsAiLoading(true);
    setAiStatus('Refining...');
    const corrected = await aiService.fixGrammar(text);
    if (editorRef.current) editorRef.current.innerText = corrected;
    setIsAiLoading(false);
    setAiStatus('Polished!');
    setTimeout(() => setAiStatus(''), 2000);
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 backdrop-blur-md bg-black/40 animate-in fade-in duration-200">
      <div className={`w-full max-w-3xl rounded-[2rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] ${isDarkMode ? 'bg-slate-900 border border-slate-800 text-white' : 'bg-white border border-slate-100 text-slate-900'}`}>

        <div className={`p-4 border-b flex items-center justify-between ${isDarkMode ? 'bg-slate-800/50 border-slate-700' : 'bg-slate-50 border-slate-100'}`}>
          <h2 className="font-serif font-bold italic px-4">Refining History</h2>
          <button onClick={onClose} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors">
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12"/></svg>
          </button>
        </div>

        {/* Toolbar */}
        <div className={`p-3 border-b flex flex-wrap items-center gap-1.5 ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
           <select 
            onChange={(e) => execCommand('fontName', e.target.value)}
            className={`px-2 py-1.5 text-[10px] font-bold rounded-lg outline-none cursor-pointer ${isDarkMode ? 'bg-slate-800 text-slate-300' : 'bg-white text-slate-600 shadow-sm'}`}
          >
            <option value="Inter">Modern Sans</option>
            <option value="Playfair Display">Classic Serif</option>
            <option value="monospace">Tech Mono</option>
          </select>

          {[
            { cmd: 'bold', label: 'B', title: 'Bold' },
            { cmd: 'italic', label: 'I', title: 'Italic', class: 'italic' },
            { cmd: 'underline', label: 'U', title: 'Underline', class: 'underline' },
          ].map((tool) => (
            <button
              key={tool.cmd}
              type="button"
              onClick={() => execCommand(tool.cmd)}
              className={`w-8 h-8 flex items-center justify-center rounded-lg text-xs font-black transition-all ${isDarkMode ? 'bg-slate-800 text-slate-300' : 'bg-white text-slate-600 border shadow-sm'}`}
            >
              <span className={tool.class}>{tool.label}</span>
            </button>
          ))}

          <button
            type="button"
            onClick={() => execCommand('insertUnorderedList')}
            className={`w-8 h-8 flex items-center justify-center rounded-lg text-xs font-black transition-all ${isDarkMode ? 'bg-slate-800 text-slate-300' : 'bg-white text-slate-600 border shadow-sm'}`}
          >
            •
          </button>

          <div className="flex-1" />

          {aiStatus && <span className="text-[9px] font-black uppercase text-indigo-500 mr-4">{aiStatus}</span>}
          <button
            type="button"
            onClick={handleFixGrammar}
            disabled={isAiLoading}
            className="px-4 py-1.5 bg-indigo-600 text-white rounded-lg text-[9px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all"
          >
            {isAiLoading ? '...' : '✨ Polish'}
          </button>
        </div>

        <div className="p-6 md:p-10 overflow-y-auto flex-1">
          <input 
            required
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            className="w-full mb-6 text-2xl md:text-3xl font-serif font-bold bg-transparent outline-none border-b border-transparent focus:border-indigo-500/30"
          />
          <div 
            ref={editorRef}
            contentEditable
            className={`w-full min-h-[400px] outline-none text-sm md:text-base leading-relaxed rich-editor ${
              isDarkMode ? 'text-slate-300' : 'text-slate-600'
            }`}
          />
        </div>

        <div className={`p-6 border-t flex gap-4 ${isDarkMode ? 'bg-slate-950 border-slate-800' : 'bg-slate-50 border-slate-100'}`}>
          <button onClick={onClose} className={`flex-1 py-4 text-[10px] font-black uppercase tracking-widest rounded-2xl border ${isDarkMode ? 'border-slate-800 text-slate-400' : 'border-slate-200 text-slate-500'}`}>Cancel</button>
          <button onClick={handleSave} disabled={isSaving} className="flex-[2] py-4 bg-indigo-600 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest shadow-xl active:scale-95 disabled:opacity-50">Update Changes</button>
        </div>
      </div>
    </div>
  );
};

export type Page = 'home' | 'create' | 'login' | 'register' | 'my-stories' | 'profile' | 'bookmarks';

export interface User {
  id: string;
  username: string;
  email: string;
  avatar: string;
  bio?: string;
  bookmarks: string[];
  blockedUsers: string[];
  totalLikes: number;
  badge: BadgeTier;
  followerCount: number;
  followingCount: number;
  password?: string;
  reportCount?: number;
  bannedUntil?: string;
  settings?: {
    showReportCount: boolean;
    showStats: boolean;
  };
}

export enum BadgeTier {
  NOVICE = 'Novice',
  BRONZE = 'Bronze',
  SILVER = 'Silver',
  GOLD = 'Gold',
  PLATINUM = 'Platinum'
}

export type ReportType = 'user' | 'post' | 'comment';

export interface Comment {
  id: string;
  userId: string;
  username: string;
  content: string;
  createdAt: string;
  reportCount?: number;
}

export interface Post {
  id: string;
  userId: string;
  username: string;
  title: string;
  content: string;
  likes: number;
  likedBy: string[]; 
  comments: Comment[];
  shares: number;
  createdAt: string;
  userAvatar: string;
  reportCount?: number;
  lastEditedAt?: string;
}

export interface Notification {
  id: string;
  type: 'like' | 'comment' | 'follow' | 'system';
  message: string;
  title?: string;
}

export interface AppState {
  currentUser: User | null;
  posts: Post[];
  isDarkMode: boolean;
  searchQuery: string;
}

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Post, User, Page, BadgeTier, Notification } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { AuthForm } from './components/AuthForm';
import { CreatePostForm } from './components/CreatePostForm';
import { PostList } from './components/PostList';
import { Profile } from './components/Profile';
import { ToastContainer } from './components/ToastContainer';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [viewingUser, setViewingUser] = useState<User | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      document.body.className = 'bg-slate-950 text-slate-100';
    } else {
      document.documentElement.classList.remove('dark');
      document.body.className = 'bg-slate-50 text-slate-900';
    }
  }, [isDarkMode]);

  const addNotification = useCallback((notif: Omit<Notification, 'id'>) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newNotif = { ...notif, id };
    setNotifications(prev => [newNotif, ...prev].slice(0, 5));
    setTimeout(() => {
      setNotifications(prev => prev.filter(n => n.id !== id));
    }, 4000);
  }, []);

  const fetchPosts = useCallback(async () => {
    setIsLoading(true);
    const data = await db.getPosts();
    setPosts(data);
    setIsLoading(false);
  }, []);

  const refreshCurrentUser = useCallback(async () => {
    const user = db.getCurrentUser();
    if (user) {
      const refreshedUser = await db.refreshUser(user.id);
      if (refreshedUser) setCurrentUser(refreshedUser);
    }
  }, []);

  useEffect(() => {
    const user = db.getCurrentUser();
    if (user) {
      setCurrentUser(user);
      refreshCurrentUser();
    }
    fetchPosts();
  }, [fetchPosts, refreshCurrentUser]);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentUser) {
      const blockedIds = currentUser.blockedUsers || [];
      result = result.filter(p => !blockedIds.includes(p.userId));
    }
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    } else if (currentPage === 'bookmarks' && currentUser) {
      const bookmarkIds = currentUser.bookmarks || [];
      result = result.filter(p => bookmarkIds.includes(p.id));
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
    setViewingUser(null);
    addNotification({ type: 'system', message: 'Successfully logged out.' });
  };

  const handleNavigate = async (page: Page, userId?: string) => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setSearchQuery('');
    if (page === 'profile') {
      const id = userId || currentUser?.id;
      if (id) {
        setIsLoading(true);
        const userToView = await db.getUserById(id);
        setViewingUser(userToView);
        setCurrentPage('profile');
        setIsLoading(false);
      } else {
        setCurrentPage('login');
      }
    } else {
      setCurrentPage(page);
      setViewingUser(null);
    }
  };

  const handleUserUpdate = (updated: User) => {
    if (currentUser?.id === updated.id) setCurrentUser(updated);
    if (viewingUser?.id === updated.id) setViewingUser(updated);
  };

  const handleFollowToggle = async (targetUserId: string) => {
    if (!currentUser) {
      setCurrentPage('login');
      return;
    }

    const isFollowing = await db.isFollowing(currentUser.id, targetUserId);
    const result = isFollowing 
      ? await db.unfollowUser(currentUser.id, targetUserId)
      : await db.followUser(currentUser.id, targetUserId);

    if (result.follower) setCurrentUser(result.follower);
    if (result.following) {
      if (viewingUser?.id === targetUserId) setViewingUser(result.following);
      addNotification({ 
        type: 'follow', 
        message: isFollowing ? `Unfollowed @${result.following.username}` : `Now following @${result.following.username}`,
        title: 'Connection Updated'
      });
    }
  };

  const getListHeader = () => {
    if (searchQuery) return { title: `Search Results`, description: `Displaying matches for "${searchQuery}".` };
    switch (currentPage) {
      case 'my-stories': return { title: 'My Narratives', description: 'Your personal collection of living stories.' };
      case 'bookmarks': return { title: 'Saved Stories', description: 'Stories you have preserved in your library.' };
      default: return { title: 'Discover the Verse', description: 'Where the world shares its hidden stories.' };
    }
  };

  const { title, description } = getListHeader();

  const BottomNavItem = ({ page, label, icon }: { page: Page; label: string; icon: React.ReactNode }) => (
    <button 
      onClick={() => handleNavigate(page)}
      className={`flex flex-col items-center gap-1 transition-all ${
        currentPage === page ? 'text-indigo-600' : 'text-slate-400'
      }`}
    >
      {icon}
      <span className="text-[9px] font-black uppercase tracking-widest">{label}</span>
    </button>
  );

  return (
    <div className={`min-h-screen flex flex-col ${isDarkMode ? 'bg-slate-950 text-slate-100' : 'bg-slate-50 text-slate-900'}`}>
      <Navbar 
        user={currentUser} 
        isDarkMode={isDarkMode} 
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
        onSearch={setSearchQuery}
        onLogout={handleLogout}
        onNavigate={handleNavigate}
        currentPage={currentPage}
      />

      <ToastContainer notifications={notifications} isDarkMode={isDarkMode} />

      <main className="flex-1 w-full max-w-5xl mx-auto px-4 pt-8 sm:pt-12 pb-24">
        {isLoading ? (
          <div className="flex flex-col items-center justify-center py-40">
            <div className={`w-12 h-12 border-4 border-t-indigo-500 rounded-full animate-spin ${isDarkMode ? 'border-slate-800' : 'border-slate-200'}`}></div>
          </div>
        ) : (
          <div className="space-y-8 sm:space-y-12">
            {(currentPage === 'home' || currentPage === 'my-stories' || currentPage === 'bookmarks') && (
              <>
                <div className="text-center mb-10 sm:mb-16">
                  <h1 className="font-serif text-3xl sm:text-5xl md:text-6xl font-bold mb-3 sm:mb-4 tracking-tight px-2">{title}</h1>
                  <p className="text-[10px] sm:text-sm md:text-base text-slate-400 font-medium px-4">{description}</p>
                </div>
                <PostList 
                  posts={filteredPosts}
                  currentUser={currentUser}
                  isDarkMode={isDarkMode}
                  onPostUpdate={(upd) => setPosts(prev => prev.map(p => p.id === upd.id ? upd : p))}
                  onPostDeleted={fetchPosts}
                  onBookmarkToggle={handleUserUpdate}
                  onUserClick={(id) => handleNavigate('profile', id)}
                  onActionClick={() => handleNavigate('create')}
                  onFollowToggle={handleFollowToggle}
                  notify={addNotification}
                  title="" 
                  description=""
                />
              </>
            )}

            {currentPage === 'create' && currentUser && (
              <CreatePostForm currentUser={currentUser} isDarkMode={isDarkMode} onPostCreated={() => { fetchPosts(); setCurrentPage('home'); addNotification({ type: 'system', message: 'Your narrative has been published.' }); }} />
            )}

            {currentPage === 'profile' && viewingUser && (
              <Profile 
                user={viewingUser} 
                currentUser={currentUser} 
                posts={posts} 
                isDarkMode={isDarkMode} 
                onAccountDeleted={handleLogout} 
                onLogout={handleLogout} 
                onUserUpdate={handleUserUpdate} 
                onFollowToggle={handleFollowToggle}
                onUserClick={(id) => handleNavigate('profile', id)}
              />
            )}

            {(currentPage === 'login' || currentPage === 'register') && (
              <div className="max-w-md mx-auto pt-4 sm:pt-10">
                <AuthForm mode={currentPage} isDarkMode={isDarkMode} onAuthSuccess={(u) => { setCurrentUser(u); setCurrentPage('home'); addNotification({ type: 'system', message: `Welcome back, @${u.username}` }); }} onSwitchMode={setCurrentPage} />
              </div>
            )}
          </div>
        )}
      </main>

      {/* Desktop Footer */}
      <footer className={`hidden md:block w-full py-16 border-t text-center ${isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'}`}>
        <div className="max-w-4xl mx-auto px-4 flex flex-col items-center">
          <h2 className="font-serif text-2xl font-bold mb-6">StoryVerse</h2>
          <div className="flex items-center gap-2 mb-8">
            <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div>
            <span className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-500">Connected to Supabase</span>
          </div>
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">
            © 2026 StoryVerse Collective. Verified Global Sync.
          </p>
        </div>
      </footer>

      {/* Mobile Bottom Navigation */}
      <div className={`md:hidden fixed bottom-0 left-0 w-full h-20 border-t z-50 flex items-center justify-around px-2 shadow-[0_-4px_12px_rgba(0,0,0,0.03)] transition-colors ${
        isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100'
      }`}>
        <BottomNavItem 
          page="home" 
          label="Feed" 
          icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>} 
        />
        <BottomNavItem 
          page="bookmarks" 
          label="Saved" 
          icon={<svg className="w-6 h-6" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z" /></svg>} 
        />
        <BottomNavItem 
          page="create" 
          label="Write" 
          icon={<div className="bg-indigo-600 text-white rounded-xl p-1.5"><svg className="w-5 h-5" fill="none" stroke="currentColor" strokeWidth="3" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" /></svg></div>} 
        />
        <BottomNavItem 
          page="profile" 
          label="Me" 
          icon={currentUser ? (
            <img src={currentUser.avatar} className="w-6 h-6 rounded-lg object-cover ring-2 ring-transparent group-active:ring-indigo-600 transition-all" />
          ) : (
            <svg className="w-6 h-6" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" /></svg>
          )} 
        />
      </div>
    </div>
  );
};

export default App;

