import React, { useState, useMemo, useEffect } from 'react';
import { Post, User, BadgeTier, Notification } from '../types';
import { BadgeIcon } from './BadgeIcon';
import { db } from '../services/db';
import { EditPostModal } from './EditPostModal';

interface PostCardProps {
  post: Post;
  currentUser: User | null;
  isDarkMode: boolean;
  onPostUpdate: (post: Post) => void;
  onPostDeleted: () => void;
  onUserClick?: (userId: string) => void;
  onBookmarkToggle?: (updatedUser: User) => void;
  onFollowToggle?: (targetUserId: string) => void;
  notify?: (notif: Omit<Notification, 'id'>) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ 
  post, 
  currentUser, 
  isDarkMode,
  onPostUpdate, 
  onPostDeleted,
  onUserClick,
  onBookmarkToggle,
  onFollowToggle,
  notify
}) => {
  const [showComments, setShowComments] = useState(false);
  const [isExpanded, setIsExpanded] = useState(false);
  const [showMenu, setShowMenu] = useState(false);
  const [showEditModal, setShowEditModal] = useState(false);
  const [authorBadge, setAuthorBadge] = useState<BadgeTier>(BadgeTier.NOVICE);
  const [isFollowing, setIsFollowing] = useState(false);
  const [isFollowLoading, setIsFollowLoading] = useState(false);
  const [showShareFeedback, setShowShareFeedback] = useState(false);
  const [isSharing, setIsSharing] = useState(false);

  const isOwner = currentUser?.id === post.userId;
  const isBookmarked = currentUser?.bookmarks?.includes(post.id);
  const isLiked = currentUser ? post.likedBy?.includes(currentUser.id) : false;

  useEffect(() => {
    db.getUserById(post.userId).then(u => u && setAuthorBadge(u.badge));
    if (currentUser && !isOwner) {
      db.isFollowing(currentUser.id, post.userId).then(setIsFollowing);
    }
  }, [post.userId, currentUser, isOwner]);

  const handleLike = async () => {
    if (!currentUser) return;
    const hasLiked = post.likedBy?.includes(currentUser.id);
    const updated = { 
      ...post, 
      likes: post.likes + (hasLiked ? -1 : 1), 
      likedBy: hasLiked ? post.likedBy.filter(id => id !== currentUser.id) : [...(post.likedBy || []), currentUser.id] 
    };
    onPostUpdate(updated);
    await db.updatePost(updated);
    await db.updateUserLikes(post.userId, hasLiked ? -1 : 1);

    if (notify) {
      notify({
        type: 'like',
        message: hasLiked ? `Like removed from "${post.title}"` : `You liked "${post.title}"`,
        title: hasLiked ? 'Activity' : 'New Interaction'
      });
    }
  };

  const handleFollowClick = async () => {
    if (!currentUser || !onFollowToggle || isFollowLoading) return;
    setIsFollowLoading(true);
    await onFollowToggle(post.userId);
    setIsFollowing(!isFollowing);
    setIsFollowLoading(false);
  };

  const handleShare = async () => {
    if (isSharing) return;
    const currentUrl = window.location.href.startsWith('http') 
      ? window.location.href 
      : window.location.origin;

    const shareData = {
      title: post.title,
      text: `Check out "${post.title}" by @${post.username} on StoryVerse!`,
      url: currentUrl,
    };

    setIsSharing(true);
    try {
      if (navigator.share && navigator.canShare && navigator.canShare(shareData)) {
        try {
          await navigator.share(shareData);
          return;
        } catch (err) {
          if ((err as Error).name === 'AbortError') return;
        }
      }
      try {
        await navigator.clipboard.writeText(currentUrl);
        setShowShareFeedback(true);
        setTimeout(() => setShowShareFeedback(false), 2000);
      } catch (err) {
        console.error('Clipboard copy failed:', err);
      }
    } finally {
      setIsSharing(false);
    }
  };

  return (
    <div className={`rounded-[2rem] border transition-all mb-6 overflow-hidden ${
      isDarkMode ? 'bg-slate-900 border-slate-800' : 'bg-white border-slate-100 shadow-sm'
    }`}>
      <div className="p-6 sm:p-8 md:p-10">
        <div className="flex items-start justify-between mb-4 sm:mb-8">
          <div className="flex items-center gap-3 sm:gap-4">
            <img 
              src={post.userAvatar} 
              className="w-10 h-10 sm:w-12 sm:h-12 rounded-xl object-cover cursor-pointer shadow-sm" 
              onClick={() => onUserClick?.(post.userId)}
            />
            <div>
              <div className="flex flex-wrap items-center gap-2 mb-0.5 sm:mb-1">
                <span className="font-bold text-xs sm:text-sm cursor-pointer" onClick={() => onUserClick?.(post.userId)}>@{post.username}</span>
                <BadgeIcon tier={authorBadge} />

                {!isOwner && currentUser && (
                  <button 
                    onClick={handleFollowClick}
                    disabled={isFollowLoading}
                    className={`text-[8px] sm:text-[9px] font-black uppercase tracking-widest px-2 py-0.5 sm:px-3 sm:py-1 rounded-full transition-all ${
                      isFollowing 
                        ? (isDarkMode ? 'bg-slate-800 text-slate-400' : 'bg-slate-100 text-slate-500')
                        : 'text-indigo-600 hover:text-indigo-700'
                    }`}
                  >
                    {isFollowLoading ? '...' : (isFollowing ? 'Following' : 'Follow')}
                  </button>
                )}
              </div>
              <div className="flex items-center gap-2 text-[8px] sm:text-[9px] text-slate-400 font-bold uppercase tracking-widest">
                <span>{new Date(post.createdAt).toLocaleDateString(undefined, { day: 'numeric', month: 'short' }).toUpperCase()}</span>
                <span>•</span>
                <span>READING NOW</span>
              </div>
            </div>
          </div>
          <div className="relative">
            <button onClick={() => setShowMenu(!showMenu)} className="p-2 text-slate-300 hover:text-slate-600 transition-colors">
              <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M10 6a2 2 0 110-4 2 2 0 010 4zM10 12a2 2 0 110-4 2 2 0 010 4zM10 18a2 2 0 110-4 2 2 0 010 4z"/></svg>
            </button>
            {showMenu && (
              <div className={`absolute right-0 top-10 w-44 rounded-2xl shadow-2xl border z-20 ${isDarkMode ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-100'}`}>
                <button onClick={() => { onUserClick?.(post.userId); setShowMenu(false); }} className="w-full text-left px-4 py-3 text-[10px] font-black uppercase tracking-widest hover:bg-slate-50 dark:hover:bg-slate-700">View Profile</button>
                {isOwner && (
                  <>
                    <button onClick={() => { setShowEditModal(true); setShowMenu(false); }} className="w-full text-left px-4 py-3 text-[10px] font-black uppercase tracking-widest border-t dark:border-slate-700">Edit Story</button>
                    <button onClick={async () => { await db.deletePost(post.id); onPostDeleted(); }} className="w-full text-left px-4 py-3 text-[10px] font-black uppercase tracking-widest text-red-500 border-t dark:border-slate-700">Delete</button>
                  </>
                )}
              </div>
            )}
          </div>
        </div>

        <h3 className="font-serif text-xl sm:text-2xl md:text-3xl font-bold mb-3 sm:mb-6 leading-tight">{post.title}</h3>

        <div 
          className={`rich-content text-sm sm:text-base leading-relaxed mb-4 sm:mb-6 ${isDarkMode ? 'text-slate-400' : 'text-slate-500'} ${isExpanded ? '' : 'line-clamp-[8]'}`}
          dangerouslySetInnerHTML={{ __html: post.content }}
        />

        <button onClick={() => setIsExpanded(!isExpanded)} className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-600 mb-6 sm:mb-10 flex items-center gap-1 hover:underline group">
          {isExpanded ? 'Collapse Story ↑' : 'Read Full Story ↓'}
        </button>

        <div className="flex items-center justify-between pt-4 sm:pt-8 border-t dark:border-slate-800">
          <div className="flex items-center gap-6 sm:gap-8">
            <button onClick={handleLike} className={`flex items-center gap-1.5 sm:gap-2.5 text-xs font-bold transition-all ${isLiked ? 'text-red-500' : 'text-slate-400 hover:text-slate-600'}`}>
              <svg className={`w-5 h-5 sm:w-6 sm:h-6 ${isLiked ? 'fill-red-500 text-red-500' : 'fill-none stroke-current'}`} strokeWidth="2" viewBox="0 0 24 24"><path d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"/></svg>
              <span className={isLiked ? 'text-red-500' : ''}>{post.likes}</span>
            </button>
            <button onClick={() => setShowComments(!showComments)} className="flex items-center gap-1.5 sm:gap-2.5 text-xs font-bold text-slate-400 hover:text-slate-600">
              <svg className="w-5 h-5 sm:w-6 sm:h-6" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"/></svg>
              <span>{post.comments.length}</span>
            </button>
            <button 
              onClick={handleShare}
              disabled={isSharing}
              className={`flex items-center gap-1 relative transition-all group ${showShareFeedback ? 'text-indigo-600 scale-110' : 'text-slate-400 hover:text-indigo-500'} disabled:opacity-50`}
              title="Share Story"
            >
              <svg className="w-5 h-5 sm:w-6 sm:h-6" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" d="M7.217 10.907a2.25 2.25 0 1 0 0 2.186m0-2.186c.18.324.283.696.283 1.093s-.103.77-.283 1.093m0-2.186 9.566-5.314m-9.566 7.5 9.566 5.314m0 0a2.25 2.25 0 1 0 3.935 2.186 2.25 2.25 0 0 0-3.935-2.186Zm0-12.814a2.25 2.25 0 1 0 3.933-2.185 2.25 2.25 0 0 0-3.933 2.185Z" />
              </svg>
              {showShareFeedback && (
                <span className="absolute -top-10 left-1/2 -translate-x-1/2 text-[9px] font-black uppercase bg-indigo-600 text-white px-3 py-1.5 rounded-xl shadow-xl animate-in fade-in slide-in-from-bottom-2 z-10 whitespace-nowrap">
                  Link Copied!
                </span>
              )}
            </button>
          </div>
          <button onClick={async () => {
             const updated = await db.toggleBookmark(currentUser!.id, post.id);
             if (updated && onBookmarkToggle) {
               onBookmarkToggle(updated);
               if (notify) notify({ type: 'system', message: updated.bookmarks.includes(post.id) ? 'Story saved to library.' : 'Story removed from library.' });
             }
          }} className={`p-1 transition-all ${isBookmarked ? 'text-indigo-500 scale-110' : 'text-slate-300 hover:text-slate-500'}`}>
            <svg className={`w-5 h-5 sm:w-6 sm:h-6 ${isBookmarked ? 'fill-current' : 'fill-none stroke-current'}`} strokeWidth="2" viewBox="0 0 24 24"><path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z" /></svg>
          </button>
        </div>
      </div>

      {showComments && (
        <div className={`p-6 sm:p-8 border-t dark:border-slate-800 animate-in slide-in-from-top duration-300 ${isDarkMode ? 'bg-slate-900/50' : 'bg-slate-50'}`}>
          <div className="space-y-4 sm:space-y-6 mb-6 sm:mb-8">
            {post.comments.map(c => (
              <div key={c.id} className="flex gap-3 sm:gap-4">
                <div className="w-8 h-8 sm:w-9 sm:h-9 rounded-xl bg-indigo-500/10 border border-indigo-500/10 flex items-center justify-center text-indigo-600 text-[10px] font-black shrink-0">{c.username[0].toUpperCase()}</div>
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-1">
                    <p className="text-[10px] sm:text-xs font-bold">@{c.username}</p>
                    <span className="text-[8px] text-slate-400 font-bold uppercase tracking-widest">{new Date(c.createdAt).toLocaleDateString()}</span>
                  </div>
                  <p className="text-xs sm:text-sm text-slate-500 leading-relaxed">{c.content}</p>
                </div>
              </div>
            ))}
            {post.comments.length === 0 && <p className="text-center text-[10px] text-slate-400 italic py-4">No responses yet.</p>}
          </div>
          {currentUser && (
            <form onSubmit={async (e) => {
              e.preventDefault();
              const text = (e.target as any).reply.value;
              if (!text.trim() || !currentUser) return;
              const comm = { id: Math.random().toString(36).substr(2, 9), userId: currentUser.id, username: currentUser.username, content: text, createdAt: new Date().toISOString() };
              await db.addComment(post.id, comm);
              onPostUpdate({ ...post, comments: [...post.comments, comm] });
              (e.target as any).reply.value = '';
              if (notify) notify({ type: 'comment', message: 'Your response was published.', title: 'Comment Posted' });
            }} className="flex gap-2 sm:gap-3">
              <input name="reply" placeholder="Add response..." className={`flex-1 px-4 py-2.5 rounded-xl text-xs border outline-none transition-all ${isDarkMode ? 'bg-slate-950 border-slate-700' : 'bg-white border-slate-200'}`} />
              <button type="submit" className="px-4 py-2.5 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest shadow-lg active:scale-95 transition-all">Reply</button>
            </form>
          )}
        </div>
      )}
      {showEditModal && <EditPostModal post={post} isDarkMode={isDarkMode} onClose={() => setShowEditModal(false)} onUpdate={onPostUpdate} />}
    </div>
  );
};

import { createClient } from '@supabase/supabase-js';
import { Post, User, BadgeTier, Comment, ReportType } from '../types';

const getEnv = (key: string): string => {
  if (typeof process !== 'undefined' && process.env && (process.env as any)[key]) {
    return (process.env as any)[key];
  }
  return '';
};

const SUPABASE_URL = getEnv('SUPABASE_URL') || 'https://uvjavqzhhqxkfuklkxdo.supabase.co';
const SUPABASE_ANON_KEY = getEnv('SUPABASE_ANON_KEY') || 'sb_publishable_-GDZiq_v45oEVhlly7tG-w_cKockqn6';

const isConfigured = SUPABASE_URL !== '' && SUPABASE_ANON_KEY !== '';
const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);
const SESSION_KEY = 'storyverse_session';

export const getBadge = (likes: number): BadgeTier => {
  if (likes >= 500) return BadgeTier.PLATINUM;
  if (likes >= 100) return BadgeTier.GOLD;
  if (likes >= 25) return BadgeTier.SILVER;
  if (likes >= 5) return BadgeTier.BRONZE;
  return BadgeTier.NOVICE;
};

export const db = {
  // --- Auth & Identity ---
  async register(username: string, email: string, password: string): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };

    const lowerEmail = email.toLowerCase().trim();
    if (!lowerEmail.endsWith('@gmail.com')) {
      return { success: false, error: 'Registration restricted to @gmail.com addresses only.' };
    }

    try {
      const userId = Math.random().toString(36).substr(2, 9);
      const userPayload = {
        id: userId,
        username: username.toLowerCase().trim(),
        email: lowerEmail,
        password: password,
        avatar: `https://picsum.photos/seed/${username}/100`,
        bio: '',
        bookmarks: [],
        blocked_users: [],
        total_likes: 0,
        badge: BadgeTier.NOVICE,
        report_count: 0
      };

      const { error } = await supabase.from('users').insert([userPayload]);
      if (error) {
        if (error.message.includes('unique constraint')) return { success: false, error: 'Username or Email already taken.' };
        return { success: false, error: error.message };
      }

      const user: User = {
        id: userId,
        username: userPayload.username,
        email: userPayload.email,
        avatar: userPayload.avatar,
        bio: '',
        bookmarks: [],
        blockedUsers: [],
        totalLikes: 0,
        badge: BadgeTier.NOVICE,
        followerCount: 0,
        followingCount: 0,
        reportCount: 0,
        settings: { showReportCount: true, showStats: true }
      };

      localStorage.setItem(SESSION_KEY, JSON.stringify(user));
      return { success: true, user };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async login(identifier: string, password: string, method: 'username' | 'email'): Promise<{ success: boolean, user?: User, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not linked.' };
    const field = method === 'username' ? 'username' : 'email';
    try {
      const { data, error } = await supabase.from('users').select('*').ilike(field, identifier).eq('password', password).maybeSingle();
      if (error) return { success: false, error: error.message };
      if (!data) return { success: false, error: 'Invalid credentials.' };
      const user = await this.refreshUser(data.id);
      return user ? { success: true, user } : { success: false, error: 'Session error.' };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async signInWithGoogle(): Promise<{ success: boolean, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Backend not configured.' };
    try {
      const { error } = await supabase.auth.signInWithOAuth({
        provider: 'google',
        options: {
          redirectTo: window.location.origin
        }
      });
      if (error) return { success: false, error: error.message };
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async handleOauthCallback(sbUser: any): Promise<User | null> {
    try {
      const { data: existingUser } = await supabase.from('users').select('*').eq('email', sbUser.email).maybeSingle();

      if (existingUser) {
        return await this.refreshUser(existingUser.id);
      }

      const username = sbUser.user_metadata?.full_name?.toLowerCase().replace(/\s/g, '') || sbUser.email.split('@')[0];
      const userId = sbUser.id; 
      const userPayload = {
        id: userId,
        username: username,
        email: sbUser.email,
        password: 'OAUTH_USER_' + Math.random().toString(36),
        avatar: sbUser.user_metadata?.avatar_url || `https://picsum.photos/seed/${username}/100`,
        bio: '',
        bookmarks: [],
        blocked_users: [],
        total_likes: 0,
        badge: BadgeTier.NOVICE,
        report_count: 0
      };

      await supabase.from('users').insert([userPayload]);
      return await this.refreshUser(userId);
    } catch (err) {
      console.error("OAuth sync error:", err);
      return null;
    }
  },

  onAuthChange(callback: (user: User | null) => void) {
    return supabase.auth.onAuthStateChange(async (event, session) => {
      if (session?.user && !this.getCurrentUser()) {
        const user = await this.handleOauthCallback(session.user);
        if (user) callback(user);
      }
    });
  },

  async updateUserProfile(userId: string, data: { username?: string; avatar?: string; bio?: string }): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const updatePayload: any = {};
      if (data.username !== undefined) updatePayload.username = data.username.toLowerCase();
      if (data.avatar !== undefined) updatePayload.avatar = data.avatar;
      if (data.bio !== undefined) updatePayload.bio = data.bio;

      await supabase.from('users').update(updatePayload).eq('id', userId);

      if (data.username || data.avatar) {
        const postUpdate: any = {};
        if (data.username) postUpdate.username = data.username.toLowerCase();
        if (data.avatar) postUpdate.user_avatar = data.avatar;
        await supabase.from('posts').update(postUpdate).eq('user_id', userId);
      }

      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  // --- Blocking System ---
  async blockUser(userId: string, targetId: string): Promise<User | null> {
    if (!isConfigured || !userId || !targetId) return null;
    try {
      const { data, error } = await supabase.from('users').select('blocked_users').eq('id', userId).maybeSingle();
      if (error) throw error;

      let blockedList = Array.isArray(data?.blocked_users) ? data.blocked_users : [];
      if (!blockedList.includes(targetId)) {
        blockedList = [...blockedList, targetId];
        const { error: updateError } = await supabase.from('users').update({ blocked_users: blockedList }).eq('id', userId);
        if (updateError) throw updateError;
      }
      return await this.refreshUser(userId);
    } catch (err) {
      console.error("blockUser failed:", err);
      return null;
    }
  },

  async unblockUser(userId: string, targetId: string): Promise<User | null> {
    if (!isConfigured || !userId || !targetId) return null;
    try {
      const { data, error } = await supabase.from('users').select('blocked_users').eq('id', userId).maybeSingle();
      if (error) throw error;

      let blockedList = Array.isArray(data?.blocked_users) ? data.blocked_users : [];
      const newBlockedList = blockedList.filter((id: string) => id !== targetId);

      const { error: updateError } = await supabase.from('users').update({ blocked_users: newBlockedList }).eq('id', userId);
      if (updateError) throw updateError;

      return await this.refreshUser(userId);
    } catch (err) {
      console.error("unblockUser failed:", err);
      return null;
    }
  },

  // --- Posts & Content ---
  async getPosts(): Promise<Post[]> {
    if (!isConfigured) return [];
    try {
      const { data, error } = await supabase
        .from('posts')
        .select(`*, comments (*)`)
        .order('created_at', { ascending: false });

      if (error) throw error;

      return (data || []).map(post => ({
        id: post.id,
        userId: post.user_id,
        username: post.username,
        title: post.title,
        content: post.content,
        likes: post.likes || 0,
        likedBy: Array.isArray(post.liked_by) ? post.liked_by : [],
        shares: post.shares || 0,
        createdAt: post.created_at,
        userAvatar: post.user_avatar,
        reportCount: post.report_count || 0,
        lastEditedAt: post.last_edited_at,
        comments: (post.comments || []).map((c: any) => ({
          id: c.id,
          userId: c.user_id,
          username: c.username,
          content: c.content,
          createdAt: c.created_at,
          reportCount: c.report_count || 0
        }))
      }));
    } catch (err) {
      console.error("getPosts failed:", err);
      return [];
    }
  },

  async savePost(post: Post): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Suspended account.");
    if (!isConfigured) return;
    await supabase.from('posts').insert([{
      id: post.id,
      user_id: post.userId,
      username: post.username,
      title: post.title,
      content: post.content,
      likes: post.likes,
      liked_by: post.likedBy,
      shares: post.shares,
      user_avatar: post.userAvatar,
      created_at: post.createdAt,
      report_count: 0
    }]);
  },

  async updatePost(updatedPost: Post): Promise<void> {
    if (!isConfigured) return;
    await supabase.from('posts').update({
      likes: updatedPost.likes,
      liked_by: updatedPost.likedBy,
      shares: updatedPost.shares,
      title: updatedPost.title,
      content: updatedPost.content
    }).eq('id', updatedPost.id);
  },

  async updatePostContent(postId: string, title: string, content: string): Promise<boolean> {
    if (!isConfigured) return false;
    try {
      const { error } = await supabase.from('posts').update({
        title,
        content,
        last_edited_at: new Date().toISOString()
      }).eq('id', postId);
      return !error;
    } catch {
      return false;
    }
  },

  async deletePost(postId: string): Promise<{ success: boolean, error?: string }> {
    if (!isConfigured) return { success: false };
    try {
      await supabase.from('comments').delete().eq('post_id', postId);
      const { error } = await supabase.from('posts').delete().eq('id', postId);
      if (error) throw error;
      return { success: true };
    } catch (err: any) {
      return { success: false, error: err.message };
    }
  },

  async addComment(postId: string, comment: Comment): Promise<void> {
    const user = this.getCurrentUser();
    if (this.isBanned(user)) throw new Error("Suspended account.");
    if (!isConfigured) return;
    await supabase.from('comments').insert([{
      id: comment.id,
      post_id: postId,
      user_id: comment.userId,
      username: comment.username,
      content: comment.content,
      created_at: comment.createdAt,
      report_count: 0
    }]);
  },

  // --- Global Utility ---
  async getUserById(userId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data, error } = await supabase.from('users').select('*').eq('id', userId).maybeSingle();
      if (error || !data) return null;
      const stats = await this.getFollowStats(data.id);
      return {
        id: data.id,
        username: data.username,
        email: data.email,
        avatar: data.avatar,
        bio: data.bio || '',
        bookmarks: Array.isArray(data.bookmarks) ? data.bookmarks : [],
        blockedUsers: Array.isArray(data.blocked_users) ? data.blocked_users : [],
        totalLikes: data.total_likes || 0,
        badge: (data.badge as BadgeTier) || BadgeTier.NOVICE,
        followerCount: stats.followers,
        followingCount: stats.following,
        reportCount: data.report_count || 0,
        bannedUntil: data.banned_until,
        settings: { showReportCount: true, showStats: true }
      };
    } catch (err) {
      console.error("getUserById error:", err);
      return null;
    }
  },

  async refreshUser(userId: string): Promise<User | null> {
    const user = await this.getUserById(userId);
    if (user) localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    return user;
  },

  getCurrentUser(): User | null {
    try {
      const session = localStorage.getItem(SESSION_KEY);
      return session ? JSON.parse(session) : null;
    } catch {
      return null;
    }
  },

  async toggleBookmark(userId: string, postId: string): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const { data: user } = await supabase.from('users').select('bookmarks').eq('id', userId).maybeSingle();
      if (!user) return null;
      let bookmarks = Array.isArray(user.bookmarks) ? user.bookmarks : [];
      const newBookmarks = bookmarks.includes(postId)
        ? bookmarks.filter((id: string) => id !== postId)
        : [...bookmarks, postId];
      await supabase.from('users').update({ bookmarks: newBookmarks }).eq('id', userId);
      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  async updateUserLikes(userId: string, delta: number): Promise<void> {
    if (!isConfigured) return;
    const { data: dbUser } = await supabase.from('users').select('total_likes').eq('id', userId).maybeSingle();
    if (!dbUser) return;
    const newTotalLikes = Math.max(0, (dbUser.total_likes || 0) + delta);
    const newBadge = getBadge(newTotalLikes);
    await supabase.from('users').update({ total_likes: newTotalLikes, badge: newBadge }).eq('id', userId);
  },

  async updateUserSettings(userId: string, settings: any): Promise<User | null> {
    if (!isConfigured || !userId) return null;
    try {
      const user = this.getCurrentUser();
      if (user && user.id === userId) {
        user.settings = settings;
        localStorage.setItem(SESSION_KEY, JSON.stringify(user));
        return user;
      }
      return await this.refreshUser(userId);
    } catch (err) {
      return null;
    }
  },

  async reportEntity(reporterId: string, targetType: ReportType, targetId: string, reason: string): Promise<{ success: boolean, message: string }> {
    if (!isConfigured) return { success: false, message: 'Backend not configured.' };
    try {
      const alreadyReported = await this.hasAlreadyReported(reporterId, targetType, targetId);
      if (alreadyReported) return { success: false, message: 'Already reported.' };
      let table = targetType === 'user' ? 'users' : (targetType === 'post' ? 'posts' : 'comments');
      await supabase.from('reports').insert([{ id: Math.random().toString(36).substr(2, 9), reporter_id: reporterId, target_type: targetType, target_id: targetId, reason }]);
      const { data } = await supabase.from(table).select('report_count').eq('id', targetId).maybeSingle();
      const newCount = (data?.report_count || 0) + 1;
      await supabase.from(table).update({ report_count: newCount }).eq('id', targetId);
      return { success: true, message: 'Report submitted.' };
    } catch {
      return { success: false, message: 'Error submitting report.' };
    }
  },

  async hasAlreadyReported(reporterId: string, targetType: ReportType, targetId: string): Promise<boolean> {
    const { data } = await supabase.from('reports').select('id').eq('reporter_id', reporterId).eq('target_type', targetType).eq('target_id', targetId).maybeSingle();
    return !!data;
  },

  async getFollowStats(userId: string): Promise<{ followers: number, following: number }> {
    try {
      const { count: followers } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('following_id', userId);
      const { count: following } = await supabase.from('follows').select('*', { count: 'exact', head: true }).eq('follower_id', userId);
      return { followers: followers || 0, following: following || 0 };
    } catch { return { followers: 0, following: 0 }; }
  },

  async getFollowers(userId: string): Promise<User[]> {
    try {
      const { data } = await supabase.from('follows').select('follower_id').eq('following_id', userId);
      if (!data) return [];
      const ids = data.map(f => f.follower_id);
      if (ids.length === 0) return [];
      const users = await Promise.all(ids.map(id => this.getUserById(id)));
      return users.filter((u): u is User => u !== null);
    } catch { return []; }
  },

  async getFollowingList(userId: string): Promise<User[]> {
    try {
      const { data } = await supabase.from('follows').select('following_id').eq('follower_id', userId);
      if (!data) return [];
      const ids = data.map(f => f.following_id);
      if (ids.length === 0) return [];
      const users = await Promise.all(ids.map(id => this.getUserById(id)));
      return users.filter((u): u is User => u !== null);
    } catch { return []; }
  },

  async isFollowing(followerId: string, followingId: string): Promise<boolean> {
    const { data } = await supabase.from('follows').select('*').eq('follower_id', followerId).eq('following_id', followingId).maybeSingle();
    return !!data;
  },

  async followUser(followerId: string, followingId: string): Promise<{ follower: User | null, following: User | null }> {
    await supabase.from('follows').insert([{ follower_id: followerId, following_id: followingId }]);
    return { follower: await this.refreshUser(followerId), following: await this.getUserById(followingId) };
  },

  async unfollowUser(followerId: string, followingId: string): Promise<{ follower: User | null, following: User | null }> {
    await supabase.from('follows').delete().eq('follower_id', followerId).eq('following_id', followingId);
    return { follower: await this.refreshUser(followerId), following: await this.getUserById(followingId) };
  },

  async deleteAccount(userId: string): Promise<{ success: boolean, error?: string }> {
    if (!isConfigured) return { success: false, error: 'Database connection lost.' };
    try {
      const { data: postsData } = await supabase.from('posts').select('id').eq('user_id', userId);
      const postIds = (postsData || []).map(p => p.id);

      if (postIds.length > 0) {
        await supabase.from('comments').delete().in('post_id', postIds);
        await supabase.from('reports').delete().eq('target_type', 'post').in('target_id', postIds);
      }

      await supabase.from('comments').delete().eq('user_id', userId);
      await supabase.from('posts').delete().eq('user_id', userId);
      await supabase.from('follows').delete().eq('follower_id', userId);
      await supabase.from('follows').delete().eq('following_id', userId);
      await supabase.from('reports').delete().eq('reporter_id', userId);
      await supabase.from('reports').delete().eq('target_type', 'user').eq('target_id', userId);

      const { error } = await supabase.from('users').delete().eq('id', userId);
      if (error) throw error;

      this.logout();
      return { success: true };
    } catch (err: any) {
      console.error("Account deletion failed:", err);
      return { success: false, error: err.message || 'Deletion failed due to database constraints.' };
    }
  },

  isBanned(user: User | null): boolean {
    if (!user || !user.bannedUntil) return false;
    return new Date(user.bannedUntil) > new Date();
  },

  logout() {
    localStorage.removeItem(SESSION_KEY);
    supabase.auth.signOut();
  }
};

import React, { useState } from 'react';
import { User } from '../types';
import { db } from '../services/db';
import { aiService } from '../services/ai';
import { EyeIcon, EyeOffIcon } from './Icons';

interface AuthFormProps {
  mode: 'login' | 'register';
  isDarkMode: boolean;
  onAuthSuccess: (user: User) => void;
  onSwitchMode: (newMode: 'login' | 'register') => void;
}

type RegisterStep = 'INFO' | 'SUCCESS';

export const AuthForm: React.FC<AuthFormProps> = ({ mode, isDarkMode, onAuthSuccess, onSwitchMode }) => {
  const [loginMethod, setLoginMethod] = useState<'username' | 'email'>('username');
  const [step, setStep] = useState<RegisterStep>('INFO');

  const [authUsername, setAuthUsername] = useState('');
  const [authEmail, setAuthEmail] = useState('');
  const [authPassword, setAuthPassword] = useState('');
  const [authConfirmPassword, setAuthConfirmPassword] = useState('');

  const [authError, setAuthError] = useState('');
  const [verifyingEmail, setVerifyingEmail] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const validatePassword = (pass: string) => {
    return pass.length >= 8 && /[A-Z]/.test(pass) && /[0-9]/.test(pass);
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');
    setIsSubmitting(true);

    const lowerEmail = authEmail.toLowerCase().trim();
    if (!lowerEmail.endsWith('@gmail.com')) {
      setAuthError('Access Denied: Only @gmail.com addresses are permitted for registration.');
      setIsSubmitting(false);
      return;
    }

    if (authPassword !== authConfirmPassword) {
      setAuthError('Passwords do not match');
      setIsSubmitting(false);
      return;
    }

    if (!validatePassword(authPassword)) {
      setAuthError('Password must be 8+ characters with uppercase and numbers.');
      setIsSubmitting(false);
      return;
    }

    setVerifyingEmail(true);
    try {
      const riskCheck = await aiService.validateEmailRisk(authEmail);
      setVerifyingEmail(false);
      if (!riskCheck.isSafe) {
        setAuthError(riskCheck.reason || "This email does not meet our security standards. Please use a verified provider.");
        setIsSubmitting(false);
        return;
      }
    } catch (err) {
      setVerifyingEmail(false);
    }

    try {
      const result = await db.register(authUsername, authEmail, authPassword);
      if (result.success && result.user) {
        setStep('SUCCESS');
        setTimeout(() => onAuthSuccess(result.user!), 1500);
      } else {
        setAuthError(result.error || 'Registration failed.');
      }
    } catch (err) {
      setAuthError('Failed to register. Please try again.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError('');
    setIsSubmitting(true);

    const identifier = loginMethod === 'username' ? authUsername : authEmail;
    try {
      const result = await db.login(identifier, authPassword, loginMethod);
      if (result.success && result.user) {
        onAuthSuccess(result.user);
      } else {
        setAuthError(result.error || 'Invalid credentials.');
      }
    } catch (err) {
      setAuthError('Login service unavailable.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleGoogleSignIn = async () => {
    setAuthError('');
    setIsSubmitting(true);
    try {
      const result = await db.signInWithGoogle();
      if (!result.success) {
        setAuthError(result.error || 'Google connection failed.');
        setIsSubmitting(false);
      }
      // Redirect happens automatically
    } catch (err) {
      setAuthError('Identity services currently offline.');
      setIsSubmitting(false);
    }
  };

  if (step === 'SUCCESS') {
    return (
      <div className="max-w-md mx-auto py-20 text-center animate-in zoom-in duration-500">
        <div className="w-20 h-20 bg-emerald-500 rounded-full flex items-center justify-center mx-auto mb-6 text-white shadow-xl shadow-emerald-500/20">
          <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7"/></svg>
        </div>
        <h2 className="text-3xl font-serif font-bold mb-2">Welcome!</h2>
        <p className="text-slate-500 uppercase text-[10px] font-black tracking-widest">Entry granted to the StoryVerse Collective.</p>
      </div>
    );
  }

  return (
    <section className="max-w-md mx-auto py-6 md:py-10 text-center px-4">
      <div className="mb-8 flex flex-col items-center">
        <h2 className="text-2xl md:text-3xl font-serif font-bold mb-3">
          {mode === 'login' ? 'Welcome Back' : 'Join StoryVerse'}
        </h2>
      </div>

      {authError && (
        <div className="mb-6 p-4 bg-red-50 border border-red-200 text-red-700 text-xs md:text-sm rounded-xl font-bold flex items-center gap-3 text-left animate-in slide-in-from-top duration-200">
          <svg className="w-5 h-5 shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd"/></svg>
          <div className="flex flex-col">
             <span className="text-[10px] uppercase opacity-60">Security Alert</span>
             <span>{authError}</span>
          </div>
        </div>
      )}

      <div className={`p-6 md:p-8 rounded-2xl shadow-xl space-y-6 text-left ${isDarkMode ? 'bg-slate-900 border border-slate-800' : 'bg-white border border-slate-100'}`}>
        {mode === 'login' && (
          <>
            <div className={`flex p-1 rounded-xl mb-4 ${isDarkMode ? 'bg-slate-800' : 'bg-slate-100'}`}>
              <button 
                onClick={() => setLoginMethod('username')}
                className={`flex-1 py-2 text-[10px] md:text-xs font-bold rounded-lg transition-all ${loginMethod === 'username' ? (isDarkMode ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600 shadow-sm') : 'text-slate-500'}`}
              >
                Username
              </button>
              <button 
                onClick={() => setLoginMethod('email')}
                className={`flex-1 py-2 text-[10px] md:text-xs font-bold rounded-lg transition-all ${loginMethod === 'email' ? (isDarkMode ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600 shadow-sm') : 'text-slate-500'}`}
              >
                Email
              </button>
            </div>

            <form onSubmit={handleLogin} className="space-y-4">
              <div>
                <label className="text-[10px] font-bold uppercase text-slate-400 block mb-1">{loginMethod === 'username' ? 'Username' : 'Email Address'}</label>
                <input 
                  type={loginMethod === 'username' ? "text" : "email"} 
                  required
                  disabled={isSubmitting}
                  value={loginMethod === 'username' ? authUsername : authEmail}
                  onChange={(e) => loginMethod === 'username' ? setAuthUsername(e.target.value) : setAuthEmail(e.target.value)}
                  className={`w-full p-3 rounded-xl border outline-none transition-all text-sm ${isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'}`}
                />
              </div>

              <div>
                <label className="text-[10px] font-bold uppercase text-slate-400 block mb-1">Password</label>
                <div className="relative">
                  <input 
                    type={showPassword ? "text" : "password"} 
                    required
                    disabled={isSubmitting}
                    value={authPassword}
                    onChange={(e) => setAuthPassword(e.target.value)}
                    className={`w-full p-3 pr-10 rounded-xl border outline-none transition-all text-sm ${isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'}`}
                  />
                  <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400">
                    {showPassword ? <EyeOffIcon /> : <EyeIcon />}
                  </button>
                </div>
              </div>

              <button type="submit" disabled={isSubmitting} className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-md flex items-center justify-center gap-2">
                {isSubmitting && !verifyingEmail ? <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div> : 'Login'}
              </button>
            </form>
          </>
        )}

        {mode === 'register' && (
          <form onSubmit={handleRegister} className="space-y-4">
            <div>
              <label className="text-[10px] font-bold uppercase text-slate-400 block mb-1">Username</label>
              <input type="text" required value={authUsername} onChange={(e) => setAuthUsername(e.target.value)} className={`w-full p-3 rounded-xl border outline-none transition-all text-sm ${isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'}`} />
            </div>
            <div>
              <label className="text-[10px] font-bold uppercase text-slate-400 block mb-1">Email Address (@gmail.com only)</label>
              <input type="email" required placeholder="e.g. name@gmail.com" value={authEmail} onChange={(e) => setAuthEmail(e.target.value)} className={`w-full p-3 rounded-xl border outline-none transition-all text-sm ${isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'}`} />
            </div>
            <div>
              <label className="text-[10px] font-bold uppercase text-slate-400 block mb-1">Create Password</label>
              <div className="relative">
                <input type={showPassword ? "text" : "password"} required value={authPassword} onChange={(e) => setAuthPassword(e.target.value)} className={`w-full p-3 pr-10 rounded-xl border outline-none transition-all text-sm ${isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'}`} />
                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400"><EyeIcon /></button>
              </div>
            </div>
            <div>
              <label className="text-[10px] font-bold uppercase text-slate-400 block mb-1">Confirm Password</label>
              <input type="password" required value={authConfirmPassword} onChange={(e) => setAuthConfirmPassword(e.target.value)} className={`w-full p-3 rounded-xl border outline-none transition-all text-sm ${isDarkMode ? 'bg-slate-900 border-slate-700 focus:border-indigo-500 text-white' : 'bg-white border-slate-200 focus:border-indigo-500'}`} />
            </div>
            <button type="submit" disabled={isSubmitting} className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold shadow-lg flex items-center justify-center gap-2 overflow-hidden relative">
              {verifyingEmail ? (
                <div className="flex items-center gap-2">
                   <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                   <span>Securing Identity...</span>
                </div>
              ) : isSubmitting ? (
                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
              ) : (
                'Create Account'
              )}
            </button>
          </form>
        )}

        <div className="relative py-4">
           <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-slate-100 dark:border-slate-800"></div></div>
           <div className="relative flex justify-center text-[10px] font-black uppercase tracking-widest"><span className={`px-4 ${isDarkMode ? 'bg-slate-900 text-slate-600' : 'bg-white text-slate-400'}`}>Secure Options</span></div>
        </div>

        <button 
          onClick={handleGoogleSignIn}
          disabled={isSubmitting}
          className={`w-full py-3 px-4 rounded-xl border flex items-center justify-center gap-3 transition-all active:scale-[0.98] disabled:opacity-50 ${isDarkMode ? 'bg-slate-900 border-slate-700 hover:bg-slate-800' : 'bg-white border-slate-200 hover:bg-slate-50 shadow-sm'}`}
        >
           {isSubmitting && mode === 'login' ? (
              <div className="w-4 h-4 border-2 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
           ) : (
             <svg className="w-5 h-5" viewBox="0 0 24 24"><path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/><path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/><path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l3.66-2.84z"/><path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/></svg>
           )}
           <span className="text-xs font-bold">Sign in with Google</span>
        </button>
      </div>

      <div className="mt-8 text-sm">
        {mode === 'login' ? (
          <p className="text-slate-500">
            Need an account? {' '}
            <button onClick={() => onSwitchMode('register')} className="text-indigo-600 font-bold hover:underline">Register</button>
          </p>
        ) : (
          <p className="text-slate-500">
            Already have an account? {' '}
            <button onClick={() => onSwitchMode('login')} className="text-indigo-600 font-bold hover:underline">Login</button>
          </p>
        )}
      </div>
    </section>
  );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Post, User, Page, BadgeTier, Notification } from './types';
import { db } from './services/db';
import { Navbar } from './components/Navbar';
import { AuthForm } from './components/AuthForm';
import { CreatePostForm } from './components/CreatePostForm';
import { PostList } from './components/PostList';
import { Profile } from './components/Profile';
import { ToastContainer } from './components/ToastContainer';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [posts, setPosts] = useState<Post[]>([]);
  const [isDarkMode, setIsDarkMode] = useState(false);
  const [currentPage, setCurrentPage] = useState<Page>('home');
  const [viewingUser, setViewingUser] = useState<User | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  useEffect(() => {
    if (isDarkMode) {
      document.documentElement.classList.add('dark');
      document.body.className = 'bg-slate-950 text-slate-100';
    } else {
      document.documentElement.classList.remove('dark');
      document.body.className = 'bg-slate-50 text-slate-900';
    }
  }, [isDarkMode]);

  const addNotification = useCallback((notif: Omit<Notification, 'id'>) => {
    const id = Math.random().toString(36).substr(2, 9);
    const newNotif = { ...notif, id };
    setNotifications(prev => [newNotif, ...prev].slice(0, 5));
    setTimeout(() => {
      setNotifications(prev => prev.filter(n => n.id !== id));
    }, 4000);
  }, []);

  const fetchPosts = useCallback(async () => {
    setIsLoading(true);
    const data = await db.getPosts();
    setPosts(data);
    setIsLoading(false);
  }, []);

  const refreshCurrentUser = useCallback(async () => {
    const user = db.getCurrentUser();
    if (user) {
      const refreshedUser = await db.refreshUser(user.id);
      if (refreshedUser) setCurrentUser(refreshedUser);
    }
  }, []);

  useEffect(() => {
    const user = db.getCurrentUser();
    if (user) {
      setCurrentUser(user);
      refreshCurrentUser();
    }
    fetchPosts();

    // Listen for OAuth identity changes
    const { data: { subscription } } = db.onAuthChange((user) => {
      if (user) {
        setCurrentUser(user);
        addNotification({ type: 'system', message: `Welcome back, @${user.username}` });
        setCurrentPage('home');
      }
    });

    return () => subscription.unsubscribe();
  }, [fetchPosts, refreshCurrentUser, addNotification]);

  const filteredPosts = useMemo(() => {
    let result = [...posts];
    if (currentUser) {
      const blockedIds = currentUser.blockedUsers || [];
      result = result.filter(p => !blockedIds.includes(p.userId));
    }
    if (currentPage === 'my-stories' && currentUser) {
      result = result.filter(p => p.userId === currentUser.id);
    } else if (currentPage === 'bookmarks' && currentUser) {
      const bookmarkIds = currentUser.bookmarks || [];
      result = result.filter(p => bookmarkIds.includes(p.id));
    }
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      result = result.filter(p => 
        p.title.toLowerCase().includes(q) || 
        p.content.toLowerCase().includes(q) || 
        p.username.toLowerCase().includes(q)
      );
    }
    return result;
  }, [posts, searchQuery, currentPage, currentUser]);

  const handleLogout = () => {
    db.logout();
    setCurrentUser(null);
    setCurrentPage('home');
    setViewingUser(null);
    addNotification({ type: 'system', message: 'Successfully logged out.' });
  };

  const handleNavigate = async (page: Page, userId?: string) => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setSearchQuery('');
    if (page === 'profile') {
      const id = userId || currentUser?.id;
      if (id) {
        setIsLoading(true);
        const userToView = await db.getUserById(id);
        setViewingUser(userToView);
        setCurrentPage('profile');
        setIsLoading(false);
      } else {
        setCurrentPage('login');
      }
    } else {
      setCurrentPage(page);
      setViewingUser(null);
    }
  };

  const handleUserUpdate = (updated: User) => {
    if (currentUser?.id === updated.id) setCurrentUser(updated);
    if (viewingUser?.id === updated.id) setViewingUser(updated);
  };

  const handleFollowToggle = async (targetUserId: string) => {
    if (!currentUser) {
      setCurrentPage('login');
      return;
    }

    const isFollowing = await db.isFollowing(currentUser.id, targetUserId);
    const result = isFollowing 
      ? await db.unfollowUser(currentUser.id, targetUserId)
      : await db.followUser(currentUser.id, targetUserId);

    if (result.follower) setCurrentUser(result.follower);
    if (result.following) {
      if (viewingUser?.id === targetUserId) setViewingUser(result.following);
      addNotification({ 
        type: 'follow', 
        message: isFollowing ? `Unfollowed @${result.following.username}` : `Now following @${result.following.username}`,
        title: 'Connection Updated'
      });
    }
  };

  const getListHeader = () => {
    if (searchQuery) return { title: `Search Results`, description: `Displaying matches for "${searchQuery}".` };
    switch (currentPage) {
      case 'my-stories': return { title: 'My Narratives', description: 'Your personal collection of living stories.' };
      case 'bookmarks': return { title: 'Saved Stories', description: 'Stories you have preserved in your library.' };
      default: return { title: 'Discover the Verse', description: 'Where the world shares its hidden stories.' };
